"use client";

import { useState } from "react";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Badge, Icon } from "@/components/shared";
import { useApp } from "@/lib/store";
import { ProviderManager } from "@/lib/ai/services";
import { toast } from "sonner";

// Common models per provider type — used to populate the model picker
const MODEL_CATALOG: Record<string, { name: string; contextWindow: string; inputCost?: number; outputCost?: number; tags?: string[] }[]> = {
  openai: [
    { name: "gpt-4o", contextWindow: "128K", inputCost: 0.0000025, outputCost: 0.00001, tags: ["flagship", "vision"] },
    { name: "gpt-4o-mini", contextWindow: "128K", inputCost: 0.00000015, outputCost: 0.0000006, tags: ["cheap", "fast"] },
    { name: "gpt-4-turbo", contextWindow: "128K", inputCost: 0.00001, outputCost: 0.00003 },
    { name: "o1-preview", contextWindow: "128K", inputCost: 0.000015, outputCost: 0.00006, tags: ["reasoning"] },
  ],
  claude: [
    { name: "claude-3-5-sonnet-20241022", contextWindow: "200K", inputCost: 0.000003, outputCost: 0.000015, tags: ["flagship"] },
    { name: "claude-3-5-haiku-20241022", contextWindow: "200K", inputCost: 0.0000008, outputCost: 0.000004, tags: ["fast"] },
    { name: "claude-3-opus-20240229", contextWindow: "200K", inputCost: 0.000015, outputCost: 0.000075 },
  ],
  gemini: [
    { name: "gemini-2.0-flash", contextWindow: "1M", inputCost: 0.0000001, outputCost: 0.0000004, tags: ["fast", "vision"] },
    { name: "gemini-1.5-pro", contextWindow: "2M", inputCost: 0.00000125, outputCost: 0.000005 },
    { name: "gemini-1.5-flash", contextWindow: "1M", inputCost: 0.000000075, outputCost: 0.0000003 },
  ],
  deepseek: [
    { name: "deepseek-chat", contextWindow: "64K", inputCost: 0.00000014, outputCost: 0.00000028 },
    { name: "deepseek-reasoner", contextWindow: "64K", inputCost: 0.00000055, outputCost: 0.00000219, tags: ["reasoning"] },
  ],
  groq: [
    { name: "llama-3.3-70b-versatile", contextWindow: "128K", tags: ["fast", "free"] },
    { name: "llama-3.1-8b-instant", contextWindow: "128K", tags: ["fastest"] },
    { name: "mixtral-8x7b-32768", contextWindow: "32K" },
  ],
  puter: [
    { name: "claude-sonnet-4", contextWindow: "200K", tags: ["free", "flagship"] },
    { name: "gpt-4o", contextWindow: "128K", tags: ["free"] },
    { name: "gemini-2.0-flash", contextWindow: "1M", tags: ["free"] },
    { name: "llama-3.3-70b", contextWindow: "128K", tags: ["free"] },
    { name: "mistral-large", contextWindow: "128K", tags: ["free"] },
  ],
  ollama: [
    { name: "llama3.3:70b", contextWindow: "128K", tags: ["self-hosted"] },
    { name: "qwen2.5:32b", contextWindow: "32K", tags: ["self-hosted"] },
    { name: "mistral-nemo", contextWindow: "128K", tags: ["self-hosted"] },
    { name: "phi4:14b", contextWindow: "16K", tags: ["self-hosted", "small"] },
  ],
  opencode: [
    { name: "deepseek-v4-flash-free", contextWindow: "64K", tags: ["free", "fast"] },
    { name: "mimo-v2.5-free", contextWindow: "32K", tags: ["free"] },
    { name: "minimax-m3-free", contextWindow: "32K", tags: ["free"] },
    { name: "nemotron-3-ultra-free", contextWindow: "32K", tags: ["free"] },
    { name: "north-mini-code-free", contextWindow: "32K", tags: ["free", "code"] },
    { name: "claude-sonnet-4", contextWindow: "200K", tags: ["premium"] },
    { name: "claude-opus-4-8", contextWindow: "200K", tags: ["premium"] },
    { name: "gpt-5", contextWindow: "128K", tags: ["premium"] },
    { name: "gpt-5.5", contextWindow: "128K", tags: ["premium"] },
    { name: "gemini-3-flash", contextWindow: "1M", tags: ["premium"] },
    { name: "gemini-3.5-flash", contextWindow: "1M", tags: ["premium"] },
    { name: "deepseek-v4-pro", contextWindow: "64K", tags: ["premium"] },
    { name: "glm-5", contextWindow: "128K", tags: ["premium"] },
    { name: "kimi-k2.6", contextWindow: "128K", tags: ["premium"] },
    { name: "qwen3.6-plus", contextWindow: "128K", tags: ["premium"] },
  ],
};

export function AIModels() {
  const providers = useApp((s) => s.providers);
  const updateProvider = useApp((s) => s.updateProvider);
  const [selectedProviderId, setSelectedProviderId] = useState<string>(providers[0]?.id ?? "");
  const [customModel, setCustomModel] = useState("");
  const [fetching, setFetching] = useState(false);
  const [liveModels, setLiveModels] = useState<string[]>([]);

  const selected = providers.find((p) => p.id === selectedProviderId);
  const catalog = selected ? (MODEL_CATALOG[selected.type] ?? []) : [];
  const enabledModels = selected?.enabledModels ?? [];

  const fetchLiveModels = async () => {
    if (!selected) return;
    setFetching(true);
    setLiveModels([]);
    const result = await ProviderManager.fetchModels(selected);
    setFetching(false);
    if (result.ok && result.models.length > 0) {
      setLiveModels(result.models);
      toast.success(`Fetched ${result.models.length} live models from ${selected.name}.`);
    } else {
      toast.error(result.error || "Failed to fetch models. Check the provider's API key and Base URL.");
    }
  };

  const toggleModel = (modelName: string) => {
    if (!selected) return;
    const current = selected.enabledModels ?? [];
    const next = current.includes(modelName)
      ? current.filter((m) => m !== modelName)
      : [...current, modelName];
    updateProvider(selected.id, { enabledModels: next });
    toast.success(`${modelName} ${next.includes(modelName) ? "enabled" : "disabled"} for ${selected.name}.`);
  };

  const addCustom = () => {
    if (!selected || !customModel.trim()) return;
    const next = [...(selected.enabledModels ?? []), customModel.trim()];
    updateProvider(selected.id, { enabledModels: next });
    setCustomModel("");
    toast.success(`Added custom model: ${customModel.trim()}`);
  };

  const setAsDefaultModel = (modelName: string) => {
    if (!selected) return;
    updateProvider(selected.id, { modelName });
    toast.success(`${modelName} set as default model for ${selected.name}.`);
  };

  return (
    <div className="space-y-6">
      <div>
        <h1 className="font-display text-2xl font-bold flex items-center gap-2"><Icon name="Boxes" className="w-6 h-6 text-brand" /> AI Models</h1>
        <p className="text-sm text-muted-foreground mt-1">Browse the model catalog and enable specific models per provider.</p>
      </div>

      <div className="grid lg:grid-cols-12 gap-6">
        {/* Provider picker */}
        <Card className="lg:col-span-3">
          <CardHeader><CardTitle className="text-base">Providers</CardTitle></CardHeader>
          <CardContent className="space-y-1">
            {providers.map((p) => (
              <button
                key={p.id}
                onClick={() => setSelectedProviderId(p.id)}
                className={`w-full text-left p-2.5 rounded-md text-sm transition ${selectedProviderId === p.id ? "bg-brand text-white" : "hover:bg-secondary"}`}
              >
                <div className="font-medium truncate">{p.name}</div>
                <div className={`text-xs ${selectedProviderId === p.id ? "text-white/70" : "text-muted-foreground"} capitalize`}>{p.type.replace("-", " ")}</div>
              </button>
            ))}
          </CardContent>
        </Card>

        {/* Model catalog */}
        <div className="lg:col-span-9 space-y-4">
          {selected && (
            <>
              <Card>
                <CardContent className="p-4 flex items-center justify-between gap-3">
                  <div>
                    <div className="font-semibold flex items-center gap-2">
                      {selected.name}
                      <Badge variant="outline" className="capitalize text-[10px]">{selected.type.replace("-", " ")}</Badge>
                    </div>
                    <div className="text-xs text-muted-foreground mt-0.5">
                      Default model: <span className="font-mono">{selected.modelName || "—"}</span> · {enabledModels.length} models enabled
                    </div>
                  </div>
                </CardContent>
              </Card>

              {/* Add custom model + fetch live models */}
              <Card>
                <CardContent className="p-4 space-y-3">
                  <div className="flex gap-2">
                    <Input value={customModel} onChange={(e) => setCustomModel(e.target.value)} placeholder="Add custom model name (e.g. gpt-4o-2024-08-06)" onKeyDown={(e) => e.key === "Enter" && addCustom()} />
                    <Button onClick={addCustom} disabled={!customModel.trim()} className="bg-brand hover:bg-brand-dark text-white gap-2 shrink-0">
                      <Icon name="Plus" className="w-4 h-4" /> Add
                    </Button>
                  </div>
                  <div className="flex items-center gap-2 pt-2 border-t border-border">
                    <Button onClick={fetchLiveModels} disabled={fetching || !selected} variant="outline" className="gap-2">
                      {fetching ? <Icon name="Loader2" className="w-4 h-4 animate-spin" /> : <Icon name="DownloadCloud" className="w-4 h-4" />}
                      {fetching ? "Fetching…" : "Fetch live models from API"}
                    </Button>
                    <span className="text-xs text-muted-foreground">Calls GET /v1/models on the provider's API</span>
                  </div>
                  {liveModels.length > 0 && (
                    <div className="space-y-2">
                      <div className="text-xs font-semibold uppercase tracking-wide text-muted-foreground">{liveModels.length} live models from {selected?.name}</div>
                      <div className="grid sm:grid-cols-2 lg:grid-cols-3 gap-2 max-h-60 overflow-y-auto p-1">
                        {liveModels.map((m) => {
                          const isEnabled = enabledModels.includes(m);
                          const isDefault = selected?.modelName === m;
                          return (
                            <div key={m} className={`rounded-md border p-2 ${isEnabled ? "border-brand bg-brand-light/30" : "border-border"}`}>
                              <div className="flex items-center justify-between gap-1">
                                <span className="font-mono text-[11px] truncate">{m}</span>
                                {isDefault && <Badge variant="gold" className="text-[8px] shrink-0">DEFAULT</Badge>}
                              </div>
                              <div className="flex gap-1 mt-1">
                                <button onClick={() => toggleModel(m)} className={`text-[10px] px-1.5 py-0.5 rounded ${isEnabled ? "bg-brand text-white" : "bg-secondary"}`}>
                                  {isEnabled ? "Enabled" : "Enable"}
                                </button>
                                <button onClick={() => setAsDefaultModel(m)} className="text-[10px] px-1.5 py-0.5 rounded bg-secondary" title="Set as default">
                                  <Icon name="Star" className="w-2.5 h-2.5" />
                                </button>
                              </div>
                            </div>
                          );
                        })}
                      </div>
                    </div>
                  )}
                </CardContent>
              </Card>

              {/* Catalog grid */}
              {catalog.length > 0 ? (
                <div className="grid sm:grid-cols-2 lg:grid-cols-3 gap-3">
                  {catalog.map((m) => {
                    const isEnabled = enabledModels.includes(m.name);
                    const isDefault = selected.modelName === m.name;
                    return (
                      <Card key={m.name} className={isEnabled ? "border-brand" : ""}>
                        <CardContent className="p-4">
                          <div className="flex items-start justify-between mb-2">
                            <div className="font-mono text-sm font-semibold break-all">{m.name}</div>
                            {isDefault && <Badge variant="gold" className="text-[9px]">DEFAULT</Badge>}
                          </div>
                          <div className="flex flex-wrap gap-1 mb-3">
                            <Badge variant="outline" className="text-[10px]">{m.contextWindow} ctx</Badge>
                            {m.tags?.map((t) => <Badge key={t} variant="brand" className="text-[10px]">{t}</Badge>)}
                          </div>
                          {(m.inputCost || m.outputCost) && (
                            <div className="text-xs text-muted-foreground mb-3">
                              ${(m.inputCost ?? 0).toFixed(7)}/in · ${(m.outputCost ?? 0).toFixed(7)}/out
                            </div>
                          )}
                          <div className="flex gap-1">
                            <Button size="sm" variant={isEnabled ? "default" : "outline"} onClick={() => toggleModel(m.name)} className="flex-1 gap-1.5">
                              <Icon name={isEnabled ? "Check" : "Plus"} className="w-3.5 h-3.5" /> {isEnabled ? "Enabled" : "Enable"}
                            </Button>
                            <Button size="sm" variant="ghost" onClick={() => setAsDefaultModel(m.name)} title="Set as default">
                              <Icon name="Star" className="w-3.5 h-3.5" />
                            </Button>
                          </div>
                        </CardContent>
                      </Card>
                    );
                  })}
                </div>
              ) : (
                <Card>
                  <CardContent className="p-8 text-center">
                    <Icon name="Boxes" className="w-10 h-10 text-muted-foreground/40 mx-auto" />
                    <p className="text-sm text-muted-foreground mt-2">No catalog models for {selected.type}. Add custom model names above.</p>
                  </CardContent>
                </Card>
              )}

              {/* Enabled models list */}
              {enabledModels.length > 0 && (
                <Card>
                  <CardHeader><CardTitle className="text-base">Enabled models ({enabledModels.length})</CardTitle></CardHeader>
                  <CardContent>
                    <div className="flex flex-wrap gap-2">
                      {enabledModels.map((m) => (
                        <div key={m} className="flex items-center gap-1.5 px-2.5 py-1.5 rounded-md border border-border bg-card">
                          <span className="font-mono text-xs">{m}</span>
                          <button onClick={() => toggleModel(m)} className="text-muted-foreground hover:text-destructive" aria-label="Remove">
                            <Icon name="X" className="w-3 h-3" />
                          </button>
                        </div>
                      ))}
                    </div>
                  </CardContent>
                </Card>
              )}
            </>
          )}
        </div>
      </div>
    </div>
  );
}

src/components/app/modules/AIProviderEdi:
"use client";

import { useState } from "react";
import { motion } from "framer-motion";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Switch } from "@/components/ui/switch";
import { Badge, Icon } from "@/components/shared";
import { ProviderManager } from "@/lib/ai/services";
import { toast } from "sonner";
import type { AIProvider, AIProviderType } from "@/lib/types";

const PROVIDER_TYPES: { type: AIProviderType; label: string; icon: string; defaultUrl?: string; defaultModel?: string; authType?: "bearer" | "header" | "query" | "none" }[] = [
  { type: "puter", label: "Puter.js (Free)", icon: "Sparkles", defaultUrl: "https://api.puter.com", defaultModel: "claude-sonnet-4", authType: "none" },
  { type: "opencode", label: "OpenCode Zen (Free models)", icon: "Gift", defaultUrl: "https://opencode.ai/zen/v1", defaultModel: "deepseek-v4-flash-free", authType: "bearer" },
  { type: "openai", label: "OpenAI", icon: "Bot", defaultUrl: "https://api.openai.com/v1", defaultModel: "gpt-4o-mini", authType: "bearer" },
  { type: "claude", label: "Anthropic Claude", icon: "Bot", defaultUrl: "https://api.anthropic.com/v1", defaultModel: "claude-3-5-sonnet-20241022", authType: "header" },
  { type: "gemini", label: "Google Gemini", icon: "Bot", defaultUrl: "https://generativelanguage.googleapis.com/v1beta", defaultModel: "gemini-2.0-flash", authType: "query" },
  { type: "deepseek", label: "DeepSeek", icon: "Bot", defaultUrl: "https://api.deepseek.com/v1", defaultModel: "deepseek-chat", authType: "bearer" },
  { type: "groq", label: "Groq", icon: "Zap", defaultUrl: "https://api.groq.com/openai/v1", defaultModel: "llama-3.3-70b-versatile", authType: "bearer" },
  { type: "mistral", label: "Mistral AI", icon: "Bot", defaultUrl: "https://api.mistral.ai/v1", defaultModel: "mistral-large-latest", authType: "bearer" },
  { type: "cohere", label: "Cohere", icon: "Bot", defaultUrl: "https://api.cohere.com/v2", defaultModel: "command-r-plus", authType: "bearer" },
  { type: "perplexity", label: "Perplexity", icon: "Search", defaultUrl: "https://api.perplexity.ai", defaultModel: "llama-3.1-sonar-large-128k-online", authType: "bearer" },
  { type: "openrouter", label: "OpenRouter", icon: "Network", defaultUrl: "https://openrouter.ai/api/v1", defaultModel: "anthropic/claude-3.5-sonnet", authType: "bearer" },
  { type: "together", label: "Together AI", icon: "Users", defaultUrl: "https://api.together.xyz/v1", defaultModel: "meta-llama/Llama-3.3-70B-Instruct-Turbo", authType: "bearer" },
  { type: "huggingface", label: "HuggingFace", icon: "Box", defaultUrl: "https://api-inference.huggingface.co/models", defaultModel: "meta-llama/Llama-3.3-70B-Instruct", authType: "bearer" },
  { type: "ollama", label: "Ollama (self-hosted)", icon: "HardDrive", defaultUrl: "http://localhost:11434", defaultModel: "llama3.3:70b", authType: "none" },
  { type: "azure-openai", label: "Azure OpenAI", icon: "Cloud", defaultUrl: "https://{resource}.openai.azure.com/openai/deployments/{deployment}", defaultModel: "gpt-4o", authType: "header" },
  { type: "bedrock", label: "AWS Bedrock", icon: "Cloud", defaultUrl: "https://bedrock-runtime.us-east-1.amazonaws.com", defaultModel: "anthropic.claude-3-5-sonnet-20241022-v1:0", authType: "bearer" },
  { type: "custom", label: "Custom / self-hosted LLM", icon: "Settings", defaultUrl: "", defaultModel: "", authType: "bearer" },
];

export function ProviderEditor({ provider, onClose, onSave }: {
  provider: AIProvider | null;
  onClose: () => void;
  onSave: (p: Partial<AIProvider>) => void;
}) {
  const [fetchingModels, setFetchingModels] = useState(false);
  const [fetchedModels, setFetchedModels] = useState<string[]>([]);
  const [form, setForm] = useState(() => ({
    name: provider?.name ?? "",
    type: (provider?.type ?? "custom") as AIProviderType,
    baseUrl: provider?.baseUrl ?? provider?.apiUrl ?? "",
    apiKey: provider?.apiKey ?? "",
    modelName: provider?.modelName ?? "",
    temperature: provider?.temperature ?? 0.7,
    maxTokens: provider?.maxTokens ?? 4096,
    headersJson: provider?.headersJson ?? "",
    parametersJson: provider?.parametersJson ?? "",
    requestTemplate: provider?.requestTemplate ?? "",
    responsePath: provider?.responsePath ?? "",
    streamingEnabled: provider?.streamingEnabled ?? false,
    priority: provider?.priority ?? 10,
    isActive: provider?.isActive ?? true,
    isDefault: provider?.isDefault ?? false,
    timeout: provider?.timeout ?? 30000,
    retryAttempts: provider?.retryAttempts ?? 2,
    rateLimitPerMinute: provider?.rateLimitPerMinute ?? 60,
    authType: (provider?.authType ?? "bearer") as "bearer" | "header" | "query" | "none",
    supportsFunctionCalling: provider?.supportsFunctionCalling ?? false,
    allowedForRegularUsers: provider?.allowedForRegularUsers ?? false,
    costPerInputToken: provider?.costPerInputToken ?? 0,
    costPerOutputToken: provider?.costPerOutputToken ?? 0,
    // Puter
    applicationId: provider?.applicationId ?? "",
    clientId: provider?.clientId ?? "",
    redirectUri: provider?.redirectUri ?? "",
    enabledModels: provider?.enabledModels?.join(", ") ?? "",
  }));

  const cfg = PROVIDER_TYPES.find((t) => t.type === form.type);
  const isCustom = form.type === "custom";
  const isPuter = form.type === "puter";

  const onTypeChange = (type: AIProviderType) => {
    const t = PROVIDER_TYPES.find((x) => x.type === type) ?? PROVIDER_TYPES[0];
    setForm((f) => ({
      ...f,
      type,
      baseUrl: f.baseUrl || t.defaultUrl || "",
      modelName: f.modelName || t.defaultModel || "",
      authType: t.authType ?? "bearer",
    }));
  };

  return (
    <motion.div
      initial={{ opacity: 0 }}
      animate={{ opacity: 1 }}
      exit={{ opacity: 0 }}
      className="fixed inset-0 z-50 bg-background/80 backdrop-blur-sm flex items-center justify-center p-0 sm:p-4"
      onClick={onClose}
    >
      <motion.div
        initial={{ y: 20, opacity: 0 }}
        animate={{ y: 0, opacity: 1 }}
        exit={{ y: 20, opacity: 0 }}
        transition={{ type: "spring", damping: 26, stiffness: 280 }}
        className="bg-card rounded-t-2xl sm:rounded-2xl border border-border shadow-premium w-full sm:max-w-3xl max-h-[95vh] overflow-y-auto"
        onClick={(e) => e.stopPropagation()}
      >
        <div className="sticky top-0 bg-card border-b border-border p-4 flex items-center justify-between z-10">
          <h3 className="font-display font-bold text-lg flex items-center gap-2">
            <Icon name={cfg?.icon ?? "Cpu"} className="w-5 h-5 text-brand" />
            {provider ? "Edit provider" : "Add provider"}
          </h3>
          <Button variant="ghost" size="icon" onClick={onClose}><Icon name="X" className="w-4 h-4" /></Button>
        </div>

        <div className="p-5 space-y-5">
          {/* Type selector */}
          <div>
            <Label className="text-xs uppercase tracking-wide text-muted-foreground">Provider type</Label>
            <div className="grid grid-cols-2 sm:grid-cols-4 gap-2 mt-2 max-h-44 overflow-y-auto p-1 rounded-lg bg-secondary/50">
              {PROVIDER_TYPES.map((t) => (
                <button
                  key={t.type}
                  onClick={() => onTypeChange(t.type)}
                  className={`flex items-center gap-1.5 p-2 rounded-md text-xs font-medium transition ${form.type === t.type ? "bg-brand text-white shadow-sm" : "bg-card hover:bg-secondary text-muted-foreground"}`}
                  title={t.label}
                >
                  <Icon name={t.icon} className="w-3.5 h-3.5 shrink-0" />
                  <span className="truncate">{t.label.split(" ")[0]}</span>
                </button>
              ))}
            </div>
          </div>

          {/* Basic fields */}
          <div className="grid sm:grid-cols-2 gap-3">
            <Field label="Display name"><Input value={form.name} onChange={(e) => setForm({ ...form, name: e.target.value })} placeholder="OpenAI Production" /></Field>
            <div className="space-y-1.5">
              <Label className="text-xs uppercase tracking-wide text-muted-foreground">Model name</Label>
              <div className="flex gap-2">
                <Input value={form.modelName} onChange={(e) => setForm({ ...form, modelName: e.target.value })} placeholder={cfg?.defaultModel ?? "gpt-4o-mini"} className="flex-1" />
                <Button
                  type="button"
                  variant="outline"
                  size="sm"
                  onClick={async () => {
                    // === PUTER: use static built-in models, not API fetch ===
                    if (form.type === "puter") {
                      setFetchingModels(true);
                      const result = await ProviderManager.fetchModels({
                        type: "puter",
                        isActive: true,
                      } as any);
                      setFetchingModels(false);
                      if (result.ok && result.models.length > 0) {
                        setFetchedModels(result.models);
                        toast.success(`Loaded ${result.models.length} built-in Puter models.`);
                      } else {
                        toast.error("Failed to load Puter models.");
                      }
                      return;
                    }
                    if (!form.baseUrl) { toast.error("Enter a Base URL first."); return; }
                    setFetchingModels(true);
                    setFetchedModels([]);
                    const result = await ProviderManager.fetchModelsForConfig({
                      type: form.type,
                      baseUrl: form.baseUrl,
                      apiKey: form.apiKey,
                      headersJson: form.headersJson,
                      authType: form.authType,
                      timeout: form.timeout,
                    });
                    setFetchingModels(false);
                    if (result.ok && result.models.length > 0) {
                      setFetchedModels(result.models);
                      toast.success(`Fetched ${result.models.length} models from the API.`);
                    } else {
                      toast.error(result.error || "No models returned. Check the API key and Base URL.");
                    }
                  }}
                  disabled={fetchingModels || (form.type !== "puter" && !form.baseUrl)}
                  className="gap-1.5 shrink-0"
                >
                  {fetchingModels ? <Icon name="Loader2" className="w-3.5 h-3.5 animate-spin" /> : <Icon name="DownloadCloud" className="w-3.5 h-3.5" />}
                  {form.type === "puter" ? "Built-in" : "Fetch"}
                </Button>
              </div>
              {fetchedModels.length > 0 && (
                <div className="mt-1">
                  <select
                    value={form.modelName}
                    onChange={(e) => setForm({ ...form, modelName: e.target.value })}
                    className="w-full h-9 px-2 rounded-md border border-input bg-background text-sm"
                  >
                    <option value="">— Select a model —</option>
                    {fetchedModels.map((m) => <option key={m} value={m}>{m}</option>)}
                  </select>
                  <p className="text-[10px] text-muted-foreground mt-0.5">{fetchedModels.length} live models fetched from the API</p>
                </div>
              )}
            </div>
            <Field label="Base URL"><Input value={form.baseUrl} onChange={(e) => setForm({ ...form, baseUrl: e.target.value })} placeholder={cfg?.defaultUrl ?? "https://api.example.com/v1"} /></Field>
            <Field label="API key (encrypted at rest)">
              <Input type="password" value={form.apiKey} onChange={(e) => setForm({ ...form, apiKey: e.target.value })} placeholder={isPuter ? "(not required for Puter)" : "sk-..."} disabled={isPuter} />
            </Field>
            <Field label="Auth type">
              <select value={form.authType} onChange={(e) => setForm({ ...form, authType: e.target.value as any })} className="w-full h-9 px-3 rounded-md border border-input bg-background text-sm">
                <option value="bearer">Bearer token (Authorization header)</option>
                <option value="header">Custom header (X-API-Key)</option>
                <option value="query">Query parameter (?api_key=)</option>
                <option value="none">None (open endpoint)</option>
              </select>
            </Field>
            <Field label="Priority (1 = highest)"><Input type="number" value={form.priority} onChange={(e) => setForm({ ...form, priority: parseInt(e.target.value) || 10 })} /></Field>
            <Field label="Temperature"><Input type="number" step="0.1" min="0" max="2" value={form.temperature} onChange={(e) => setForm({ ...form, temperature: parseFloat(e.target.value) || 0.7 })} /></Field>
            <Field label="Max tokens"><Input type="number" value={form.maxTokens} onChange={(e) => setForm({ ...form, maxTokens: parseInt(e.target.value) || 4096 })} /></Field>
            <Field label="Timeout (ms)"><Input type="number" value={form.timeout} onChange={(e) => setForm({ ...form, timeout: parseInt(e.target.value) || 30000 })} /></Field>
            <Field label="Retry attempts"><Input type="number" value={form.retryAttempts} onChange={(e) => setForm({ ...form, retryAttempts: parseInt(e.target.value) || 2 })} /></Field>
            <Field label="Rate limit (req/min)"><Input type="number" value={form.rateLimitPerMinute} onChange={(e) => setForm({ ...form, rateLimitPerMinute: parseInt(e.target.value) || 60 })} /></Field>
            <Field label="Cost per 1K input tokens (USD)"><Input type="number" step="0.0001" value={form.costPerInputToken * 1000} onChange={(e) => setForm({ ...form, costPerInputToken: (parseFloat(e.target.value) || 0) / 1000 })} /></Field>
            <Field label="Cost per 1K output tokens (USD)"><Input type="number" step="0.0001" value={form.costPerOutputToken * 1000} onChange={(e) => setForm({ ...form, costPerOutputToken: (parseFloat(e.target.value) || 0) / 1000 })} /></Field>
          </div>

          {/* Toggles */}
          <div className="grid sm:grid-cols-2 gap-2">
            <Toggle label="Enable provider" desc="Make this provider available for requests" checked={form.isActive} onChange={(v) => setForm({ ...form, isActive: v })} />
            <Toggle label="Set as default" desc="Use as the first-choice provider" checked={form.isDefault} onChange={(v) => setForm({ ...form, isDefault: v })} />
            <Toggle label="Enable streaming" desc="Stream responses token-by-token" checked={form.streamingEnabled} onChange={(v) => setForm({ ...form, streamingEnabled: v })} />
            <Toggle label="Function calling" desc="Provider supports tool/function calls" checked={form.supportsFunctionCalling} onChange={(v) => setForm({ ...form, supportsFunctionCalling: v })} />
          </div>

          {/* User Access Control — super admin only */}
          <div className="rounded-lg border-2 border-brand/30 bg-brand-light/30 dark:bg-brand/5 p-4">
            <div className="flex items-center justify-between gap-3">
              <div className="flex items-center gap-2">
                <Icon name="Users" className="w-5 h-5 text-brand" />
                <div>
                  <div className="font-semibold text-sm flex items-center gap-2">
                    Allow regular users to use this provider
                  </div>
                  <div className="text-xs text-muted-foreground mt-0.5">
                    When ON, all signed-in users can route AI requests through this provider.
                    When OFF, only super admins can use it. Use this to control which AI models
                    regular users get access to (e.g. Puter.js = free for everyone, OpenAI = super-admin-only).
                  </div>
                </div>
              </div>
              <Switch checked={form.allowedForRegularUsers} onCheckedChange={(v) => setForm({ ...form, allowedForRegularUsers: v })} />
            </div>
            {form.allowedForRegularUsers && (
              <div className="mt-2 text-xs text-emerald-600 flex items-center gap-1">
                <Icon name="CheckCircle2" className="w-3.5 h-3.5" />
                This provider is available to ALL users (regular + admin + super admin)
              </div>
            )}
            {!form.allowedForRegularUsers && (
              <div className="mt-2 text-xs text-amber-600 flex items-center gap-1">
                <Icon name="Lock" className="w-3.5 h-3.5" />
                This provider is super-admin-only
              </div>
            )}
          </div>

          {/* Puter-specific */}
          {isPuter && (
            <div className="rounded-lg border border-amber-300/50 bg-amber-100/40 dark:bg-amber-400/5 p-4 space-y-3">
              <div className="flex items-center gap-2 text-sm font-semibold text-amber-800 dark:text-amber-300"><Icon name="Sparkles" className="w-4 h-4" /> Puter.js configuration</div>
              <p className="text-xs text-amber-700 dark:text-amber-400/80">Puter.js is free for end users — they authenticate with their own Google account. No API key needed from you.</p>
              <div className="grid sm:grid-cols-2 gap-3">
                <Field label="Application ID"><Input value={form.applicationId} onChange={(e) => setForm({ ...form, applicationId: e.target.value })} placeholder="resumeai-pro-app" /></Field>
                <Field label="Client ID"><Input value={form.clientId} onChange={(e) => setForm({ ...form, clientId: e.target.value })} placeholder="resumeai-pro-client" /></Field>
                <Field label="Redirect URI"><Input value={form.redirectUri} onChange={(e) => setForm({ ...form, redirectUri: e.target.value })} placeholder="https://resumeai.pro/auth/puter/callback" /></Field>
                <Field label="Enabled models (comma-separated)"><Input value={form.enabledModels} onChange={(e) => setForm({ ...form, enabledModels: e.target.value })} placeholder="claude-sonnet-4, gpt-4o, gemini-2.0-flash" /></Field>
              </div>
            </div>
          )}

          {/* Custom provider config */}
          {isCustom && (
            <div className="rounded-lg border border-brand/30 bg-brand-light/30 dark:bg-brand/5 p-4 space-y-3">
              <div className="flex items-center gap-2 text-sm font-semibold text-brand"><Icon name="Settings" className="w-4 h-4" /> Custom provider configuration</div>
              <p className="text-xs text-muted-foreground">Configure any LLM with templated request/response. Use <code className="text-xs bg-secondary px-1 rounded">{"{{model}}"}</code>, <code className="text-xs bg-secondary px-1 rounded">{"{{messages}}"}</code>, <code className="text-xs bg-secondary px-1 rounded">{"{{temperature}}"}</code>, <code className="text-xs bg-secondary px-1 rounded">{"{{max_tokens}}"}</code>, <code className="text-xs bg-secondary px-1 rounded">{"{{api_key}}"}</code> placeholders.</p>
              <Field label="Request body template (JSON)">
                <textarea
                  value={form.requestTemplate}
                  onChange={(e) => setForm({ ...form, requestTemplate: e.target.value })}
                  rows={6}
                  placeholder={`{\n  "model": "{{model}}",\n  "messages": "{{messages}}",\n  "temperature": {{temperature}},\n  "max_tokens": {{max_tokens}}\n}`}
                  className="w-full rounded-md border border-input bg-background px-3 py-2 text-xs font-mono resize-none focus:outline-none focus:ring-2 focus:ring-ring"
                />
              </Field>
              <Field label="Response JSON path (where to extract the text)">
                <Input value={form.responsePath} onChange={(e) => setForm({ ...form, responsePath: e.target.value })} placeholder="choices[0].message.content" className="font-mono text-xs" />
              </Field>
            </div>
          )}

          {/* Advanced */}
          <details className="rounded-lg border border-border">
            <summary className="cursor-pointer p-3 text-sm font-medium flex items-center gap-2"><Icon name="ChevronDown" className="w-4 h-4" /> Advanced (custom headers & parameters)</summary>
            <div className="p-3 pt-0 space-y-3">
              <Field label="Custom headers (JSON)">
                <textarea
                  value={form.headersJson}
                  onChange={(e) => setForm({ ...form, headersJson: e.target.value })}
                  rows={3}
                  placeholder='{ "X-Custom-Header": "value" }'
                  className="w-full rounded-md border border-input bg-background px-3 py-2 text-xs font-mono resize-none focus:outline-none focus:ring-2 focus:ring-ring"
                />
              </Field>
              <Field label="Custom parameters (JSON)">
                <textarea
                  value={form.parametersJson}
                  onChange={(e) => setForm({ ...form, parametersJson: e.target.value })}
                  rows={3}
                  placeholder='{ "top_p": 0.9, "frequency_penalty": 0 }'
                  className="w-full rounded-md border border-input bg-background px-3 py-2 text-xs font-mono resize-none focus:outline-none focus:ring-2 focus:ring-ring"
                />
              </Field>
            </div>
          </details>

          <div className="rounded-lg bg-amber-100 dark:bg-amber-400/10 p-3 text-xs flex items-start gap-2">
            <Icon name="ShieldCheck" className="w-4 h-4 text-amber-700 dark:text-amber-400 shrink-0 mt-0.5" />
            <div className="text-amber-800 dark:text-amber-300">
              API keys are stored encrypted at rest and never exposed to the client in production. In production (Cloudflare Workers), store keys as secrets via <code className="bg-amber-200/50 dark:bg-amber-400/20 px-1 rounded">wrangler secret put</code> — never in source code.
            </div>
          </div>
        </div>

        <div className="sticky bottom-0 bg-card border-t border-border p-4 flex justify-end gap-2">
          <Button variant="outline" onClick={onClose}>Cancel</Button>
          <Button
            onClick={() => {
              if (!form.name.trim()) { toast.error("Please enter a display name."); return; }
              onSave({
                ...form,
                baseUrl: form.baseUrl,
                apiUrl: form.baseUrl, // keep both in sync
                enabledModels: form.enabledModels.split(",").map((s) => s.trim()).filter(Boolean),
              });
            }}
            className="bg-brand hover:bg-brand-dark text-white gap-2"
          >
            <Icon name="Save" className="w-4 h-4" /> Save provider
          </Button>
        </div>
      </motion.div>
    </motion.div>
  );
}

function Field({ label, children }: { label: string; children: React.ReactNode }) {
  return (
    <div className="space-y-1.5">
      <Label className="text-xs uppercase tracking-wide text-muted-foreground">{label}</Label>
      {children}
    </div>
  );
}

function Toggle({ label, desc, checked, onChange }: { label: string; desc: string; checked: boolean; onChange: (v: boolean) => void }) {
  return (
    <div className="flex items-center justify-between gap-3 p-3 rounded-lg border border-border">
      <div className="min-w-0">
        <div className="text-sm font-medium">{label}</div>
        <div className="text-xs text-muted-foreground">{desc}</div>
      </div>
      <Switch checked={checked} onCheckedChange={onChange} />
    </div>
  );
}

src/components/app/modules/AIProviders.t:
"use client";

import { useState, useMemo, useEffect, useCallback } from "react";
import { motion } from "framer-motion";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Switch } from "@/components/ui/switch";
import { Badge, Icon } from "@/components/shared";
import { useApp, uid } from "@/lib/store";
import { ProviderManager } from "@/lib/ai/services";
import { toast } from "sonner";
import type { AIProvider, AIProviderType } from "@/lib/types";
import { isOpenCodeZenFree } from "@/lib/provider-capabilities";
import { ProviderEditor } from "./AIProviderEditor";
import { ProviderAnalytics } from "./ProviderAnalytics";
import { ProviderLogsTable } from "./ProviderLogsTable";
import { TestConnectionModal } from "./TestConnectionModal";
import { PuterAuthCard } from "./PuterAuthCard";
import { getPuterProvider } from "@/lib/providers";
import type { ProviderAuthStatus } from "@/lib/providers/interface";
import {
  AreaChart, Area, BarChart, Bar, PieChart, Pie, Cell,
  XAxis, YAxis, Tooltip, ResponsiveContainer, Legend,
} from "recharts";

const PROVIDER_TYPES: { type: AIProviderType; label: string; icon: string; defaultUrl?: string; defaultModel?: string; authType?: "bearer" | "header" | "query" | "none" }[] = [
  { type: "puter", label: "Puter.js (Free)", icon: "Sparkles", defaultUrl: "https://api.puter.com", defaultModel: "claude-sonnet-4" },
  { type: "openai", label: "OpenAI", icon: "Bot", defaultUrl: "https://api.openai.com/v1", defaultModel: "gpt-4o-mini", authType: "bearer" },
  { type: "claude", label: "Anthropic Claude", icon: "Bot", defaultUrl: "https://api.anthropic.com/v1", defaultModel: "claude-3-5-sonnet-20241022", authType: "header" },
  { type: "gemini", label: "Google Gemini", icon: "Bot", defaultUrl: "https://generativelanguage.googleapis.com/v1beta", defaultModel: "gemini-2.0-flash", authType: "bearer" },
  { type: "deepseek", label: "DeepSeek", icon: "Bot", defaultUrl: "https://api.deepseek.com/v1", defaultModel: "deepseek-chat", authType: "bearer" },
  { type: "groq", label: "Groq", icon: "Zap", defaultUrl: "https://api.groq.com/openai/v1", defaultModel: "llama-3.3-70b-versatile", authType: "bearer" },
  { type: "mistral", label: "Mistral AI", icon: "Bot", defaultUrl: "https://api.mistral.ai/v1", defaultModel: "mistral-large-latest", authType: "bearer" },
  { type: "cohere", label: "Cohere", icon: "Bot", defaultUrl: "https://api.cohere.com/v1", defaultModel: "command-r-plus", authType: "bearer" },
  { type: "perplexity", label: "Perplexity", icon: "Search", defaultUrl: "https://api.perplexity.ai", defaultModel: "llama-3.1-sonar-large-128k-online", authType: "bearer" },
  { type: "openrouter", label: "OpenRouter", icon: "Network", defaultUrl: "https://openrouter.ai/api/v1", defaultModel: "anthropic/claude-3.5-sonnet", authType: "bearer" },
  { type: "together", label: "Together AI", icon: "Users", defaultUrl: "https://api.together.xyz/v1", defaultModel: "meta-llama/Llama-3.3-70B-Instruct-Turbo", authType: "bearer" },
  { type: "huggingface", label: "HuggingFace", icon: "Box", defaultUrl: "https://api-inference.huggingface.co", defaultModel: "meta-llama/Llama-3.3-70B-Instruct", authType: "bearer" },
  { type: "ollama", label: "Ollama (self-hosted)", icon: "HardDrive", defaultUrl: "http://localhost:11434", defaultModel: "llama3.3:70b", authType: "none" },
  { type: "azure-openai", label: "Azure OpenAI", icon: "Cloud", defaultUrl: "https://{resource}.openai.azure.com/openai/deployments/{deployment}", defaultModel: "gpt-4o", authType: "header" },
  { type: "bedrock", label: "AWS Bedrock", icon: "Cloud", defaultUrl: "https://bedrock-runtime.us-east-1.amazonaws.com", defaultModel: "anthropic.claude-3-5-sonnet-20241022-v1:0", authType: "bearer" },
  { type: "custom", label: "Custom / self-hosted LLM", icon: "Settings", defaultUrl: "", defaultModel: "", authType: "bearer" },
];

type Tab = "providers" | "auth" | "analytics" | "logs";

export function AIProviders() {
  const providers = useApp((s) => s.providers);
  const settings = useApp((s) => s.providerSettings);
  const setView = useApp((s) => s.setView);

  // Provider auth state — MUST be declared before the tab state that references them
  const [puterStatus, setPuterStatus] = useState<ProviderAuthStatus>({
    connected: false, authenticated: false, email: null, expiresAt: null, models: [], sharedAdminAccount: false, authMethod: null, googleUserId: null, googlePicture: null,
  });
  

  // Default to providers tab if Puter is authenticated; otherwise show auth
  const [tab, setTab] = useState<Tab>(puterStatus.authenticated ? "providers" : "auth");
  const [showAdd, setShowAdd] = useState(false);
  const [editing, setEditing] = useState<AIProvider | null>(null);
  const [testing, setTesting] = useState<AIProvider | null>(null);
  const [q, setQ] = useState("");

  // Refresh auth status from providers
  const refreshAuthStatus = useCallback(() => {
    try {
      setPuterStatus(getPuterProvider().getStatus());
    } catch (e) { console.warn("[AIProviders] Puter status check failed:", e instanceof Error ? e.message : e); }
  }, []);

  // Restore sessions on mount and switch to providers tab if already authenticated
  useEffect(() => {
    (async () => {
      let puterOk = false;
      
      try { const s = await getPuterProvider().restore(); puterOk = !!s?.authenticated; } catch (e) { console.warn("[AIProviders] Puter restore failed:", e instanceof Error ? e.message : e); }
      
      refreshAuthStatus();
      // If already authenticated, show providers tab (not auth tab)
      if (puterOk) {
        setTab("providers");
      }
    })();
  }, [refreshAuthStatus]);

  const totalReqs = providers.reduce((n, p) => n + p.usage.requests, 0);
  const activeCount = providers.filter((p) => p.isActive).length;
  const healthyCount = providers.filter((p) => p.status === "healthy").length;
  const totalCost = providers.reduce((n, p) => n + p.usage.cost, 0);

  const filtered = providers.filter((p) => p.name.toLowerCase().includes(q.toLowerCase()) || p.type.toLowerCase().includes(q.toLowerCase()));

  const handleTest = async (provider: AIProvider) => {
    setTesting(provider);
  };

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between flex-wrap gap-3">
        <div>
          <h1 className="font-display text-2xl font-bold flex items-center gap-2"><Icon name="Cpu" className="w-6 h-6 text-brand" /> AI Providers</h1>
          <p className="text-sm text-muted-foreground mt-1">Multi-provider system with automatic failover. 17 types supported — extendable without code changes.</p>
        </div>
        <div className="flex gap-2">
          <Button variant="outline" onClick={() => setView("ai-settings")} className="gap-2">
            <Icon name="Settings" className="w-4 h-4" /> Routing settings
          </Button>
          <Button onClick={() => { setEditing(null); setShowAdd(true); }} className="bg-brand hover:bg-brand-dark text-white gap-2">
            <Icon name="Plus" className="w-4 h-4" /> Add provider
          </Button>
        </div>
      </div>

      {/* KPI cards */}
      <div className="grid grid-cols-2 lg:grid-cols-6 gap-3">
        {[
          { label: "Total providers", value: providers.length, icon: "Cpu", color: "#1154A3" },
          { label: "Active", value: activeCount, icon: "CheckCircle2", color: "#10B981" },
          { label: "Healthy", value: healthyCount, icon: "Heart", color: "#10B981" },
          { label: "Total requests", value: totalReqs.toLocaleString(), icon: "Activity", color: "#F59E0B" },
          { label: "Est. cost", value: `$${totalCost.toFixed(4)}`, icon: "DollarSign", color: "#8B5CF6" },
          { label: "OAuth Auth", value: [puterStatus.authenticated].filter(Boolean).length, icon: "Shield", color: "#10B981" },
        ].map((s) => (
          <Card key={s.label}>
            <CardContent className="p-4 flex items-center gap-3">
              <div className="w-9 h-9 rounded-lg flex items-center justify-center shrink-0" style={{ background: `${s.color}15`, color: s.color }}>
                <Icon name={s.icon} className="w-4 h-4" />
              </div>
              <div className="min-w-0">
                <div className="text-lg font-bold font-display truncate">{s.value}</div>
                <div className="text-xs text-muted-foreground truncate">{s.label}</div>
              </div>
            </CardContent>
          </Card>
        ))}
      </div>

      {/* Tabs */}
      <div className="flex gap-1 p-1 bg-secondary rounded-lg w-fit">
        {[
          { id: "providers" as const, label: "Providers", icon: "List" },
          { id: "auth" as const, label: !puterStatus.authenticated ? "Sign In" : "OAuth Auth", icon: !puterStatus.authenticated ? "LogIn" : "Shield" },
          { id: "analytics" as const, label: "Usage Analytics", icon: "BarChart3" },
          { id: "logs" as const, label: "Error Logs", icon: "ScrollText" },
        ].map((t) => (
          <button
            key={t.id}
            onClick={() => setTab(t.id)}
            className={`flex items-center gap-1.5 px-4 py-2 rounded-md text-sm font-medium transition ${tab === t.id ? "bg-card shadow-sm text-brand" : "text-muted-foreground hover:text-foreground"}`}
          >
            <Icon name={t.icon} className="w-4 h-4" /> {t.label}
            {t.id === "auth" && !puterStatus.authenticated && (
              <span className="w-2 h-2 rounded-full bg-red-500 animate-pulse" />
            )}
          </button>
        ))}
      </div>

      {/* Providers tab */}
      {tab === "providers" && (
        <>
          {/* Auth required banner — shown when no OAuth providers are connected */}
          {!puterStatus.authenticated && (
            <Card className="border-amber-300 dark:border-amber-700 bg-amber-50/50 dark:bg-amber-950/20">
              <CardContent className="p-4 flex items-start gap-3">
                <Icon name="AlertTriangle" className="w-5 h-5 text-amber-600 shrink-0 mt-0.5" />
                <div className="flex-1">
                  <p className="text-sm font-medium text-amber-700 dark:text-amber-400">No AI provider authenticated</p>
                  <p className="text-xs text-amber-600/80 dark:text-amber-500/80 mt-0.5">
                    Connect Puter.js (free, Google OAuth) to enable resume optimization. Without authentication, the optimizer cannot run.
                  </p>
                  <Button
                    variant="outline"
                    size="sm"
                    className="mt-2 gap-1.5 border-amber-400 text-amber-700 hover:bg-amber-100 dark:border-amber-600 dark:text-amber-400 dark:hover:bg-amber-950/40"
                    onClick={() => setTab("auth")}
                  >
                    <Icon name="LogIn" className="w-3.5 h-3.5" /> Go to OAuth Auth
                  </Button>
                </div>
              </CardContent>
            </Card>
          )}
        <Card>
          <CardContent className="p-0">
            <div className="p-4 border-b border-border flex items-center justify-between gap-3 flex-wrap">
              <div className="relative w-full sm:w-72">
                <Icon name="Search" className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground" />
                <Input value={q} onChange={(e) => setQ(e.target.value)} placeholder="Search providers…" className="pl-9 h-9" />
              </div>
              <div className="flex items-center gap-2 text-xs text-muted-foreground">
                <Icon name="Info" className="w-3.5 h-3.5" /> Default: <span className="font-semibold text-foreground">{providers.find((p) => p.id === settings.defaultProviderId)?.name ?? "None"}</span>
                <span>·</span>
                <span>Fallbacks: <span className="font-semibold text-foreground">{settings.fallbackProviderIds.length}</span></span>
              </div>
            </div>
            <div className="overflow-x-auto">
              <table className="w-full text-sm">
                <thead className="border-b border-border bg-secondary/40">
                  <tr className="text-left text-xs uppercase tracking-wide text-muted-foreground">
                    <th className="px-4 py-2 font-semibold">Provider</th>
                    <th className="px-4 py-2 font-semibold">Type</th>
                    <th className="px-4 py-2 font-semibold">Base URL</th>
                    <th className="px-4 py-2 font-semibold">Model</th>
                    <th className="px-4 py-2 font-semibold">Status</th>
                    <th className="px-4 py-2 font-semibold">Priority</th>
                    <th className="px-4 py-2 font-semibold">Requests</th>
                    <th className="px-4 py-2 font-semibold">Last used</th>
                    <th className="px-4 py-2 font-semibold text-right">Actions</th>
                  </tr>
                </thead>
                <tbody>
                  {filtered.map((p) => {
                    const cfg = PROVIDER_TYPES.find((t) => t.type === p.type);
                    const statusColor = p.status === "healthy" ? "success" : p.status === "degraded" ? "warning" : p.status === "untested" ? "outline" : "danger";
                    return (
                      <tr key={p.id} className="border-b border-border hover:bg-secondary/30">
                        <td className="px-4 py-3">
                          <div className="flex items-center gap-2">
                            <div className="w-8 h-8 rounded-lg flex items-center justify-center shrink-0" style={{ background: `${p.type === "puter" ? "#F59E0B" : "#94A3B8"}15`, color: p.type === "puter" ? "#F59E0B" : "#475569" }}>
                              <Icon name={cfg?.icon ?? "Cpu"} className="w-4 h-4" />
                            </div>
                            <div className="min-w-0">
                              <div className="font-medium truncate flex items-center gap-1.5">
                                {p.name}
                                {p.isDefault && <Badge variant="gold" className="text-[9px]">DEFAULT</Badge>}
                                {p.isFallback && <Badge variant="brand" className="text-[9px]">FALLBACK</Badge>}
                                {p.allowedForRegularUsers && <Badge variant="success" className="text-[9px]">USER ACCESS</Badge>}
                                {p.isBuiltIn && <Badge variant="outline" className="text-[9px]">BUILT-IN</Badge>}
                              </div>
                              <div className="text-xs text-muted-foreground truncate">{p.name}</div>
                              {isOpenCodeZenFree(p) && (
                                <div className="text-[10px] text-amber-600 dark:text-amber-400 font-medium mt-0.5">
                                  ⚠ Free model – third-party rate limits may apply.
                                </div>
                              )}
                            </div>
                          </div>
                        </td>
                        <td className="px-4 py-3"><Badge variant="outline" className="text-[10px] capitalize">{p.type.replace("-", " ")}</Badge></td>
                        <td className="px-4 py-3 text-xs text-muted-foreground font-mono truncate max-w-[180px]">{p.baseUrl || p.apiUrl || "—"}</td>
                        <td className="px-4 py-3 text-xs font-mono">{p.modelName || "—"}</td>
                        <td className="px-4 py-3"><Badge variant={statusColor as any} className="capitalize text-[10px]">{p.status}</Badge></td>
                        <td className="px-4 py-3"><span className="font-mono text-xs">#{p.priority}</span></td>
                        <td className="px-4 py-3 text-xs">{p.usage.requests.toLocaleString()}</td>
                        <td className="px-4 py-3 text-xs text-muted-foreground">{p.lastUsedAt ? new Date(p.lastUsedAt).toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" }) : "—"}</td>
                        <td className="px-4 py-3">
                          <div className="flex gap-0.5 justify-end">
                            <IconBtn icon="Pencil" label="Edit" onClick={() => { setEditing(p); setShowAdd(true); }} />
                            <IconBtn icon="Zap" label="Test connection" onClick={() => handleTest(p)} color="#F59E0B" />
                            <IconBtn icon="Copy" label="Duplicate" onClick={() => { const id = ProviderManager.duplicate(p.id); if (id) toast.success("Provider duplicated."); }} />
                            <IconBtn icon={p.isDefault ? "Star" : "StarOff"} label="Set as default" onClick={() => { ProviderManager.setDefault(p.id); toast.success(`${p.name} set as default.`); }} color={p.isDefault ? "#F59E0B" : undefined} />
                            {!p.isBuiltIn && <IconBtn icon="Trash2" label="Delete" color="#DC2626" onClick={() => { if (confirm(`Delete provider "${p.name}"?`)) { ProviderManager.remove(p.id); toast.success("Provider deleted."); } }} />}
                          </div>
                        </td>
                      </tr>
                    );
                  })}
                  {filtered.length === 0 && (
                    <tr><td colSpan={9} className="text-center py-12 text-muted-foreground">No providers match "{q}".</td></tr>
                  )}
                </tbody>
              </table>
            </div>
          </CardContent>
        </Card>
        </>
      )}

      {/* OAuth Auth tab */}
      {tab === "auth" && (
        <div className="space-y-4">
          <div className="flex items-center justify-between">
            <div>
              <h2 className="text-lg font-semibold font-display flex items-center gap-2">
                <Icon name="Shield" className="w-5 h-5 text-brand" />
                Provider Authentication
              </h2>
              <p className="text-sm text-muted-foreground mt-1">
                Authenticate with AI providers to enable seamless optimization. Authenticated providers never silently fall back to offline mode.
              </p>
            </div>
            <Button variant="outline" size="sm" onClick={refreshAuthStatus} className="gap-1.5">
              <Icon name="RefreshCw" className="w-3.5 h-3.5" /> Refresh Status
            </Button>
          </div>

          <div className="grid gap-4 md:grid-cols-2">
            {/* Puter.js Auth (Multi-Account) */}
            <PuterAuthCard status={puterStatus} onRefreshStatus={refreshAuthStatus} />
          </div>

          {/* Auth info box */}
          <Card className="bg-blue-50/50 dark:bg-blue-950/20 border-blue-200 dark:border-blue-800">
            <CardContent className="p-4 flex items-start gap-3">
              <Icon name="Info" className="w-5 h-5 text-blue-600 shrink-0 mt-0.5" />
              <div className="text-sm text-blue-700 dark:text-blue-300 space-y-1">
                <p className="font-medium">How Provider Authentication Works</p>
                <ul className="text-xs space-y-0.5 text-blue-600/80 dark:text-blue-400/80">
                                    <li>• <strong>Puter.js</strong> uses Google OAuth via a browser popup. Sign in once and your session persists across reloads.</li>
                  <li>• When a provider is authenticated, it becomes available in the AI routing chain for all optimization requests.</li>
                  <li>• <strong>Shared Admin Account</strong> mode lets all users on this instance use your authenticated session — ideal for team deployments.</li>
                  <li>• Authentication errors are <strong>never silently ignored</strong> — you will always see a clear "Authentication required" message.</li>
                </ul>
              </div>
            </CardContent>
          </Card>
        </div>
      )}

      {/* Analytics tab */}
      {tab === "analytics" && <ProviderAnalytics />}

      {/* Logs tab */}
      {tab === "logs" && <ProviderLogsTable />}

      {/* Editor drawer */}
      {showAdd && (
        <ProviderEditor
          provider={editing}
          onClose={() => { setShowAdd(false); setEditing(null); }}
          onSave={(p) => {
            if (editing) {
              ProviderManager.update(editing.id, p);
              toast.success("Provider updated.");
            } else {
              const id = ProviderManager.add({
                ...p,
                isBuiltIn: false,
              } as any);
              toast.success(`Provider added (id: ${id}).`);
            }
            setShowAdd(false);
            setEditing(null);
          }}
        />
      )}

      {/* Test connection modal */}
      {testing && (
        <TestConnectionModal provider={testing} onClose={() => setTesting(null)} />
      )}
    </div>
  );
}

function IconBtn({ icon, label, onClick, color }: { icon: string; label: string; onClick: () => void; color?: string }) {
  return (
    <button
      onClick={onClick}
      title={label}
      aria-label={label}
      className="w-7 h-7 rounded-md hover:bg-secondary flex items-center justify-center text-muted-foreground hover:text-foreground transition"
      style={color ? { color } : undefined}
    >
      <Icon name={icon} className="w-3.5 h-3.5" />
    </button>
  );
}

src/components/app/modules/AIProviderSet:
"use client";

import { useState, useEffect } from "react";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Switch } from "@/components/ui/switch";
import { Badge, Icon } from "@/components/shared";
import { useApp } from "@/lib/store";
import { ProviderManager } from "@/lib/ai/services";
import { toast } from "sonner";

export function AIProviderSettings() {
  const settings = useApp((s) => s.providerSettings);
  const providers = useApp((s) => s.providers);
  const updateProviderSettings = useApp((s) => s.updateProviderSettings);

  // Local form state (editable, saved on "Save")
  const [form, setForm] = useState(settings);
  const [saving, setSaving] = useState(false);
  const [hasChanges, setHasChanges] = useState(false);

  // Sync form when settings change from the store (only if no unsaved changes)
  const settingsRef = settings;
  if (!hasChanges && form !== settingsRef && JSON.stringify(form) !== JSON.stringify(settingsRef)) {
    setForm(settingsRef);
  }

  // Model prefetch state
  const [fetchingModels, setFetchingModels] = useState(false);
  const [liveModels, setLiveModels] = useState<string[]>([]);

  const defaultProvider = providers.find((p) => p.id === form.defaultProviderId);
  const fallbackProviders = form.fallbackProviderIds
    .map((id) => providers.find((p) => p.id === id))
    .filter(Boolean) as typeof providers;
  const availableForFallback = providers.filter(
    (p) => p.id !== form.defaultProviderId && !form.fallbackProviderIds.includes(p.id)
  );

  const update = (patch: Partial<typeof form>) => {
    setForm({ ...form, ...patch });
    setHasChanges(true);
  };

  const save = async () => {
    setSaving(true);
    await new Promise((r) => setTimeout(r, 400));
    updateProviderSettings(form);
    setSaving(false);
    setHasChanges(false);
    toast.success("AI routing settings saved to D1.");
  };

  const fetchModels = async () => {
    if (!defaultProvider) {
      toast.error("Select a default provider first.");
      return;
    }
    setFetchingModels(true);
    // === PRESERVE last known valid model list on failure ===
    // Do NOT clear liveModels on failure — keep the previous list so the
    // user's routing configuration stays valid. Only clear on success.
    const result = await ProviderManager.fetchModels(defaultProvider);
    setFetchingModels(false);
    if (result.ok && result.models.length > 0) {
      setLiveModels(result.models);
      toast.success(`Loaded ${result.models.length} ${defaultProvider.type === "puter" ? "built-in" : "live"} models from ${defaultProvider.name}.`);
    } else {
      // === DO NOT clear provider, model, or routing config ===
      // Just show the error — the user's last known valid config is preserved.
      toast.error(result.error || "Failed to fetch models. Your existing configuration is preserved.");
    }
  };

  // === Import / Export ===
  const exportConfig = () => {
    const config = {
      settings: form,
      providers: providers.map((p) => ({
        ...p,
        apiKey: p.apiKey ? "***REDACTED***" : undefined,
      })),
      exportedAt: new Date().toISOString(),
    };
    const blob = new Blob([JSON.stringify(config, null, 2)], { type: "application/json" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = `ai-routing-config-${new Date().toISOString().slice(0, 10)}.json`;
    a.click();
    URL.revokeObjectURL(url);
    toast.success("Configuration exported.");
  };

  const importConfig = () => {
    const input = document.createElement("input");
    input.type = "file";
    input.accept = ".json";
    input.onchange = async (e) => {
      const file = (e.target as HTMLInputElement).files?.[0];
      if (!file) return;
      try {
        const text = await file.text();
        const config = JSON.parse(text);
        if (config.settings) {
          setForm(config.settings);
          setHasChanges(true);
          toast.success("Configuration imported. Click 'Save' to apply.");
        } else {
          toast.error("Invalid config file — missing 'settings' key.");
        }
      } catch {
        toast.error("Failed to parse config file.");
      }
    };
    input.click();
  };

  return (
    <div className="space-y-6 max-w-4xl">
      <div className="flex items-center justify-between flex-wrap gap-3">
        <div>
          <h1 className="font-display text-2xl font-bold flex items-center gap-2"><Icon name="Settings" className="w-6 h-6 text-brand" /> AI Routing Settings</h1>
          <p className="text-sm text-muted-foreground mt-1">Configure default provider, model, fallback chain, and routing policy.</p>
        </div>
        <div className="flex gap-2">
          <Button variant="outline" size="sm" onClick={importConfig} className="gap-1.5"><Icon name="Upload" className="w-3.5 h-3.5" /> Import</Button>
          <Button variant="outline" size="sm" onClick={exportConfig} className="gap-1.5"><Icon name="Download" className="w-3.5 h-3.5" /> Export</Button>
          <Button size="sm" onClick={save} disabled={!hasChanges || saving} className="bg-brand hover:bg-brand-dark text-white gap-1.5">
            {saving ? <Icon name="Loader2" className="w-3.5 h-3.5 animate-spin" /> : <Icon name="Save" className="w-3.5 h-3.5" />}
            {saving ? "Saving…" : "Save"}
          </Button>
        </div>
      </div>

      {hasChanges && (
        <div className="rounded-lg bg-amber-100 dark:bg-amber-400/10 border border-amber-300 p-3 text-xs text-amber-800 dark:text-amber-300 flex items-center gap-2">
          <Icon name="AlertTriangle" className="w-4 h-4" /> You have unsaved changes. Click "Save" to persist to D1.
        </div>
      )}

      {/* Default Provider + Model */}
      <Card>
        <CardHeader><CardTitle className="text-lg flex items-center gap-2"><Icon name="Star" className="w-4 h-4 text-gold" /> Default Provider & Model</CardTitle><CardDescription>The provider and model used first for every AI request.</CardDescription></CardHeader>
        <CardContent className="space-y-4">
          <div className="grid sm:grid-cols-2 gap-3">
            <div className="space-y-1.5">
              <Label className="text-xs uppercase tracking-wide text-muted-foreground">Default provider</Label>
              <select
                value={form.defaultProviderId ?? ""}
                onChange={(e) => { update({ defaultProviderId: e.target.value || null }); setLiveModels([]); }}
                className="w-full h-9 px-3 rounded-md border border-input bg-background text-sm"
              >
                <option value="">— None —</option>
                {providers.map((p) => <option key={p.id} value={p.id}>{p.name}</option>)}
              </select>
            </div>
            <div className="space-y-1.5">
              <Label className="text-xs uppercase tracking-wide text-muted-foreground">Default model</Label>
              <div className="flex gap-2">
                {liveModels.length > 0 ? (
                  <select
                    value={form.defaultModel}
                    onChange={(e) => update({ defaultModel: e.target.value })}
                    className="w-full h-9 px-3 rounded-md border border-input bg-background text-sm flex-1"
                  >
                    <option value="">— Select a model —</option>
                    {liveModels.map((m) => <option key={m} value={m}>{m}</option>)}
                  </select>
                ) : (
                  <Input value={form.defaultModel} onChange={(e) => update({ defaultModel: e.target.value })} placeholder="claude-sonnet-4" className="flex-1" />
                )}
                {defaultProvider?.type === "puter" ? (
                  // Puter uses built-in models — show a static list instead of fetching
                  <Button variant="outline" size="sm" onClick={fetchModels} disabled={fetchingModels} className="gap-1.5 shrink-0">
                    {fetchingModels ? <Icon name="Loader2" className="w-3.5 h-3.5 animate-spin" /> : <Icon name="List" className="w-3.5 h-3.5" />}
                    Show built-in models
                  </Button>
                ) : (
                  <Button variant="outline" size="sm" onClick={fetchModels} disabled={fetchingModels || !defaultProvider} className="gap-1.5 shrink-0">
                    {fetchingModels ? <Icon name="Loader2" className="w-3.5 h-3.5 animate-spin" /> : <Icon name="DownloadCloud" className="w-3.5 h-3.5" />}
                    Fetch models
                  </Button>
                )}
              </div>
              {defaultProvider?.type === "puter" && liveModels.length === 0 && <p className="text-[10px] text-muted-foreground">Puter uses built-in models — click "Show built-in models" to load them.</p>}
              {liveModels.length > 0 && <p className="text-[10px] text-muted-foreground">{liveModels.length} {defaultProvider?.type === "puter" ? "built-in" : "live"} models from {defaultProvider?.name}</p>}
            </div>
          </div>
        </CardContent>
      </Card>

      {/* Fallback Chain */}
      <Card>
        <CardHeader><CardTitle className="text-lg flex items-center gap-2"><Icon name="Layers" className="w-4 h-4 text-brand" /> Fallback Chain</CardTitle><CardDescription>Providers tried in order if the default fails.</CardDescription></CardHeader>
        <CardContent className="space-y-3">
          {fallbackProviders.length === 0 && (
            <div className="text-sm text-muted-foreground text-center py-4 rounded-lg border border-dashed border-border">No fallback providers configured.</div>
          )}
          {fallbackProviders.map((p, i) => (
            <div key={p.id} className="flex items-center gap-3 p-3 rounded-lg border border-border">
              <div className="w-7 h-7 rounded-full bg-brand text-white flex items-center justify-center text-xs font-bold">{i + 1}</div>
              <div className="flex-1 min-w-0">
                <div className="font-medium text-sm truncate">{p.name}</div>
                <div className="text-xs text-muted-foreground capitalize">{p.type.replace("-", " ")} · {p.modelName}</div>
              </div>
              <Button size="sm" variant="ghost" disabled={i === 0} onClick={() => { const ids = [...form.fallbackProviderIds]; [ids[i-1], ids[i]] = [ids[i], ids[i-1]]; update({ fallbackProviderIds: ids }); }}><Icon name="ChevronUp" className="w-4 h-4" /></Button>
              <Button size="sm" variant="ghost" disabled={i === fallbackProviders.length - 1} onClick={() => { const ids = [...form.fallbackProviderIds]; [ids[i+1], ids[i]] = [ids[i], ids[i+1]]; update({ fallbackProviderIds: ids }); }}><Icon name="ChevronDown" className="w-4 h-4" /></Button>
              <Button size="sm" variant="ghost" className="text-destructive" onClick={() => update({ fallbackProviderIds: form.fallbackProviderIds.filter((fid) => fid !== p.id) })}><Icon name="X" className="w-4 h-4" /></Button>
            </div>
          ))}
          {availableForFallback.length > 0 && (
            <div className="pt-2 border-t border-border">
              <Label className="text-xs uppercase tracking-wide text-muted-foreground">Add to fallback chain</Label>
              <div className="flex flex-wrap gap-2 mt-2">
                {availableForFallback.map((p) => (
                  <button key={p.id} onClick={() => update({ fallbackProviderIds: [...form.fallbackProviderIds, p.id] })} className="flex items-center gap-1.5 px-2.5 py-1.5 rounded-md border border-border bg-card hover:bg-secondary text-xs">
                    <Icon name="Plus" className="w-3 h-3" /> {p.name}
                  </button>
                ))}
              </div>
            </div>
          )}
        </CardContent>
      </Card>

      {/* Retry & Timeout */}
      <Card>
        <CardHeader><CardTitle className="text-lg flex items-center gap-2"><Icon name="Timer" className="w-4 h-4 text-gold" /> Retry & Timeout</CardTitle></CardHeader>
        <CardContent className="grid sm:grid-cols-3 gap-3">
          <div className="space-y-1.5">
            <Label className="text-xs uppercase tracking-wide text-muted-foreground">Retry attempts</Label>
            <Input type="number" min="0" max="5" value={form.retryAttempts} onChange={(e) => update({ retryAttempts: parseInt(e.target.value) || 0 })} />
          </div>
          <div className="space-y-1.5">
            <Label className="text-xs uppercase tracking-wide text-muted-foreground">Timeout (ms)</Label>
            <Input type="number" value={form.timeout} onChange={(e) => update({ timeout: parseInt(e.target.value) || 30000 })} />
          </div>
          <div className="space-y-1.5">
            <Label className="text-xs uppercase tracking-wide text-muted-foreground">Rate limit (req/min)</Label>
            <Input type="number" value={form.rateLimitPerMinute} onChange={(e) => update({ rateLimitPerMinute: parseInt(e.target.value) || 60 })} />
          </div>
        </CardContent>
      </Card>

      {/* Feature toggles */}
      <Card>
        <CardHeader><CardTitle className="text-lg">Routing features</CardTitle></CardHeader>
        <CardContent className="space-y-2">
          <ToggleRow label="Enable failover" desc="Automatically try the next provider when one fails" checked={form.enableFailover} onChange={(v) => update({ enableFailover: v })} />
          <ToggleRow label="Enable response caching" desc="Cache identical prompts for 1 hour to save tokens" checked={form.enableCaching} onChange={(v) => update({ enableCaching: v })} />
          <ToggleRow label="Enable cost tracking" desc="Track token usage and estimate cost per provider" checked={form.enableCostTracking} onChange={(v) => update({ enableCostTracking: v })} />
        </CardContent>
      </Card>

      {/* Sticky save bar */}
      {hasChanges && (
        <div className="sticky bottom-4 z-30 flex justify-end">
          <Button onClick={save} disabled={saving} className="bg-brand hover:bg-brand-dark text-white gap-2 shadow-premium">
            {saving ? <Icon name="Loader2" className="w-4 h-4 animate-spin" /> : <Icon name="Save" className="w-4 h-4" />}
            {saving ? "Saving…" : "Save changes"}
          </Button>
        </div>
      )}
    </div>
  );
}

function ToggleRow({ label, desc, checked, onChange }: { label: string; desc: string; checked: boolean; onChange: (v: boolean) => void }) {
  return (
    <div className="flex items-center justify-between gap-3 p-3 rounded-lg border border-border">
      <div>
        <div className="text-sm font-medium">{label}</div>
        <div className="text-xs text-muted-foreground">{desc}</div>
      </div>
      <Switch checked={checked} onCheckedChange={onChange} />
    </div>
  );
}

src/components/app/modules/AITools.tsx:
"use client";

import { useState } from "react";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Textarea } from "@/components/ui/textarea";
import { Badge, Icon } from "@/components/shared";
import { useApp, uid } from "@/lib/store";
import { callAI } from "@/lib/ai";
import { toast } from "sonner";

const TOOLS = [
  { id: "summary", name: "Professional Summary Generator", icon: "AlignLeft", desc: "Generate a 2-3 line summary from your experience.", color: "#1154A3" },
  { id: "bullets", name: "Bullet Point Generator", icon: "List", desc: "Rewrite weak bullets with measurable outcomes.", color: "#F59E0B" },
  { id: "linkedin", name: "LinkedIn Profile Generator", icon: "Linkedin", desc: "Generate a full LinkedIn About + Experience section.", color: "#0EA5E9" },
  { id: "translator", name: "Resume Translator", icon: "Languages", desc: "Translate your resume to 30+ languages.", color: "#10B981" },
  { id: "career", name: "Career Advisor", icon: "Compass", desc: "Get tailored next-role suggestions.", color: "#8B5CF6" },
  { id: "keywords", name: "Keyword Generator", icon: "KeyRound", desc: "Extract industry keywords from your field.", color: "#EC4899" },
  { id: "skills", name: "Skill Suggestions", icon: "Wrench", desc: "Suggest skills you should add based on your role.", color: "#1154A3" },
  { id: "rewrite", name: "Resume Rewriter", icon: "RefreshCcw", desc: "Rewrite your entire resume section-by-section.", color: "#F59E0B" },
];

export function AITools() {
  const resumes = useApp((s) => s.resumes);
  const incUsage = useApp((s) => s.incUsage);
  const log = useApp((s) => s.log);

  const [active, setActive] = useState<string | null>(null);
  const [input, setInput] = useState("");
  const [output, setOutput] = useState("");
  const [running, setRunning] = useState(false);

  const resume = resumes[0];

  const run = async () => {
    if (!active) return;
    setRunning(true);
    setOutput("");
    try {
      let sys = "You are ResumeAI Pro, an expert career assistant. Respond clearly and concisely.";
      let user = input;
      if (active === "summary") {
        user = `Generate a 2-3 line professional summary for:\n${input || JSON.stringify(resume?.experience)}`;
      } else if (active === "bullets") {
        user = `Rewrite these bullets with strong action verbs and measurable outcomes (one per line):\n${input}`;
      } else if (active === "linkedin") {
        user = `Generate a LinkedIn About section (~250 words) and 3 experience entries from this resume:\n${input || JSON.stringify(resume ?? {})}`;
      } else if (active === "translator") {
        user = `Translate this resume content to French (keep proper nouns):\n${input}`;
      } else if (active === "career") {
        user = `Suggest 5 next career roles with rationale, based on:\n${input || JSON.stringify(resume?.experience)}`;
      } else if (active === "keywords") {
        user = `Extract the 15 most important ATS keywords for this role/field:\n${input}`;
      } else if (active === "skills") {
        user = `Suggest 10 skills (with brief justification) this candidate should add:\n${input || JSON.stringify(resume?.skills)}`;
      } else if (active === "rewrite") {
        user = `Rewrite this resume section to be ATS-friendly and impactful:\n${input}`;
      }
      const result = await callAI({ systemPrompt: sys, userPrompt: user, maxTokens: 1500, taskCategory: "document" });
      setOutput(result.text);
      incUsage("resumesGenerated");
      log({ actor: "you", action: `AI tool: ${active}`, category: "ai", details: `via ${result.provider}`, severity: "info" });
      toast.success(`Generated via ${result.provider}`);
    } catch (e: any) {
      toast.error(e?.message || "Failed.");
    } finally {
      setRunning(false);
    }
  };

  return (
    <div className="space-y-6">
      <div>
        <h1 className="font-display text-2xl font-bold flex items-center gap-2"><Icon name="Sparkles" className="w-6 h-6 text-brand" /> AI Tools</h1>
        <p className="text-sm text-muted-foreground mt-1">Eleven AI-powered generators. Free, unlimited. Pick a tool and start writing.</p>
      </div>

      <div className="grid sm:grid-cols-2 lg:grid-cols-4 gap-3">
        {TOOLS.map((t) => (
          <button
            key={t.id}
            onClick={() => { setActive(t.id); setInput(""); setOutput(""); }}
            className={`text-left rounded-xl border p-4 transition ${active === t.id ? "border-brand bg-brand-light/40 shadow-premium" : "border-border hover:border-brand/40 hover:shadow-card"}`}
          >
            <div className="w-10 h-10 rounded-lg flex items-center justify-center mb-3" style={{ background: `${t.color}15`, color: t.color }}>
              <Icon name={t.icon} className="w-5 h-5" />
            </div>
            <div className="font-semibold text-sm">{t.name}</div>
            <div className="text-xs text-muted-foreground mt-1">{t.desc}</div>
          </button>
        ))}
      </div>

      {active && (
        <Card>
          <CardHeader>
            <div className="flex items-center justify-between">
              <CardTitle className="text-base flex items-center gap-2">
                <Icon name={TOOLS.find((t) => t.id === active)?.icon ?? "Sparkles"} className="w-4 h-4 text-brand" />
                {TOOLS.find((t) => t.id === active)?.name}
              </CardTitle>
              <Button size="sm" variant="ghost" onClick={() => setActive(null)}><Icon name="X" className="w-4 h-4" /></Button>
            </div>
          </CardHeader>
          <CardContent className="space-y-3">
            <Textarea
              value={input}
              onChange={(e) => setInput(e.target.value)}
              rows={6}
              placeholder="Paste your content here, or leave blank to use your current resume…"
            />
            <Button onClick={run} disabled={running} className="bg-brand hover:bg-brand-dark text-white gap-2">
              {running ? <Icon name="Loader2" className="w-4 h-4 animate-spin" /> : <Icon name="Sparkles" className="w-4 h-4" />}
              {running ? "Generating…" : "Generate"}
            </Button>
            {output && (
              <div className="rounded-lg border border-border bg-secondary/40 p-4">
                <div className="flex items-center justify-between mb-2">
                  <Badge variant="success"><Icon name="CheckCircle2" className="w-3 h-3" /> Output</Badge>
                  <Button size="sm" variant="ghost" onClick={() => { navigator.clipboard.writeText(output); toast.success("Copied to clipboard."); }}>
                    <Icon name="Copy" className="w-3.5 h-3.5" /> Copy
                  </Button>
                </div>
                <pre className="whitespace-pre-wrap text-sm font-sans text-foreground/90 text-pretty">{output}</pre>
              </div>
            )}
          </CardContent>
        </Card>
      )}
    </div>
  );
}

src/components/app/modules/AIWorkspace.t:
"use client";

import { useState } from "react";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Badge, Icon } from "@/components/shared";
import { useApp, uid } from "@/lib/store";
import { toast } from "sonner";
import {
  PROJECT_TREE, listDirectory, searchFiles,
  executeTask, applyPatch, rollbackPatch, approvePatch, rejectPatch,
  runBuild, runTests, createStagingBranch, getCommitHistory, getBranches,
  runAutonomousDebug,
} from "@/lib/ai-builder-agent";
import {
  runDetailedDebugScan, healIssue, healMultipleIssues
} from "@/lib/autonomous-healing";
import type { AITask, AIWorkspacePatch, AIFile, AIHealingIssue } from "@/lib/types";

type Tab =
  | "overview"
  | "repository"
  | "editor"
  | "tasks"
  | "patches"
  | "build"
  | "tests"
  | "git"
  | "rollback"
  | "debug"
  | "settings";

const TABS: { key: Tab; label: string; icon: string }[] = [
  { key: "overview", label: "Overview", icon: "LayoutDashboard" },
  { key: "repository", label: "Repository", icon: "FolderTree" },
  { key: "editor", label: "File Editor", icon: "FileCode" },
  { key: "tasks", label: "AI Tasks", icon: "ListTodo" },
  { key: "patches", label: "Patch Center", icon: "GitBranch" },
  { key: "build", label: "Build Manager", icon: "Hammer" },
  { key: "tests", label: "Test Runner", icon: "FlaskConical" },
  { key: "git", label: "Git Manager", icon: "GitBranch" },
  { key: "rollback", label: "Rollback", icon: "Undo2" },
  { key: "debug", label: "Autonomous Debug", icon: "Bug" },
  { key: "settings", label: "Settings", icon: "Settings" },
];

export function AIWorkspace() {
  const [tab, setTab] = useState<Tab>("overview");

  return (
    <div className="space-y-6">
      <div>
        <h1 className="font-display text-2xl font-bold flex items-center gap-2">
          <Icon name="Code2" className="w-6 h-6 text-brand" /> AI Workspace
        </h1>
        <p className="text-sm text-muted-foreground mt-1">
          Full AI Builder Agent — read code, generate code, edit files, create features, validate builds, and manage patches in a staging environment.
        </p>
      </div>

      <div className="flex flex-wrap gap-1 border-b border-border pb-2 overflow-x-auto">
        {TABS.map((t) => (
          <button
            key={t.key}
            onClick={() => setTab(t.key)}
            className={`flex items-center gap-1.5 px-3 py-1.5 rounded-md text-sm font-medium transition whitespace-nowrap ${
              tab === t.key ? "bg-brand text-white" : "text-muted-foreground hover:bg-secondary hover:text-foreground"
            }`}
          >
            <Icon name={t.icon} className="w-3.5 h-3.5" />
            <span>{t.label}</span>
          </button>
        ))}
      </div>

      {tab === "overview" && <OverviewTab />}
      {tab === "repository" && <RepositoryTab />}
      {tab === "editor" && <EditorTab />}
      {tab === "tasks" && <TasksTab />}
      {tab === "patches" && <PatchesTab />}
      {tab === "build" && <BuildTab />}
      {tab === "tests" && <TestsTab />}
      {tab === "git" && <GitTab />}
      {tab === "rollback" && <RollbackTab />}
      {tab === "debug" && <DebugTab />}
      {tab === "settings" && <SettingsTab />}
    </div>
  );
}

// ============================================================================
// Overview Tab
// ============================================================================

function OverviewTab() {
  const tasks = useApp((s) => s.aiTasks);
  const patches = useApp((s) => s.aiPatches);
  const branches = useApp((s) => s.aiBranches);
  const rollbacks = useApp((s) => s.aiRollbacks);

  const pendingPatches = patches.filter((p) => p.status === "pending").length;
  const appliedPatches = patches.filter((p) => p.status === "applied").length;
  const activeTasks = tasks.filter((t) => !["applied", "rejected", "failed"].includes(t.status)).length;

  return (
    <div className="space-y-6">
      <div className="grid sm:grid-cols-2 lg:grid-cols-4 gap-4">
        <StatCard label="Active Tasks" value={activeTasks} icon="ListTodo" color="#3B82F6" />
        <StatCard label="Pending Patches" value={pendingPatches} icon="GitBranch" color="#F59E0B" />
        <StatCard label="Applied Patches" value={appliedPatches} icon="CheckCircle2" color="#10B981" />
        <StatCard label="Git Branches" value={branches.length} icon="GitBranch" color="#8B5CF6" />
      </div>

      <Card>
        <CardHeader>
          <CardTitle className="text-lg">Safe Apply Workflow</CardTitle>
          <CardDescription>Every AI change goes through this pipeline before reaching production.</CardDescription>
        </CardHeader>
        <CardContent>
          <div className="flex flex-wrap items-center gap-2 text-xs">
            {["User Request", "AI Analysis", "Execution Plan", "Generate Patch", "Generate Tests", "Build Validation", "Test Validation", "Show Diff", "Approval", "Apply"].map((step, i, arr) => (
              <div key={step} className="flex items-center gap-2">
                <div className="px-3 py-1.5 rounded-md bg-secondary font-medium">{step}</div>
                {i < arr.length - 1 && <Icon name="ArrowRight" className="w-3 h-3 text-muted-foreground" />}
              </div>
            ))}
          </div>
        </CardContent>
      </Card>

      <div className="grid lg:grid-cols-2 gap-4">
        <Card>
          <CardHeader>
            <CardTitle className="text-base">Recent Tasks</CardTitle>
          </CardHeader>
          <CardContent>
            {tasks.length === 0 ? (
              <p className="text-sm text-muted-foreground">No tasks yet. Create one in the AI Tasks tab.</p>
            ) : (
              <div className="space-y-2">
                {tasks.slice(0, 5).map((t) => (
                  <div key={t.id} className="flex items-center justify-between text-sm">
                    <span className="truncate">{t.title}</span>
                    <Badge variant={t.status === "applied" ? "success" : t.status === "ready" ? "brand" : "outline"} className="text-[10px] capitalize ml-2 shrink-0">{t.status}</Badge>
                  </div>
                ))}
              </div>
            )}
          </CardContent>
        </Card>

        <Card>
          <CardHeader>
            <CardTitle className="text-base">Recent Patches</CardTitle>
          </CardHeader>
          <CardContent>
            {patches.length === 0 ? (
              <p className="text-sm text-muted-foreground">No patches yet.</p>
            ) : (
              <div className="space-y-2">
                {patches.slice(0, 5).map((p) => (
                  <div key={p.id} className="flex items-center justify-between text-sm">
                    <span className="truncate">{p.title}</span>
                    <Badge variant={p.status === "applied" ? "success" : p.status === "pending" ? "warning" : p.status === "rejected" || p.status === "rolled_back" ? "danger" : "outline"} className="text-[10px] capitalize ml-2 shrink-0">{p.status.replace("_", " ")}</Badge>
                  </div>
                ))}
              </div>
            )}
          </CardContent>
        </Card>
      </div>
    </div>
  );
}

function StatCard({ label, value, icon, color }: { label: string; value: number; icon: string; color: string }) {
  return (
    <Card>
      <CardContent className="p-4">
        <div className="flex items-center justify-between">
          <div>
            <div className="text-2xl font-bold font-display" style={{ color }}>{value}</div>
            <div className="text-xs text-muted-foreground">{label}</div>
          </div>
          <div className="w-10 h-10 rounded-lg flex items-center justify-center" style={{ background: `${color}15` }}>
            <Icon name={icon} className="w-5 h-5" style={{ color }} />
          </div>
        </div>
      </CardContent>
    </Card>
  );
}

// ============================================================================
// Repository Explorer Tab
// ============================================================================

function RepositoryTab() {
  const [currentPath, setCurrentPath] = useState("src");
  const [searchQuery, setSearchQuery] = useState("");
  const [selectedFile, setSelectedFile] = useState<AIFile | null>(null);
  const [fileContent, setFileContent] = useState<string>("");
  const [loadingContent, setLoadingContent] = useState(false);

  const items = searchQuery ? searchFiles(searchQuery) : listDirectory(currentPath);

  const loadFileContent = async (file: AIFile) => {
    setSelectedFile(file);
    setLoadingContent(true);
    setFileContent("");
    try {
      const { readFile } = await import("@/lib/agent-runtime");
      const content = await readFile(file.path);
      setFileContent(content.content);
    } catch (e: any) {
      setFileContent(`Error loading file: ${e?.message || "unknown"}`);
    } finally {
      setLoadingContent(false);
    }
  };

  return (
    <div className="grid lg:grid-cols-3 gap-4">
      {/* File tree */}
      <Card className="lg:col-span-1">
        <CardHeader>
          <CardTitle className="text-base flex items-center gap-2"><Icon name="FolderTree" className="w-4 h-4 text-brand" /> Repository</CardTitle>
        </CardHeader>
        <CardContent className="space-y-3">
          <Input
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            placeholder="Search files..."
            className="text-sm"
          />
          {!searchQuery && (
            <div className="text-xs text-muted-foreground font-mono">
              /{currentPath}
              {currentPath !== "" && (
                <button onClick={() => setCurrentPath(currentPath.split("/").slice(0, -1).join("/"))} className="ml-2 text-brand hover:underline">
                  ↑ up
                </button>
              )}
            </div>
          )}
          <div className="space-y-0.5 max-h-96 overflow-y-auto">
            {items.length === 0 ? (
              <p className="text-xs text-muted-foreground">No files found.</p>
            ) : (
              items.map((item) => (
                <button
                  key={item.path}
                  onClick={() => {
                    if (item.type === "directory") {
                      setCurrentPath(item.path);
                      setSearchQuery("");
                    } else {
                      loadFileContent(item);
                    }
                  }}
                  className="w-full flex items-center gap-2 px-2 py-1 rounded text-sm hover:bg-secondary text-left"
                >
                  <Icon name={item.type === "directory" ? "Folder" : "FileCode"} className={`w-3.5 h-3.5 shrink-0 ${item.type === "directory" ? "text-amber-500" : "text-blue-500"}`} />
                  <span className="truncate">{item.path.split("/").pop()}</span>
