"use client";

import { useState, useMemo } from "react";
import { motion } from "framer-motion";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Badge, Icon, ScoreRing } from "@/components/shared";
import { useApp, uid } from "@/lib/store";
import { callAI, extractJSON } from "@/lib/ai";
import { detectIndustry, INDUSTRY_PROFILES } from "@/lib/industry-ats";
import { exportCoverLetterPDF, exportCoverLetterDOCX, exportCoverLetterTXT } from "@/lib/exporter";
import { toast } from "sonner";
import type { CoverLetter } from "@/lib/types";

// ============================================================================
// Tone options
// ============================================================================
const TONES = [
  { id: "Professional", label: "Professional", desc: "Balanced, confident, standard business tone" },
  { id: "Executive", label: "Executive", desc: "Strategic, outcomes-led, C-suite level" },
  { id: "Friendly", label: "Friendly", desc: "Warm, approachable, human connection" },
  { id: "Formal", label: "Formal", desc: "Traditional, precise, highly structured" },
  { id: "Enthusiastic", label: "Enthusiastic", desc: "Energetic, passionate, shows excitement" },
  { id: "Balanced", label: "Balanced", desc: "Mix of professional and warm" },
] as const;

export function CoverLetter() {
  const coverLetters = useApp((s) => s.coverLetters);
  const resumes = useApp((s) => s.resumes);
  const jds = useApp((s) => s.jobDescriptions);
  const addCoverLetter = useApp((s) => s.addCoverLetter);
  const updateCoverLetter = useApp((s) => s.updateCoverLetter);
  const removeCoverLetter = useApp((s) => s.removeCoverLetter);
  const incUsage = useApp((s) => s.incUsage);
  const log = useApp((s) => s.log);

  const [activeId, setActiveId] = useState<string>(coverLetters[0]?.id ?? "");
  const [generating, setGenerating] = useState(false);
  const [selectedTone, setSelectedTone] = useState<string>("Professional");
  const [matchScore, setMatchScore] = useState<number | null>(null);
  const [keywordsUsed, setKeywordsUsed] = useState<string[]>([]);
  const [sectionsReferenced, setSectionsReferenced] = useState<string[]>([]);

  const active = coverLetters.find((c) => c.id === activeId) ?? null;

  // === Auto-detect industry from JD + resume ===
  const industryDetection = useMemo(() => {
    const resume = resumes[0];
    const jd = jds[0];
    if (!jd) return null;
    const jdText = jd.rawText ?? jd.keywords.join(" ");
    const resumeText = `${resume?.name ?? ""} ${resume?.headline ?? ""} ${resume?.summary ?? ""} ${resume?.experience.map((e) => e.title + " " + e.company).join(" ")}`;
    return detectIndustry(jdText, resumeText);
  }, [resumes, jds]);

  const industryProfile = industryDetection ? INDUSTRY_PROFILES[industryDetection.industryId] : null;

  // === Dynamic Cover Letter Generation ===
  const generate = async () => {
    const resume = resumes[0];
    const jd = jds[0];

    if (!resume) {
      toast.error("Please upload or create a resume first.");
      return;
    }
    if (!jd) {
      toast.error("Please add a job description first.");
      return;
    }

    setGenerating(true);
    setMatchScore(null);
    setKeywordsUsed([]);
    setSectionsReferenced([]);

    try {
      // Build context from optimized resume (preferred) or original
      const resumeContext = JSON.stringify({
        name: resume.name,
        headline: resume.headline,
        summary: resume.summary,
        experience: resume.experience.map((e) => ({
          title: e.title,
          company: e.company,
          location: e.location,
          startDate: e.startDate,
          endDate: e.endDate,
          bullets: e.bullets,
        })),
        skills: resume.skills.map((s) => s.name),
        education: resume.education.map((ed) => ({ degree: ed.degree, institution: ed.institution })),
        languages: resume.languages.map((l) => l.name),
        certifications: resume.certifications.map((c) => c.name),
      });

      const jdContext = jd.rawText ?? JSON.stringify({
        title: jd.title,
        company: jd.company,
        location: jd.location,
        responsibilities: jd.responsibilities,
        requiredSkills: jd.requiredSkills,
        preferredSkills: jd.preferredSkills,
        keywords: jd.keywords,
      });

      const industryContext = industryProfile ? `
INDUSTRY: ${industryProfile.label}
INDUSTRY WRITING GUIDANCE: ${industryProfile.writingGuidance}
INDUSTRY KEYWORDS: ${industryProfile.priorityKeywords.join(", ")}
` : "";

      const result = await callAI({
        systemPrompt: `You are an Expert Cover Letter Writer, Senior Recruiter, and ATS Specialist. You write highly personalized, recruiter-grade cover letters that sound human and professional. You NEVER fabricate experience, skills, or achievements — you only use information from the candidate's resume. You adapt language to the detected industry. Always return ONLY valid JSON.

TONE: ${selectedTone}
${industryContext}

COVER LETTER STRUCTURE:
1. Professional Greeting (address the hiring manager or "Dear Hiring Manager")
2. Introduction (hook: why this role at this company excites you)
3. Why This Company (reference the company's mission/values/position if known from the job description)
4. Why This Role (connect your experience to the specific responsibilities)
5. Relevant Experience (2-3 key achievements from your resume that align with JD requirements)
6. Value Proposition (what you bring that others don't)
7. Closing Statement (confident CTA — request an interview)
8. Professional Signature

CONTENT RULES:
- Target 350-500 words (preferably ~450 words)
- One page maximum
- Sound HUMAN — avoid generic AI language ("dynamic professional", "passionate about", "track record of", "I excel in", "my professional journey", "I am confident")
- Use strong action verbs: Delivered, Implemented, Improved, Optimized, Led, Designed
- Reference SPECIFIC achievements from the resume with measurable outcomes (numbers, %, $)
- Incorporate keywords from the job description naturally (no stuffing)
- Industry-adaptive language (use industry terminology from the keyword bank)
- NEVER mention skills not present in the resume
- NEVER fabricate company information — only use what's in the JD
- ATS-friendly: include key JD keywords naturally

GROUNDING REQUIREMENTS (CRITICAL):
- You MUST reference at least 3 different resume sections in the cover letter:
  1. Professional Summary (background + years of experience)
  2. Experience (at least 2 specific achievements with metrics from actual roles)
  3. Skills (at least 3 relevant skills from the resume)
- If the resume has Languages, mention them.
- If the resume has Certifications, mention them.
- If the resume has Education relevant to the role, mention it.
- The sectionsReferenced array MUST list ALL sections you actually used.

Return JSON:
{
  "content": "The full cover letter text (plain text, no markdown)",
  "matchScore": 85,
  "keywordsUsed": ["keyword1", "keyword2"],
  "sectionsReferenced": ["Professional Summary", "Experience", "Skills", "Languages", "Certifications"]
}`,
        userPrompt: `CANDIDATE'S RESUME (primary source of truth — use ONLY this information):
${resumeContext}

JOB DESCRIPTION:
${jdContext}

COMPANY: ${jd.company || "the company"}
JOB TITLE: ${jd.title || "the role"}
INDUSTRY: ${industryProfile?.label || "Generic"}

Generate a highly personalized, recruiter-grade cover letter that aligns the candidate's experience with the job requirements. Use the candidate's REAL achievements and skills — never fabricate. Incorporate JD keywords naturally. Adapt language to the ${industryProfile?.label || "relevant"} industry.

Return ONLY valid JSON.`,
        maxTokens: 2000,
        temperature: 0.5,
        taskCategory: "document",
      });

      // Parse the AI response
      let data: { content: string; matchScore: number; keywordsUsed: string[]; sectionsReferenced: string[] };
      try {
        const raw = extractJSON<any>(result.text);
        // === NORMALIZATION: handle multiple possible key names ===
        // The AI may return { content: "..." }, { letter: "..." }, { text: "..." },
        // or just a plain string. Normalize to { content, matchScore, ... }.
        const content = raw.content || raw.letter || raw.text || raw.coverLetter || raw.body || "";
        if (content && typeof content === "string" && content.trim().length > 50) {
          data = {
            content,
            matchScore: raw.matchScore || raw.match_score || raw.score || 75,
            keywordsUsed: Array.isArray(raw.keywordsUsed) ? raw.keywordsUsed
              : Array.isArray(raw.keywords_used) ? raw.keywords_used
              : Array.isArray(raw.keywords) ? raw.keywords
              : jd.keywords.slice(0, 8),
            sectionsReferenced: Array.isArray(raw.sectionsReferenced) ? raw.sectionsReferenced
              : Array.isArray(raw.sections_referenced) ? raw.sections_referenced
              : Array.isArray(raw.sections) ? raw.sections
              : ["Professional Summary", "Experience", "Skills"],
          };
        } else {
          // JSON parsed but content is missing/empty — treat the raw text as content
          data = {
            content: result.text,
            matchScore: 75,
            keywordsUsed: jd.keywords.slice(0, 8),
            sectionsReferenced: ["Professional Summary", "Experience", "Skills"],
          };
        }
      } catch {
        // Fallback: treat the entire response as cover letter content
        data = {
          content: result.text,
          matchScore: 75,
          keywordsUsed: jd.keywords.slice(0, 8),
          sectionsReferenced: ["Summary", "Experience", "Skills"],
        };
      }

      const cl: CoverLetter = {
        id: uid("cl"),
        title: `Cover Letter — ${jd.company || "Target Company"}`,
        template: "modern",
        content: data.content || result.text,
        resumeId: resume.id,
        jdId: jd.id,
        company: jd.company,
        role: jd.title,
        createdAt: new Date().toISOString(),
        updatedAt: new Date().toISOString(),
      };
      addCoverLetter(cl);
      setActiveId(cl.id);
      setMatchScore(data.matchScore ?? 75);
      setKeywordsUsed(data.keywordsUsed ?? []);
      setSectionsReferenced(data.sectionsReferenced ?? []);
      incUsage("coverLetters");
      log({
        actor: "you",
        action: "Cover letter generated (dynamic)",
        category: "ai",
        details: `${selectedTone} tone · ${industryProfile?.label || "Generic"} industry · ${data.matchScore ?? 75}% match via ${result.provider}`,
        severity: "info",
      });
      toast.success(`Cover letter generated — ${data.matchScore ?? 75}% match via ${result.provider}`);
    } catch (e: any) {
      toast.error(e?.message || "Generation failed. Please try again.");
    } finally {
      setGenerating(false);
    }
  };

  const updateContent = (content: string) => {
    if (!active) return;
    updateCoverLetter(active.id, { content });
  };

  // === Empty state ===
  if (!active && coverLetters.length === 0) {
    return (
      <div className="space-y-6">
        <div>
          <h1 className="font-display text-2xl font-bold flex items-center gap-2"><Icon name="Mail" className="w-6 h-6 text-brand" /> Cover Letter Generator</h1>
          <p className="text-sm text-muted-foreground mt-1">Dynamic, context-aware cover letters tailored to your optimized resume and job description.</p>
        </div>

        {/* Context summary */}
        <Card>
          <CardContent className="p-4 space-y-3">
            <div className="grid sm:grid-cols-2 gap-3 text-xs">
              <div className="rounded-lg bg-secondary/40 p-2.5 flex items-center justify-between">
                <span className="text-muted-foreground">Resume:</span>
                <span className="font-semibold">{resumes[0]?.name ?? "Not uploaded"}</span>
              </div>
              <div className="rounded-lg bg-secondary/40 p-2.5 flex items-center justify-between">
                <span className="text-muted-foreground">Job Description:</span>
                <span className="font-semibold">{jds[0]?.title ?? "Not added"}</span>
              </div>
              <div className="rounded-lg bg-secondary/40 p-2.5 flex items-center justify-between">
                <span className="text-muted-foreground">Company:</span>
                <span className="font-semibold">{jds[0]?.company ?? "Not specified"}</span>
              </div>
              <div className="rounded-lg bg-secondary/40 p-2.5 flex items-center justify-between">
                <span className="text-muted-foreground">Detected Industry:</span>
                <span className="font-semibold">{industryProfile?.label ?? "Generic"}</span>
              </div>
            </div>
            {industryDetection && industryDetection.confidence >= 15 && (
              <div className="rounded-lg bg-brand/5 dark:bg-brand/10 border border-brand/20 p-2.5 flex items-start gap-2">
                <Icon name="Info" className="w-3.5 h-3.5 text-brand shrink-0 mt-0.5" />
                <p className="text-xs text-muted-foreground">
                  Industry detected: <strong>{industryProfile?.label}</strong>. The cover letter will be tailored with {industryProfile?.label.toLowerCase()} terminology and writing style.
                </p>
              </div>
            )}
          </CardContent>
        </Card>

        {/* Tone selector */}
        <Card>
          <CardHeader><CardTitle className="text-base">Select Tone</CardTitle></CardHeader>
          <CardContent>
            <div className="grid grid-cols-2 sm:grid-cols-3 gap-2">
              {TONES.map((t) => (
                <button
                  key={t.id}
                  onClick={() => setSelectedTone(t.id)}
                  className={`flex flex-col items-start p-3 rounded-lg border-2 transition text-left ${
                    selectedTone === t.id ? "border-brand bg-brand/10" : "border-border hover:border-brand/40"
                  }`}
                >
                  <span className={`text-sm font-medium ${selectedTone === t.id ? "text-brand" : "text-foreground"}`}>{t.label}</span>
                  <span className="text-[10px] text-muted-foreground mt-0.5">{t.desc}</span>
                </button>
              ))}
            </div>
          </CardContent>
        </Card>

        {/* Generate button */}
        <Card>
          <CardContent className="p-5 sm:p-6 text-center">
            <Icon name="Sparkles" className="w-10 h-10 text-brand mx-auto" />
            <h3 className="mt-3 font-semibold text-base">Generate Your Cover Letter</h3>
            <p className="text-sm text-muted-foreground mt-1 max-w-md mx-auto">
              AI-generated from your resume and job description. Tailored to {industryProfile?.label || "your industry"} with {selectedTone.toLowerCase()} tone. Recruiter-grade, ATS-friendly, one page.
            </p>
            <Button onClick={generate} disabled={generating || !resumes[0] || !jds[0]} className="bg-brand hover:bg-brand-dark text-white gap-2 mt-4">
              {generating ? <Icon name="Loader2" className="w-4 h-4 animate-spin" /> : <Icon name="Wand2" className="w-4 h-4" />}
              {generating ? "Generating…" : "Generate Cover Letter"}
            </Button>
            {(!resumes[0] || !jds[0]) && (
              <p className="text-xs text-amber-600 mt-2">
                {!resumes[0] ? "Upload a resume first. " : ""}
                {!jds[0] ? "Add a job description first." : ""}
              </p>
            )}
          </CardContent>
        </Card>
      </div>
    );
  }

  // === Active cover letter view ===
  if (!active) return null;
  return (
    <div className="space-y-4">
      <div className="flex flex-wrap items-center justify-between gap-3">
        <div>
          <h1 className="font-display text-2xl font-bold flex items-center gap-2"><Icon name="Mail" className="w-6 h-6 text-brand" /> Cover Letter Generator</h1>
          <p className="text-sm text-muted-foreground mt-1">Edit the draft, then export in your preferred format.</p>
        </div>
        <div className="flex gap-2">
          <Button variant="outline" size="sm" onClick={() => { removeCoverLetter(active.id); setActiveId(coverLetters.find(c => c.id !== active.id)?.id ?? ""); toast.success("Deleted."); }}>
            <Icon name="Trash2" className="w-4 h-4" />
          </Button>
          <Button variant="outline" size="sm" onClick={() => exportCoverLetterTXT(active)} className="gap-1.5"><Icon name="FileText" className="w-3.5 h-3.5" /> TXT</Button>
          <Button variant="outline" size="sm" onClick={() => { exportCoverLetterDOCX(active); incUsage("downloads"); toast.success("DOCX exported."); }} className="gap-1.5"><Icon name="FileType" className="w-3.5 h-3.5" /> DOCX</Button>
          <Button size="sm" onClick={() => { exportCoverLetterPDF(active); incUsage("downloads"); log({ actor: "you", action: "Cover letter exported (PDF)", category: "export", details: `${active.title}.pdf`, severity: "info" }); toast.success("PDF exported."); }} className="bg-brand hover:bg-brand-dark text-white gap-1.5"><Icon name="Download" className="w-3.5 h-3.5" /> PDF</Button>
        </div>
      </div>

      <div className="grid lg:grid-cols-12 gap-4">
        {/* Editor + metadata */}
        <div className="lg:col-span-7 space-y-3">
          {/* Match score + keywords */}
          {matchScore !== null && (
            <Card>
              <CardContent className="p-4">
                <div className="flex items-center gap-4 flex-wrap">
                  <ScoreRing value={matchScore} size={60} label="Match" />
                  <div className="flex-1 min-w-0 space-y-2">
                    {keywordsUsed.length > 0 && (
                      <div>
                        <div className="text-[10px] uppercase tracking-wide text-muted-foreground font-semibold mb-1">Keywords Used ({keywordsUsed.length})</div>
                        <div className="flex flex-wrap gap-1">
                          {keywordsUsed.slice(0, 12).map((k, i) => <Badge key={i} variant="success" className="text-[9px]">{k}</Badge>)}
                        </div>
                      </div>
                    )}
                    {sectionsReferenced.length > 0 && (
                      <div>
                        <div className="text-[10px] uppercase tracking-wide text-muted-foreground font-semibold mb-1">Resume Sections Referenced</div>
                        <div className="flex flex-wrap gap-1">
                          {sectionsReferenced.map((s, i) => <Badge key={i} variant="outline" className="text-[9px]">{s}</Badge>)}
                        </div>
                      </div>
                    )}
                  </div>
                </div>
              </CardContent>
            </Card>
          )}

          <Card>
            <CardHeader>
              <div className="flex items-center justify-between">
                <CardTitle className="text-base">Edit</CardTitle>
                <Badge variant="outline">{active.company ? `${active.role ?? ""} at ${active.company}` : active.template}</Badge>
              </div>
            </CardHeader>
            <CardContent className="space-y-3">
              <div className="grid sm:grid-cols-2 gap-3">
                <Field label="Title">
                  <Input value={active.title} onChange={(e) => updateCoverLetter(active.id, { title: e.target.value })} />
                </Field>
                <Field label="Company">
                  <Input value={active.company ?? ""} onChange={(e) => updateCoverLetter(active.id, { company: e.target.value })} />
                </Field>
              </div>
              <Field label="Content">
                <Textarea
                  value={active.content}
                  onChange={(e) => updateContent(e.target.value)}
                  rows={18}
                  className="font-serif text-[15px] leading-relaxed"
                />
                <p className="text-xs text-muted-foreground mt-1">{active.content.split(/\s+/).length} words {active.content.split(/\s+/).length > 500 && <span className="text-amber-600">· exceeds 500-word target</span>}</p>
              </Field>
            </CardContent>
          </Card>

          {/* Generate another */}
          <Card>
            <CardHeader><CardTitle className="text-base">Generate Another</CardTitle></CardHeader>
            <CardContent className="space-y-3">
              <div>
                <Label className="text-[10px] uppercase tracking-wide text-muted-foreground font-semibold mb-1.5 block">Tone</Label>
                <div className="flex flex-wrap gap-1.5">
                  {TONES.map((t) => (
                    <button
                      key={t.id}
                      onClick={() => setSelectedTone(t.id)}
                      className={`text-xs px-2.5 py-1 rounded-full border transition ${
                        selectedTone === t.id ? "border-brand bg-brand/10 text-brand font-medium" : "border-border text-muted-foreground hover:text-foreground"
                      }`}
                    >
                      {t.label}
                    </button>
                  ))}
                </div>
              </div>
              <Button onClick={generate} disabled={generating} className="bg-brand hover:bg-brand-dark text-white gap-2">
                {generating ? <Icon name="Loader2" className="w-4 h-4 animate-spin" /> : <Icon name="Sparkles" className="w-4 h-4" />}
                {generating ? "Generating…" : `Generate with ${selectedTone} tone`}
              </Button>
            </CardContent>
          </Card>
        </div>

        {/* Preview */}
        <div className="lg:col-span-5">
          <div className="sticky top-20">
            <div className="rounded-xl bg-secondary/60 p-4 max-h-[calc(100vh-160px)] overflow-y-auto">
              <div className="a4-page !w-full !min-h-0 !max-h-none p-[16mm]" style={{ transformOrigin: "top" }}>
                <div className="text-[10pt] leading-relaxed text-slate-800" style={{ fontFamily: "'Inter', sans-serif" }}>
                  <div className="border-b-2 pb-3 mb-4" style={{ borderColor: "#1154A3" }}>
                    <div className="text-[14pt] font-bold text-slate-900">{active.title}</div>
                    {active.role && active.company && <div className="text-[10pt] text-slate-600 mt-0.5">{active.role} at {active.company}</div>}
                    <div className="text-[9pt] text-slate-500 mt-1" suppressHydrationWarning>{new Date().toLocaleDateString("en-US", { year: "numeric", month: "long", day: "numeric" })}</div>
                  </div>
                  {active.content.split(/\n\s*\n/).map((p, i) => (
                    <p key={i} className="mb-3 text-pretty">{p.trim()}</p>
                  ))}
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Saved letters */}
      <Card>
        <CardHeader><CardTitle className="text-base">All cover letters ({coverLetters.length})</CardTitle></CardHeader>
        <CardContent>
          {coverLetters.length === 0 ? (
            <p className="text-sm text-muted-foreground text-center py-4">No cover letters yet. Generate one above.</p>
          ) : (
            <div className="grid sm:grid-cols-2 lg:grid-cols-3 gap-2">
              {coverLetters.map((c) => (
                <button key={c.id} onClick={() => setActiveId(c.id)} className={`text-left rounded-lg border p-3 transition ${c.id === active.id ? "border-brand bg-brand-light/40" : "border-border hover:border-brand/40"}`}>
                  <div className="font-semibold text-sm truncate">{c.title}</div>
                  <div className="text-xs text-muted-foreground mt-0.5">{c.content.split(/\s+/).length} words{c.company ? ` · ${c.company}` : ""}</div>
                </button>
              ))}
            </div>
          )}
        </CardContent>
      </Card>
    </div>
  );
}

function Field({ label, children }: { label: string; children: React.ReactNode }) {
  return (
    <div className="space-y-1.5">
      <Label className="text-xs uppercase tracking-wide text-muted-foreground">{label}</Label>
      {children}
    </div>
  );
}

src/components/app/modules/Downloads.tsx:
"use client";

import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge, Icon } from "@/components/shared";
import { useApp } from "@/lib/store";
import {
  exportResumePDF, exportResumeDOCX, exportResumeTXT,
  exportCoverLetterPDF, exportCoverLetterDOCX, exportCoverLetterTXT,
  exportInterviewPDF, exportInterviewDOCX,
} from "@/lib/exporter";

export function Downloads() {
  const resumes = useApp((s) => s.resumes);
  const coverLetters = useApp((s) => s.coverLetters);
  const interviews = useApp((s) => s.interviews);
  const incUsage = useApp((s) => s.incUsage);
  const log = useApp((s) => s.log);

  const downloadResume = (r: any, fmt: "pdf" | "docx" | "txt") => {
    if (fmt === "pdf") { const res = exportResumePDF(r, { enforceOnePage: true }); if (!res.ok) return; }
    if (fmt === "docx") exportResumeDOCX(r);
    if (fmt === "txt") exportResumeTXT(r);
    incUsage("downloads");
    log({ actor: "you", action: `Downloaded resume (${fmt})`, category: "export", details: `${r.name}_resume.${fmt}`, severity: "info" });
  };

  const downloadCL = (c: any, fmt: "pdf" | "docx" | "txt") => {
    if (fmt === "pdf") exportCoverLetterPDF(c);
    if (fmt === "docx") exportCoverLetterDOCX(c);
    if (fmt === "txt") exportCoverLetterTXT(c);
    incUsage("downloads");
    log({ actor: "you", action: `Downloaded cover letter (${fmt})`, category: "export", details: `${c.title}.${fmt}`, severity: "info" });
  };

  const downloadIV = (p: any, fmt: "pdf" | "docx") => {
    if (fmt === "pdf") exportInterviewPDF(p);
    if (fmt === "docx") exportInterviewDOCX(p);
    incUsage("downloads");
    log({ actor: "you", action: `Downloaded interview prep (${fmt})`, category: "export", details: `${p.role}.pdf`, severity: "info" });
  };

  return (
    <div className="space-y-6">
      <div>
        <h1 className="font-display text-2xl font-bold flex items-center gap-2"><Icon name="Download" className="w-6 h-6 text-brand" /> Downloads</h1>
        <p className="text-sm text-muted-foreground mt-1">All your generated files in one place. Free, unlimited, no watermarks.</p>
      </div>

      <Card>
        <CardHeader>
          <CardTitle className="text-lg flex items-center gap-2"><Icon name="FileText" className="w-4 h-4 text-brand" /> Resumes ({resumes.length})</CardTitle>
          <CardDescription>PDF (one A4 page guaranteed) · DOCX · TXT</CardDescription>
        </CardHeader>
        <CardContent className="space-y-2">
          {resumes.map((r) => (
            <div key={r.id} className="flex items-center justify-between gap-3 p-3 rounded-lg border border-border">
              <div className="min-w-0">
                <div className="font-semibold text-sm truncate">{r.name}_resume</div>
                <div className="text-xs text-muted-foreground">{r.headline ?? r.template}</div>
              </div>
              <div className="flex gap-1.5 shrink-0">
                <Button size="sm" variant="outline" onClick={() => downloadResume(r, "pdf")} className="gap-1.5"><Icon name="Download" className="w-3.5 h-3.5" /> PDF</Button>
                <Button size="sm" variant="outline" onClick={() => downloadResume(r, "docx")} className="gap-1.5"><Icon name="FileType" className="w-3.5 h-3.5" /> DOCX</Button>
                <Button size="sm" variant="outline" onClick={() => downloadResume(r, "txt")} className="gap-1.5"><Icon name="FileText" className="w-3.5 h-3.5" /> TXT</Button>
              </div>
            </div>
          ))}
          {resumes.length === 0 && <Empty icon="FileText" label="No resumes yet" />}
        </CardContent>
      </Card>

      <Card>
        <CardHeader>
          <CardTitle className="text-lg flex items-center gap-2"><Icon name="Mail" className="w-4 h-4 text-brand" /> Cover letters ({coverLetters.length})</CardTitle>
        </CardHeader>
        <CardContent className="space-y-2">
          {coverLetters.map((c) => (
            <div key={c.id} className="flex items-center justify-between gap-3 p-3 rounded-lg border border-border">
              <div className="min-w-0">
                <div className="font-semibold text-sm truncate">{c.title}</div>
                <div className="text-xs text-muted-foreground capitalize">{c.template} · {c.content.split(/\s+/).length} words</div>
              </div>
              <div className="flex gap-1.5 shrink-0">
                <Button size="sm" variant="outline" onClick={() => downloadCL(c, "pdf")} className="gap-1.5"><Icon name="Download" className="w-3.5 h-3.5" /> PDF</Button>
                <Button size="sm" variant="outline" onClick={() => downloadCL(c, "docx")} className="gap-1.5"><Icon name="FileType" className="w-3.5 h-3.5" /> DOCX</Button>
                <Button size="sm" variant="outline" onClick={() => downloadCL(c, "txt")} className="gap-1.5"><Icon name="FileText" className="w-3.5 h-3.5" /> TXT</Button>
              </div>
            </div>
          ))}
          {coverLetters.length === 0 && <Empty icon="Mail" label="No cover letters yet" />}
        </CardContent>
      </Card>

      <Card>
        <CardHeader>
          <CardTitle className="text-lg flex items-center gap-2"><Icon name="MessagesSquare" className="w-4 h-4 text-brand" /> Interview packages ({interviews.length})</CardTitle>
        </CardHeader>
        <CardContent className="space-y-2">
          {interviews.map((p) => (
            <div key={p.id} className="flex items-center justify-between gap-3 p-3 rounded-lg border border-border">
              <div className="min-w-0">
                <div className="font-semibold text-sm truncate">{p.role ?? "Interview prep"}{p.company ? ` — ${p.company}` : ""}</div>
                <div className="text-xs text-muted-foreground">{p.questions.length} questions</div>
              </div>
              <div className="flex gap-1.5 shrink-0">
                <Button size="sm" variant="outline" onClick={() => downloadIV(p, "pdf")} className="gap-1.5"><Icon name="Download" className="w-3.5 h-3.5" /> PDF</Button>
                <Button size="sm" variant="outline" onClick={() => downloadIV(p, "docx")} className="gap-1.5"><Icon name="FileType" className="w-3.5 h-3.5" /> DOCX</Button>
              </div>
            </div>
          ))}
          {interviews.length === 0 && <Empty icon="MessagesSquare" label="No interview packages yet" />}
        </CardContent>
      </Card>

      <Card className="gradient-brand text-white">
        <CardContent className="p-5 flex items-center justify-between gap-3">
          <div className="flex items-center gap-3">
            <Icon name="Gift" className="w-6 h-6" />
            <div>
              <div className="font-semibold">All downloads are free, forever.</div>
              <div className="text-xs text-white/80">No watermarks. No usage limits. No email required.</div>
            </div>
          </div>
          <Badge variant="gold">100% Free</Badge>
        </CardContent>
      </Card>
    </div>
  );
}

function Empty({ icon, label }: { icon: string; label: string }) {
  return (
    <div className="text-center py-8">
      <Icon name={icon} className="w-8 h-8 text-muted-foreground/40 mx-auto" />
      <p className="text-sm text-muted-foreground mt-2">{label}</p>
    </div>
  );
}

"use client";

import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Switch } from "@/components/ui/switch";
import { Badge, Icon } from "@/components/shared";
import { useApp } from "@/lib/store";
import { toast } from "sonner";
import type { FeatureFlags as Flags } from "@/lib/types";

const FLAGS: { key: keyof Flags; label: string; desc: string; icon: string; severity: "safe" | "feature" | "danger" }[] = [
  { key: "enableResumeBuilder", label: "Resume Builder", desc: "Allow users to create and edit resumes.", icon: "FilePlus2", severity: "feature" },
  { key: "enableATSChecker", label: "ATS Checker", desc: "Enable the ATS scoring engine.", icon: "ScanText", severity: "feature" },
  { key: "enableOptimizer", label: "Resume Optimizer", desc: "Enable AI-powered resume optimization.", icon: "Wand2", severity: "feature" },
  { key: "enableCoverLetter", label: "Cover Letter Generator", desc: "Enable cover letter creation.", icon: "Mail", severity: "feature" },
  { key: "enableInterviewPrep", label: "Interview Prep", desc: "Enable interview question generation.", icon: "MessagesSquare", severity: "feature" },
  { key: "enableJDScraper", label: "Job Description Scraper", desc: "Allow URL-based JD scraping.", icon: "Search", severity: "feature" },
  { key: "enableAIFailover", label: "AI Failover", desc: "Automatically switch providers on failure.", icon: "RefreshCcw", severity: "safe" },
  { key: "enableDonations", label: "Donations", desc: "Show optional donation prompts.", icon: "Heart", severity: "safe" },
  { key: "enableAds", label: "Advertisements", desc: "Non-intrusive ads. Must never block features.", icon: "Megaphone", severity: "safe" },
  { key: "maintenanceMode", label: "Maintenance Mode", desc: "Take the entire app offline for users.", icon: "Wrench", severity: "danger" },
];

export function FeatureFlags() {
  const flags = useApp((s) => s.flags);
  const updateFlag = useApp((s) => s.updateFlag);
  const log = useApp((s) => s.log);

  return (
    <div className="space-y-6">
      <div>
        <h1 className="font-display text-2xl font-bold flex items-center gap-2"><Icon name="Flag" className="w-6 h-6 text-brand" /> Feature Flags</h1>
        <p className="text-sm text-muted-foreground mt-1">Toggle features on or off instantly, without redeploying.</p>
      </div>

      <div className="grid sm:grid-cols-2 gap-3">
        {FLAGS.map((f) => {
          const on = flags[f.key];
          return (
            <Card key={f.key} className={on ? "" : "opacity-70"}>
              <CardContent className="p-4 flex items-start gap-3">
                <div className={`w-10 h-10 rounded-lg flex items-center justify-center shrink-0 ${f.severity === "danger" ? "bg-red-100 text-red-700 dark:bg-red-400/10 dark:text-red-300" : f.severity === "feature" ? "bg-brand-light text-brand dark:bg-brand/15" : "bg-amber-100 text-amber-700 dark:bg-amber-400/10 dark:text-amber-300"}`}>
                  <Icon name={f.icon} className="w-5 h-5" />
                </div>
                <div className="flex-1 min-w-0">
                  <div className="flex items-center gap-2">
                    <div className="font-semibold text-sm">{f.label}</div>
                    {f.severity === "danger" && <Badge variant="danger" className="text-[10px]">Danger</Badge>}
                  </div>
                  <div className="text-xs text-muted-foreground mt-0.5">{f.desc}</div>
                </div>
                <Switch
                  checked={on}
                  onCheckedChange={(v) => {
                    updateFlag(f.key, v);
                    log({ actor: "you", action: `Flag ${f.key} ${v ? "ON" : "OFF"}`, category: "admin", details: f.label, severity: v ? "info" : "warning" });
                    toast.success(`${f.label} ${v ? "enabled" : "disabled"}.`);
                  }}
                />
              </CardContent>
            </Card>
          );
        })}
      </div>

      <Card className="bg-amber-100/40 dark:bg-amber-400/5 border-amber-300/50">
        <CardContent className="p-4 flex items-start gap-3">
          <Icon name="AlertTriangle" className="w-5 h-5 text-amber-600 shrink-0 mt-0.5" />
          <div className="text-sm">
            <div className="font-semibold">Use with care</div>
            <div className="text-xs text-muted-foreground mt-1">Disabling core features will immediately hide them from all users. Maintenance mode blocks all non-admin access.</div>
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

src/components/app/modules/Interview.tsx:
"use client";

import { useState, useCallback, useMemo } from "react";
import { motion } from "framer-motion";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge, Icon, ScoreRing } from "@/components/shared";
import { useApp, uid } from "@/lib/store";
import { callAI, extractJSON } from "@/lib/ai";
import { detectIndustry, INDUSTRY_PROFILES } from "@/lib/industry-ats";
import { exportInterviewPDF, exportInterviewDOCX } from "@/lib/exporter";
import { InterviewSession, InterviewSkeleton } from "@/components/interview/InterviewSession";
import { toast } from "sonner";
import type { InterviewPackage, InterviewQuestion } from "@/lib/types";

const CATEGORIES = [
  { id: "technical", label: "Technical", icon: "Code2", color: "#1154A3" },
  { id: "behavioral", label: "Behavioral", icon: "Users", color: "#F59E0B" },
  { id: "situational", label: "Situational", icon: "GitBranch", color: "#10B981" },
  { id: "hr", label: "HR", icon: "UserCheck", color: "#8B5CF6" },
  { id: "company", label: "Company-specific", icon: "Building2", color: "#EC4899" },
] as const;

const DIFFICULTY_COLORS: Record<string, string> = { easy: "#10B981", medium: "#F59E0B", hard: "#DC2626" };

export function Interview() {
  const interviews = useApp((s) => s.interviews);
  const resumes = useApp((s) => s.resumes);
  const jds = useApp((s) => s.jobDescriptions);
  const addInterview = useApp((s) => s.addInterview);
  const removeInterview = useApp((s) => s.removeInterview);
  const incUsage = useApp((s) => s.incUsage);
  const log = useApp((s) => s.log);
  const setView = useApp((s) => s.setView);

  const [generating, setGenerating] = useState(false);
  const [expanded, setExpanded] = useState<string | null>(null);
  const [practiceSession, setPracticeSession] = useState<InterviewPackage | null>(null);
  const [selectedResumeId, setSelectedResumeId] = useState<string>(resumes[0]?.id ?? "");
  const [selectedJdId, setSelectedJdId] = useState<string>(jds[0]?.id ?? "");
  const [completedQuestions, setCompletedQuestions] = useState<Set<string>>(new Set());
  const [readinessData, setReadinessData] = useState<{ score: number; strengths: string[]; weaknesses: string[]; topicsToReview: string[]; skillsToReview: string[]; focusAreas: string[] } | null>(null);

  // === Auto-detect context ===
  const selectedResume = resumes.find((r) => r.id === selectedResumeId) ?? resumes[0] ?? null;
  const selectedJd = jds.find((j) => j.id === selectedJdId) ?? jds[0] ?? null;

  const industryDetection = useMemo(() => {
    if (!selectedJd) return null;
    const jdText = selectedJd.rawText ?? selectedJd.keywords.join(" ");
    const resumeText = `${selectedResume?.name ?? ""} ${selectedResume?.headline ?? ""} ${selectedResume?.summary ?? ""} ${selectedResume?.experience.map((e) => e.title + " " + e.company).join(" ")}`;
    return detectIndustry(jdText, resumeText);
  }, [selectedJd, selectedResume]);

  const industryProfile = industryDetection ? INDUSTRY_PROFILES[industryDetection.industryId] : null;

  // === Generate interview prep package ===
  const generate = async () => {
    if (!selectedResume) {
      toast.error("Please upload or create a resume first.");
      return;
    }
    if (!selectedJd) {
      toast.error("Please add a job description first.");
      return;
    }

    setGenerating(true);
    setReadinessData(null);
    try {
      const resumeContext = JSON.stringify({
        name: selectedResume.name,
        headline: selectedResume.headline,
        summary: selectedResume.summary,
        experience: selectedResume.experience.map((e) => ({
          title: e.title,
          company: e.company,
          location: e.location,
          bullets: e.bullets,
        })),
        skills: selectedResume.skills.map((s) => s.name),
        education: selectedResume.education.map((ed) => ({ degree: ed.degree, institution: ed.institution })),
        languages: selectedResume.languages.map((l) => l.name),
        certifications: selectedResume.certifications.map((c) => c.name),
      });

      const jdContext = selectedJd.rawText ?? JSON.stringify({
        title: selectedJd.title,
        company: selectedJd.company,
        responsibilities: selectedJd.responsibilities,
        requiredSkills: selectedJd.requiredSkills,
        preferredSkills: selectedJd.preferredSkills,
        keywords: selectedJd.keywords,
      });

      const industryContext = industryProfile ? `
INDUSTRY: ${industryProfile.label}
INDUSTRY KEYWORDS: ${industryProfile.priorityKeywords.join(", ")}
INDUSTRY WRITING GUIDANCE: ${industryProfile.writingGuidance}
` : "";

      const result = await callAI({
        systemPrompt: `You are an Expert Interview Coach and Senior Recruiter. You generate highly personalized interview preparation packages tailored to the candidate's resume and the job description. You NEVER ask about technologies or experiences not present in the resume. You NEVER fabricate answers — all answers reference real experience from the resume. You adapt questions to the detected industry. Always return ONLY valid JSON.

${industryContext}`,
        userPrompt: `CANDIDATE'S RESUME (primary source — use ONLY this information for answers):
${resumeContext}

JOB DESCRIPTION:
${jdContext}

COMPANY: ${selectedJd.company || "the company"}
JOB TITLE: ${selectedJd.title || "the role"}
INDUSTRY: ${industryProfile?.label || "Generic"}

Generate a comprehensive interview preparation package with 9-15 questions:
- 3-5 Technical questions (about technologies/skills IN the resume)
- 3-5 Behavioral questions (STAR method, past experiences from the resume)
- 2-3 Situational questions (hypothetical scenarios relevant to the role)
- 1-3 Company-specific questions (about the company's values/culture/products)

For each question provide:
- category: "technical" | "behavioral" | "situational" | "hr" | "company"
- question: the interview question
- difficulty: "easy" | "medium" | "hard"
- recommendedAnswer: recruiter-grade answer using the candidate's REAL experience
- talkingPoints: 3-5 bullet points for the answer
- starExample: { situation, task, action, result } (for behavioral/situational)
- followUps: 2-3 follow-up questions

Also provide:
- readinessScore: 0-100 (how prepared the candidate is)
- strengths: 3-5 areas where the candidate is strong
- weaknesses: 3-5 areas to improve
- topicsToReview: 3-5 topics to study before the interview
- skillsToReview: 3-5 skills to brush up on
- focusAreas: 3-5 likely interview focus areas for this role/company

Return JSON:
{
  "questions": [ { "category": "...", "question": "...", "difficulty": "...", "recommendedAnswer": "...", "talkingPoints": [...], "starExample": {...}, "followUps": [...] } ],
  "readinessScore": 78,
  "strengths": ["..."],
  "weaknesses": ["..."],
  "topicsToReview": ["..."],
  "skillsToReview": ["..."],
  "focusAreas": ["..."]
}`,
        maxTokens: 6000,
        temperature: 0.5,
        taskCategory: "document",
      });

      let data: { questions: any[]; readinessScore?: number; strengths?: string[]; weaknesses?: string[]; topicsToReview?: string[]; skillsToReview?: string[]; focusAreas?: string[] };
      try {
        data = extractJSON<any>(result.text);
      } catch {
        throw new Error("Failed to parse AI response. Please try again.");
      }

      const questions: InterviewQuestion[] = (data.questions ?? []).map((q: any) => ({
        id: uid("q"),
        category: q.category || "hr",
        question: q.question || "",
        difficulty: q.difficulty || "medium",
        recommendedAnswer: q.recommendedAnswer || "",
        talkingPoints: Array.isArray(q.talkingPoints) ? q.talkingPoints : [],
        starExample: q.starExample,
        followUps: Array.isArray(q.followUps) ? q.followUps : [],
      }));

      if (!questions.length) throw new Error("AI returned no questions.");

      const pkg: InterviewPackage = {
        id: uid("iv"),
        resumeId: selectedResume.id,
        jdId: selectedJd.id,
        company: selectedJd.company,
        role: selectedJd.title,
        questions,
        createdAt: new Date().toISOString(),
      };
      addInterview(pkg);
      setReadinessData({
        score: data.readinessScore ?? 75,
        strengths: data.strengths ?? [],
        weaknesses: data.weaknesses ?? [],
        topicsToReview: data.topicsToReview ?? [],
        skillsToReview: data.skillsToReview ?? [],
        focusAreas: data.focusAreas ?? [],
      });
      setCompletedQuestions(new Set());
      incUsage("interviewPreps");
      log({
        actor: "you",
        action: "Interview prep generated (dynamic)",
        category: "ai",
        details: `${questions.length} questions · ${industryProfile?.label ?? "Generic"} · readiness ${data.readinessScore ?? 75}/100 via ${result.provider}`,
        severity: "info",
      });
      toast.success(`${questions.length} questions generated — readiness ${data.readinessScore ?? 75}/100`);
    } catch (e: any) {
      toast.error(e?.message || "Generation failed.");
    } finally {
      setGenerating(false);
    }
  };

  const toggleCompleted = (qId: string) => {
    setCompletedQuestions((prev) => {
      const next = new Set(prev);
      if (next.has(qId)) next.delete(qId);
      else next.add(qId);
      return next;
    });
  };

  const grouped = (pkg: InterviewPackage) => {
    const g: Record<string, InterviewQuestion[]> = {};
    for (const q of pkg.questions) (g[q.category] ||= []).push(q);
    return g;
  };

  const latestPkg = interviews[0] ?? null;
  const prepPercent = latestPkg ? Math.round((completedQuestions.size / latestPkg.questions.length) * 100) : 0;

  // === Practice session mode ===
  if (practiceSession) {
    return <InterviewSession pkg={practiceSession} onClose={() => setPracticeSession(null)} />;
  }

  // === No resume state ===
  if (resumes.length === 0) {
    return (
      <div className="space-y-6">
        <div>
          <h1 className="font-display text-2xl font-bold flex items-center gap-2"><Icon name="MessagesSquare" className="w-6 h-6 text-brand" /> Interview Prep</h1>
          <p className="text-sm text-muted-foreground mt-1">Dynamic, context-aware interview preparation tailored to your resume and job description.</p>
        </div>
        <Card>
          <CardContent className="py-12 text-center">
            <Icon name="FileText" className="w-10 h-10 text-muted-foreground/40 mx-auto" />
            <h3 className="mt-3 font-semibold">Optimize a resume first</h3>
            <p className="text-sm text-muted-foreground mt-1 max-w-md mx-auto">Upload and optimize a resume to generate personalized interview preparation with tailored questions and answers.</p>
            <Button onClick={() => setView("optimizer")} className="bg-brand hover:bg-brand-dark text-white gap-2 mt-4">
              <Icon name="Wand2" className="w-4 h-4" /> Go to Resume Optimizer
            </Button>
          </CardContent>
        </Card>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <div className="flex flex-wrap items-center justify-between gap-3">
        <div>
          <h1 className="font-display text-2xl font-bold flex items-center gap-2"><Icon name="MessagesSquare" className="w-6 h-6 text-brand" /> Interview Prep</h1>
          <p className="text-sm text-muted-foreground mt-1">Dynamic, context-aware interview preparation tailored to your resume and job description.</p>
        </div>
        <Button onClick={generate} disabled={generating || !selectedResume || !selectedJd} className="bg-brand hover:bg-brand-dark text-white gap-2">
          {generating ? <Icon name="Loader2" className="w-4 h-4 animate-spin" /> : <Icon name="Sparkles" className="w-4 h-4" />}
          {generating ? "Generating…" : "Generate package"}
        </Button>
      </div>

      {/* === Context selection === */}
      <Card>
        <CardContent className="p-4 space-y-3">
          <div className="grid sm:grid-cols-2 gap-3">
            <div className="space-y-1.5">
              <label className="text-[10px] uppercase tracking-wide text-muted-foreground font-semibold">Select Resume</label>
              <select value={selectedResumeId} onChange={(e) => setSelectedResumeId(e.target.value)} className="w-full h-9 px-2 rounded-md border border-input bg-background text-sm">
                {resumes.map((r) => <option key={r.id} value={r.id}>{r.name}{r.headline ? ` — ${r.headline}` : ""}</option>)}
              </select>
            </div>
            <div className="space-y-1.5">
              <label className="text-[10px] uppercase tracking-wide text-muted-foreground font-semibold">Select Target Job</label>
              <select value={selectedJdId} onChange={(e) => setSelectedJdId(e.target.value)} className="w-full h-9 px-2 rounded-md border border-input bg-background text-sm">
                <option value="">No job selected</option>
                {jds.map((j) => <option key={j.id} value={j.id}>{j.title}{j.company ? ` — ${j.company}` : ""}</option>)}
              </select>
            </div>
          </div>
          {industryDetection && industryDetection.confidence >= 15 && (
            <div className="grid sm:grid-cols-3 gap-2 text-xs">
              <div className="rounded-lg bg-secondary/40 p-2 flex items-center justify-between">
                <span className="text-muted-foreground">Company:</span>
                <span className="font-semibold">{selectedJd?.company ?? "N/A"}</span>
              </div>
              <div className="rounded-lg bg-secondary/40 p-2 flex items-center justify-between">
                <span className="text-muted-foreground">Industry:</span>
                <span className="font-semibold">{industryProfile?.label ?? "Generic"}</span>
              </div>
              <div className="rounded-lg bg-secondary/40 p-2 flex items-center justify-between">
                <span className="text-muted-foreground">Role:</span>
                <span className="font-semibold">{selectedJd?.title ?? "N/A"}</span>
              </div>
            </div>
          )}
          {(!selectedResume || !selectedJd) && (
            <p className="text-xs text-amber-600">
              {!selectedResume ? "Select a resume. " : ""}
              {!selectedJd ? "Add and select a job description for tailored questions." : ""}
            </p>
          )}
        </CardContent>
      </Card>

      {/* === Readiness Dashboard === */}
      {readinessData && (
        <Card>
          <CardContent className="p-4 sm:p-5">
            <div className="flex items-center gap-4 flex-wrap mb-4">
              <ScoreRing value={readinessData.score} size={80} label="Readiness" />
              <div className="flex-1 min-w-0">
                <h3 className="font-semibold text-sm">Interview Readiness Dashboard</h3>
                <p className="text-xs text-muted-foreground mt-0.5">
                  {readinessData.score >= 80 ? "Excellent — you're well-prepared!" : readinessData.score >= 60 ? "Good — review the topics below." : "Needs work — focus on the areas below."}
                </p>
              </div>
              {latestPkg && (
                <div className="text-right">
                  <div className="text-xs font-semibold text-brand">{completedQuestions.size}/{latestPkg.questions.length}</div>
                  <div className="text-[10px] text-muted-foreground">completed</div>
                </div>
              )}
            </div>
            <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-3">
              {readinessData.strengths.length > 0 && (
                <div><div className="text-[10px] font-semibold uppercase tracking-wide text-emerald-600 mb-1">Strengths</div>
                <ul className="space-y-0.5">{readinessData.strengths.map((s, i) => <li key={i} className="text-xs flex gap-1"><span className="text-emerald-600">✓</span> {s}</li>)}</ul></div>
              )}
              {readinessData.weaknesses.length > 0 && (
                <div><div className="text-[10px] font-semibold uppercase tracking-wide text-amber-600 mb-1">Weaknesses</div>
                <ul className="space-y-0.5">{readinessData.weaknesses.map((w, i) => <li key={i} className="text-xs flex gap-1"><span className="text-amber-600">→</span> {w}</li>)}</ul></div>
              )}
              {readinessData.focusAreas.length > 0 && (
                <div><div className="text-[10px] font-semibold uppercase tracking-wide text-brand mb-1">Focus Areas</div>
                <div className="flex flex-wrap gap-1">{readinessData.focusAreas.map((f, i) => <Badge key={i} variant="outline" className="text-[9px]">{f}</Badge>)}</div></div>
              )}
              {readinessData.topicsToReview.length > 0 && (
                <div><div className="text-[10px] font-semibold uppercase tracking-wide text-amber-500 mb-1">Topics To Review</div>
                <div className="flex flex-wrap gap-1">{readinessData.topicsToReview.map((t, i) => <Badge key={i} variant="warning" className="text-[9px]">{t}</Badge>)}</div></div>
              )}
              {readinessData.skillsToReview.length > 0 && (
                <div><div className="text-[10px] font-semibold uppercase tracking-wide text-red-500 mb-1">Skills To Review</div>
                <div className="flex flex-wrap gap-1">{readinessData.skillsToReview.map((s, i) => <Badge key={i} variant="warning" className="text-[9px]">{s}</Badge>)}</div></div>
              )}
            </div>
          </CardContent>
        </Card>
      )}

      {/* === Progress tracker === */}
      {latestPkg && prepPercent > 0 && (
        <Card>
          <CardContent className="p-3">
            <div className="flex items-center justify-between text-xs mb-1.5">
              <span className="font-medium text-muted-foreground">Preparation Progress</span>
              <span className="font-bold text-brand">{prepPercent}%</span>
            </div>
            <div className="h-2 bg-secondary rounded-full overflow-hidden">
              <div className="h-full bg-gradient-to-r from-brand to-emerald-500 rounded-full transition-all" style={{ width: `${prepPercent}%` }} />
            </div>
          </CardContent>
        </Card>
      )}

      {/* === Loading skeleton === */}
      {generating && <InterviewSkeleton />}

      {/* === Empty state === */}
      {!generating && interviews.length === 0 && (
        <Card>
          <CardContent className="py-12 text-center">
            <Icon name="MessagesSquare" className="w-10 h-10 text-muted-foreground/40 mx-auto" />
            <h3 className="mt-3 font-semibold">No interview packages yet</h3>
            <p className="text-sm text-muted-foreground mt-1 max-w-md mx-auto">
              {selectedResume && selectedJd
                ? "Click \"Generate package\" to create personalized interview questions with tailored answers."
                : "Select a resume and job description above, then generate."}
            </p>
          </CardContent>
        </Card>
      )}

      {/* === Interview packages === */}
      {!generating && interviews.map((pkg) => {
        const g = grouped(pkg);
        return (
          <Card key={pkg.id}>
            <CardHeader>
              <div className="flex items-center justify-between flex-wrap gap-2">
                <div>
                  <CardTitle className="text-lg flex items-center gap-2">
                    <Icon name="Package" className="w-4 h-4 text-brand" />
                    {pkg.role ?? "Interview Prep"}{pkg.company ? ` at ${pkg.company}` : ""}
                  </CardTitle>
                  <CardDescription>{pkg.questions.length} questions · generated {new Date(pkg.createdAt).toLocaleDateString()}</CardDescription>
                </div>
                <div className="flex gap-2 flex-wrap">
                  <Button size="sm" variant="outline" onClick={() => setPracticeSession(pkg)} className="gap-1.5 border-brand text-brand hover:bg-brand-light" title="Start interactive practice session">
                    <Icon name="Play" className="w-3.5 h-3.5" /> Practice
                  </Button>
                  <Button size="sm" variant="outline" onClick={() => { exportInterviewDOCX(pkg); incUsage("downloads"); toast.success("DOCX exported."); }} className="gap-1.5"><Icon name="FileType" className="w-3.5 h-3.5" /> DOCX</Button>
                  <Button size="sm" onClick={() => { exportInterviewPDF(pkg); incUsage("downloads"); log({ actor: "you", action: "Interview prep exported (PDF)", category: "export", details: `${pkg.role}.pdf`, severity: "info" }); toast.success("PDF exported."); }} className="bg-brand hover:bg-brand-dark text-white gap-1.5"><Icon name="Download" className="w-3.5 h-3.5" /> PDF</Button>
                  <Button size="sm" variant="ghost" className="text-destructive" onClick={() => { removeInterview(pkg.id); toast.success("Deleted."); }}><Icon name="Trash2" className="w-3.5 h-3.5" /></Button>
                </div>
              </div>
            </CardHeader>
            <CardContent>
              {/* Category summary */}
              <div className="flex flex-wrap gap-2 mb-4">
                {CATEGORIES.map((c) => {
                  const n = g[c.id]?.length ?? 0;
                  if (!n) return null;
                  return (
                    <div key={c.id} className="flex items-center gap-1.5 px-2.5 py-1 rounded-full text-xs font-medium" style={{ background: `${c.color}15`, color: c.color }}>
                      <Icon name={c.icon} className="w-3.5 h-3.5" /> {c.label}: <span className="font-bold">{n}</span>
                    </div>
                  );
                })}
              </div>

              <div className="space-y-3">
                {pkg.questions.map((q, i) => {
                  const cat = CATEGORIES.find((c) => c.id === q.category) ?? CATEGORIES[0];
                  const isOpen = expanded === q.id;
                  const isCompleted = completedQuestions.has(q.id);
                  return (
                    <div key={q.id} className={`rounded-xl border overflow-hidden transition ${isCompleted ? "border-emerald-300 bg-emerald-50/30 dark:bg-emerald-950/10" : "border-border"}`}>
                      <div className="flex items-stretch">
                        <button
                          onClick={() => toggleCompleted(q.id)}
                          className="shrink-0 w-8 flex items-center justify-center hover:bg-secondary/50 transition"
                          title={isCompleted ? "Mark as not completed" : "Mark as completed"}
                        >
                          <Icon name={isCompleted ? "CheckCircle2" : "Circle"} className={`w-4 h-4 ${isCompleted ? "text-emerald-600" : "text-muted-foreground"}`} />
                        </button>
                        <button onClick={() => setExpanded(isOpen ? null : q.id)} className="flex-1 flex items-start gap-3 p-4 text-left hover:bg-secondary/50 transition min-w-0">
                          <div className="w-8 h-8 rounded-lg flex items-center justify-center shrink-0" style={{ background: `${cat.color}15`, color: cat.color }}>
                            <Icon name={cat.icon} className="w-4 h-4" />
                          </div>
                          <div className="flex-1 min-w-0">
                            <div className="flex items-center gap-2 mb-1 flex-wrap">
                              <span className="text-[10px] uppercase tracking-wide font-semibold" style={{ color: cat.color }}>{cat.label}</span>
                              <span className="text-[10px] px-1.5 py-0.5 rounded-full font-semibold" style={{ background: `${DIFFICULTY_COLORS[q.difficulty]}20`, color: DIFFICULTY_COLORS[q.difficulty] }}>{q.difficulty}</span>
                              {isCompleted && <span className="text-[10px] text-emerald-600 font-medium">✓ completed</span>}
                            </div>
                            <div className={`font-semibold text-sm text-pretty ${isCompleted ? "line-through opacity-60" : ""}`}>{i + 1}. {q.question}</div>
                          </div>
                          <Icon name="ChevronDown" className={`w-4 h-4 text-muted-foreground shrink-0 transition-transform ${isOpen ? "rotate-180" : ""}`} />
                        </button>
                      </div>
                      {isOpen && (
                        <motion.div initial={{ height: 0, opacity: 0 }} animate={{ height: "auto", opacity: 1 }} className="overflow-hidden">
                          <div className="p-4 pt-0 space-y-3 text-sm">
                            <div>
                              <div className="text-xs font-semibold uppercase tracking-wide text-muted-foreground mb-1">Recommended Answer</div>
                              <p className="text-foreground/90 text-pretty">{q.recommendedAnswer}</p>
                            </div>
                            {q.talkingPoints?.length > 0 && (
                              <div>
                                <div className="text-xs font-semibold uppercase tracking-wide text-muted-foreground mb-1">Talking Points</div>
                                <ul className="space-y-0.5">{q.talkingPoints.map((t, j) => <li key={j} className="flex gap-2"><span className="text-brand">›</span> <span>{t}</span></li>)}</ul>
                              </div>
                            )}
                            {q.starExample && (
                              <div>
                                <div className="text-xs font-semibold uppercase tracking-wide text-muted-foreground mb-1">STAR Example</div>
                                <div className="rounded-lg bg-secondary p-3 space-y-1 text-xs">
                                  <div><span className="font-semibold text-brand">Situation:</span> {q.starExample.situation}</div>
                                  <div><span className="font-semibold text-brand">Task:</span> {q.starExample.task}</div>
                                  <div><span className="font-semibold text-brand">Action:</span> {q.starExample.action}</div>
                                  <div><span className="font-semibold text-brand">Result:</span> {q.starExample.result}</div>
                                </div>
                              </div>
                            )}
                            {q.followUps?.length > 0 && (
                              <div>
                                <div className="text-xs font-semibold uppercase tracking-wide text-muted-foreground mb-1">Follow-Up Questions</div>
                                <ul className="space-y-0.5">{q.followUps.map((f, j) => <li key={j} className="flex gap-2 text-xs"><span className="text-gold">?</span> <span>{f}</span></li>)}</ul>
                              </div>
                            )}
                          </div>
                        </motion.div>
                      )}
                    </div>
                  );
                })}
              </div>
            </CardContent>
          </Card>
        );
      })}
    </div>
  );
}

src/components/app/modules/JDScraper.tsx:
"use client";

import { useState } from "react";
import { motion } from "framer-motion";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Badge, Icon } from "@/components/shared";
import { useApp, uid } from "@/lib/store";
import { callAI, extractJSON } from "@/lib/ai";
import { processAIResponse } from "@/lib/ai-response-processor";
import { toast } from "sonner";
import type { JobDescription } from "@/lib/types";

const SAMPLE_URLS = [
  "https://www.linkedin.com/jobs/view/1234567890/",
  "https://www.indeed.com/viewjob?jk=abc123",
  "https://www.glassdoor.com/job-listing/senior-engineer",
];

export function JDScraper() {
  const jds = useApp((s) => s.jobDescriptions);
  const addJD = useApp((s) => s.addJD);
  const removeJD = useApp((s) => s.removeJD);
  const setActiveJD = useApp((s) => s.setActiveJD);
  const setView = useApp((s) => s.setView);
  const log = useApp((s) => s.log);

  const [url, setUrl] = useState("");
  const [rawText, setRawText] = useState("");
  const [scraping, setScraping] = useState(false);
  const [extracting, setExtracting] = useState(false);
  const [logLines, setLogLines] = useState<string[]>([]);

  const scrapeUrl = async () => {
    if (!url || !/^https?:\/\//.test(url)) {
      toast.error("Please enter a valid URL (including https://).");
      return;
    }
    setScraping(true);
    setLogLines([`Fetching ${url}…`]);
    // Abort the request after 20s so the spinner never spins forever.
    const controller = new AbortController();
    const timeout = setTimeout(() => controller.abort(), 20000);
    try {
      const res = await fetch("/api/jd-scrape", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ url }),
        signal: controller.signal,
      });

      // Safely parse JSON — handle empty/non-JSON responses
      const text = await res.text();
      let data: any;
      try {
        data = JSON.parse(text);
      } catch {
        throw new Error(`Server returned a non-JSON response (${res.status} ${res.statusText}). The site may be blocking our scraper.`);
      }

      if (!res.ok) throw new Error(data.error || `Fetch failed (${res.status})`);

      if (!data.text || data.text.trim().length < 30) {
        throw new Error("The page was fetched but no readable text was found. The site may use JavaScript rendering. Please paste the JD text manually.");
      }

      setLogLines((l) => [...l, `Retrieved ${data.text.length} chars.`, "Page text ready for AI extraction."]);
      setRawText(data.text);
      toast.success(`Scraped ${data.title || url}`);
    } catch (e: any) {
      const msg = e?.name === "AbortError"
        ? "The scrape request timed out after 20 seconds. The site may be slow or blocking our request — please paste the JD text manually below."
        : (e?.message || "Unknown error");
      setLogLines((l) => [...l, `⚠ ${msg}`, "Falling back: paste the JD text manually below."]);
      toast.error(msg.includes("paste") ? msg : "Couldn't fetch the URL. Please paste the JD text manually below — same AI extraction.");
    } finally {
      clearTimeout(timeout);
      setScraping(false);
    }
  };

  const extract = async () => {
    if (rawText.trim().length < 30) {
      toast.error("Please paste at least 30 characters of job description text.");
      return;
    }
    setExtracting(true);
    setLogLines((l) => [...l, "Calling AI to extract structure…"]);
    try {
      const result = await callAI({
        systemPrompt: "You are a job description parser. Extract structured data. Return ONLY valid JSON.",
        userPrompt: `Extract from this job description:\n\n${rawText}\n\nReturn JSON with keys: title, company, location, employmentType, salary, responsibilities (array of strings), requiredSkills (array), preferredSkills (array), technologies (array), experienceYears, education, keywords (array of 8-15 most important).`,
        maxTokens: 2000,
        taskCategory: "document",
      });

      // === DIAGNOSTICS ===
      console.group("Job URL Parsing");
      console.log("Provider:", result.provider);
      console.log("Raw Text Length:", rawText.length);
      console.log("AI Response Length:", result.text?.length ?? 0);
      console.log("AI Response Preview:", result.text?.slice(0, 200) ?? "(empty)");
      console.groupEnd();

      // Process through the AI Response Processing Layer — this catches
      // errors, repairs JSON, strips leaks, and validates safety
      const processed = processAIResponse<any>(result.text, result.provider, { expectJson: true });

      // === MORE DIAGNOSTICS ===
      console.log("Parsed JD:", processed.data);
      console.log("JD Description Length:", processed.data?.description?.length ?? "N/A");
      console.log("Keywords Extracted:", processed.data?.keywords?.length ?? 0);

      if (!processed.data) {
        // JSON parsing failed even after repair — use heuristic fallback
        setLogLines((l) => [...l, "⚠ AI did not return valid JSON — using heuristic fallback extraction."]);
        const words = rawText.toLowerCase().match(/\b[a-z][a-z0-9+#.]+\b/g) ?? [];
        const freq: Record<string, number> = {};
        for (const w of words) if (w.length > 2) freq[w] = (freq[w] || 0) + 1;
        const keywords = Object.entries(freq).sort((a, b) => b[1] - a[1]).slice(0, 12).map(([k]) => k);
        const jd: JobDescription = {
          id: uid("jd"),
          title: "Parsed role",
          keywords,
          responsibilities: [],
          requiredSkills: [],
          preferredSkills: [],
          technologies: [],
          rawText,
          source: url ? "url" : "text",
          url: url || undefined,
          createdAt: new Date().toISOString(),
        };
        addJD(jd);
        toast.success(`Extracted ${keywords.length} keywords (heuristic fallback).`);
        setExtracting(false);
        return;
      }

      const data = processed.data;
      // === NORMALIZE: flatten any object values to strings ===
      const flattenLoc = (v: any): string | undefined => {
        if (!v) return undefined;
        if (typeof v === "string") return v;
        if (typeof v === "object") {
          const parts = [v.city, v.state, v.region, v.country, v.address].filter((x: any) => x && typeof x === "string");
          if (parts.length > 0) return parts.join(", ");
          return Object.values(v).filter(Boolean).join(", ");
        }
        return String(v);
      };
      const flattenStr = (v: any): string | undefined => {
        if (v === null || v === undefined) return undefined;
        if (typeof v === "string") return v;
        if (typeof v === "number" || typeof v === "boolean") return String(v);
        if (typeof v === "object") return JSON.stringify(v);
        return String(v);
      };
      const flattenArray = (v: any): string[] => {
        if (!Array.isArray(v)) return [];
        return v.map((x: any) => typeof x === "string" ? x : (typeof x === "object" ? JSON.stringify(x) : String(x))).filter(Boolean);
      };
      const jd: JobDescription = {
        id: uid("jd"),
        title: flattenStr(data.title) || "Untitled role",
        company: flattenStr(data.company),
        location: flattenLoc(data.location),
        employmentType: flattenStr(data.employmentType),
        salary: flattenStr(data.salary),
        responsibilities: flattenArray(data.responsibilities),
        requiredSkills: flattenArray(data.requiredSkills),
        preferredSkills: flattenArray(data.preferredSkills),
        technologies: flattenArray(data.technologies),
        experienceYears: flattenStr(data.experienceYears),
        education: flattenStr(data.education),
        keywords: flattenArray(data.keywords),
        rawText,
        source: url ? "url" : "text",
        url: url || undefined,
        createdAt: new Date().toISOString(),
      };
      addJD(jd);
      log({ actor: "you", action: "JD scraped & extracted", category: "ai", details: `${jd.title} at ${jd.company ?? "—"}`, severity: "info" });
      setLogLines((l) => [...l, `✓ Extracted ${jd.keywords.length} keywords, ${jd.requiredSkills.length} required skills.`, `Saved to library via ${result.provider}.`]);
      toast.success(`Extracted: ${jd.title}`);
      setUrl("");
      setRawText("");
    } catch (e: any) {
      setLogLines((l) => [...l, `⚠ ${e?.message}`, "Falling back to heuristic extraction."]);
      // Heuristic fallback
      const words = rawText.toLowerCase().match(/\b[a-z][a-z0-9+#.]+\b/g) ?? [];
      const freq: Record<string, number> = {};
      for (const w of words) if (w.length > 2) freq[w] = (freq[w] || 0) + 1;
      const keywords = Object.entries(freq).sort((a, b) => b[1] - a[1]).slice(0, 12).map(([k]) => k);
      const jd: JobDescription = {
        id: uid("jd"),
        title: "Parsed role",
        keywords,
        responsibilities: [],
        requiredSkills: [],
        preferredSkills: [],
        technologies: [],
        rawText,
        source: url ? "url" : "text",
        url: url || undefined,
        createdAt: new Date().toISOString(),
      };
      addJD(jd);
      toast.success(`Extracted ${keywords.length} keywords (heuristic).`);
    } finally {
      setExtracting(false);
    }
  };

  return (
    <div className="space-y-6">
      <div>
        <h1 className="font-display text-2xl font-bold flex items-center gap-2"><Icon name="Search" className="w-6 h-6 text-brand" /> Job Description Scraper</h1>
        <p className="text-sm text-muted-foreground mt-1">Drop in any URL — LinkedIn, Indeed, Glassdoor, or a company careers page. We'll fetch, parse, and extract structured data.</p>
      </div>

      <div className="grid lg:grid-cols-2 gap-4">
        {/* URL scrape */}
        <Card>
          <CardHeader>
            <CardTitle className="text-lg flex items-center gap-2"><Icon name="Link" className="w-4 h-4 text-brand" /> From a URL</CardTitle>
            <CardDescription>Works with LinkedIn, Indeed, Glassdoor, or any public job posting.</CardDescription>
          </CardHeader>
          <CardContent className="space-y-3">
            <div className="flex gap-2">
              <Input value={url} onChange={(e) => setUrl(e.target.value)} placeholder="https://..." className="flex-1" onKeyDown={(e) => e.key === "Enter" && scrapeUrl()} />
              <Button onClick={scrapeUrl} disabled={scraping} className="bg-brand hover:bg-brand-dark text-white gap-2">
                {scraping ? <Icon name="Loader2" className="w-4 h-4 animate-spin" /> : <Icon name="Download" className="w-4 h-4" />} Scrape
              </Button>
            </div>
            <div className="flex flex-wrap gap-1.5">
              {SAMPLE_URLS.map((u) => (
                <button key={u} onClick={() => setUrl(u)} className="text-[10px] px-2 py-1 rounded-md bg-secondary hover:bg-secondary/70 text-muted-foreground truncate max-w-[180px]">
                  {u}
                </button>
              ))}
            </div>
            <p className="text-xs text-muted-foreground">Note: some sites block server-side scraping. If that happens, paste the text instead — same AI extraction.</p>
          </CardContent>
        </Card>

        {/* Text paste */}
        <Card>
          <CardHeader>
            <CardTitle className="text-lg flex items-center gap-2"><Icon name="ClipboardPaste" className="w-4 h-4 text-brand" /> From pasted text</CardTitle>
            <CardDescription>Copy-paste the JD and let the AI extract the structure.</CardDescription>
          </CardHeader>
          <CardContent className="space-y-3">
            <Textarea
              value={rawText}
              onChange={(e) => setRawText(e.target.value)}
              rows={6}
              placeholder="Paste the full job description here…"
            />
            <Button onClick={extract} disabled={extracting || rawText.length < 30} className="w-full bg-brand hover:bg-brand-dark text-white gap-2">
              {extracting ? <Icon name="Loader2" className="w-4 h-4 animate-spin" /> : <Icon name="Sparkles" className="w-4 h-4" />}
              {extracting ? "Extracting…" : "Extract with AI"}
            </Button>
          </CardContent>
        </Card>
      </div>

      {/* Log */}
      {logLines.length > 0 && (
        <Card>
          <CardContent className="p-4">
            <div className="text-xs font-mono space-y-1 max-h-40 overflow-y-auto">
              {logLines.map((l, i) => (
                <div key={i} className="flex items-center gap-2">
                  <span className="text-brand">›</span> <span className={l.startsWith("⚠") ? "text-amber-600" : l.startsWith("✓") ? "text-emerald-600" : ""}>{l}</span>
                </div>
              ))}
            </div>
          </CardContent>
        </Card>
      )}

      {/* Saved JDs */}
      <Card>
        <CardHeader>
          <div className="flex items-center justify-between">
            <div>
              <CardTitle className="text-lg flex items-center gap-2"><Icon name="Library" className="w-4 h-4 text-brand" /> Saved job descriptions ({jds.length})</CardTitle>
              <CardDescription>Click any to use in the ATS checker or optimizer.</CardDescription>
            </div>
          </div>
        </CardHeader>
        <CardContent>
          <div className="grid sm:grid-cols-2 gap-3">
            {jds.map((j) => (
              <motion.div key={j.id} initial={{ opacity: 0, y: 8 }} animate={{ opacity: 1, y: 0 }} className="rounded-xl border border-border p-4 hover:shadow-premium transition">
                <div className="flex items-start justify-between mb-2">
                  <div className="min-w-0">
                    <div className="font-semibold text-sm truncate">{j.title}</div>
                    {j.company && <div className="text-xs text-muted-foreground">{j.company}{j.location ? ` · ${j.location}` : ""}</div>}
                  </div>
                  <Badge variant="outline" className="text-[10px] capitalize shrink-0 ml-2">{j.source}</Badge>
                </div>
                <div className="flex flex-wrap gap-1 mb-3">
                  {j.keywords.slice(0, 6).map((k) => <Badge key={k} variant="brand" className="text-[10px]">{k}</Badge>)}
                  {j.keywords.length > 6 && <Badge variant="outline" className="text-[10px]">+{j.keywords.length - 6}</Badge>}
                </div>
                <div className="flex gap-1.5">
                  <Button size="sm" variant="outline" className="flex-1" onClick={() => { setActiveJD(j.id); setView("ats-checker"); }}>
                    <Icon name="ScanText" className="w-3.5 h-3.5 mr-1" /> ATS check
                  </Button>
                  <Button size="sm" variant="outline" className="flex-1" onClick={() => { setActiveJD(j.id); setView("optimizer"); }}>
                    <Icon name="Wand2" className="w-3.5 h-3.5 mr-1" /> Optimize
                  </Button>
                  <Button size="sm" variant="ghost" className="text-destructive" onClick={() => { removeJD(j.id); toast.success("Deleted."); }}>
                    <Icon name="Trash2" className="w-3.5 h-3.5" />
                  </Button>
                </div>
              </motion.div>
            ))}
            {jds.length === 0 && (
              <div className="col-span-full text-center py-8">
                <Icon name="Library" className="w-10 h-10 text-muted-foreground/40 mx-auto" />
                <p className="text-sm text-muted-foreground mt-2">No saved JDs yet. Scrape or paste one above.</p>
              </div>
            )}
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

