import { useState } from "react";
import { Card, CardHeader, CardTitle, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Switch } from "@/components/ui/switch";
import { Label } from "@/components/ui/label";
import { Icon } from "@/components/shared";
import { toast } from "sonner";
import { getPuterProvider } from "@/lib/providers/puter-provider";

export function PuterAuthCard({ status, onRefreshStatus }: { status: any, onRefreshStatus: () => void }) {
  const [loading, setLoading] = useState(false);
  const puter = getPuterProvider();
  
  const handleAddAccount = async () => {
    setLoading(true);
    try {
      await puter.login();
      toast.success("Account added successfully.");
      onRefreshStatus();
    } catch (e: any) {
      toast.error(e.message || "Failed to add account");
    } finally {
      setLoading(false);
    }
  };

  const handleSwitch = async (id: string) => {
    setLoading(true);
    try {
      await puter.setActiveAccount(id);
      toast.success("Account switched.");
      onRefreshStatus();
    } catch (e: any) {
      toast.error(e.message || "Failed to switch account");
    } finally {
      setLoading(false);
    }
  };

  const handleRemove = async (id: string) => {
    setLoading(true);
    try {
      await puter.removeAccount(id);
      toast.success("Account removed.");
      onRefreshStatus();
    } catch (e: any) {
      toast.error(e.message || "Failed to remove account");
    } finally {
      setLoading(false);
    }
  };

  const handleRefreshTokens = async () => {
    setLoading(true);
    try {
      await puter.refresh();
      toast.success("Sessions refreshed.");
      onRefreshStatus();
    } catch (e: any) {
      toast.error(e.message || "Failed to refresh");
    } finally {
      setLoading(false);
    }
  };

  const accounts = status.accounts || [];

  return (
    <Card className="border-amber-500/20 overflow-hidden flex flex-col h-full bg-card shadow-sm hover:shadow-md transition-shadow">
      <CardHeader className="bg-amber-500/5 pb-4 border-b border-amber-500/10">
        <CardTitle className="text-base flex justify-between items-center">
          <div className="flex items-center gap-2">
            <div className="w-8 h-8 rounded-lg flex items-center justify-center bg-amber-500/20 text-amber-600 dark:text-amber-500">
              <Icon name="Sparkles" className="w-4 h-4" />
            </div>
            <div>
              <span>Puter.js</span>
              <p className="text-xs font-normal text-muted-foreground mt-0.5">Free browser-auth with Google OAuth</p>
            </div>
          </div>
          <div className="flex gap-2">
            <Button size="sm" variant="outline" onClick={handleRefreshTokens} disabled={loading} title="Refresh">
              <Icon name="RefreshCw" className="w-3.5 h-3.5" />
            </Button>
            <Button size="sm" onClick={handleAddAccount} disabled={loading} className="bg-amber-600 hover:bg-amber-700 text-white gap-1.5">
              {loading ? <Icon name="Loader2" className="w-3.5 h-3.5 animate-spin" /> : <Icon name="Plus" className="w-3.5 h-3.5" />}
              Add Account
            </Button>
          </div>
        </CardTitle>
      </CardHeader>
      <CardContent className="p-0 flex-1 flex flex-col">
        <div className="p-4 space-y-4">
          <div className="text-sm font-medium text-foreground border-b border-border pb-2">Connected Accounts</div>
          
          {accounts.length === 0 ? (
             <div className="text-sm text-muted-foreground text-center py-4">No accounts connected.</div>
          ) : (
            <div className="space-y-3">
              {accounts.map((acc: any) => (
                <div key={acc.id} className={`p-3 rounded-lg border ${acc.active ? 'border-amber-500 bg-amber-50 dark:bg-amber-500/10' : 'border-border bg-secondary/30'} flex flex-col gap-2`}>
                   <div className="flex items-center justify-between">
                      <div className="flex items-center gap-2">
                        <div className={`w-2 h-2 rounded-full ${acc.status === 'healthy' ? 'bg-emerald-500' : acc.status === 'rate_limited' ? 'bg-amber-500' : 'bg-red-500'}`} />
                        <span className="font-medium text-sm">{acc.email}</span>
                        {acc.active && <span className="text-[10px] uppercase font-bold tracking-wider px-1.5 py-0.5 rounded bg-amber-500/20 text-amber-700 dark:text-amber-400">Active</span>}
                      </div>
                      <div className="flex gap-1.5">
                        {!acc.active && (
                          <Button size="sm" variant="outline" className="h-7 text-xs px-2" onClick={() => handleSwitch(acc.id)} disabled={loading}>Switch</Button>
                        )}
                        <Button size="sm" variant="ghost" className="h-7 text-xs px-2 text-red-600 hover:text-red-700 hover:bg-red-50" onClick={() => handleRemove(acc.id)} disabled={loading}>Remove</Button>
                      </div>
                   </div>
                   <div className="text-xs text-muted-foreground grid grid-cols-2 gap-1">
                      <div>Models: claude-sonnet-4-5, gpt-4o, gemini-2.5-flash</div>
                      <div>Status: {acc.status === "healthy" ? "Healthy" : acc.status === "rate_limited" ? "Rate Limited" : "Expired"}</div>
                   </div>
                </div>
              ))}
            </div>
          )}
        </div>
        
        {accounts.length > 0 && (
          <div className="mt-auto border-t border-border bg-secondary/20 p-4 space-y-3">
            <div className="flex items-center justify-between">
              <div className="space-y-0.5">
                <Label className="text-sm font-medium">Auto-rotate accounts</Label>
                <p className="text-xs text-muted-foreground">Switch to next healthy account when limits reached</p>
              </div>
              <Switch checked={status.autoRotate} onCheckedChange={async (v) => { await puter.setAutoRotate(v); onRefreshStatus(); }} disabled={loading} />
            </div>
            <div className="flex items-center justify-between">
              <div className="space-y-0.5">
                <Label className="text-sm font-medium">Use selected account globally</Label>
                <p className="text-xs text-muted-foreground">Force this account for all generation tasks</p>
              </div>
              <Switch checked={status.useGlobally} onCheckedChange={async (v) => { await puter.setUseGlobally(v); onRefreshStatus(); }} disabled={loading} />
            </div>
          </div>
        )}
      </CardContent>
    </Card>
  );
}

src/components/app/modules/ResumeReviewP:
"use client";

/**
 * ResumeReviewPlatform — Advanced AI Resume Review Platform
 *
 * EVOLUTIONARY UPGRADE of the legacy AiResumeReview component.
 * The legacy component (in CareerTools.tsx) is preserved untouched; this new
 * platform is wired in via AppShell.tsx so the same nav entry ("AI Resume
 * Review") now opens the full 10-module experience.
 *
 * Modules:
 *   1. ATS Review — score, keyword match, parsing risks, pass probability
 *   2. Recruiter Review — per-section strengths/weaknesses/recommendations
 *   3. Job Match Review — match % across 5 axes + missing skills/keywords/certs
 *   4. Industry Benchmark — readiness score vs. industry averages
 *   5. Resume Improvements — better summary/headlines/skills/bullets
 *   6. Priority Action Plan — critical/high/optional fixes + expected ATS gain
 *   7. One-Click Fixes — Fix Summary, Fix Skills, Fix Experience, etc.
 *   8. Interview Readiness — likely questions, weak areas, talking points
 *   9. Visual Dashboard — radar chart, progress bars, heat-map style
 *  10. Persistence — localStorage backup + store; survives refresh/logout/login
 *
 * Exports: JSON / PDF (print) / DOCX (via clipboard-friendly text).
 *
 * All AI generation is LIVE — no demo data, no hardcoded scores, no
 * placeholders. Every recommendation is dynamically generated from the
 * resume content, optimized resume (if any), job description (if any),
 * company information (if any), and industry profile (auto-detected).
 */

import { useEffect, useMemo, useRef, useState } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Badge, Icon } from "@/components/shared";
import { useApp, uid } from "@/lib/store";
import { callAI, extractJSON } from "@/lib/ai";
import { detectIndustry, INDUSTRY_PROFILES } from "@/lib/industry-ats";
import { toast } from "sonner";
import type { ResumeData, ResumeReviewReport, JobDescription } from "@/lib/types";

// ============================================================================
// Helpers
// ============================================================================

const scoreColor = (s: number, inverted = false) => {
  // inverted=true means LOWER is better (e.g. missing keywords count)
  if (inverted) return s === 0 ? "#10B981" : s <= 3 ? "#F59E0B" : "#DC2626";
  if (s >= 80) return "#10B981";
  if (s >= 60) return "#1154A3";
  if (s >= 40) return "#F59E0B";
  return "#DC2626";
};

const scoreLabel = (s: number) => {
  if (s >= 85) return "Excellent";
  if (s >= 70) return "Good";
  if (s >= 50) return "Needs Work";
  return "Critical";
};

/** Build a compact JSON snapshot of a resume for the AI prompt. */
function resumeSnapshot(r: ResumeData | undefined | null): string {
  if (!r) return "(no resume)";
  return JSON.stringify({
    name: r.name,
    headline: r.headline,
    summary: r.summary,
    contact: r.contact,
    experience: r.experience.map((e) => ({
      title: e.title, company: e.company, location: e.location,
      startDate: e.startDate, endDate: e.endDate,
      bullets: e.bullets,
    })),
    education: r.education.map((e) => ({
      institution: e.institution, degree: e.degree, field: e.field,
    })),
    skills: r.skills.map((s) => s.name),
    projects: r.projects,
    certifications: r.certifications,
    languages: r.languages,
    achievements: r.achievements,
  });
}

/** Build a compact JD snapshot. */
function jdSnapshot(jd: JobDescription | undefined | null): string {
  if (!jd) return "(no job description)";
  return JSON.stringify({
    title: jd.title,
    company: jd.company,
    location: jd.location,
    responsibilities: jd.responsibilities,
    requiredSkills: jd.requiredSkills,
    preferredSkills: jd.preferredSkills,
    technologies: jd.technologies,
    experienceYears: jd.experienceYears,
    education: jd.education,
    keywords: jd.keywords,
    rawText: jd.rawText?.slice(0, 2500),
  });
}

// ============================================================================
// Main component
// ============================================================================

type ModuleTab =
  | "dashboard"
  | "ats"
  | "recruiter"
  | "job-match"
  | "benchmark"
  | "improvements"
  | "action-plan"
  | "fixes"
  | "interview"
  | "history";

export function ResumeReviewPlatform() {
  const resumes = useApp((s) => s.resumes);
  const jds = useApp((s) => s.jobDescriptions);
  const reviewReports = useApp((s) => s.reviewReports);
  const addReviewReport = useApp((s) => s.addReviewReport);
  const removeReviewReport = useApp((s) => s.removeReviewReport);
  const updateResume = useApp((s) => s.updateResume);
  const addResume = useApp((s) => s.addResume);
  const setActiveResume = useApp((s) => s.setActiveResume);
  const setActiveJD = useApp((s) => s.setActiveJD);
  const setView = useApp((s) => s.setView);
  const user = useApp((s) => s.user);
  const log = useApp((s) => s.log);
  const incUsage = useApp((s) => s.incUsage);

  // === Multi-source input state ===
  // Auto-detect the most recent resume and JD as defaults.
  const [resumeId, setResumeId] = useState("");
  const [optimizedResumeId, setOptimizedResumeId] = useState("");
  const [jdId, setJdId] = useState("");
  const [companyName, setCompanyName] = useState("");

  // Auto-select defaults on mount / when resumes arrive
  useEffect(() => {
    if (!resumeId && resumes.length > 0) {
      // Pick the most recently updated resume that's NOT marked as optimized
      const original = resumes.find((r) => r.source !== "ai-optimized") ?? resumes[0];
      setResumeId(original.id);
    }
    if (!jdId && jds.length > 0) setJdId(jds[0].id);
  }, [resumes, jds, resumeId, jdId]);

  const resume = useMemo(() => resumes.find((r) => r.id === resumeId) ?? null, [resumes, resumeId]);
  const optimizedResume = useMemo(() => resumes.find((r) => r.id === optimizedResumeId) ?? null, [resumes, optimizedResumeId]);
  const jd = useMemo(() => jds.find((j) => j.id === jdId) ?? null, [jds, jdId]);

  // Auto-detect industry from JD + resume
  const industryDetection = useMemo(() => {
    if (!resume) return null;
    const jdText = jd?.rawText || jd?.keywords?.join(" ") || "";
    const resumeText = `${resume.name} ${resume.headline ?? ""} ${resume.summary ?? ""} ${resume.experience.map((e) => e.title + " " + e.company).join(" ")}`;
    return detectIndustry(jdText, resumeText);
  }, [resume, jd]);
  const industryProfile = industryDetection ? INDUSTRY_PROFILES[industryDetection.industryId] : null;

  // Auto-populate company name from JD
  useEffect(() => {
    if (jd?.company && !companyName) setCompanyName(jd.company);
  }, [jd, companyName]);

  const [loading, setLoading] = useState(false);
  const [activeTab, setActiveTab] = useState<ModuleTab>("dashboard");
  const [report, setReport] = useState<ResumeReviewReport | null>(null);
  const [fixLoading, setFixLoading] = useState<string | null>(null);

  // ============================================================================
  // MAIN REVIEW — calls AI once with a comprehensive prompt that returns the
  // full multi-module JSON. This avoids 10 separate round-trips and keeps
  // the experience fast even on slow providers.
  // ============================================================================
  const runReview = async () => {
    if (!resume) { toast.error("Select a resume to review."); return; }
    setLoading(true);
    setReport(null);
    setActiveTab("dashboard");
    try {
      const industryLabel = industryProfile?.label ?? "Generic";
      // keywordBank is a single string of comma/newline-separated keywords — split it.
      const industryKeywordsRaw = industryProfile?.keywordBank ?? "";
      const industryKeywords = industryKeywordsRaw
        .split(/[\n,]/)
        .map((k) => k.trim())
        .filter((k) => k.length > 0)
        .slice(0, 60);

      const systemPrompt = `You are an elite Resume Review Platform combining the expertise of a Senior Recruiter, ATS Engineer, Industry Benchmark Analyst, and Career Coach. You analyze resumes holistically and produce a comprehensive multi-module review. NEVER fabricate information — only reference real content from the resume. Return ONLY valid JSON matching the requested schema. No prose, no markdown fences.`;

      const userPrompt = `# RESUME REVIEW REQUEST

## Context
- Industry: ${industryLabel}
- Industry Keywords: ${industryKeywords.join(", ")}
- Company: ${companyName || "(not specified)"}
- Has Optimized Resume: ${optimizedResume ? "yes" : "no"}
- Has Job Description: ${jd ? "yes" : "no"}

## ORIGINAL RESUME
${resumeSnapshot(resume)}

${optimizedResume ? `## OPTIMIZED RESUME (also review this)\n${resumeSnapshot(optimizedResume)}` : ""}

${jd ? `## JOB DESCRIPTION\n${jdSnapshot(jd)}` : ""}

## TASK
Generate a comprehensive review covering all 10 modules. Return JSON with EXACTLY this shape:

{
  "ats": {
    "atsScore": <0-100>,
    "keywordMatch": <0-100>,
    "missingKeywords": ["..."],
    "formattingIssues": ["..."],
    "sectionDetection": [{"section":"Contact","detected":true,"confidence":95}, ...],
    "parsingRisks": ["..."],
    "graphicsRisks": ["..."],
    "tablesRisks": ["..."],
    "fileCompatibility": ["PDF: ✓", "DOCX: ✓", "ATS-friendly: ✓"],
    "passProbability": <0-100>,
    "recommendations": ["..."]
  },
  "recruiter": {
    "overallScore": <0-10>,
    "sections": [
      {"section":"Headline","score":<0-10>,"strengths":["..."],"weaknesses":["..."],"recommendations":["..."]},
      {"section":"Summary","score":<0-10>,"strengths":["..."],"weaknesses":["..."],"recommendations":["..."]},
      {"section":"Experience","score":<0-10>,"strengths":["..."],"weaknesses":["..."],"recommendations":["..."]},
      {"section":"Skills","score":<0-10>,"strengths":["..."],"weaknesses":["..."],"recommendations":["..."]},
      {"section":"Education","score":<0-10>,"strengths":["..."],"weaknesses":["..."],"recommendations":["..."]},
      {"section":"Projects","score":<0-10>,"strengths":["..."],"weaknesses":["..."],"recommendations":["..."]},
      {"section":"Certifications","score":<0-10>,"strengths":["..."],"weaknesses":["..."],"recommendations":["..."]},
      {"section":"Achievements","score":<0-10>,"strengths":["..."],"weaknesses":["..."],"recommendations":["..."]},
      {"section":"Languages","score":<0-10>,"strengths":["..."],"weaknesses":["..."],"recommendations":["..."]}
    ]
  },
  "jobMatch": ${jd ? `{
    "overallMatch": <0-100>,
    "atsMatch": <0-100>,
    "experienceMatch": <0-100>,
    "skillMatch": <0-100>,
    "educationMatch": <0-100>,
    "industryMatch": <0-100>,
    "missingSkills": ["..."],
    "missingKeywords": ["..."],
    "missingCertifications": ["..."]
  }` : `null`},
  "benchmark": {
    "industry": "${industryLabel}",
    "role": "<detected role>",
    "seniority": "<Entry|Mid|Senior|Lead|Executive>",
    "country": "<detected or 'Global'>",
    "industryReadinessScore": <0-100>,
    "benchmarkComparisons": [
      {"metric":"Years of Experience","candidate":<n>,"industryAverage":<n>,"topPercentile":<n>},
      {"metric":"Skills Count","candidate":<n>,"industryAverage":<n>,"topPercentile":<n>},
      {"metric":"Quantified Bullets %","candidate":<n>,"industryAverage":<n>,"topPercentile":<n>}
    ],
    "insights": ["..."]
  },
  "improvements": {
    "betterSummary": "<a stronger 2-3 sentence summary>",
    "betterHeadlines": ["<alt headline 1>","<alt headline 2>","<alt headline 3>"],
    "betterSkills": ["<skill to add 1>","<skill to add 2>"],
    "betterBulletPoints": [{"original":"<weak bullet>","improved":"<strong bullet with metric>"}],
    "betterAchievements": ["..."],
    "actionVerbs": ["Led","Built","Shipped","..."],
    "metrics": ["<suggested metric to add>"],
    "highValueKeywords": ["..."]
  },
  "actionPlan": {
    "criticalFixes": [{"fix":"...","impact":"..."}],
    "highPriorityFixes": [{"fix":"...","impact":"..."}],
    "optionalImprovements": [{"fix":"...","impact":"..."}],
    "expectedAtsIncrease": <number of ATS points>
  },
  "interviewReadiness": {
    "likelyQuestions": ["..."],
    "weakAreas": ["..."],
    "talkingPoints": ["..."],
    "preparationAdvice": ["..."]
  }
}

Rules:
- All scores must be REALISTIC and derived from the actual resume content. NEVER use placeholder scores.
- Section scores should reflect actual content quality (empty sections get 0, not 5).
- Missing keywords must come from the JD or industry keyword bank.
- Bullet improvements must rewrite ACTUAL bullets from the resume, not invent new ones.
- Be honest — a weak resume should get low scores, not generic 7/10s.`;

      const result = await callAI({
        systemPrompt,
        userPrompt,
        maxTokens: 4500,
        temperature: 0.3,
        taskCategory: "document",
      });

      let data: any;
      try { data = extractJSON<any>(result.text); }
      catch { throw new Error("AI did not return valid JSON. Please try again."); }

      // Validate minimum shape
      if (!data.ats || !data.recruiter || !data.benchmark || !data.improvements || !data.actionPlan || !data.interviewReadiness) {
        throw new Error("AI response missing required modules. Please try again.");
      }

      // === DEFENSIVE NORMALIZATION ===
      // The AI may return array elements as objects (e.g. {goal, actions, resources})
      // instead of plain strings, which crashes React with error #31
      // ("Objects are not valid as a React child") when we render {item} inside
      // <li>/<Badge>. Coerce every array field to string[] and every scalar to
      // its expected type so the render is always safe.
      const toArray = (v: any): string[] => {
        if (!Array.isArray(v)) {
          if (typeof v === "string" && v.trim()) return v.split(/[,\n]/).map((s) => s.trim()).filter(Boolean);
          return [];
        }
        return v.map((item) => {
          if (item === null || item === undefined) return "";
          if (typeof item === "string") return item;
          if (typeof item === "number" || typeof item === "boolean") return String(item);
          try {
            const vals = Object.values(item as any);
            if (vals.length > 0 && vals.every((x) => typeof x === "string" || typeof x === "number")) {
              return vals.map(String).join(" — ");
            }
            return JSON.stringify(item);
          } catch { return String(item); }
        }).filter((s) => s.length > 0);
      };
      const toStr = (v: any): string => {
        if (v === null || v === undefined) return "";
        if (typeof v === "string") return v;
        if (typeof v === "number" || typeof v === "boolean") return String(v);
        try { return JSON.stringify(v); } catch { return String(v); }
      };
      const toNum = (v: any): number => {
        const n = Number(v);
        return Number.isFinite(n) ? n : 0;
      };
      // Preserve object-shaped array elements (like betterBulletPoints {original, improved}
      // and benchmarkComparisons {metric, candidate, ...}) but only if they're objects.
      const toObjArray = <T,>(v: any): T[] => Array.isArray(v) ? v.filter((x) => x && typeof x === "object") : [];
      // Section detection array — each item is {section, detected, confidence}
      const toSectionArray = (v: any) => {
        if (!Array.isArray(v)) return [];
        return v.map((item) => ({
          section: toStr(item?.section),
          detected: !!item?.detected,
          confidence: toNum(item?.confidence),
        }));
      };
      // Fix items — each is {fix, impact}
      const toFixArray = (v: any) => {
        if (!Array.isArray(v)) return [];
        return v.map((item) => ({
          fix: toStr(item?.fix),
          impact: toStr(item?.impact),
        }));
      };
      // Section feedback — each is {section, score, strengths[], weaknesses[], recommendations[]}
      const toSectionFeedback = (v: any) => {
        if (!Array.isArray(v)) return [];
        return v.map((item) => ({
          section: toStr(item?.section),
          score: toNum(item?.score),
          strengths: toArray(item?.strengths),
          weaknesses: toArray(item?.weaknesses),
          recommendations: toArray(item?.recommendations),
        }));
      };

      // Normalize each module
      const normAts = {
        atsScore: toNum(data.ats.atsScore),
        keywordMatch: toNum(data.ats.keywordMatch),
        missingKeywords: toArray(data.ats.missingKeywords),
        formattingIssues: toArray(data.ats.formattingIssues),
        sectionDetection: toSectionArray(data.ats.sectionDetection),
        parsingRisks: toArray(data.ats.parsingRisks),
        graphicsRisks: toArray(data.ats.graphicsRisks),
        tablesRisks: toArray(data.ats.tablesRisks),
        fileCompatibility: toArray(data.ats.fileCompatibility),
        passProbability: toNum(data.ats.passProbability),
        recommendations: toArray(data.ats.recommendations),
      };
      const normRecruiter = {
        overallScore: toNum(data.recruiter.overallScore),
        sections: toSectionFeedback(data.recruiter.sections),
      };
      const normJobMatch = data.jobMatch ? {
        overallMatch: toNum(data.jobMatch.overallMatch),
        atsMatch: toNum(data.jobMatch.atsMatch),
        experienceMatch: toNum(data.jobMatch.experienceMatch),
        skillMatch: toNum(data.jobMatch.skillMatch),
        educationMatch: toNum(data.jobMatch.educationMatch),
        industryMatch: toNum(data.jobMatch.industryMatch),
        missingSkills: toArray(data.jobMatch.missingSkills),
        missingKeywords: toArray(data.jobMatch.missingKeywords),
        missingCertifications: toArray(data.jobMatch.missingCertifications),
      } : null;
      const normBenchmark = {
        industry: toStr(data.benchmark.industry),
        role: toStr(data.benchmark.role),
        seniority: toStr(data.benchmark.seniority),
        country: toStr(data.benchmark.country),
        industryReadinessScore: toNum(data.benchmark.industryReadinessScore),
        benchmarkComparisons: toObjArray<any>(data.benchmark.benchmarkComparisons).map((b) => ({
          metric: toStr(b.metric),
          candidate: toNum(b.candidate),
          industryAverage: toNum(b.industryAverage),
          topPercentile: toNum(b.topPercentile),
        })),
        insights: toArray(data.benchmark.insights),
      };
      const normImprovements = {
        betterSummary: toStr(data.improvements.betterSummary),
        betterHeadlines: toArray(data.improvements.betterHeadlines),
        betterSkills: toArray(data.improvements.betterSkills),
        betterBulletPoints: toObjArray<any>(data.improvements.betterBulletPoints).map((b) => ({
          original: toStr(b.original),
          improved: toStr(b.improved),
        })),
        betterAchievements: toArray(data.improvements.betterAchievements),
        actionVerbs: toArray(data.improvements.actionVerbs),
        metrics: toArray(data.improvements.metrics),
        highValueKeywords: toArray(data.improvements.highValueKeywords),
      };
      const normActionPlan = {
        criticalFixes: toFixArray(data.actionPlan.criticalFixes),
        highPriorityFixes: toFixArray(data.actionPlan.highPriorityFixes),
        optionalImprovements: toFixArray(data.actionPlan.optionalImprovements),
        expectedAtsIncrease: toNum(data.actionPlan.expectedAtsIncrease),
      };
      const normInterview = {
        likelyQuestions: toArray(data.interviewReadiness.likelyQuestions),
        weakAreas: toArray(data.interviewReadiness.weakAreas),
        talkingPoints: toArray(data.interviewReadiness.talkingPoints),
        preparationAdvice: toArray(data.interviewReadiness.preparationAdvice),
      };

      // Compute dashboard aggregate scores
      const formattingScore = normAts.formattingIssues.length > 0
        ? Math.max(0, 100 - normAts.formattingIssues.length * 8)
        : normAts.atsScore;
      const readabilityScore = Math.round(
        (normRecruiter.sections.find((s) => s.section === "Summary")?.score ?? 5) * 10
      );
      const recruiterScore = normRecruiter.overallScore;

      const newReport: ResumeReviewReport = {
        id: uid("rr"),
        userId: user?.id || "anonymous",
        resumeId: resume.id,
        optimizedResumeId: optimizedResume?.id,
        jdId: jd?.id,
        companyName: companyName || jd?.company || undefined,
        industryProfile: industryProfile?.label ?? "Generic",
        createdAt: new Date().toISOString(),
        updatedAt: new Date().toISOString(),
        ats: normAts,
        recruiter: normRecruiter,
        jobMatch: normJobMatch,
        benchmark: normBenchmark,
        improvements: normImprovements,
        actionPlan: normActionPlan,
        interviewReadiness: normInterview,
        dashboard: {
          atsScore: normAts.atsScore,
          recruiterScore,
          jobMatch: normJobMatch?.overallMatch ?? null,
          formattingScore,
          readabilityScore,
          industryBenchmark: normBenchmark.industryReadinessScore,
        },
      };

      setReport(newReport);
      addReviewReport(newReport);
      incUsage("atsChecks");
      log({
        actor: user?.email || "you",
        action: "AI Resume Review generated",
        category: "ai",
        details: `ATS ${newReport.dashboard.atsScore}/100 · Recruiter ${newReport.dashboard.recruiterScore}/10 · Industry ${newReport.dashboard.industryBenchmark}/100 via ${result.provider}`,
        severity: "info",
      });
      toast.success(`Review complete — ATS ${newReport.dashboard.atsScore}/100 · Recruiter ${newReport.dashboard.recruiterScore}/10`);
    } catch (e: any) {
      toast.error(e?.message || "Review failed. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  // ============================================================================
  // ONE-CLICK FIXES — Module 7
  // Each fix calls AI to rewrite a specific section and applies it to the
  // resume via updateResume() (or creates an optimized copy via addResume()).
  // ============================================================================
  const runOneClickFix = async (fixType: "summary" | "skills" | "experience" | "ats" | "all") => {
    if (!resume) { toast.error("Select a resume first."); return; }
    if (!report) { toast.error("Run a review first to get recommendations."); return; }
    setFixLoading(fixType);
    try {
      const fixPrompts: Record<string, string> = {
        summary: `Rewrite ONLY the summary section of this resume. Use the review's recommendations and the suggested betterSummary. Return JSON: {"summary": "..."}.\n\nRESUME:\n${resumeSnapshot(resume)}\n\nREVIEW SUMMARY RECOMMENDATIONS:\n${JSON.stringify(report.recruiter.sections.find((s) => s.section === "Summary"))}\n\nSUGGESTED BETTER SUMMARY:\n${report.improvements.betterSummary}`,
        skills: `Improve ONLY the skills section. Add the suggested missing skills, remove redundant ones, and reorganize by category. Return JSON: {"skills": [{"name":"...","category":"..."}]}.\n\nRESUME:\n${resumeSnapshot(resume)}\n\nSUGGESTED SKILLS TO ADD:\n${JSON.stringify(report.improvements.betterSkills)}`,
        experience: `Rewrite ONLY the experience bullets to be more impactful. Apply the betterBulletPoints suggestions. Return JSON: {"experience": [{"title":"...","company":"...","location":"...","startDate":"...","endDate":"...","bullets":["..."]}]}.\n\nRESUME:\n${resumeSnapshot(resume)}\n\nBULLET IMPROVEMENTS:\n${JSON.stringify(report.improvements.betterBulletPoints)}`,
        ats: `Optimize this resume for maximum ATS score by embedding the missing keywords naturally and applying all action verbs. NEVER fabricate experience. Return the FULL optimized resume as JSON matching the resume schema.\n\nRESUME:\n${resumeSnapshot(resume)}\n\nMISSING KEYWORDS:\n${JSON.stringify(report.ats.missingKeywords)}\n\nACTION VERBS:\n${JSON.stringify(report.improvements.actionVerbs)}`,
        all: `Fully optimize this resume by applying ALL recommendations from the review: better summary, better headlines, better skills, better bullets, missing keywords. NEVER fabricate experience. Return the FULL optimized resume as JSON matching the resume schema with keys: name, headline, summary, contact, experience, education, skills, projects, certifications, languages, achievements.\n\nRESUME:\n${resumeSnapshot(resume)}\n\nFULL REVIEW:\n${JSON.stringify({ improvements: report.improvements, ats: report.ats, actionPlan: report.actionPlan })}`,
      };

      const result = await callAI({
        systemPrompt: "You are an expert resume optimizer. Apply the requested fixes precisely. Return ONLY valid JSON. NEVER fabricate experience or metrics not present in the original resume.",
        userPrompt: fixPrompts[fixType],
        maxTokens: fixType === "all" || fixType === "ats" ? 3500 : 1500,
        temperature: 0.4,
        taskCategory: "document",
      });

      let data: any;
      try { data = extractJSON<any>(result.text); }
      catch { throw new Error("AI did not return valid JSON for the fix."); }

      if (fixType === "all" || fixType === "ats") {
        // Create an optimized copy as a new resume
        const optimized: ResumeData = {
          ...resume,
          id: uid("r"),
          headline: data.headline || resume.headline,
          summary: data.summary || resume.summary,
          skills: (data.skills ?? resume.skills).map((s: any) => typeof s === "string" ? { id: uid("s"), name: s, category: "Skills" } : { id: uid("s"), ...s }),
          experience: (data.experience ?? resume.experience).map((e: any) => ({
            id: uid("e"), title: e.title || "", company: e.company || "", location: e.location || "",
            startDate: e.startDate || "", endDate: e.endDate || "Present",
            bullets: e.bullets ?? [],
          })),
          template: resume.template,
          accentColor: resume.accentColor,
          createdAt: new Date().toISOString(),
          updatedAt: new Date().toISOString(),
          source: "ai-optimized",
          fileName: `${resume.name.replace(/\s+/g, "_")}_optimized.pdf`,
        };
        addResume(optimized);
        toast.success(`Optimized resume created — "${optimized.name} (Optimized)" added to your library.`);
      } else {
        // Patch the existing resume
        const patch: Partial<ResumeData> = {};
        if (fixType === "summary" && data.summary) patch.summary = data.summary;
        if (fixType === "skills" && data.skills) {
          patch.skills = data.skills.map((s: any) => typeof s === "string" ? { id: uid("s"), name: s, category: "Skills" } : { id: uid("s"), ...s });
        }
        if (fixType === "experience" && data.experience) {
          patch.experience = data.experience.map((e: any) => ({
            id: uid("e"), title: e.title || "", company: e.company || "", location: e.location || "",
            startDate: e.startDate || "", endDate: e.endDate || "Present",
            bullets: e.bullets ?? [],
          }));
        }
        updateResume(resume.id, patch);
        toast.success(`${fixType.charAt(0).toUpperCase() + fixType.slice(1)} updated — review the changes in My Resumes.`);
      }
      log({
        actor: user?.email || "you",
        action: `One-click fix applied: ${fixType}`,
        category: "ai",
        details: `Resume: ${resume.name} via ${result.provider}`,
        severity: "info",
      });
    } catch (e: any) {
      toast.error(e?.message || "Fix failed.");
    } finally {
      setFixLoading(null);
    }
  };

  // ============================================================================
  // OPTIMIZE RESUME CTA — navigate to the Resume Optimizer with the current
  // review's resume + JD pre-selected so the user can immediately run the
  // 5-agent optimization pipeline. The optimizer will pick up the active
  // resume + active JD from the store.
  // ============================================================================
  const goToOptimizer = () => {
    if (!resume) { toast.error("No resume selected."); return; }
    // Set the active resume + JD so the Optimizer picks them up automatically.
    // IMPORTANT: always set BOTH — if no JD is selected, explicitly clear
    // activeJdId so the Optimizer doesn't pick up a stale JD from a previous
    // navigation (which would auto-load the wrong job description).
    setActiveResume(resume.id);
    if (jd) {
      setActiveJD(jd.id);
    } else {
      setActiveJD(null);
    }
    log({
      actor: user?.email || "you",
      action: "Optimize Resume clicked from AI Resume Review",
      category: "ai",
      details: `Resume: ${resume.name}${jd ? ` · JD: ${jd.title}` : ""} · Review ATS: ${report?.dashboard.atsScore ?? "?"}/100`,
      severity: "info",
    });
    toast.success("Opening Resume Optimizer…");
    setView("optimizer");
  };

  // ============================================================================
  // EXPORTS
  // ============================================================================
  const exportJSON = () => {
    if (!report) return;
    const blob = new Blob([JSON.stringify(report, null, 2)], { type: "application/json" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = `resume-review-${resume?.name?.replace(/\s+/g, "_") ?? "report"}-${new Date().toISOString().slice(0, 10)}.json`;
    a.click();
    URL.revokeObjectURL(url);
    toast.success("JSON report exported.");
  };

  const exportPDF = () => {
    if (!report) return;
    // Use the browser's print dialog — user can save as PDF.
    // This is the most reliable cross-browser approach on Cloudflare Free.
    window.print();
    toast.info("Use your browser's print dialog to save as PDF.");
  };

  const exportDOCX = () => {
    if (!report) return;
    // Build a plain-text version that pastes cleanly into Word/Google Docs.
    const lines: string[] = [];
    lines.push("AI RESUME REVIEW REPORT");
    lines.push("========================");
    lines.push(`Generated: ${new Date(report.createdAt).toLocaleString()}`);
    lines.push(`Resume: ${resume?.name ?? "N/A"}`);
    if (optimizedResume) lines.push(`Optimized Resume: ${optimizedResume.name}`);
    if (jd) lines.push(`Job: ${jd.title} at ${jd.company || "N/A"}`);
    lines.push(`Industry: ${report.industryProfile}`);
    lines.push("");
    lines.push("DASHBOARD");
    lines.push("---------");
    lines.push(`ATS Score: ${report.dashboard.atsScore}/100`);
    lines.push(`Recruiter Score: ${report.dashboard.recruiterScore}/10`);
    if (report.dashboard.jobMatch !== null) lines.push(`Job Match: ${report.dashboard.jobMatch}%`);
    lines.push(`Formatting Score: ${report.dashboard.formattingScore}/100`);
    lines.push(`Readability Score: ${report.dashboard.readabilityScore}/100`);
    lines.push(`Industry Benchmark: ${report.dashboard.industryBenchmark}/100`);
    lines.push("");
    lines.push("MODULE 1 — ATS REVIEW");
    lines.push("---------------------");
    lines.push(`ATS Score: ${report.ats.atsScore}/100`);
    lines.push(`Keyword Match: ${report.ats.keywordMatch}/100`);
    lines.push(`Pass Probability: ${report.ats.passProbability}%`);
    lines.push(`Missing Keywords: ${report.ats.missingKeywords.join(", ") || "none"}`);
    lines.push(`Formatting Issues: ${report.ats.formattingIssues.join("; ") || "none"}`);
    lines.push(`Parsing Risks: ${report.ats.parsingRisks.join("; ") || "none"}`);
    lines.push(`Recommendations: ${report.ats.recommendations.join("; ") || "none"}`);
    lines.push("");
    lines.push("MODULE 2 — RECRUITER REVIEW");
    lines.push("---------------------------");
    lines.push(`Overall: ${report.recruiter.overallScore}/10`);
    for (const s of report.recruiter.sections) {
      lines.push(`  ${s.section} (${s.score}/10)`);
      lines.push(`    Strengths: ${s.strengths.join("; ")}`);
      lines.push(`    Weaknesses: ${s.weaknesses.join("; ")}`);
      lines.push(`    Recommendations: ${s.recommendations.join("; ")}`);
    }
    lines.push("");
    if (report.jobMatch) {
      lines.push("MODULE 3 — JOB MATCH REVIEW");
      lines.push("---------------------------");
      lines.push(`Overall Match: ${report.jobMatch.overallMatch}%`);
      lines.push(`ATS Match: ${report.jobMatch.atsMatch}%`);
      lines.push(`Experience Match: ${report.jobMatch.experienceMatch}%`);
      lines.push(`Skill Match: ${report.jobMatch.skillMatch}%`);
      lines.push(`Education Match: ${report.jobMatch.educationMatch}%`);
      lines.push(`Industry Match: ${report.jobMatch.industryMatch}%`);
      lines.push(`Missing Skills: ${report.jobMatch.missingSkills.join(", ") || "none"}`);
      lines.push(`Missing Keywords: ${report.jobMatch.missingKeywords.join(", ") || "none"}`);
      lines.push(`Missing Certifications: ${report.jobMatch.missingCertifications.join(", ") || "none"}`);
      lines.push("");
    }
    lines.push("MODULE 4 — INDUSTRY BENCHMARK");
    lines.push("------------------------------");
    lines.push(`Industry: ${report.benchmark.industry}`);
    lines.push(`Role: ${report.benchmark.role}`);
    lines.push(`Seniority: ${report.benchmark.seniority}`);
    lines.push(`Country: ${report.benchmark.country}`);
    lines.push(`Industry Readiness Score: ${report.benchmark.industryReadinessScore}/100`);
    for (const b of report.benchmark.benchmarkComparisons) {
      lines.push(`  ${b.metric}: candidate=${b.candidate}, industry avg=${b.industryAverage}, top percentile=${b.topPercentile}`);
    }
    lines.push(`Insights: ${report.benchmark.insights.join("; ")}`);
    lines.push("");
    lines.push("MODULE 5 — RESUME IMPROVEMENTS");
    lines.push("------------------------------");
    lines.push(`Better Summary: ${report.improvements.betterSummary}`);
    lines.push(`Better Headlines: ${report.improvements.betterHeadlines.join(" | ")}`);
    lines.push(`Skills to Add: ${report.improvements.betterSkills.join(", ") || "none"}`);
    lines.push(`Better Bullets:`);
    for (const b of report.improvements.betterBulletPoints) {
      lines.push(`  - "${b.original}" → "${b.improved}"`);
    }
    lines.push(`Action Verbs: ${report.improvements.actionVerbs.join(", ")}`);
    lines.push(`Suggested Metrics: ${report.improvements.metrics.join(", ")}`);
    lines.push(`High-Value Keywords: ${report.improvements.highValueKeywords.join(", ")}`);
    lines.push("");
    lines.push("MODULE 6 — PRIORITY ACTION PLAN");
    lines.push("------------------------------");
    lines.push(`Expected ATS Increase: +${report.actionPlan.expectedAtsIncrease} points`);
    lines.push(`Critical Fixes:`);
    for (const f of report.actionPlan.criticalFixes) lines.push(`  - ${f.fix} (impact: ${f.impact})`);
    lines.push(`High Priority Fixes:`);
    for (const f of report.actionPlan.highPriorityFixes) lines.push(`  - ${f.fix} (impact: ${f.impact})`);
    lines.push(`Optional Improvements:`);
    for (const f of report.actionPlan.optionalImprovements) lines.push(`  - ${f.fix} (impact: ${f.impact})`);
    lines.push("");
    lines.push("MODULE 8 — INTERVIEW READINESS");
    lines.push("-----------------------------");
    lines.push(`Likely Questions:`);
    for (const q of report.interviewReadiness.likelyQuestions) lines.push(`  - ${q}`);
    lines.push(`Weak Areas: ${report.interviewReadiness.weakAreas.join(", ")}`);
    lines.push(`Talking Points: ${report.interviewReadiness.talkingPoints.join("; ")}`);
    lines.push(`Preparation Advice: ${report.interviewReadiness.preparationAdvice.join("; ")}`);

    const blob = new Blob([lines.join("\n")], { type: "text/plain" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = `resume-review-${resume?.name?.replace(/\s+/g, "_") ?? "report"}-${new Date().toISOString().slice(0, 10)}.docx.txt`;
    a.click();
    URL.revokeObjectURL(url);
    toast.success("DOCX-compatible text exported (opens in Word/Google Docs).");
  };

  // ============================================================================
  // Render
  // ============================================================================

  const tabs: { id: ModuleTab; label: string; icon: string; disabled?: boolean }[] = [
    { id: "dashboard", label: "Dashboard", icon: "LayoutDashboard" },
    { id: "ats", label: "ATS Review", icon: "ShieldCheck" },
    { id: "recruiter", label: "Recruiter Review", icon: "Users" },
    { id: "job-match", label: "Job Match", icon: "Target", disabled: !report?.jobMatch },
    { id: "benchmark", label: "Industry Benchmark", icon: "BarChart3" },
    { id: "improvements", label: "Improvements", icon: "Sparkles" },
    { id: "action-plan", label: "Action Plan", icon: "ListChecks" },
    { id: "fixes", label: "One-Click Fixes", icon: "Wand2" },
    { id: "interview", label: "Interview Readiness", icon: "MessageSquare" },
    { id: "history", label: "History", icon: "History" },
  ];

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex flex-wrap items-start justify-between gap-3">
        <div>
          <h1 className="font-display text-2xl font-bold flex items-center gap-2">
            <Icon name="FileSearch" className="w-6 h-6 text-brand" /> AI Resume Review Platform
          </h1>
          <p className="text-sm text-muted-foreground mt-1">
            Recruiter-grade review · ATS analysis · Industry benchmark · Job match · One-click fixes · Interview readiness
          </p>
        </div>
        {report && (
          <div className="flex gap-2 flex-wrap">
            <Button size="sm" variant="outline" onClick={exportJSON} className="gap-1.5"><Icon name="Braces" className="w-3.5 h-3.5" /> JSON</Button>
            <Button size="sm" variant="outline" onClick={exportDOCX} className="gap-1.5"><Icon name="FileType" className="w-3.5 h-3.5" /> DOCX</Button>
            <Button size="sm" variant="outline" onClick={exportPDF} className="gap-1.5"><Icon name="Printer" className="w-3.5 h-3.5" /> PDF</Button>
          </div>
        )}
      </div>

      {/* Multi-source input */}
      <Card><CardContent className="p-4 space-y-4">
        <div className="grid sm:grid-cols-2 lg:grid-cols-4 gap-3">
          <div>
            <Label>Original Resume</Label>
            <select value={resumeId} onChange={(e) => setResumeId(e.target.value)} className="w-full h-9 px-3 rounded-md border border-input bg-background text-sm mt-1">
              <option value="">Select...</option>
              {resumes.map((r) => <option key={r.id} value={r.id}>{r.name}{r.source === "ai-optimized" ? " (optimized)" : ""}</option>)}
            </select>
          </div>
          <div>
            <Label>Optimized Resume <span className="text-muted-foreground text-[10px]">(optional)</span></Label>
            <select value={optimizedResumeId} onChange={(e) => setOptimizedResumeId(e.target.value)} className="w-full h-9 px-3 rounded-md border border-input bg-background text-sm mt-1">
              <option value="">None</option>
              {resumes.filter((r) => r.id !== resumeId).map((r) => <option key={r.id} value={r.id}>{r.name}</option>)}
            </select>
          </div>
          <div>
            <Label>Job Description <span className="text-muted-foreground text-[10px]">(optional)</span></Label>
            <select value={jdId} onChange={(e) => setJdId(e.target.value)} className="w-full h-9 px-3 rounded-md border border-input bg-background text-sm mt-1">
              <option value="">None</option>
              {jds.map((j) => <option key={j.id} value={j.id}>{j.title}{j.company ? ` — ${j.company}` : ""}</option>)}
            </select>
          </div>
          <div>
            <Label>Company <span className="text-muted-foreground text-[10px]">(auto-detected)</span></Label>
            <Input value={companyName} onChange={(e) => setCompanyName(e.target.value)} placeholder="e.g. Emirates" className="mt-1" />
          </div>
        </div>

        {/* Auto-detected context badges */}
        <div className="flex flex-wrap gap-2 items-center text-xs">
          {industryProfile && <Badge variant="brand" className="gap-1"><Icon name="Building2" className="w-3 h-3" /> Industry: {industryProfile.label}</Badge>}
          {industryDetection && industryDetection.confidence >= 30 && <Badge variant="outline">Confidence: {industryDetection.confidence}%</Badge>}
          {resume && <Badge variant="outline">Resume: {resume.name}</Badge>}
          {optimizedResume && <Badge variant="success">Optimized: {optimizedResume.name}</Badge>}
          {jd && <Badge variant="warning">JD: {jd.title}</Badge>}
          {!jd && <Badge variant="outline">No JD — Job Match module will be skipped</Badge>}
        </div>

        <Button onClick={runReview} disabled={loading || !resume} className="bg-brand hover:bg-brand-dark text-white gap-2 w-full sm:w-auto">
          <Icon name={loading ? "Loader2" : "FileSearch"} className={`w-4 h-4 ${loading ? "animate-spin" : ""}`} />
          {loading ? "Running multi-module review..." : "Run Full Review"}
        </Button>
        {!resume && <p className="text-xs text-amber-600 mt-1">⚠ Create or upload a resume first to enable the review.</p>}
      </CardContent></Card>

      {/* Loading state */}
      {loading && (
        <Card><CardContent className="p-4">
          <div className="flex items-center gap-2 mb-2">
            <Icon name="Loader2" className="w-4 h-4 animate-spin text-brand" />
            <span className="text-sm text-muted-foreground">Running 10-module review — this may take 15-30 seconds…</span>
          </div>
          <div className="grid grid-cols-2 sm:grid-cols-5 gap-2 text-[10px] text-muted-foreground">
            {["ATS", "Recruiter", "Job Match", "Benchmark", "Improvements", "Action Plan", "Fixes", "Interview", "Dashboard", "Persistence"].map((m, i) => (
              <div key={m} className="flex items-center gap-1"><span className="text-brand">✓</span> {m}</div>
            ))}
          </div>
        </CardContent></Card>
      )}

      {/* Empty state */}
      {!loading && !report && reviewReports.length === 0 && (
        <Card><CardContent className="py-12 text-center">
          <Icon name="FileSearch" className="w-12 h-12 text-muted-foreground/30 mx-auto" />
          <h3 className="mt-3 font-semibold">No reviews yet</h3>
          <p className="text-sm text-muted-foreground mt-1 max-w-md mx-auto">
            Select a resume above and click <strong>Run Full Review</strong> to generate a comprehensive 10-module analysis — ATS score, recruiter feedback, industry benchmark, job match, one-click fixes, and interview readiness.
          </p>
        </CardContent></Card>
      )}

      {/* Tabs + content */}
      {report && !loading && (
        <>
          {/* Tab strip */}
          <div className="flex gap-1 overflow-x-auto pb-1 border-b border-border">
            {tabs.map((t) => (
              <button
                key={t.id}
                disabled={t.disabled}
                onClick={() => setActiveTab(t.id)}
                className={`flex items-center gap-1.5 px-3 py-2 text-xs font-medium whitespace-nowrap border-b-2 transition-colors ${
                  activeTab === t.id
                    ? "border-brand text-brand"
                    : t.disabled
                      ? "border-transparent text-muted-foreground/40 cursor-not-allowed"
                      : "border-transparent text-muted-foreground hover:text-foreground"
                }`}
              >
                <Icon name={t.icon} className="w-3.5 h-3.5" /> {t.label}
              </button>
            ))}
          </div>

          <AnimatePresence mode="wait">
            <motion.div key={activeTab} initial={{ opacity: 0, y: 8 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0, y: -8 }} transition={{ duration: 0.15 }}>
              {activeTab === "dashboard" && <DashboardModule report={report} />}
              {activeTab === "ats" && <ATSModule report={report} />}
              {activeTab === "recruiter" && <RecruiterModule report={report} />}
              {activeTab === "job-match" && report.jobMatch && <JobMatchModule report={report} />}
              {activeTab === "benchmark" && <BenchmarkModule report={report} />}
              {activeTab === "improvements" && <ImprovementsModule report={report} />}
              {activeTab === "action-plan" && <ActionPlanModule report={report} />}
              {activeTab === "fixes" && <FixesModule report={report} onFix={runOneClickFix} loading={fixLoading} />}
              {activeTab === "interview" && <InterviewModule report={report} />}
              {activeTab === "history" && (
                <HistoryModule
                  reports={reviewReports}
                  resumes={resumes}
                  currentReportId={report.id}
                  onSelect={(r) => setReport(r)}
                  onDelete={(id) => { removeReviewReport(id); if (id === report.id) setReport(null); }}
                />
              )}
            </motion.div>
          </AnimatePresence>

          {/* === OPTIMIZE RESUME CTA ===
              Prominent action banner shown after every review tab (except
              History) so the user can immediately act on the review's
              recommendations by jumping to the 5-agent Resume Optimizer
              with the current resume + JD pre-selected. */}
          {activeTab !== "history" && (
            <motion.div
              initial={{ opacity: 0, y: 12 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: 0.2, duration: 0.3 }}
            >
              <Card className="border-2 border-brand/40 bg-gradient-to-br from-brand/5 to-emerald-500/5 dark:from-brand/10 dark:to-emerald-500/10">
                <CardContent className="p-5">
                  <div className="flex flex-col sm:flex-row items-start sm:items-center gap-4">
                    <div className="w-12 h-12 rounded-xl bg-brand/15 flex items-center justify-center shrink-0">
                      <Icon name="Wand2" className="w-6 h-6 text-brand" />
                    </div>
                    <div className="flex-1 min-w-0">
                      <h3 className="font-display font-bold text-base flex items-center gap-2 flex-wrap">
                        Ready to optimize this resume?
                        {report.dashboard.atsScore < 85 && (
                          <Badge variant="warning" className="text-[10px] gap-1">
                            <Icon name="TrendingUp" className="w-3 h-3" /> +{report.actionPlan.expectedAtsIncrease} pts available
                          </Badge>
                        )}
                      </h3>
                      <p className="text-xs text-muted-foreground mt-1">
                        Jump to the <strong>Resume Optimizer</strong> with this resume{jd ? " and job description" : ""} pre-loaded. The 5-agent pipeline will rewrite bullets, embed missing keywords, and maximize your ATS score.
                      </p>
                      <div className="flex flex-wrap gap-1.5 mt-2">
                        {report.ats.missingKeywords.slice(0, 5).map((k, i) => (
                          <span key={i} className="text-[10px] px-1.5 py-0.5 rounded bg-red-100 text-red-700 dark:bg-red-950/40 dark:text-red-300">{k}</span>
                        ))}
                        {report.ats.missingKeywords.length > 5 && (
                          <span className="text-[10px] px-1.5 py-0.5 rounded bg-muted text-muted-foreground">+{report.ats.missingKeywords.length - 5} more</span>
                        )}
                      </div>
                    </div>
                    <div className="flex flex-col gap-2 shrink-0 w-full sm:w-auto">
                      <Button onClick={goToOptimizer} className="bg-brand hover:bg-brand-dark text-white gap-2 h-10 px-5">
                        <Icon name="Wand2" className="w-4 h-4" /> Optimize Resume
                        <Icon name="ArrowRight" className="w-4 h-4" />
                      </Button>
                      <Button
                        variant="outline"
                        size="sm"
                        onClick={() => setActiveTab("fixes")}
                        className="gap-1.5 text-xs h-7"
                      >
                        <Icon name="Zap" className="w-3 h-3" /> Or try One-Click Fixes
                      </Button>
                    </div>
                  </div>
                </CardContent>
              </Card>
            </motion.div>
          )}
        </>
      )}

      {/* If no current report but history exists, show history list */}
      {!report && !loading && reviewReports.length > 0 && (
        <HistoryModule
          reports={reviewReports}
          resumes={resumes}
          currentReportId={null}
          onSelect={(r) => { setReport(r); setActiveTab("dashboard"); }}
          onDelete={(id) => removeReviewReport(id)}
        />
      )}
    </div>
  );
}

// ============================================================================
// MODULE 9 — VISUAL DASHBOARD
// ============================================================================

function DashboardModule({ report }: { report: ResumeReviewReport }) {
  const scores = [
    { label: "ATS Score", value: report.dashboard.atsScore, max: 100, color: scoreColor(report.dashboard.atsScore) },
    { label: "Recruiter Score", value: report.dashboard.recruiterScore * 10, max: 100, color: scoreColor(report.dashboard.recruiterScore * 10) },
    { label: "Formatting", value: report.dashboard.formattingScore, max: 100, color: scoreColor(report.dashboard.formattingScore) },
    { label: "Readability", value: report.dashboard.readabilityScore, max: 100, color: scoreColor(report.dashboard.readabilityScore) },
    { label: "Industry Benchmark", value: report.dashboard.industryBenchmark, max: 100, color: scoreColor(report.dashboard.industryBenchmark) },
  ];
  if (report.dashboard.jobMatch !== null) {
    scores.push({ label: "Job Match", value: report.dashboard.jobMatch, max: 100, color: scoreColor(report.dashboard.jobMatch) });
  }

  // Radar chart — SVG-based (no external dependency, works on Cloudflare Free)
  const radarValues = scores.slice(0, 6);
  const radarSize = 220;
  const radarCenter = radarSize / 2;
  const radarRadius = radarSize / 2 - 30;
  const radarPoints = radarValues.map((s, i) => {
    const angle = (Math.PI * 2 * i) / radarValues.length - Math.PI / 2;
    const r = (s.value / s.max) * radarRadius;
    return [radarCenter + r * Math.cos(angle), radarCenter + r * Math.sin(angle)];
  });
  const radarPath = radarPoints.map((p) => p.join(",")).join(" ");
  const radarLabels = radarValues.map((s, i) => {
    const angle = (Math.PI * 2 * i) / radarValues.length - Math.PI / 2;
    const labelR = radarRadius + 18;
    return {
      label: s.label,
      value: Math.round(s.value),
      x: radarCenter + labelR * Math.cos(angle),
      y: radarCenter + labelR * Math.sin(angle),
    };
  });

  return (
    <div className="space-y-4">
      <div className="grid lg:grid-cols-2 gap-4">
        {/* Radar Chart */}
        <Card>
          <CardHeader className="pb-2"><CardTitle className="text-sm flex items-center gap-2"><Icon name="Radar" className="w-4 h-4 text-brand" /> Performance Radar</CardTitle></CardHeader>
          <CardContent className="flex justify-center pt-2">
            <svg width={radarSize} height={radarSize} className="max-w-full">
              {/* Grid circles */}
              {[0.25, 0.5, 0.75, 1].map((f) => (
                <circle key={f} cx={radarCenter} cy={radarCenter} r={radarRadius * f} fill="none" stroke="currentColor" strokeWidth="0.5" className="text-muted-foreground/30" />
              ))}
              {/* Grid lines */}
              {radarValues.map((_, i) => {
                const angle = (Math.PI * 2 * i) / radarValues.length - Math.PI / 2;
                return <line key={i} x1={radarCenter} y1={radarCenter} x2={radarCenter + radarRadius * Math.cos(angle)} y2={radarCenter + radarRadius * Math.sin(angle)} stroke="currentColor" strokeWidth="0.5" className="text-muted-foreground/30" />;
              })}
              {/* Score polygon */}
              <polygon points={radarPath} fill="rgba(17, 84, 163, 0.25)" stroke="#1154A3" strokeWidth="2" />
              {/* Score points */}
              {radarPoints.map((p, i) => <circle key={i} cx={p[0]} cy={p[1]} r="3" fill="#1154A3" />)}
              {/* Labels */}
              {radarLabels.map((l, i) => (
                <g key={i}>
                  <text x={l.x} y={l.y} textAnchor="middle" dominantBaseline="middle" className="text-[9px] fill-muted-foreground font-medium">{l.label}</text>
                  <text x={l.x} y={l.y + 10} textAnchor="middle" dominantBaseline="middle" className="text-[10px] font-bold" fill={scoreColor(l.value)}>{l.value}</text>
                </g>
              ))}
            </svg>
          </CardContent>
        </Card>

        {/* Progress bars */}
        <Card>
          <CardHeader className="pb-2"><CardTitle className="text-sm flex items-center gap-2"><Icon name="BarChart3" className="w-4 h-4 text-brand" /> Score Breakdown</CardTitle></CardHeader>
          <CardContent className="space-y-3 pt-2">
            {scores.map((s) => (
              <div key={s.label}>
                <div className="flex justify-between text-xs mb-1">
                  <span className="font-medium">{s.label}</span>
                  <span className="font-bold" style={{ color: s.color }}>{Math.round(s.value)}<span className="text-muted-foreground text-[10px]">/{s.max}</span></span>
                </div>
                <div className="h-2 bg-secondary rounded-full overflow-hidden">
                  <motion.div
                    initial={{ width: 0 }}
                    animate={{ width: `${(s.value / s.max) * 100}%` }}
                    transition={{ duration: 0.6, ease: "easeOut" }}
                    className="h-full rounded-full"
                    style={{ background: s.color }}
                  />
                </div>
              </div>
            ))}
            <div className="pt-2 border-t border-border flex items-center justify-between text-xs">
              <span className="text-muted-foreground">Overall verdict</span>
              <Badge variant={report.dashboard.atsScore >= 70 ? "success" : report.dashboard.atsScore >= 50 ? "warning" : "danger"}>
                {scoreLabel(report.dashboard.atsScore)}
              </Badge>
            </div>
          </CardContent>
        </Card>
      </div>

      {/* Heat-map style section scores */}
      <Card>
        <CardHeader className="pb-2"><CardTitle className="text-sm flex items-center gap-2"><Icon name="Grid3x3" className="w-4 h-4 text-brand" /> Section Heat Map</CardTitle></CardHeader>
        <CardContent className="pt-2">
          <div className="grid grid-cols-3 sm:grid-cols-5 lg:grid-cols-9 gap-2">
            {report.recruiter.sections.map((s) => {
              const pct = (s.score / 10) * 100;
              const color = pct >= 80 ? "#10B981" : pct >= 60 ? "#1154A3" : pct >= 40 ? "#F59E0B" : "#DC2626";
              return (
                <div key={s.section} className="rounded-lg p-2 text-center border" style={{ borderColor: color + "40", background: color + "10" }}>
                  <div className="text-[9px] uppercase text-muted-foreground truncate">{s.section}</div>
                  <div className="text-lg font-bold" style={{ color }}>{s.score}<span className="text-[10px] text-muted-foreground">/10</span></div>
                </div>
              );
            })}
          </div>
        </CardContent>
      </Card>

      {/* Top critical fixes preview */}
      {report.actionPlan.criticalFixes.length > 0 && (
        <Card>
          <CardHeader className="pb-2"><CardTitle className="text-sm flex items-center gap-2 text-red-600"><Icon name="AlertTriangle" className="w-4 h-4" /> Critical Fixes Preview</CardTitle></CardHeader>
          <CardContent className="pt-2 space-y-2">
            {report.actionPlan.criticalFixes.slice(0, 3).map((f, i) => (
              <div key={i} className="flex items-start gap-2 text-xs">
                <span className="text-red-500 font-bold mt-0.5">{i + 1}.</span>
                <div><span className="font-medium">{f.fix}</span> <span className="text-muted-foreground">— {f.impact}</span></div>
              </div>
            ))}
            <div className="pt-2 border-t border-border flex items-center justify-between text-xs">
              <span className="text-muted-foreground">Expected ATS increase after all fixes</span>
              <Badge variant="success" className="gap-1"><Icon name="TrendingUp" className="w-3 h-3" /> +{report.actionPlan.expectedAtsIncrease} pts</Badge>
            </div>
          </CardContent>
        </Card>
      )}
    </div>
  );
}

// ============================================================================
// MODULE 1 — ATS REVIEW
// ============================================================================

function ATSModule({ report }: { report: ResumeReviewReport }) {
  const a = report.ats;
  return (
    <div className="space-y-4">
      <div className="grid sm:grid-cols-3 gap-4">
        <Card><CardContent className="p-4 text-center">
          <div className="text-3xl font-bold font-display" style={{ color: scoreColor(a.atsScore) }}>{a.atsScore}</div>
          <div className="text-[10px] text-muted-foreground uppercase mt-1">ATS Score / 100</div>
        </CardContent></Card>
        <Card><CardContent className="p-4 text-center">
          <div className="text-3xl font-bold font-display" style={{ color: scoreColor(a.keywordMatch) }}>{a.keywordMatch}%</div>
          <div className="text-[10px] text-muted-foreground uppercase mt-1">Keyword Match</div>
        </CardContent></Card>
        <Card><CardContent className="p-4 text-center">
          <div className="text-3xl font-bold font-display" style={{ color: scoreColor(a.passProbability) }}>{a.passProbability}%</div>
          <div className="text-[10px] text-muted-foreground uppercase mt-1">Pass Probability</div>
        </CardContent></Card>
      </div>

      <div className="grid md:grid-cols-2 gap-4">
        <Card><CardHeader className="pb-2"><CardTitle className="text-sm text-red-600 flex items-center gap-2"><Icon name="KeyRound" className="w-4 h-4" /> Missing Keywords ({a.missingKeywords.length})</CardTitle></CardHeader>
          <CardContent className="pt-0">
            {a.missingKeywords.length > 0 ? (
              <div className="flex flex-wrap gap-1">{a.missingKeywords.map((k, i) => <Badge key={i} variant="danger" className="text-[10px]">{k}</Badge>)}</div>
            ) : <p className="text-xs text-muted-foreground">None — all keywords matched ✓</p>}
          </CardContent>
        </Card>
        <Card><CardHeader className="pb-2"><CardTitle className="text-sm text-amber-600 flex items-center gap-2"><Icon name="AlertCircle" className="w-4 h-4" /> Formatting Issues ({a.formattingIssues.length})</CardTitle></CardHeader>
          <CardContent className="pt-0">
            {a.formattingIssues.length > 0 ? (
              <ul className="space-y-1 text-xs">{a.formattingIssues.map((f, i) => <li key={i} className="flex gap-1.5"><span className="text-amber-500">!</span> {f}</li>)}</ul>
            ) : <p className="text-xs text-muted-foreground">No formatting issues ✓</p>}
          </CardContent>
        </Card>
      </div>

      <div className="grid md:grid-cols-3 gap-4">
        <Card><CardHeader className="pb-2"><CardTitle className="text-xs">Section Detection</CardTitle></CardHeader>
          <CardContent className="pt-0 space-y-1">
            {a.sectionDetection.map((s, i) => (
              <div key={i} className="flex items-center justify-between text-xs">
                <span>{s.section}</span>
                <span className={s.detected ? "text-emerald-600" : "text-red-500"}>{s.detected ? `✓ ${s.confidence}%` : "✗ missing"}</span>
              </div>
            ))}
          </CardContent>
        </Card>
        <Card><CardHeader className="pb-2"><CardTitle className="text-xs">Parsing Risks</CardTitle></CardHeader>
          <CardContent className="pt-0">
            {a.parsingRisks.length > 0 ? <ul className="space-y-1 text-xs">{a.parsingRisks.map((r, i) => <li key={i} className="flex gap-1.5"><span className="text-amber-500">!</span> {r}</li>)}</ul> : <p className="text-xs text-emerald-600">No parsing risks ✓</p>}
          </CardContent>
        </Card>
        <Card><CardHeader className="pb-2"><CardTitle className="text-xs">File Compatibility</CardTitle></CardHeader>
          <CardContent className="pt-0 space-y-1">
            {a.fileCompatibility.map((f, i) => <div key={i} className="text-xs">{f}</div>)}
            {a.graphicsRisks.length > 0 && <div className="mt-2 pt-2 border-t border-border"><div className="text-[10px] uppercase text-muted-foreground mb-1">Graphics Risks</div>{a.graphicsRisks.map((r, i) => <div key={i} className="text-xs text-amber-600">⚠ {r}</div>)}</div>}
            {a.tablesRisks.length > 0 && <div className="mt-2 pt-2 border-t border-border"><div className="text-[10px] uppercase text-muted-foreground mb-1">Tables Risks</div>{a.tablesRisks.map((r, i) => <div key={i} className="text-xs text-amber-600">⚠ {r}</div>)}</div>}
          </CardContent>
        </Card>
      </div>

      <Card><CardHeader className="pb-2"><CardTitle className="text-sm flex items-center gap-2"><Icon name="Lightbulb" className="w-4 h-4 text-brand" /> ATS Recommendations</CardTitle></CardHeader>
        <CardContent className="pt-0"><ul className="space-y-1.5 text-xs">{a.recommendations.map((r, i) => <li key={i} className="flex gap-1.5"><span className="text-brand">→</span> {r}</li>)}</ul></CardContent>
      </Card>
    </div>
  );
}

// ============================================================================
// MODULE 2 — RECRUITER REVIEW
// ============================================================================

function RecruiterModule({ report }: { report: ResumeReviewReport }) {
  return (
    <div className="space-y-4">
      <Card><CardContent className="p-4 flex items-center gap-4">
        <div className="text-center">
          <div className="text-4xl font-bold font-display" style={{ color: scoreColor(report.recruiter.overallScore * 10) }}>{report.recruiter.overallScore}</div>
          <div className="text-[10px] text-muted-foreground uppercase">Overall / 10</div>
        </div>
        <div className="flex-1 text-sm text-muted-foreground">
          A senior recruiter's honest assessment of each resume section. Scores reflect real content quality — empty or weak sections get low scores, not generic 7/10s.
        </div>
      </CardContent></Card>

      <div className="grid md:grid-cols-2 gap-4">
        {report.recruiter.sections.map((s, i) => {
          const pct = (s.score / 10) * 100;
          const color = pct >= 80 ? "#10B981" : pct >= 60 ? "#1154A3" : pct >= 40 ? "#F59E0B" : "#DC2626";
          return (
            <Card key={i}>
              <CardHeader className="pb-2">
                <div className="flex items-center justify-between">
                  <CardTitle className="text-sm">{s.section}</CardTitle>
                  <span className="inline-flex items-center rounded-full px-2 py-0.5 text-[10px] font-bold" style={{ background: color + "20", color }}>{s.score}/10</span>
                </div>
              </CardHeader>
              <CardContent className="pt-0 space-y-2 text-xs">
                {s.strengths.length > 0 && <div><div className="font-semibold text-emerald-600 mb-0.5">✓ Strengths</div><ul className="space-y-0.5">{s.strengths.map((x, j) => <li key={j} className="flex gap-1"><span className="text-emerald-500">+</span> {x}</li>)}</ul></div>}
                {s.weaknesses.length > 0 && <div><div className="font-semibold text-red-600 mb-0.5 mt-2">✗ Weaknesses</div><ul className="space-y-0.5">{s.weaknesses.map((x, j) => <li key={j} className="flex gap-1"><span className="text-red-500">−</span> {x}</li>)}</ul></div>}
                {s.recommendations.length > 0 && <div><div className="font-semibold text-brand mb-0.5 mt-2">→ Recommendations</div><ul className="space-y-0.5">{s.recommendations.map((x, j) => <li key={j} className="flex gap-1"><span className="text-brand">›</span> {x}</li>)}</ul></div>}
              </CardContent>
            </Card>
          );
        })}
      </div>
    </div>
  );
}

// ============================================================================
// MODULE 3 — JOB MATCH REVIEW
// ============================================================================

function JobMatchModule({ report }: { report: ResumeReviewReport }) {
  if (!report.jobMatch) return null;
  const jm = report.jobMatch;
  const axes = [
    { label: "Overall Match", val: jm.overallMatch },
    { label: "ATS Match", val: jm.atsMatch },
    { label: "Experience Match", val: jm.experienceMatch },
    { label: "Skill Match", val: jm.skillMatch },
    { label: "Education Match", val: jm.educationMatch },
    { label: "Industry Match", val: jm.industryMatch },
  ];
  return (
    <div className="space-y-4">
      <Card><CardContent className="p-4 flex items-center gap-4">
        <div className="text-center">
          <div className="text-4xl font-bold font-display" style={{ color: scoreColor(jm.overallMatch) }}>{jm.overallMatch}%</div>
          <div className="text-[10px] text-muted-foreground uppercase">Overall Match</div>
        </div>
        <div className="flex-1 grid grid-cols-2 sm:grid-cols-3 gap-2">
          {axes.slice(1).map((a) => (
            <div key={a.label}>
              <div className="text-[10px] uppercase text-muted-foreground">{a.label}</div>
              <div className="h-1.5 bg-secondary rounded-full overflow-hidden mt-0.5"><div className="h-full rounded-full" style={{ width: `${a.val}%`, background: scoreColor(a.val) }} /></div>
              <div className="text-[10px] font-bold mt-0.5" style={{ color: scoreColor(a.val) }}>{a.val}%</div>
            </div>
          ))}
        </div>
      </CardContent></Card>

      <div className="grid md:grid-cols-3 gap-4">
        <Card><CardHeader className="pb-2"><CardTitle className="text-sm text-red-600">Missing Skills</CardTitle></CardHeader>
          <CardContent className="pt-0">{jm.missingSkills.length > 0 ? <div className="flex flex-wrap gap-1">{jm.missingSkills.map((s, i) => <Badge key={i} variant="danger" className="text-[10px]">{s}</Badge>)}</div> : <p className="text-xs text-emerald-600">All skills matched ✓</p>}</CardContent>
        </Card>
        <Card><CardHeader className="pb-2"><CardTitle className="text-sm text-amber-600">Missing Keywords</CardTitle></CardHeader>
          <CardContent className="pt-0">{jm.missingKeywords.length > 0 ? <div className="flex flex-wrap gap-1">{jm.missingKeywords.map((s, i) => <Badge key={i} variant="warning" className="text-[10px]">{s}</Badge>)}</div> : <p className="text-xs text-emerald-600">All keywords matched ✓</p>}</CardContent>
        </Card>
        <Card><CardHeader className="pb-2"><CardTitle className="text-sm text-blue-600">Missing Certifications</CardTitle></CardHeader>
          <CardContent className="pt-0">{jm.missingCertifications.length > 0 ? <ul className="space-y-0.5 text-xs">{jm.missingCertifications.map((s, i) => <li key={i} className="flex gap-1"><span className="text-blue-500">+</span> {s}</li>)}</ul> : <p className="text-xs text-emerald-600">No required certs missing ✓</p>}</CardContent>
        </Card>
      </div>
    </div>
  );
}

// ============================================================================
// MODULE 4 — INDUSTRY BENCHMARK
// ============================================================================

function BenchmarkModule({ report }: { report: ResumeReviewReport }) {
  const b = report.benchmark;
  return (
    <div className="space-y-4">
      <Card><CardContent className="p-4 flex items-center gap-4 flex-wrap">
        <div className="text-center">
          <div className="text-4xl font-bold font-display" style={{ color: scoreColor(b.industryReadinessScore) }}>{b.industryReadinessScore}</div>
          <div className="text-[10px] text-muted-foreground uppercase">Industry Readiness / 100</div>
        </div>
        <div className="flex-1 grid grid-cols-2 sm:grid-cols-4 gap-2 text-xs">
          <div><div className="text-[10px] uppercase text-muted-foreground">Industry</div><div className="font-semibold">{b.industry}</div></div>
          <div><div className="text-[10px] uppercase text-muted-foreground">Role</div><div className="font-semibold">{b.role}</div></div>
          <div><div className="text-[10px] uppercase text-muted-foreground">Seniority</div><div className="font-semibold">{b.seniority}</div></div>
          <div><div className="text-[10px] uppercase text-muted-foreground">Country</div><div className="font-semibold">{b.country}</div></div>
        </div>
      </CardContent></Card>

      <Card>
        <CardHeader className="pb-2"><CardTitle className="text-sm flex items-center gap-2"><Icon name="BarChart3" className="w-4 h-4 text-brand" /> Benchmark vs. Industry</CardTitle></CardHeader>
        <CardContent className="pt-0 space-y-3">
          {b.benchmarkComparisons.map((c, i) => {
            const maxVal = Math.max(c.candidate, c.industryAverage, c.topPercentile, 1);
            return (
              <div key={i}>
                <div className="flex justify-between text-xs mb-1">
                  <span className="font-medium">{c.metric}</span>
                  <span className="text-muted-foreground">You: <span className="font-bold" style={{ color: scoreColor((c.candidate / maxVal) * 100) }}>{c.candidate}</span> · Avg: {c.industryAverage} · Top: {c.topPercentile}</span>
                </div>
                <div className="space-y-0.5">
                  <div className="h-2 bg-secondary rounded-full overflow-hidden"><div className="h-full rounded-full bg-brand" style={{ width: `${(c.candidate / maxVal) * 100}%` }} /></div>
                  <div className="h-1 bg-secondary rounded-full overflow-hidden"><div className="h-full rounded-full bg-muted-foreground/40" style={{ width: `${(c.industryAverage / maxVal) * 100}%` }} /></div>
                  <div className="h-1 bg-secondary rounded-full overflow-hidden"><div className="h-full rounded-full bg-emerald-500" style={{ width: `${(c.topPercentile / maxVal) * 100}%` }} /></div>
                </div>
              </div>
            );
          })}
        </CardContent>
      </Card>

      <Card><CardHeader className="pb-2"><CardTitle className="text-sm flex items-center gap-2"><Icon name="Lightbulb" className="w-4 h-4 text-brand" /> Insights</CardTitle></CardHeader>
        <CardContent className="pt-0"><ul className="space-y-1.5 text-xs">{b.insights.map((s, i) => <li key={i} className="flex gap-1.5"><span className="text-brand">→</span> {s}</li>)}</ul></CardContent>
      </Card>
    </div>
  );
}

// ============================================================================
// MODULE 5 — RESUME IMPROVEMENTS
// ============================================================================

function ImprovementsModule({ report }: { report: ResumeReviewReport }) {
  const imp = report.improvements;
  return (
    <div className="space-y-4">
      <Card>
        <CardHeader className="pb-2"><CardTitle className="text-sm flex items-center gap-2"><Icon name="FileText" className="w-4 h-4 text-brand" /> Better Summary</CardTitle></CardHeader>
        <CardContent className="pt-0"><p className="text-sm text-foreground/90 text-pretty">{imp.betterSummary}</p></CardContent>
      </Card>

      <div className="grid md:grid-cols-2 gap-4">
        <Card>
          <CardHeader className="pb-2"><CardTitle className="text-sm flex items-center gap-2"><Icon name="Type" className="w-4 h-4 text-brand" /> Better Headlines</CardTitle></CardHeader>
          <CardContent className="pt-0 space-y-2">{imp.betterHeadlines.map((h, i) => <div key={i} className="text-xs p-2 rounded-md bg-secondary/50 border border-border">{h}</div>)}</CardContent>
        </Card>
        <Card>
          <CardHeader className="pb-2"><CardTitle className="text-sm flex items-center gap-2"><Icon name="Plus" className="w-4 h-4 text-brand" /> Skills to Add</CardTitle></CardHeader>
          <CardContent className="pt-0">{imp.betterSkills.length > 0 ? <div className="flex flex-wrap gap-1">{imp.betterSkills.map((s, i) => <Badge key={i} variant="brand" className="text-[10px]">{s}</Badge>)}</div> : <p className="text-xs text-muted-foreground">None suggested</p>}</CardContent>
        </Card>
      </div>

      <Card>
        <CardHeader className="pb-2"><CardTitle className="text-sm flex items-center gap-2"><Icon name="RefreshCcw" className="w-4 h-4 text-brand" /> Better Bullet Points</CardTitle></CardHeader>
        <CardContent className="pt-0 space-y-3">
          {imp.betterBulletPoints.length > 0 ? imp.betterBulletPoints.map((b, i) => (
            <div key={i} className="rounded-lg border border-border p-3 bg-secondary/30">
              <div className="text-[10px] uppercase text-red-500 mb-1">Original</div>
              <div className="text-xs text-muted-foreground line-through mb-2">{b.original}</div>
              <div className="text-[10px] uppercase text-emerald-600 mb-1">Improved</div>
              <div className="text-xs font-medium text-foreground">{b.improved}</div>
            </div>
          )) : <p className="text-xs text-muted-foreground">No bullet improvements suggested</p>}
        </CardContent>
      </Card>

      <div className="grid md:grid-cols-3 gap-4">
        <Card><CardHeader className="pb-2"><CardTitle className="text-xs">Action Verbs</CardTitle></CardHeader><CardContent className="pt-0"><div className="flex flex-wrap gap-1">{imp.actionVerbs.map((v, i) => <Badge key={i} variant="outline" className="text-[10px]">{v}</Badge>)}</div></CardContent></Card>
        <Card><CardHeader className="pb-2"><CardTitle className="text-xs">Metrics to Add</CardTitle></CardHeader><CardContent className="pt-0"><ul className="space-y-0.5 text-xs">{imp.metrics.map((m, i) => <li key={i} className="flex gap-1"><span className="text-brand">›</span> {m}</li>)}</ul></CardContent></Card>
        <Card><CardHeader className="pb-2"><CardTitle className="text-xs">High-Value Keywords</CardTitle></CardHeader><CardContent className="pt-0"><div className="flex flex-wrap gap-1">{imp.highValueKeywords.map((k, i) => <Badge key={i} variant="warning" className="text-[10px]">{k}</Badge>)}</div></CardContent></Card>
      </div>
    </div>
  );
}

// ============================================================================
// MODULE 6 — PRIORITY ACTION PLAN
// ============================================================================

function ActionPlanModule({ report }: { report: ResumeReviewReport }) {
  const ap = report.actionPlan;
  return (
    <div className="space-y-4">
      <Card><CardContent className="p-4 flex items-center gap-4">
        <Icon name="TrendingUp" className="w-10 h-10 text-emerald-600" />
        <div>
          <div className="text-2xl font-bold font-display text-emerald-600">+{ap.expectedAtsIncrease} points</div>
          <div className="text-xs text-muted-foreground">Expected ATS increase after applying all fixes below</div>
        </div>
      </CardContent></Card>

      <Card>
        <CardHeader className="pb-2"><CardTitle className="text-sm text-red-600 flex items-center gap-2"><Icon name="AlertOctagon" className="w-4 h-4" /> Critical Fixes ({ap.criticalFixes.length})</CardTitle></CardHeader>
        <CardContent className="pt-0 space-y-2">
          {ap.criticalFixes.length > 0 ? ap.criticalFixes.map((f, i) => (
            <div key={i} className="rounded-lg border-l-4 border-red-500 p-3 bg-red-50/50 dark:bg-red-950/20">
              <div className="font-semibold text-xs text-red-700 dark:text-red-300">{f.fix}</div>
              <div className="text-xs text-muted-foreground mt-0.5">Impact: {f.impact}</div>
            </div>
          )) : <p className="text-xs text-emerald-600">No critical fixes needed ✓</p>}
        </CardContent>
      </Card>

      <Card>
        <CardHeader className="pb-2"><CardTitle className="text-sm text-amber-600 flex items-center gap-2"><Icon name="AlertTriangle" className="w-4 h-4" /> High Priority Fixes ({ap.highPriorityFixes.length})</CardTitle></CardHeader>
        <CardContent className="pt-0 space-y-2">
          {ap.highPriorityFixes.length > 0 ? ap.highPriorityFixes.map((f, i) => (
            <div key={i} className="rounded-lg border-l-4 border-amber-500 p-3 bg-amber-50/50 dark:bg-amber-950/20">
              <div className="font-semibold text-xs text-amber-700 dark:text-amber-300">{f.fix}</div>
              <div className="text-xs text-muted-foreground mt-0.5">Impact: {f.impact}</div>
            </div>
          )) : <p className="text-xs text-muted-foreground">None</p>}
        </CardContent>
      </Card>

      <Card>
        <CardHeader className="pb-2"><CardTitle className="text-sm text-blue-600 flex items-center gap-2"><Icon name="Sparkles" className="w-4 h-4" /> Optional Improvements ({ap.optionalImprovements.length})</CardTitle></CardHeader>
        <CardContent className="pt-0 space-y-2">
          {ap.optionalImprovements.length > 0 ? ap.optionalImprovements.map((f, i) => (
            <div key={i} className="rounded-lg border-l-4 border-blue-500 p-3 bg-blue-50/50 dark:bg-blue-950/20">
              <div className="font-semibold text-xs text-blue-700 dark:text-blue-300">{f.fix}</div>
              <div className="text-xs text-muted-foreground mt-0.5">Impact: {f.impact}</div>
            </div>
          )) : <p className="text-xs text-muted-foreground">None</p>}
        </CardContent>
      </Card>
    </div>
  );
}

// ============================================================================
// MODULE 7 — ONE-CLICK FIXES
// ============================================================================

function FixesModule({ report, onFix, loading }: { report: ResumeReviewReport; onFix: (type: "summary" | "skills" | "experience" | "ats" | "all") => void; loading: string | null }) {
  const fixes = [
    { id: "summary" as const, label: "Fix Summary", icon: "FileText", desc: "Rewrite the summary using the AI's recommended betterSummary.", color: "#1154A3" },
    { id: "skills" as const, label: "Fix Skills", icon: "Plus", desc: "Add suggested missing skills and reorganize by category.", color: "#10B981" },
    { id: "experience" as const, label: "Fix Experience", icon: "RefreshCcw", desc: "Rewrite weak bullets into impactful, metric-driven achievements.", color: "#F59E0B" },
    { id: "ats" as const, label: "Fix ATS", icon: "ShieldCheck", desc: "Embed all missing keywords naturally to maximize ATS score. Creates an optimized copy.", color: "#8B5CF6" },
    { id: "all" as const, label: "Optimize Entire Resume", icon: "Wand2", desc: "Apply ALL recommendations: summary, headlines, skills, bullets, keywords. Creates an optimized copy.", color: "#DC2626" },
  ];
  return (
    <div className="space-y-4">
      <Card><CardContent className="p-4">
        <div className="flex items-start gap-2 text-xs text-muted-foreground bg-brand/5 dark:bg-brand/10 border border-brand/20 rounded-lg p-3 mb-4">
          <Icon name="Info" className="w-4 h-4 text-brand shrink-0 mt-0.5" />
          <div>
            <p className="font-semibold text-foreground mb-1">How one-click fixes work</p>
            <p><strong>Fix Summary / Skills / Experience</strong> apply directly to your current resume. <strong>Fix ATS / Optimize Entire Resume</strong> create a new optimized copy in your library so you can compare side-by-side.</p>
          </div>
        </div>
        <div className="grid sm:grid-cols-2 gap-3">
          {fixes.map((f) => (
            <Card key={f.id} className="border-l-4" style={{ borderLeftColor: f.color }}>
              <CardContent className="p-4">
                <div className="flex items-start gap-3">
                  <Icon name={f.icon} className="w-5 h-5 shrink-0 mt-0.5" style={{ color: f.color }} />
                  <div className="flex-1 min-w-0">
                    <h4 className="font-semibold text-sm">{f.label}</h4>
                    <p className="text-xs text-muted-foreground mt-1">{f.desc}</p>
                    <Button size="sm" onClick={() => onFix(f.id)} disabled={loading !== null} className="mt-3 gap-1.5 text-white" style={{ background: f.color }}>
                      {loading === f.id ? <Icon name="Loader2" className="w-3.5 h-3.5 animate-spin" /> : <Icon name="Play" className="w-3.5 h-3.5" />}
                      {loading === f.id ? "Applying..." : "Apply Fix"}
                    </Button>
                  </div>
                </div>
              </CardContent>
            </Card>
          ))}
        </div>
      </CardContent></Card>
    </div>
  );
}

// ============================================================================
// MODULE 8 — INTERVIEW READINESS
// ============================================================================

function InterviewModule({ report }: { report: ResumeReviewReport }) {
  const ir = report.interviewReadiness;
  return (
    <div className="space-y-4">
      <div className="grid md:grid-cols-2 gap-4">
        <Card>
          <CardHeader className="pb-2"><CardTitle className="text-sm flex items-center gap-2"><Icon name="HelpCircle" className="w-4 h-4 text-brand" /> Likely Questions ({ir.likelyQuestions.length})</CardTitle></CardHeader>
          <CardContent className="pt-0 space-y-2">{ir.likelyQuestions.map((q, i) => <div key={i} className="text-xs p-2 rounded-md bg-secondary/40 border border-border">Q{i + 1}: {q}</div>)}</CardContent>
        </Card>
        <Card>
          <CardHeader className="pb-2"><CardTitle className="text-sm flex items-center gap-2 text-red-600"><Icon name="AlertTriangle" className="w-4 h-4" /> Weak Areas ({ir.weakAreas.length})</CardTitle></CardHeader>
          <CardContent className="pt-0 space-y-1">{ir.weakAreas.map((w, i) => <div key={i} className="text-xs flex gap-1.5"><span className="text-red-500">!</span> {w}</div>)}</CardContent>
        </Card>
      </div>
      <div className="grid md:grid-cols-2 gap-4">
        <Card>
          <CardHeader className="pb-2"><CardTitle className="text-sm flex items-center gap-2 text-emerald-600"><Icon name="MessageSquare" className="w-4 h-4" /> Talking Points ({ir.talkingPoints.length})</CardTitle></CardHeader>
          <CardContent className="pt-0 space-y-1">{ir.talkingPoints.map((t, i) => <div key={i} className="text-xs flex gap-1.5"><span className="text-emerald-500">+</span> {t}</div>)}</CardContent>
        </Card>
        <Card>
          <CardHeader className="pb-2"><CardTitle className="text-sm flex items-center gap-2 text-brand"><Icon name="Lightbulb" className="w-4 h-4" /> Preparation Advice ({ir.preparationAdvice.length})</CardTitle></CardHeader>
          <CardContent className="pt-0 space-y-1.5">{ir.preparationAdvice.map((a, i) => <div key={i} className="text-xs flex gap-1.5"><span className="text-brand">→</span> {a}</div>)}</CardContent>
        </Card>
      </div>
    </div>
  );
}

// ============================================================================
// MODULE 10 — HISTORY (persistence viewer)
// ============================================================================

function HistoryModule({
  reports,
  resumes,
  currentReportId,
  onSelect,
  onDelete,
}: {
  reports: ResumeReviewReport[];
  resumes: ResumeData[];
  currentReportId: string | null;
  onSelect: (r: ResumeReviewReport) => void;
  onDelete: (id: string) => void;
}) {
  if (reports.length === 0) {
    return <Card><CardContent className="py-8 text-center text-sm text-muted-foreground">No saved reviews yet. Run your first review above.</CardContent></Card>;
  }
  return (
    <Card>
      <CardHeader className="pb-2"><CardTitle className="text-sm flex items-center gap-2"><Icon name="History" className="w-4 h-4 text-brand" /> Saved Reviews ({reports.length})</CardTitle>
      <CardDescription className="text-xs">Reviews are saved to your browser and survive logout, login, refresh, and browser restart.</CardDescription>
      </CardHeader>
      <CardContent className="pt-0 space-y-2">
        {reports.map((r) => {
          const resumeName = resumes.find((x) => x.id === r.resumeId)?.name ?? "Unknown resume";
          const isActive = r.id === currentReportId;
          return (
            <div key={r.id} className={`flex items-center gap-3 p-3 rounded-lg border ${isActive ? "border-brand bg-brand/5" : "border-border"}`}>
              <div className="flex-1 min-w-0">
                <div className="flex items-center gap-2 flex-wrap">
                  <span className="font-semibold text-sm">{resumeName}</span>
                  {r.companyName && <Badge variant="outline" className="text-[10px]">{r.companyName}</Badge>}
                  <Badge variant="brand" className="text-[10px]">{r.industryProfile}</Badge>
                </div>
                <div className="text-xs text-muted-foreground mt-0.5">
                  ATS {r.dashboard.atsScore}/100 · Recruiter {r.dashboard.recruiterScore}/10
                  {r.dashboard.jobMatch !== null && ` · Match ${r.dashboard.jobMatch}%`}
                  · {new Date(r.createdAt).toLocaleString()}
                </div>
              </div>
              <div className="flex gap-1">
                <Button size="sm" variant={isActive ? "default" : "outline"} onClick={() => onSelect(r)} className="h-7 text-xs gap-1">
                  <Icon name={isActive ? "Check" : "Eye"} className="w-3 h-3" /> {isActive ? "Active" : "View"}
                </Button>
                <Button size="sm" variant="ghost" onClick={() => onDelete(r.id)} className="h-7 text-xs text-red-500 hover:text-red-600">
                  <Icon name="Trash2" className="w-3 h-3" />
                </Button>
              </div>
            </div>
          );
        })}
      </CardContent>
    </Card>
  );
}

src/components/app/modules/Settings.tsx:
"use client";

import { useState } from "react";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Switch } from "@/components/ui/switch";
import { Badge, Icon } from "@/components/shared";
import { useApp } from "@/lib/store";
import { toast } from "sonner";

export function Settings() {
  const user = useApp((s) => s.user);
  const theme = useApp((s) => s.theme);
  const toggleTheme = useApp((s) => s.toggleTheme);
  const signOut = useApp((s) => s.signOut);
  const updateUserName = useApp((s) => s.updateUserName);
  const updateUserEmail = useApp((s) => s.updateUserEmail);
  const changePassword = useApp((s) => s.changePassword);
  const log = useApp((s) => s.log);

  // Profile form state
  const [name, setName] = useState(user?.name ?? "");
  const [email, setEmail] = useState(user?.email ?? "");
  const [savingProfile, setSavingProfile] = useState(false);

  // Password form state
  const [currentPw, setCurrentPw] = useState("");
  const [newPw, setNewPw] = useState("");
  const [confirmPw, setConfirmPw] = useState("");
  const [showCurrent, setShowCurrent] = useState(false);
  const [showNew, setShowNew] = useState(false);
  const [showConfirm, setShowConfirm] = useState(false);
  const [savingPw, setSavingPw] = useState(false);

  // Password strength
  const strength = computeStrength(newPw);
  const strengthLabel = ["Too weak", "Weak", "Fair", "Good", "Strong"][strength];
  const strengthColor = ["#DC2626", "#DC2626", "#F59E0B", "#1154A3", "#10B981"][strength];

  const onSaveProfile = async () => {
    if (!name.trim() || name.trim().length < 2) {
      toast.error("Name must be at least 2 characters.");
      return;
    }
    if (!/^[^@\s]+@[^@\s]+\.[^@\s]+$/.test(email)) {
      toast.error("Please enter a valid email address.");
      return;
    }
    setSavingProfile(true);
    await new Promise((r) => setTimeout(r, 400));
    const nameChanged = name.trim() !== user?.name;
    const emailChanged = email.trim().toLowerCase() !== user?.email;
    if (nameChanged) updateUserName(name.trim());
    if (emailChanged) updateUserEmail(email.trim());
    setSavingProfile(false);
    if (nameChanged || emailChanged) {
      toast.success("Profile updated.");
    } else {
      toast.info("No changes to save.");
    }
  };

  const onChangePw = async () => {
    if (newPw !== confirmPw) {
      toast.error("New password and confirmation don't match.");
      return;
    }
    setSavingPw(true);
    await new Promise((r) => setTimeout(r, 500));
    const result = changePassword(currentPw, newPw);
    setSavingPw(false);
    if (result.ok) {
      toast.success("Password changed successfully.");
      setCurrentPw("");
      setNewPw("");
      setConfirmPw("");
    } else {
      toast.error(result.error || "Failed to change password.");
    }
  };

  const isOAuthUser = !!(user && user.provider !== "email");

  return (
    <div className="space-y-6 max-w-3xl">
      <div>
        <h1 className="font-display text-2xl font-bold flex items-center gap-2"><Icon name="Settings" className="w-6 h-6 text-brand" /> Settings</h1>
        <p className="text-sm text-muted-foreground mt-1">Account, security, appearance, data, and privacy.</p>
      </div>

      {/* Profile (name + email) */}
      <Card>
        <CardHeader>
          <CardTitle className="text-lg flex items-center gap-2"><Icon name="User" className="w-4 h-4 text-brand" /> Profile</CardTitle>
          <CardDescription>Your display name and email. Used across the app and on exported resumes.</CardDescription>
        </CardHeader>
        <CardContent className="space-y-4">
          <div className="grid sm:grid-cols-2 gap-3">
            <Field label="Display name">
              <Input value={name} onChange={(e) => setName(e.target.value)} placeholder="Your name" maxLength={80} />
            </Field>
            <Field label="Email address">
              <Input
                type="email"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                placeholder="you@example.com"
                disabled={isOAuthUser}
              />
              {isOAuthUser && (
                <p className="text-[11px] text-muted-foreground mt-1 flex items-center gap-1">
                  <Icon name="Lock" className="w-3 h-3" /> Email is managed by your {user?.provider} account.
                </p>
              )}
            </Field>
            <Field label="Role">
              <Input value={user?.role?.replace("_", " ") ?? ""} disabled className="capitalize" />
            </Field>
            <Field label="Auth provider">
              <Input value={user?.provider ?? ""} disabled className="capitalize" />
            </Field>
          </div>
          <div className="flex items-center justify-between">
            <p className="text-xs text-muted-foreground">Last active: {user?.lastActiveAt ? new Date(user.lastActiveAt).toLocaleString() : "—"}</p>
            <Button onClick={onSaveProfile} disabled={savingProfile} className="bg-brand hover:bg-brand-dark text-white gap-2">
              {savingProfile ? <Icon name="Loader2" className="w-4 h-4 animate-spin" /> : <Icon name="Save" className="w-4 h-4" />}
              Save profile
            </Button>
          </div>
        </CardContent>
      </Card>

      {/* Change password */}
      <Card>
        <CardHeader>
          <CardTitle className="text-lg flex items-center gap-2"><Icon name="KeyRound" className="w-4 h-4 text-brand" /> Security — Change password</CardTitle>
          <CardDescription>
            {isOAuthUser
              ? `You signed in via ${user?.provider}. Set a password to also be able to sign in with email.`
              : "Update your password. Use at least 8 characters with letters and numbers."}
          </CardDescription>
        </CardHeader>
        <CardContent className="space-y-4">
          <div className="grid sm:grid-cols-3 gap-3">
            <Field label="Current password">
              <div className="relative">
                <Input
                  type={showCurrent ? "text" : "password"}
                  value={currentPw}
                  onChange={(e) => setCurrentPw(e.target.value)}
                  placeholder="••••••••"
                  autoComplete="current-password"
                  className="pr-9"
                />
                <button type="button" onClick={() => setShowCurrent((v) => !v)} className="absolute right-2 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground" aria-label="Toggle visibility">
                  <Icon name={showCurrent ? "EyeOff" : "Eye"} className="w-4 h-4" />
                </button>
              </div>
            </Field>
            <Field label="New password">
              <div className="relative">
                <Input
                  type={showNew ? "text" : "password"}
                  value={newPw}
                  onChange={(e) => setNewPw(e.target.value)}
                  placeholder="Min 8 chars, letters + numbers"
                  autoComplete="new-password"
                  className="pr-9"
                />
                <button type="button" onClick={() => setShowNew((v) => !v)} className="absolute right-2 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground" aria-label="Toggle visibility">
                  <Icon name={showNew ? "EyeOff" : "Eye"} className="w-4 h-4" />
                </button>
              </div>
            </Field>
            <Field label="Confirm new password">
              <div className="relative">
                <Input
                  type={showConfirm ? "text" : "password"}
                  value={confirmPw}
                  onChange={(e) => setConfirmPw(e.target.value)}
                  placeholder="Repeat new password"
                  autoComplete="new-password"
                  className="pr-9"
                  onKeyDown={(e) => e.key === "Enter" && onChangePw()}
                />
                <button type="button" onClick={() => setShowConfirm((v) => !v)} className="absolute right-2 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground" aria-label="Toggle visibility">
                  <Icon name={showConfirm ? "EyeOff" : "Eye"} className="w-4 h-4" />
                </button>
              </div>
            </Field>
          </div>

          {/* Strength meter */}
          {newPw && (
            <div className="space-y-1.5">
              <div className="flex items-center justify-between text-xs">
                <span className="text-muted-foreground">Password strength</span>
                <span className="font-semibold" style={{ color: strengthColor }}>{strengthLabel}</span>
              </div>
              <div className="flex gap-1">
                {[0, 1, 2, 3, 4].map((i) => (
                  <div
                    key={i}
                    className="h-1.5 flex-1 rounded-full transition-all"
                    style={{ background: i < strength ? strengthColor : "var(--muted)" }}
                  />
                ))}
              </div>
              <ul className="text-[11px] text-muted-foreground grid grid-cols-2 gap-x-3 gap-y-0.5 mt-2">
                <li className={newPw.length >= 8 ? "text-emerald-600" : ""}>{newPw.length >= 8 ? "✓" : "○"} At least 8 characters</li>
                <li className={/[A-Za-z]/.test(newPw) ? "text-emerald-600" : ""}>{/[A-Za-z]/.test(newPw) ? "✓" : "○"} Contains a letter</li>
                <li className={/\d/.test(newPw) ? "text-emerald-600" : ""}>{/\d/.test(newPw) ? "✓" : "○"} Contains a number</li>
                <li className={newPw === confirmPw && confirmPw ? "text-emerald-600" : ""}>{newPw === confirmPw && confirmPw ? "✓" : "○"} Passwords match</li>
              </ul>
            </div>
          )}

          <div className="flex items-center justify-between">
            <p className="text-xs text-muted-foreground flex items-center gap-1">
              <Icon name="ShieldCheck" className="w-3 h-3" />
              In production, passwords are bcrypt-hashed and verified server-side via Cloudflare Workers.
            </p>
            <Button
              onClick={onChangePw}
              disabled={savingPw || !currentPw || !newPw || !confirmPw}
              className="bg-brand hover:bg-brand-dark text-white gap-2"
            >
              {savingPw ? <Icon name="Loader2" className="w-4 h-4 animate-spin" /> : <Icon name="KeyRound" className="w-4 h-4" />}
              Change password
            </Button>
          </div>
        </CardContent>
      </Card>

      {/* Appearance */}
      <Card>
        <CardHeader>
          <CardTitle className="text-lg flex items-center gap-2"><Icon name="Palette" className="w-4 h-4 text-brand" /> Appearance</CardTitle>
          <CardDescription>Customize how the app looks.</CardDescription>
        </CardHeader>
        <CardContent className="space-y-3">
          <div className="flex items-center justify-between p-3 rounded-lg border border-border">
            <div>
              <div className="font-medium text-sm">Dark mode</div>
              <div className="text-xs text-muted-foreground">Switch between light and dark themes.</div>
            </div>
            <Switch checked={theme === "dark"} onCheckedChange={toggleTheme} />
          </div>
        </CardContent>
      </Card>

      {/* Usage */}
      <Card>
        <CardHeader>
          <CardTitle className="text-lg flex items-center gap-2"><Icon name="Activity" className="w-4 h-4 text-brand" /> Usage</CardTitle>
          <CardDescription>All free, all unlimited. Your lifetime totals.</CardDescription>
        </CardHeader>
        <CardContent>
          <div className="grid grid-cols-2 sm:grid-cols-5 gap-3">
            {[
              ["Resumes", user?.usage.resumesGenerated],
              ["ATS checks", user?.usage.atsChecks],
              ["Cover letters", user?.usage.coverLetters],
              ["Interview preps", user?.usage.interviewPreps],
              ["Downloads", user?.usage.downloads],
            ].map(([label, val]) => (
              <div key={label as string} className="rounded-lg bg-secondary p-3 text-center">
                <div className="text-2xl font-bold font-display">{val}</div>
                <div className="text-xs text-muted-foreground">{label}</div>
              </div>
            ))}
          </div>
        </CardContent>
      </Card>

      {/* Privacy & data */}
      <Card>
        <CardHeader>
          <CardTitle className="text-lg flex items-center gap-2"><Icon name="ShieldCheck" className="w-4 h-4 text-brand" /> Privacy & data</CardTitle>
          <CardDescription>Your data stays on your device in dev. In production, it's encrypted at rest in Cloudflare D1 + R2.</CardDescription>
        </CardHeader>
        <CardContent className="space-y-3">
          <div className="rounded-lg border border-border p-3 flex items-start gap-3">
            <Icon name="Lock" className="w-5 h-5 text-emerald-600 shrink-0 mt-0.5" />
            <div>
              <div className="font-medium text-sm">Local-first storage</div>
              <div className="text-xs text-muted-foreground">Resumes, cover letters, and settings are stored in your browser's localStorage. They never touch a server unless you explicitly connect a cloud AI provider.</div>
            </div>
          </div>
          <div className="rounded-lg border border-border p-3 flex items-start gap-3">
            <Icon name="Download" className="w-5 h-5 text-brand shrink-0 mt-0.5" />
            <div className="flex-1">
              <div className="font-medium text-sm">Export all my data</div>
              <div className="text-xs text-muted-foreground">Download a JSON backup of everything you've created (resumes, cover letters, interview packages, JDs).</div>
            </div>
            <Button
              variant="outline"
              size="sm"
              onClick={() => {
                const state = useApp.getState();
                const data = {
                  user: state.user,
                  resumes: state.resumes,
                  coverLetters: state.coverLetters,
                  interviews: state.interviews,
                  jobDescriptions: state.jobDescriptions,
                  atsReports: state.atsReports,
                  exportedAt: new Date().toISOString(),
                };
                const blob = new Blob([JSON.stringify(data, null, 2)], { type: "application/json" });
                const url = URL.createObjectURL(blob);
                const a = document.createElement("a");
                a.href = url;
                a.download = `resumeai-pro-backup-${new Date().toISOString().slice(0, 10)}.json`;
                a.click();
                URL.revokeObjectURL(url);
                toast.success("Data exported.");
              }}
              className="gap-1.5"
            >
              <Icon name="Download" className="w-3.5 h-3.5" /> Export
            </Button>
          </div>
          <div className="rounded-lg border border-border p-3 flex items-start gap-3">
            <Icon name="Trash2" className="w-5 h-5 text-destructive shrink-0 mt-0.5" />
            <div className="flex-1">
              <div className="font-medium text-sm">Clear all local data</div>
              <div className="text-xs text-muted-foreground">Remove all resumes, cover letters, settings, and credentials from this browser. This cannot be undone.</div>
            </div>
            <Button
              variant="outline"
              size="sm"
              className="text-destructive gap-1.5"
              onClick={() => {
                if (confirm("This will delete ALL your local data (resumes, cover letters, settings, login). Continue?")) {
                  localStorage.removeItem("resumeai-pro");
                  log({ actor: "you", action: "Cleared all local data", category: "system", details: "User wiped localStorage", severity: "warning" });
                  setTimeout(() => location.reload(), 300);
                }
              }}
            >
              <Icon name="Trash2" className="w-3.5 h-3.5" /> Clear
            </Button>
          </div>
        </CardContent>
      </Card>

      {/* Sessions / sign out */}
      <Card>
        <CardHeader>
          <CardTitle className="text-lg flex items-center gap-2"><Icon name="LogOut" className="w-4 h-4 text-brand" /> Session</CardTitle>
          <CardDescription>End your current session on this device.</CardDescription>
        </CardHeader>
        <CardContent className="flex items-center justify-between">
          <div>
            <div className="font-medium text-sm">Signed in as</div>
            <div className="text-xs text-muted-foreground">{user?.email} · since {user?.createdAt ? new Date(user.createdAt).toLocaleDateString() : "—"}</div>
          </div>
          <Button variant="outline" onClick={signOut} className="gap-2">
            <Icon name="LogOut" className="w-4 h-4" /> Sign out
          </Button>
        </CardContent>
      </Card>
    </div>
  );
}

function Field({ label, children }: { label: string; children: React.ReactNode }) {
  return (
    <div className="space-y-1.5">
      <Label className="text-xs uppercase tracking-wide text-muted-foreground">{label}</Label>
      {children}
    </div>
  );
}

function computeStrength(pw: string): number {
  if (!pw) return 0;
  let score = 0;
  if (pw.length >= 8) score++;
  if (pw.length >= 12) score++;
  if (/[A-Z]/.test(pw) && /[a-z]/.test(pw)) score++;
  if (/\d/.test(pw)) score++;
  if (/[^A-Za-z0-9]/.test(pw)) score++;
  return Math.min(4, score);
}

src/components/app/modules/SuperAdmin.ts:
"use client";

import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge, Icon, ScoreRing } from "@/components/shared";
import { useApp } from "@/lib/store";

export function SuperAdmin() {
  const setView = useApp((s) => s.setView);
  const providers = useApp((s) => s.providers);
  const prompts = useApp((s) => s.prompts);
  const logs = useApp((s) => s.logs);
  const flags = useApp((s) => s.flags);

  const activeProviders = providers.filter((p) => p.isActive).length;
  const activePrompts = prompts.filter((p) => p.isActive).length;
  const systemHealth = Math.round(
    (activeProviders / Math.max(1, providers.length)) * 0.4 +
    (activePrompts / Math.max(1, prompts.length)) * 0.3 +
    (flags.maintenanceMode ? 0 : 0.3)
  * 100
  );

  const quickLinks = [
    { label: "AI Providers", desc: `${activeProviders} active of ${providers.length}`, icon: "Cpu", view: "ai-providers", color: "#1154A3" },
    { label: "Prompt Library", desc: `${prompts.length} templates · ${activePrompts} active`, icon: "Brain", view: "prompts", color: "#8B5CF6" },
    { label: "Branding", desc: "Customize logo, colors, email", icon: "Palette", view: "branding", color: "#EC4899" },
    { label: "Feature Flags", desc: `${Object.values(flags).filter(Boolean).length}/${Object.keys(flags).length} enabled`, icon: "Flag", view: "feature-flags", color: "#F59E0B" },
    { label: "Audit Logs", desc: `${logs.length} recent events`, icon: "ScrollText", view: "logs", color: "#10B981" },
    { label: "Users", desc: "Manage accounts & roles", icon: "Users", view: "users", color: "#0EA5E9" },
    { label: "Analytics", desc: "Platform metrics & funnel", icon: "BarChart3", view: "analytics", color: "#1154A3" },
    { label: "Admin Overview", desc: "KPIs & usage", icon: "ShieldCheck", view: "admin", color: "#10B981" },
  ];

  return (
    <div className="space-y-6">
      <div>
        <h1 className="font-display text-2xl font-bold flex items-center gap-2"><Icon name="Crown" className="w-6 h-6 text-gold" /> Super Admin Overview</h1>
        <p className="text-sm text-muted-foreground mt-1">Full system control. Configure AI providers, branding, prompts, flags, and audit logs.</p>
      </div>

      <div className="grid lg:grid-cols-3 gap-6">
        {/* System health */}
        <Card className="gradient-brand text-white">
          <CardContent className="p-6 flex flex-col items-center justify-center text-center">
            <div className="relative">
              <ScoreRing value={Math.min(100, systemHealth)} size={120} label="Health" />
            </div>
            <div className="mt-3 font-semibold">System health</div>
            <div className="text-xs text-white/70 mt-1">
              {flags.maintenanceMode ? "Maintenance mode ON" : "All systems operational"}
            </div>
          </CardContent>
        </Card>

        {/* Stats */}
        <div className="lg:col-span-2 grid sm:grid-cols-2 gap-4">
          {[
            { label: "AI providers", value: `${activeProviders}/${providers.length}`, icon: "Cpu", color: "#1154A3" },
            { label: "Active prompts", value: `${activePrompts}/${prompts.length}`, icon: "Brain", color: "#8B5CF6" },
            { label: "Audit logs (24h)", value: logs.length, icon: "ScrollText", color: "#10B981" },
            { label: "Flags enabled", value: `${Object.values(flags).filter(Boolean).length}/${Object.keys(flags).length}`, icon: "Flag", color: "#F59E0B" },
          ].map((s) => (
            <Card key={s.label}>
              <CardContent className="p-5 flex items-center gap-3">
                <div className="w-10 h-10 rounded-lg flex items-center justify-center" style={{ background: `${s.color}15`, color: s.color }}>
                  <Icon name={s.icon} className="w-5 h-5" />
                </div>
                <div>
                  <div className="text-xl font-bold font-display">{s.value}</div>
                  <div className="text-xs text-muted-foreground">{s.label}</div>
                </div>
              </CardContent>
            </Card>
          ))}
        </div>
      </div>

      {/* Quick links */}
      <Card>
        <CardHeader>
          <CardTitle className="text-lg">Super admin tools</CardTitle>
          <CardDescription>Jump directly to any control panel.</CardDescription>
        </CardHeader>
        <CardContent>
          <div className="grid sm:grid-cols-2 lg:grid-cols-4 gap-3">
            {quickLinks.map((q) => (
              <button key={q.label} onClick={() => setView(q.view as any)} className="group text-left rounded-xl border border-border p-4 hover:shadow-premium hover:-translate-y-0.5 transition-all">
                <div className="w-10 h-10 rounded-lg flex items-center justify-center mb-3" style={{ background: `${q.color}15`, color: q.color }}>
                  <Icon name={q.icon} className="w-5 h-5" />
                </div>
                <div className="font-semibold text-sm flex items-center gap-1">
                  {q.label}
                  <Icon name="ArrowRight" className="w-3 h-3 text-muted-foreground opacity-0 group-hover:opacity-100 group-hover:translate-x-0.5 transition" />
                </div>
                <div className="text-xs text-muted-foreground mt-0.5">{q.desc}</div>
              </button>
            ))}
          </div>
        </CardContent>
      </Card>

      {/* Recent logs */}
      <Card>
        <CardHeader>
          <div className="flex items-center justify-between">
            <CardTitle className="text-lg">Recent audit events</CardTitle>
            <Button size="sm" variant="outline" onClick={() => setView("logs")}>View all</Button>
          </div>
        </CardHeader>
        <CardContent>
          <div className="space-y-2 max-h-80 overflow-y-auto">
            {logs.slice(0, 10).map((l) => {
              const sevColor = l.severity === "info" ? "brand" : l.severity === "warning" ? "warning" : "danger";
              return (
                <div key={l.id} className="flex items-start gap-3 p-2 rounded-lg hover:bg-secondary/40">
                  <Badge variant={sevColor as any} className="text-[10px] capitalize shrink-0">{l.severity}</Badge>
                  <div className="flex-1 min-w-0">
                    <div className="text-sm font-medium truncate">{l.action}</div>
                    <div className="text-xs text-muted-foreground truncate">{l.details}</div>
                  </div>
                  <div className="text-xs text-muted-foreground shrink-0 whitespace-nowrap">{new Date(l.timestamp).toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" })}</div>
                </div>
              );
            })}
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

src/components/app/modules/TestConnectio:
"use client";

import { useState, useEffect } from "react";
import { motion } from "framer-motion";
import { Button } from "@/components/ui/button";
import { Badge, Icon } from "@/components/shared";
import { ProviderManager } from "@/lib/ai/services";
import type { AIProvider } from "@/lib/types";

interface TestResult {
  ok: boolean;
  latencyMs: number;
  message: string;
  response?: string;
  inputTokens?: number;
  outputTokens?: number;
}

export function TestConnectionModal({ provider, onClose }: { provider: AIProvider; onClose: () => void }) {
  const [status, setStatus] = useState<"idle" | "running" | "done">("idle");
  const [result, setResult] = useState<TestResult | null>(null);
  const [testPrompt, setTestPrompt] = useState("Reply with exactly: OK");
  const [steps, setSteps] = useState<string[]>([]);

  const runTest = async () => {
    setStatus("running");
    setSteps([]);
    setResult(null);

    setSteps((s) => [...s, `Resolving adapter for type "${provider.type}"…`]);
    await new Promise((r) => setTimeout(r, 200));
    setSteps((s) => [...s, `Building config (baseUrl=${provider.baseUrl || provider.apiUrl || "—"}, model=${provider.modelName || "—"})…`]);
    await new Promise((r) => setTimeout(r, 200));
    setSteps((s) => [...s, `Sending test prompt: "${testPrompt.slice(0, 60)}${testPrompt.length > 60 ? "…" : ""}"`]);

    const t0 = performance.now();
    const res = await ProviderManager.testConnection(provider);
    const totalMs = Math.round(performance.now() - t0);

    setSteps((s) => [...s, `Received response in ${res.latencyMs}ms (total ${totalMs}ms including overhead).`]);
    setResult(res);
    setStatus("done");
  };

  return (
    <motion.div
      initial={{ opacity: 0 }}
      animate={{ opacity: 1 }}
      exit={{ opacity: 0 }}
      className="fixed inset-0 z-50 bg-background/80 backdrop-blur-sm flex items-center justify-center p-4"
      onClick={onClose}
    >
      <motion.div
        initial={{ y: 20, opacity: 0, scale: 0.97 }}
        animate={{ y: 0, opacity: 1, scale: 1 }}
        exit={{ y: 20, opacity: 0, scale: 0.97 }}
        transition={{ type: "spring", damping: 26, stiffness: 280 }}
        className="bg-card rounded-2xl border border-border shadow-premium w-full max-w-2xl max-h-[90vh] overflow-y-auto"
        onClick={(e) => e.stopPropagation()}
      >
        <div className="sticky top-0 bg-card border-b border-border p-4 flex items-center justify-between">
          <h3 className="font-display font-bold text-lg flex items-center gap-2">
            <Icon name="Zap" className="w-5 h-5 text-gold" />
            Test Connection — {provider.name}
          </h3>
          <Button variant="ghost" size="icon" onClick={onClose}><Icon name="X" className="w-4 h-4" /></Button>
        </div>

        <div className="p-5 space-y-4">
          {/* Provider summary */}
          <div className="rounded-lg bg-secondary/50 p-3 grid grid-cols-2 sm:grid-cols-4 gap-2 text-xs">
            <div><div className="text-muted-foreground">Type</div><div className="font-medium capitalize">{provider.type.replace("-", " ")}</div></div>
            <div><div className="text-muted-foreground">Model</div><div className="font-medium font-mono truncate">{provider.modelName || "—"}</div></div>
            <div><div className="text-muted-foreground">Base URL</div><div className="font-mono truncate">{provider.baseUrl || provider.apiUrl || "—"}</div></div>
            <div><div className="text-muted-foreground">Timeout</div><div className="font-medium">{provider.timeout}ms</div></div>
          </div>

          {/* Test prompt editor */}
          <div className="space-y-1.5">
            <label className="text-xs uppercase tracking-wide text-muted-foreground">Test prompt</label>
            <input
              value={testPrompt}
              onChange={(e) => setTestPrompt(e.target.value)}
              disabled={status === "running"}
              className="w-full h-9 px-3 rounded-md border border-input bg-background text-sm disabled:opacity-50"
            />
          </div>

          {/* Run button */}
          <Button
            onClick={runTest}
            disabled={status === "running"}
            className="w-full bg-brand hover:bg-brand-dark text-white gap-2"
          >
            {status === "running" ? (
              <><Icon name="Loader2" className="w-4 h-4 animate-spin" /> Running test…</>
            ) : (
              <><Icon name="Play" className="w-4 h-4" /> Run test connection</>
            )}
          </Button>

          {/* Steps log */}
          {steps.length > 0 && (
            <div className="rounded-lg bg-slate-900 text-slate-100 p-3 font-mono text-xs space-y-1 max-h-40 overflow-y-auto">
              {steps.map((s, i) => (
                <div key={i} className="flex items-start gap-2">
                  <span className="text-emerald-400">›</span>
                  <span>{s}</span>
                </div>
              ))}
              {status === "running" && <div className="flex items-center gap-2 text-amber-300"><span className="animate-pulse">●</span> Awaiting response…</div>}
            </div>
          )}

          {/* Result */}
          {status === "done" && result && (
            <motion.div initial={{ opacity: 0, y: 8 }} animate={{ opacity: 1, y: 0 }} className="space-y-3">
              <div className={`rounded-lg p-4 ${result.ok ? "bg-emerald-100 dark:bg-emerald-400/10 border border-emerald-300" : "bg-red-100 dark:bg-red-400/10 border border-red-300"}`}>
                <div className="flex items-center gap-2">
                  <Icon name={result.ok ? "CheckCircle2" : "XCircle"} className={`w-5 h-5 ${result.ok ? "text-emerald-600" : "text-red-600"}`} />
                  <span className={`font-semibold ${result.ok ? "text-emerald-800 dark:text-emerald-300" : "text-red-800 dark:text-red-300"}`}>
                    {result.ok ? "Connection successful" : "Connection failed"}
                  </span>
                  <Badge variant={result.ok ? "success" : "danger"} className="ml-auto">{result.latencyMs}ms</Badge>
                </div>
                <div className={`mt-2 text-sm ${result.ok ? "text-emerald-700 dark:text-emerald-400" : "text-red-700 dark:text-red-400"}`}>{result.message}</div>
              </div>

              {result.response && (
                <div>
                  <div className="text-xs font-semibold uppercase text-muted-foreground mb-1">Response</div>
                  <pre className="rounded-lg border border-border bg-secondary/50 p-3 text-xs font-mono whitespace-pre-wrap max-h-40 overflow-y-auto">{result.response}</pre>
                </div>
              )}

              <div className="grid grid-cols-3 gap-2 text-xs">
                <div className="rounded-md bg-secondary p-2"><div className="text-muted-foreground">Latency</div><div className="font-mono font-semibold">{result.latencyMs}ms</div></div>
                <div className="rounded-md bg-secondary p-2"><div className="text-muted-foreground">Input tokens</div><div className="font-mono font-semibold">{result.inputTokens ?? "—"}</div></div>
                <div className="rounded-md bg-secondary p-2"><div className="text-muted-foreground">Output tokens</div><div className="font-mono font-semibold">{result.outputTokens ?? "—"}</div></div>
              </div>
            </motion.div>
          )}
        </div>

        <div className="sticky bottom-0 bg-card border-t border-border p-4 flex justify-end gap-2">
          <Button variant="outline" onClick={onClose}>Close</Button>
          {status === "done" && <Button onClick={runTest} className="bg-brand hover:bg-brand-dark text-white gap-2"><Icon name="RotateCcw" className="w-4 h-4" /> Run again</Button>}
        </div>
      </motion.div>
    </motion.div>
  );
}

src/components/app/modules/UserApprovals:
"use client";

import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge, Icon } from "@/components/shared";
import { useApp } from "@/lib/store";
import { refreshUsers } from "@/lib/cloud-api";
import { toast } from "sonner";
import { useState, useEffect } from "react";

export function UserApprovals() {
  const users = useApp((s) => s.users);
  const approveUser = useApp((s) => s.approveUser);
  const deleteUser = useApp((s) => s.deleteUser);
  const [q, setQ] = useState("");

  // === BUG FIX: Force-refresh users from D1 on mount ===
  useEffect(() => {
    refreshUsers(useApp);
  }, []);

  const pending = users.filter((u) => u.status === "pending");
  const filtered = pending.filter((u) => `${u.name} ${u.email} ${u.username ?? ""}`.toLowerCase().includes(q.toLowerCase()));

  const handleApprove = (id: string, name: string) => {
    approveUser(id);
    toast.success(`${name} has been approved. They can now access all features.`);
  };

  const handleReject = (id: string, name: string) => {
    if (confirm(`Reject and delete ${name}'s account?`)) {
      deleteUser(id);
      toast.success(`${name}'s account has been deleted.`);
    }
  };

  return (
    <div className="space-y-6">
      <div>
        <h1 className="font-display text-2xl font-bold flex items-center gap-2">
          <Icon name="UserCheck" className="w-6 h-6 text-brand" /> User Approvals
        </h1>
        <p className="text-sm text-muted-foreground mt-1">Review and approve new user registrations. Pending users cannot access any features until approved.</p>
      </div>

      <div className="grid grid-cols-2 sm:grid-cols-3 gap-4">
        <Card><CardContent className="p-4"><div className="text-2xl font-bold font-display text-amber-600">{pending.length}</div><div className="text-xs text-muted-foreground">Pending</div></CardContent></Card>
        <Card><CardContent className="p-4"><div className="text-2xl font-bold font-display text-emerald-600">{users.filter((u) => u.status === "approved").length}</div><div className="text-xs text-muted-foreground">Approved</div></CardContent></Card>
        <Card><CardContent className="p-4"><div className="text-2xl font-bold font-display text-red-600">{users.filter((u) => u.status === "suspended").length}</div><div className="text-xs text-muted-foreground">Suspended</div></CardContent></Card>
      </div>

      <Card>
        <CardHeader>
          <div className="flex items-center justify-between gap-3 flex-wrap">
            <CardTitle className="text-lg">Pending Approvals ({filtered.length})</CardTitle>
            <input value={q} onChange={(e) => setQ(e.target.value)} placeholder="Search…" className="h-9 px-3 rounded-md border border-input bg-background text-sm w-full sm:w-64" />
          </div>
        </CardHeader>
        <CardContent>
          {filtered.length === 0 ? (
            <div className="text-center py-12">
              <Icon name="CheckCircle2" className="w-10 h-10 text-emerald-500 mx-auto" />
              <p className="text-sm text-muted-foreground mt-2">No pending approvals. You're all caught up!</p>
            </div>
          ) : (
            <div className="space-y-3">
              {filtered.map((u) => (
                <div key={u.id} className="flex items-center justify-between gap-3 p-4 rounded-lg border border-border">
                  <div className="min-w-0">
                    <div className="font-semibold text-sm flex items-center gap-2">
                      {u.name}
                      <Badge variant="warning" className="text-[9px]">PENDING</Badge>
                    </div>
                    <div className="text-xs text-muted-foreground">{u.email}</div>
                    <div className="text-xs text-muted-foreground mt-0.5">
                      {u.provider} · registered {new Date(u.createdAt).toLocaleDateString()}
                    </div>
                  </div>
                  <div className="flex gap-1.5 shrink-0">
                    <Button size="sm" onClick={() => handleApprove(u.id, u.name)} className="bg-emerald-600 hover:bg-emerald-700 text-white gap-1.5">
                      <Icon name="Check" className="w-3.5 h-3.5" /> Approve
                    </Button>
                    <Button size="sm" variant="outline" onClick={() => handleReject(u.id, u.name)} className="text-destructive gap-1.5">
                      <Icon name="X" className="w-3.5 h-3.5" /> Reject
                    </Button>
                  </div>
                </div>
              ))}
            </div>
          )}
        </CardContent>
      </Card>
    </div>
  );
}

src/components/app/modules/UserDetailMod:
"use client";

import { useState } from "react";
import { motion } from "framer-motion";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Switch } from "@/components/ui/switch";
import { Badge, Icon } from "@/components/shared";
import { useApp } from "@/lib/store";
import { toast } from "sonner";
import type { Role } from "@/lib/types";

export interface ManagedUser {
  id: string;
  name: string;
  email: string;
  role: Role;
  status: "active" | "suspended";
  resumes: number;
  lastActive: string;
  provider: string;
  createdAt: string;
  avatarColor: string;
}

export function UserDetailModal({ user, onClose }: { user: ManagedUser; onClose: () => void }) {
  const currentUser = useApp((s) => s.user);
  const log = useApp((s) => s.log);

  const [name, setName] = useState(user.name);
  const [email, setEmail] = useState(user.email);
  const [role, setRole] = useState<Role>(user.role);
  const [status, setStatus] = useState<"active" | "suspended">(user.status);
  const [saving, setSaving] = useState(false);

  const isSelf = currentUser?.email === user.email;
  const canEditRole = currentUser?.role === "super_admin" && !isSelf;
  const canSuspend = currentUser?.role === "super_admin" && !isSelf;

  const save = async () => {
    setSaving(true);
    await new Promise((r) => setTimeout(r, 400));
    setSaving(false);
    log({
      actor: currentUser?.email ?? "admin",
      action: "User updated",
      category: "admin",
      details: `${user.email}: name="${name}", role=${role}, status=${status}`,
      severity: "info",
    });
    toast.success(`Changes saved for ${user.name}.`);
    onClose();
  };

  const resetPassword = () => {
    if (!confirm(`Send a password-reset email to ${user.email}?`)) return;
    log({
      actor: currentUser?.email ?? "admin",
      action: "Password reset triggered",
      category: "auth",
      details: `Reset email sent to ${user.email}`,
      severity: "warning",
    });
    toast.success(`Password-reset email sent to ${user.email}.`);
  };

  const initials = user.name.split(/\s+/).slice(0, 2).map((s) => s[0]?.toUpperCase()).join("");

  return (
    <motion.div
      initial={{ opacity: 0 }}
      animate={{ opacity: 1 }}
      exit={{ opacity: 0 }}
      className="fixed inset-0 z-50 bg-background/80 backdrop-blur-sm flex items-center justify-center p-0 sm:p-4"
      onClick={onClose}
    >
      <motion.div
        initial={{ y: 20, opacity: 0, scale: 0.97 }}
        animate={{ y: 0, opacity: 1, scale: 1 }}
        exit={{ y: 20, opacity: 0, scale: 0.97 }}
        transition={{ type: "spring", damping: 26, stiffness: 280 }}
        className="bg-card rounded-t-2xl sm:rounded-2xl border border-border shadow-premium w-full sm:max-w-xl max-h-[95vh] overflow-y-auto"
        onClick={(e) => e.stopPropagation()}
      >
        <div className="sticky top-0 bg-card border-b border-border p-4 flex items-center justify-between">
          <h3 className="font-display font-bold text-lg flex items-center gap-2">
            <Icon name="User" className="w-5 h-5 text-brand" /> User details
          </h3>
          <Button variant="ghost" size="icon" onClick={onClose}><Icon name="X" className="w-4 h-4" /></Button>
        </div>

        <div className="p-5 space-y-5">
          {/* Avatar + identity */}
          <div className="flex items-center gap-4">
            <div className="w-16 h-16 rounded-full flex items-center justify-center text-white font-bold text-xl shrink-0" style={{ background: user.avatarColor }}>
              {initials || "?"}
            </div>
            <div className="min-w-0">
              <div className="font-semibold text-lg flex items-center gap-2">
                {user.name}
                {isSelf && <Badge variant="brand" className="text-[10px]">YOU</Badge>}
              </div>
              <div className="text-sm text-muted-foreground truncate">{user.email}</div>
              <div className="flex flex-wrap gap-1.5 mt-1">
                <Badge variant={user.role === "super_admin" ? "gold" : user.role === "admin" ? "brand" : "outline"} className="capitalize text-[10px]">{user.role.replace("_", " ")}</Badge>
                <Badge variant={user.status === "active" ? "success" : "danger"} className="capitalize text-[10px]">{user.status}</Badge>
                <Badge variant="outline" className="capitalize text-[10px]">{user.provider}</Badge>
              </div>
            </div>
          </div>

          {/* Stats */}
          <div className="grid grid-cols-3 gap-2">
            <div className="rounded-lg bg-secondary p-3 text-center">
              <div className="text-xl font-bold font-display">{user.resumes}</div>
              <div className="text-xs text-muted-foreground">Resumes</div>
            </div>
            <div className="rounded-lg bg-secondary p-3 text-center">
              <div className="text-xl font-bold font-display">{user.lastActive}</div>
              <div className="text-xs text-muted-foreground">Last active</div>
            </div>
            <div className="rounded-lg bg-secondary p-3 text-center">
              <div className="text-xl font-bold font-display">{new Date(user.createdAt).getFullYear()}</div>
              <div className="text-xs text-muted-foreground">Joined</div>
            </div>
          </div>

          {/* Editable fields */}
          <div className="grid sm:grid-cols-2 gap-3">
            <div className="space-y-1.5">
              <Label className="text-xs uppercase tracking-wide text-muted-foreground">Display name</Label>
              <Input value={name} onChange={(e) => setName(e.target.value)} disabled={isSelf ? false : !canEditRole} />
            </div>
            <div className="space-y-1.5">
              <Label className="text-xs uppercase tracking-wide text-muted-foreground">Email</Label>
              <Input value={email} onChange={(e) => setEmail(e.target.value)} disabled />
              <p className="text-[11px] text-muted-foreground flex items-center gap-1"><Icon name="Lock" className="w-3 h-3" /> Email changes require user verification.</p>
            </div>
            <div className="space-y-1.5">
              <Label className="text-xs uppercase tracking-wide text-muted-foreground">Role</Label>
              <select
                value={role}
                onChange={(e) => setRole(e.target.value as Role)}
                disabled={!canEditRole}
                className="w-full h-9 px-3 rounded-md border border-input bg-background text-sm disabled:opacity-50"
              >
                <option value="user">User</option>
                <option value="admin">Admin</option>
                <option value="super_admin">Super Admin</option>
              </select>
              {!canEditRole && <p className="text-[11px] text-muted-foreground">{isSelf ? "You can't change your own role." : "Only Super Admins can change roles."}</p>}
            </div>
            <div className="space-y-1.5">
              <Label className="text-xs uppercase tracking-wide text-muted-foreground">Account status</Label>
              <div className="flex items-center justify-between gap-3 p-2 rounded-md border border-input h-9">
                <span className="text-sm">{status === "active" ? "Active" : "Suspended"}</span>
                <Switch checked={status === "active"} onCheckedChange={(v) => setStatus(v ? "active" : "suspended")} disabled={!canSuspend} />
              </div>
              {!canSuspend && <p className="text-[11px] text-muted-foreground">{isSelf ? "You can't suspend your own account." : "Only Super Admins can suspend users."}</p>}
            </div>
          </div>

          {/* Actions */}
          <div className="rounded-lg border border-border p-3 space-y-2">
            <div className="text-sm font-medium">Account actions</div>
            <div className="flex flex-wrap gap-2">
              <Button size="sm" variant="outline" onClick={resetPassword} className="gap-1.5">
                <Icon name="Mail" className="w-3.5 h-3.5" /> Send password reset
              </Button>
              <Button
                size="sm"
                variant="outline"
                onClick={() => {
                  log({ actor: currentUser?.email ?? "admin", action: "User data exported", category: "admin", details: user.email, severity: "info" });
                  toast.success(`Data export queued for ${user.email}.`);
                }}
                className="gap-1.5"
              >
                <Icon name="Download" className="w-3.5 h-3.5" /> Export user data
              </Button>
              {canSuspend && status === "active" ? (
                <Button size="sm" variant="outline" className="text-destructive gap-1.5" onClick={() => { setStatus("suspended"); toast.info("Mark as suspended, then Save to apply."); }}>
                  <Icon name="UserX" className="w-3.5 h-3.5" /> Suspend
                </Button>
              ) : canSuspend && status === "suspended" ? (
                <Button size="sm" variant="outline" className="text-emerald-600 gap-1.5" onClick={() => { setStatus("active"); toast.info("Mark as active, then Save to apply."); }}>
                  <Icon name="UserCheck" className="w-3.5 h-3.5" /> Reactivate
                </Button>
              ) : null}
            </div>
          </div>
        </div>

        <div className="sticky bottom-0 bg-card border-t border-border p-4 flex justify-end gap-2">
          <Button variant="outline" onClick={onClose}>Cancel</Button>
          <Button onClick={save} disabled={saving} className="bg-brand hover:bg-brand-dark text-white gap-2">
            {saving ? <Icon name="Loader2" className="w-4 h-4 animate-spin" /> : <Icon name="Save" className="w-4 h-4" />}
            Save changes
          </Button>
        </div>
      </motion.div>
    </motion.div>
  );
}

src/components/app/modules/Users.tsx:
"use client";

import { useState, useEffect } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Badge, Icon } from "@/components/shared";
import { useApp } from "@/lib/store";
import { refreshUsers } from "@/lib/cloud-api";
import { toast } from "sonner";
import { UserDetailModal, type ManagedUser } from "./UserDetailModal";
import { validatePassword } from "@/lib/auth-utils";

const AVATAR_COLORS = ["#1154A3", "#F59E0B", "#10B981", "#8B5CF6", "#EC4899", "#0EA5E9", "#DC2626", "#0B1F3A"];

export function Users() {
  const users = useApp((s) => s.users);
  const currentUser = useApp((s) => s.user);
  const approveUser = useApp((s) => s.approveUser);
  const suspendUser = useApp((s) => s.suspendUser);
  const unsuspendUser = useApp((s) => s.unsuspendUser);
  const deleteUser = useApp((s) => s.deleteUser);
  const promoteToAdmin = useApp((s) => s.promoteToAdmin);
  const demoteToUser = useApp((s) => s.demoteToUser);
  const resetUserPassword = useApp((s) => s.resetUserPassword);
  const log = useApp((s) => s.log);

  // === BUG FIX: Force-refresh users from D1 on mount ===
  // This ensures the admin always sees the latest users including Puter
  // users that were created since the last sync.
  useEffect(() => {
    refreshUsers(useApp);
  }, []);

  const [q, setQ] = useState("");
  const [roleFilter, setRoleFilter] = useState("all");
  const [statusFilter, setStatusFilter] = useState("all");
  const [selected, setSelected] = useState<ManagedUser | null>(null);
  const [resetTarget, setResetTarget] = useState<ManagedUser | null>(null);
  const [newPassword, setNewPassword] = useState("");

  const filtered = users.filter((u) => {
    if (roleFilter !== "all" && u.role !== roleFilter) return false;
    if (statusFilter !== "all" && u.status !== statusFilter) return false;
    if (q && !`${u.name} ${u.email} ${u.username ?? ""}`.toLowerCase().includes(q.toLowerCase())) return false;
    return true;
  });

  const stats = {
    total: users.length,
    approved: users.filter((u) => u.status === "approved").length,
    pending: users.filter((u) => u.status === "pending").length,
    suspended: users.filter((u) => u.status === "suspended").length,
    deleted: users.filter((u) => u.status === "deleted").length,
  };

  const toManaged = (u: any): ManagedUser => ({
    id: u.id,
    name: u.name,
    email: u.email,
    role: u.role,
    status: u.status === "suspended" ? "suspended" : "active",
    resumes: u.usage?.resumesGenerated ?? 0,
    lastActive: u.lastActiveAt ? new Date(u.lastActiveAt).toLocaleDateString() : "Never",
    provider: u.provider || "email",
    createdAt: u.createdAt,
    avatarColor: AVATAR_COLORS[users.indexOf(u) % AVATAR_COLORS.length],
  });

  const handleAction = (action: string, user: any) => {
    const isSelf = user.email === currentUser?.email;
    if (isSelf && action !== "view") {
      toast.error("You cannot perform this action on your own account.");
      return;
    }
    switch (action) {
      case "approve": approveUser(user.id); toast.success(`${user.name} approved.`); break;
      case "suspend": suspendUser(user.id); toast.success(`${user.name} suspended.`); break;
      case "unsuspend": unsuspendUser(user.id); toast.success(`${user.name} reactivated.`); break;
      case "delete": if (confirm(`Delete ${user.name}? (soft delete — data preserved)`)) { deleteUser(user.id); toast.success(`${user.name} deleted.`); } break;
      case "promote": promoteToAdmin(user.id); toast.success(`${user.name} promoted to admin.`); break;
      case "demote": demoteToUser(user.id); toast.success(`${user.name} demoted to user.`); break;
      case "reset": setResetTarget(toManaged(user)); setNewPassword(""); break;
    }
  };

  const handleResetPassword = () => {
    if (!resetTarget) return;
    const check = validatePassword(newPassword);
    if (!check.valid) {
      toast.error(`Password requirements: ${check.errors.join(", ")}`);
      return;
    }
    // Find the user by email
    const targetUser = users.find((u) => u.id === resetTarget.id);
    if (targetUser) {
      resetUserPassword(targetUser.id, newPassword);
      toast.success(`Password reset for ${resetTarget.name}.`);
    }
    setResetTarget(null);
    setNewPassword("");
  };

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between flex-wrap gap-3">
        <div>
          <h1 className="font-display text-2xl font-bold flex items-center gap-2"><Icon name="Users" className="w-6 h-6 text-brand" /> User Management</h1>
          <p className="text-sm text-muted-foreground mt-1">Manage users, roles, and status. Approve, suspend, promote, or delete accounts.</p>
        </div>
      </div>

      <div className="grid grid-cols-2 lg:grid-cols-5 gap-4">
        {[
          { label: "Total", value: stats.total, icon: "Users", color: "#1154A3" },
          { label: "Approved", value: stats.approved, icon: "CheckCircle2", color: "#10B981" },
          { label: "Pending", value: stats.pending, icon: "Clock", color: "#F59E0B" },
          { label: "Suspended", value: stats.suspended, icon: "Ban", color: "#DC2626" },
          { label: "Deleted", value: stats.deleted, icon: "Trash2", color: "#6B7280" },
        ].map((s) => (
          <Card key={s.label}>
            <CardContent className="p-4 flex items-center gap-3">
              <div className="w-9 h-9 rounded-lg flex items-center justify-center" style={{ background: `${s.color}15`, color: s.color }}>
                <Icon name={s.icon} className="w-4 h-4" />
              </div>
              <div><div className="text-lg font-bold font-display">{s.value}</div><div className="text-xs text-muted-foreground">{s.label}</div></div>
            </CardContent>
          </Card>
        ))}
      </div>

      <Card>
        <CardHeader>
          <div className="flex items-center justify-between gap-3 flex-wrap">
            <CardTitle className="text-lg">All Users ({filtered.length})</CardTitle>
            <div className="flex flex-wrap gap-2">
              <select value={roleFilter} onChange={(e) => setRoleFilter(e.target.value)} className="h-9 px-3 rounded-md border border-input bg-background text-sm">
                <option value="all">All roles</option>
                <option value="user">User</option>
                <option value="admin">Admin</option>
                <option value="super_admin">Super Admin</option>
              </select>
              <select value={statusFilter} onChange={(e) => setStatusFilter(e.target.value)} className="h-9 px-3 rounded-md border border-input bg-background text-sm">
                <option value="all">All statuses</option>
                <option value="approved">Approved</option>
                <option value="pending">Pending</option>
                <option value="suspended">Suspended</option>
                <option value="deleted">Deleted</option>
              </select>
              <div className="relative w-full sm:w-64">
                <Icon name="Search" className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground" />
                <Input value={q} onChange={(e) => setQ(e.target.value)} placeholder="Search…" className="pl-9 h-9" />
              </div>
            </div>
          </div>
        </CardHeader>
        <CardContent className="p-0">
          <div className="overflow-x-auto">
            <table className="w-full text-sm">
              <thead className="border-b border-border bg-secondary/50">
                <tr className="text-left text-xs uppercase tracking-wide text-muted-foreground">
                  <th className="px-4 py-2 font-semibold">User</th>
                  <th className="px-4 py-2 font-semibold">Role</th>
                  <th className="px-4 py-2 font-semibold">Provider</th>
                  <th className="px-4 py-2 font-semibold">Status</th>
                  <th className="px-4 py-2 font-semibold">Registered</th>
                  <th className="px-4 py-2 font-semibold">Last Login</th>
                  <th className="px-4 py-2 font-semibold text-right">Actions</th>
                </tr>
              </thead>
              <tbody>
                {filtered.map((u, idx) => {
                  const isSelf = u.email === currentUser?.email;
                  const canManage = currentUser?.role === "super_admin" && !isSelf;
                  return (
                    <tr key={u.id} className="border-b border-border hover:bg-secondary/30">
                      <td className="px-4 py-3">
                        <div className="flex items-center gap-2">
                          <div className="w-8 h-8 rounded-full flex items-center justify-center text-white text-xs font-semibold shrink-0" style={{ background: AVATAR_COLORS[idx % AVATAR_COLORS.length] }}>
                            {u.name.split(/\s+/).slice(0, 2).map((s) => s[0]?.toUpperCase()).join("")}
                          </div>
                          <div className="min-w-0">
                            <div className="font-medium flex items-center gap-1.5">{u.name}{isSelf && <Badge variant="brand" className="text-[9px]">YOU</Badge>}</div>
                            <div className="text-xs text-muted-foreground truncate">{u.email}</div>
                          </div>
                        </div>
                      </td>
                      <td className="px-4 py-3"><Badge variant={u.role === "super_admin" ? "gold" : u.role === "admin" ? "brand" : "outline"} className="capitalize text-[10px]">{u.role.replace("_", " ")}</Badge></td>
                      <td className="px-4 py-3 text-xs capitalize text-muted-foreground">{u.provider}</td>
                      <td className="px-4 py-3"><Badge variant={u.status === "approved" ? "success" : u.status === "pending" ? "warning" : u.status === "suspended" ? "danger" : "outline"} className="capitalize text-[10px]">{u.status}</Badge></td>
                      <td className="px-4 py-3 text-xs text-muted-foreground">{new Date(u.createdAt).toLocaleDateString()}</td>
                      <td className="px-4 py-3 text-xs text-muted-foreground">{u.lastLoginAt ? new Date(u.lastLoginAt).toLocaleDateString() : "Never"}</td>
                      <td className="px-4 py-3">
                        <div className="flex gap-0.5 justify-end flex-wrap">
                          {u.status === "pending" && <IconBtn icon="Check" label="Approve" color="#10B981" onClick={() => handleAction("approve", u)} disabled={!canManage} />}
                          {u.status === "approved" && <IconBtn icon="Ban" label="Suspend" color="#DC2626" onClick={() => handleAction("suspend", u)} disabled={!canManage} />}
                          {u.status === "suspended" && <IconBtn icon="UserCheck" label="Unsuspend" color="#10B981" onClick={() => handleAction("unsuspend", u)} disabled={!canManage} />}
                          {u.role === "user" && <IconBtn icon="ArrowUp" label="Promote to admin" color="#1154A3" onClick={() => handleAction("promote", u)} disabled={!canManage} />}
                          {u.role === "admin" && <IconBtn icon="ArrowDown" label="Demote to user" color="#64748B" onClick={() => handleAction("demote", u)} disabled={!canManage} />}
                          <IconBtn icon="KeyRound" label="Reset password" color="#F59E0B" onClick={() => handleAction("reset", u)} disabled={!canManage} />
                          <IconBtn icon="Eye" label="View details" onClick={() => setSelected(toManaged(u))} />
                          {u.status !== "deleted" && <IconBtn icon="Trash2" label="Delete" color="#DC2626" onClick={() => handleAction("delete", u)} disabled={!canManage} />}
                        </div>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </CardContent>
      </Card>

      {selected && <UserDetailModal user={selected} onClose={() => setSelected(null)} />}
      {resetTarget && (
        <div className="fixed inset-0 z-50 bg-background/80 backdrop-blur-sm flex items-center justify-center p-4" onClick={() => setResetTarget(null)}>
          <div className="bg-card rounded-2xl border border-border shadow-premium w-full max-w-md p-6 space-y-4" onClick={(e) => e.stopPropagation()}>
            <h3 className="font-display font-bold text-lg flex items-center gap-2"><Icon name="KeyRound" className="w-5 h-5 text-brand" /> Reset Password</h3>
            <p className="text-sm text-muted-foreground">Set a new password for <strong>{resetTarget.name}</strong> ({resetTarget.email})</p>
            <Input type="password" value={newPassword} onChange={(e) => setNewPassword(e.target.value)} placeholder="Min 12 chars, Aa1!" />
            {newPassword && <p className="text-xs text-muted-foreground">Password must have 12+ chars, uppercase, lowercase, number, special char</p>}
            <div className="flex gap-2 justify-end">
              <Button variant="outline" onClick={() => setResetTarget(null)}>Cancel</Button>
              <Button onClick={handleResetPassword} className="bg-brand hover:bg-brand-dark text-white">Reset password</Button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

function IconBtn({ icon, label, onClick, color, disabled }: { icon: string; label: string; onClick: () => void; color?: string; disabled?: boolean }) {
  return (
    <button onClick={onClick} title={label} aria-label={label} disabled={disabled} className="w-7 h-7 rounded-md hover:bg-secondary flex items-center justify-center text-muted-foreground hover:text-foreground transition disabled:opacity-30 disabled:cursor-not-allowed" style={color ? { color } : undefined}>
      <Icon name={icon} className="w-3.5 h-3.5" />
    </button>
  );
}

