"use client";

import { Component, ReactNode } from "react";

/**
 * SafeRender — a lightweight error boundary that catches render crashes
 * (e.g. "Cannot read properties of undefined (reading 'map')") and shows
 * a friendly fallback instead of Next.js's default "This page couldn't load"
 * error page.
 *
 * Usage:
 *   <SafeRender label="Company Intelligence">
 *     <CompanyResearch />
 *   </SafeRender>
 *
 * When a crash occurs inside the children, the fallback shows the label +
 * a Retry button that resets the boundary's internal state. The error is
 * also logged to the console so developers can diagnose it.
 */
interface Props {
  children: ReactNode;
  label?: string;
}
interface State {
  hasError: boolean;
  error?: Error;
}

export class SafeRender extends Component<Props, State> {
  constructor(props: Props) {
    super(props);
    this.state = { hasError: false };
  }

  static getDerivedStateFromError(error: Error): State {
    return { hasError: true, error };
  }

  componentDidCatch(error: Error, info: any) {
    console.warn(`[SafeRender${this.props.label ? `: ${this.props.label}` : ""}] Render crash:`, error, info);
  }

  render() {
    if (this.state.hasError) {
      const label = this.props.label ?? "This section";
      return (
        <div className="space-y-4">
          <div className="rounded-lg border border-amber-300 bg-amber-50 dark:bg-amber-950/30 dark:border-amber-700 p-4 text-sm">
            <div className="font-semibold text-amber-800 dark:text-amber-200 mb-1 flex items-center gap-2">
              <span className="text-base">⚠</span> {label} couldn't render
            </div>
            <p className="text-xs text-amber-700 dark:text-amber-300 mb-3">
              The AI returned data in an unexpected format. This is usually transient — please try again. If the problem persists, try a different resume or job description.
            </p>
            <button
              onClick={() => this.setState({ hasError: false, error: undefined })}
              className="inline-flex items-center gap-1.5 rounded-md bg-amber-600 hover:bg-amber-700 text-white px-3 py-1.5 text-xs font-medium"
            >
              Try again
            </button>
          </div>
          {this.state.error && (
            <details className="text-[10px] text-muted-foreground">
              <summary className="cursor-pointer">Technical details</summary>
              <pre className="mt-1 whitespace-pre-wrap break-all">{this.state.error.message}</pre>
            </details>
          )}
        </div>
      );
    }
    return this.props.children;
  }
}

src/components/app/Sidebar.tsx:
"use client";

import Link from "next/link";
import { motion } from "framer-motion";
import { Logo, Icon, Badge } from "@/components/shared";
import { useApp } from "@/lib/store";
import { NAV_USER, NAV_ADMIN, NAV_SUPER, BRAND } from "@/lib/brand";
import { cn } from "@/lib/utils";

export function Sidebar() {
  const view = useApp((s) => s.view);
  const setView = useApp((s) => s.setView);
  const user = useApp((s) => s.user);
  const collapsed = useApp((s) => s.sidebarCollapsed);
  const toggle = useApp((s) => s.toggleSidebar);

  const role = user?.role ?? "user";
  const groups: { label: string; items: typeof NAV_USER }[] = [];
  groups.push({ label: "Workspace", items: NAV_USER });
  if (role === "admin" || role === "super_admin") groups.push({ label: "Admin", items: NAV_ADMIN });
  if (role === "super_admin") groups.push({ label: "Super Admin", items: NAV_SUPER });

  return (
    <aside
      className={cn(
        "shrink-0 sticky top-0 h-screen bg-sidebar text-sidebar-foreground flex-col transition-all hidden lg:flex",
        collapsed ? "w-[68px]" : "w-[260px]"
      )}
    >
      {/* Brand */}
      <div className="h-16 px-4 flex items-center justify-between border-b border-sidebar-border">
        <Link href="/" className="flex items-center min-w-0" aria-label={BRAND.name}>
          <Logo size={32} withText={!collapsed} className="[&_span]:text-sidebar-foreground [&_.gradient-text]:text-gold" />
        </Link>
        <button
          onClick={toggle}
          className="hidden lg:flex w-7 h-7 rounded-md hover:bg-sidebar-accent items-center justify-center text-sidebar-foreground/70"
          aria-label="Toggle sidebar"
        >
          <Icon name={collapsed ? "ChevronsRight" : "ChevronsLeft"} className="w-4 h-4" />
        </button>
      </div>

      {/* Nav */}
      <nav className="flex-1 overflow-y-auto p-3 space-y-5" aria-label="App navigation">
        {groups.map((g) => (
          <div key={g.label}>
            {!collapsed && (
              <div className="px-2 mb-2 text-[10px] uppercase tracking-wider text-sidebar-foreground/50 font-semibold">
                {g.label}
              </div>
            )}
            <div className="space-y-0.5">
              {g.items.map((item) => {
                const active = view === item.key;
                return (
                  <button
                    key={item.key}
                    onClick={() => setView(item.key as any)}
                    className={cn(
                      "w-full flex items-center gap-3 px-2.5 py-2 rounded-lg text-sm font-medium transition relative group",
                      active ? "bg-sidebar-accent text-white" : "text-sidebar-foreground/80 hover:bg-sidebar-accent/60 hover:text-white",
                      collapsed && "justify-center"
                    )}
                    title={collapsed ? item.label : undefined}
                  >
                    {active && (
                      <motion.div
                        layoutId="sidebar-active"
                        className="absolute left-0 top-1/2 -translate-y-1/2 w-1 h-6 rounded-r-full bg-gold"
                      />
                    )}
                    <Icon name={item.icon} className="w-4 h-4 shrink-0" />
                    {!collapsed && <span className="truncate">{item.label}</span>}
                  </button>
                );
              })}
            </div>
          </div>
        ))}
      </nav>

      {/* Upgrade / Free badge */}
      <div className="p-3 border-t border-sidebar-border">
        {!collapsed ? (
          <div className="rounded-xl bg-sidebar-accent/60 p-3 text-center">
            <Badge variant="gold" className="mb-2"><Icon name="Gift" className="w-3 h-3" /> 100% Free</Badge>
            <div className="text-xs text-sidebar-foreground/70 mb-2">No paywalls. No watermarks. Ever.</div>
            <a href={BRAND.social.github} target="_blank" rel="noreferrer noopener" className="text-xs text-gold hover:underline flex items-center justify-center gap-1">
              <Icon name="Heart" className="w-3 h-3" /> Sponsor us
            </a>
          </div>
        ) : (
          <div className="flex justify-center">
            <div className="w-9 h-9 rounded-full gradient-gold flex items-center justify-center" title="100% Free forever">
              <Icon name="Gift" className="w-4 h-4 text-sidebar" />
            </div>
          </div>
        )}
      </div>
    </aside>
  );
}

src/components/app/TopBar.tsx:
"use client";

import { useState, useEffect, useRef, useMemo } from "react";
import { Button } from "@/components/ui/button";
import { Avatar, AvatarFallback } from "@/components/ui/avatar";
import { Icon } from "@/components/shared";
import { useApp } from "@/lib/store";
import { NAV_USER, NAV_ADMIN, NAV_SUPER } from "@/lib/brand";
import {
  DropdownMenu, DropdownMenuContent, DropdownMenuItem, DropdownMenuSeparator, DropdownMenuTrigger, DropdownMenuLabel,
} from "@/components/ui/dropdown-menu";
import { motion, AnimatePresence } from "framer-motion";

interface SearchResult {
  type: "resume" | "jd" | "cover-letter" | "interview" | "view";
  id: string;
  title: string;
  subtitle: string;
  icon: string;
  color: string;
  action: () => void;
}

export function TopBar() {
  const user = useApp((s) => s.user);
  const signOut = useApp((s) => s.signOut);
  const setView = useApp((s) => s.setView);
  const toggleTheme = useApp((s) => s.toggleTheme);
  const theme = useApp((s) => s.theme);
  const view = useApp((s) => s.view);
  const resumes = useApp((s) => s.resumes);
  const jds = useApp((s) => s.jobDescriptions);
  const coverLetters = useApp((s) => s.coverLetters);
  const interviews = useApp((s) => s.interviews);
  const logs = useApp((s) => s.logs);
  const providers = useApp((s) => s.providers);
  const setActiveResume = useApp((s) => s.setActiveResume);
  const setActiveJD = useApp((s) => s.setActiveJD);
  const setActiveCoverLetter = useApp((s) => s.setActiveCoverLetter);
  const setActiveInterview = useApp((s) => s.setActiveInterview);
  const toggleSidebar = useApp((s) => s.toggleSidebar);
  const sidebarCollapsed = useApp((s) => s.sidebarCollapsed);

  const initials = (user?.name || "U").split(/\s+/).slice(0, 2).map((s) => s[0]?.toUpperCase()).join("");
  const [q, setQ] = useState("");
  const [searchOpen, setSearchOpen] = useState(false);
  const [notifOpen, setNotifOpen] = useState(false);
  const [mobileSidebarOpen, setMobileSidebarOpen] = useState(false);
  const searchInputRef = useRef<HTMLInputElement>(null);

  // Cmd/Ctrl+K to focus search
  useEffect(() => {
    const onKey = (e: KeyboardEvent) => {
      if ((e.metaKey || e.ctrlKey) && e.key.toLowerCase() === "k") {
        e.preventDefault();
        searchInputRef.current?.focus();
        setSearchOpen(true);
      }
      if (e.key === "Escape") {
        setSearchOpen(false);
        searchInputRef.current?.blur();
      }
    };
    window.addEventListener("keydown", onKey);
    return () => window.removeEventListener("keydown", onKey);
  }, []);

  // Build search results
  const results = useMemo<SearchResult[]>(() => {
    if (!q.trim()) return [];
    const query = q.toLowerCase();
    const out: SearchResult[] = [];

    // Quick views
    const viewMatches: { key: any; label: string; icon: string }[] = [
      { key: "dashboard", label: "Dashboard", icon: "LayoutDashboard" },
      { key: "ats-checker", label: "ATS Checker", icon: "ScanText" },
      { key: "builder", label: "Resume Builder", icon: "FilePlus2" },
      { key: "optimizer", label: "Resume Optimizer", icon: "Wand2" },
      { key: "cover-letter", label: "Cover Letters", icon: "Mail" },
      { key: "interview", label: "Interview Prep", icon: "MessagesSquare" },
      { key: "jd-scraper", label: "Job Scraper", icon: "Search" },
      { key: "ai-tools", label: "AI Tools", icon: "Sparkles" },
      { key: "ai-providers", label: "AI Providers", icon: "Cpu" },
      { key: "downloads", label: "Downloads", icon: "Download" },
      { key: "settings", label: "Settings", icon: "Settings" },
    ];
    for (const v of viewMatches) {
      if (v.label.toLowerCase().includes(query)) {
        out.push({
          type: "view", id: `view-${v.key}`, title: v.label, subtitle: "Go to page",
          icon: v.icon, color: "#1154A3", action: () => { setView(v.key); setSearchOpen(false); setQ(""); },
        });
      }
    }

    // Resumes
    for (const r of resumes) {
      if (`${r.name} ${r.headline ?? ""}`.toLowerCase().includes(query)) {
        out.push({
          type: "resume", id: r.id, title: r.name, subtitle: r.headline ?? "Resume",
          icon: "FileText", color: "#1154A3", action: () => { setActiveResume(r.id); setView("builder"); setSearchOpen(false); setQ(""); },
        });
      }
    }

    // Job descriptions
    for (const j of jds) {
      if (`${j.title} ${j.company ?? ""}`.toLowerCase().includes(query)) {
        out.push({
          type: "jd", id: j.id, title: j.title, subtitle: `${j.company ?? ""} · Job description`,
          icon: "Search", color: "#0EA5E9", action: () => { setActiveJD(j.id); setView("jd-scraper"); setSearchOpen(false); setQ(""); },
        });
      }
    }

    // Cover letters
    for (const c of coverLetters) {
      if (c.title.toLowerCase().includes(query)) {
        out.push({
          type: "cover-letter", id: c.id, title: c.title, subtitle: `${c.template} · Cover letter`,
          icon: "Mail", color: "#8B5CF6", action: () => { setActiveCoverLetter(c.id); setView("cover-letter"); setSearchOpen(false); setQ(""); },
        });
      }
    }

    // Interviews
    for (const i of interviews) {
      if (`${i.role ?? "Interview"} ${i.company ?? ""}`.toLowerCase().includes(query)) {
        out.push({
          type: "interview", id: i.id, title: i.role ?? "Interview prep", subtitle: `${i.company ?? ""} · ${i.questions.length} questions`,
          icon: "MessagesSquare", color: "#EC4899", action: () => { setActiveInterview(i.id); setView("interview"); setSearchOpen(false); setQ(""); },
        });
      }
    }

    return out.slice(0, 12);
  }, [q, resumes, jds, coverLetters, interviews, setView, setActiveResume, setActiveJD, setActiveCoverLetter, setActiveInterview]);

  // Build notifications from recent logs + provider status changes
  const notifications = useMemo(() => {
    const items: { id: string; icon: string; color: string; title: string; subtitle: string; time: string; severity: "info" | "warning" | "error" }[] = [];

    // Recent audit logs (last 5)
    for (const l of logs.slice(0, 5)) {
      items.push({
        id: l.id,
        icon: l.severity === "error" ? "AlertCircle" : l.severity === "warning" ? "AlertTriangle" : "Info",
        color: l.severity === "error" ? "#DC2626" : l.severity === "warning" ? "#F59E0B" : "#1154A3",
        title: l.action,
        subtitle: l.details,
        time: timeAgo(new Date(l.timestamp)),
        severity: l.severity,
      });
    }

    // Provider status alerts
    for (const p of providers) {
      if (p.status === "down" || p.status === "degraded") {
        items.push({
          id: `prov-${p.id}`,
          icon: p.status === "down" ? "XCircle" : "AlertTriangle",
          color: p.status === "down" ? "#DC2626" : "#F59E0B",
          title: `${p.name} is ${p.status}`,
          subtitle: `Check AI Providers → ${p.name}`,
          time: p.lastUsedAt ? timeAgo(new Date(p.lastUsedAt)) : "—",
          severity: p.status === "down" ? "error" : "warning",
        });
      }
    }

    return items.slice(0, 8);
  }, [logs, providers]);

  const unreadCount = notifications.filter((n) => n.severity !== "info").length;

  return (
    <>
      <header className="sticky top-0 z-40 h-16 glass border-b border-border flex items-center gap-3 px-4 sm:px-6">
        {/* Mobile sidebar toggle — actually opens the sidebar */}
        <Button
          variant="ghost"
          size="icon"
          className="lg:hidden"
          aria-label="Toggle sidebar"
          onClick={() => setMobileSidebarOpen(true)}
        >
          <Icon name="Menu" className="w-5 h-5" />
        </Button>

        {/* Search */}
        <div className="relative flex-1 max-w-md hidden sm:block">
          <Icon name="Search" className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground" />
          <input
            ref={searchInputRef}
            value={q}
            onChange={(e) => { setQ(e.target.value); setSearchOpen(true); }}
            onFocus={() => setSearchOpen(true)}
            onBlur={() => setTimeout(() => setSearchOpen(false), 150)}
            placeholder="Search resumes, jobs, cover letters… (⌘K)"
            className="w-full pl-9 pr-16 h-9 rounded-lg bg-secondary border border-transparent focus:border-border focus:bg-card text-sm transition outline-none"
          />
          <kbd className="absolute right-2 top-1/2 -translate-y-1/2 text-[10px] px-1.5 py-0.5 rounded border border-border bg-muted text-muted-foreground hidden md:block">
            ⌘K
          </kbd>

          {/* Search results dropdown */}
          <AnimatePresence>
            {searchOpen && q.trim() && (
              <motion.div
                initial={{ opacity: 0, y: -4 }}
                animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0, y: -4 }}
                className="absolute top-full left-0 right-0 mt-2 bg-card border border-border rounded-lg shadow-premium max-h-96 overflow-y-auto z-50"
              >
                {results.length === 0 ? (
                  <div className="p-6 text-center text-sm text-muted-foreground">
                    <Icon name="SearchX" className="w-8 h-8 mx-auto text-muted-foreground/40 mb-2" />
                    No results for "{q}"
                  </div>
                ) : (
                  <>
                    <div className="px-3 py-2 text-[10px] uppercase tracking-wide text-muted-foreground font-semibold border-b border-border">
                      {results.length} result{results.length === 1 ? "" : "s"}
                    </div>
                    {results.map((r) => (
                      <button
                        key={`${r.type}-${r.id}`}
                        onClick={r.action}
                        className="w-full flex items-center gap-3 px-3 py-2.5 hover:bg-secondary text-left transition border-b border-border last:border-0"
                      >
                        <div className="w-8 h-8 rounded-md flex items-center justify-center shrink-0" style={{ background: `${r.color}15`, color: r.color }}>
                          <Icon name={r.icon} className="w-4 h-4" />
                        </div>
                        <div className="min-w-0 flex-1">
                          <div className="text-sm font-medium truncate">{r.title}</div>
                          <div className="text-xs text-muted-foreground truncate">{r.subtitle}</div>
                        </div>
                        <Icon name="ArrowRight" className="w-3.5 h-3.5 text-muted-foreground shrink-0" />
                      </button>
                    ))}
                  </>
                )}
              </motion.div>
            )}
          </AnimatePresence>
        </div>

        <div className="flex-1 sm:hidden" />

        {/* Quick actions */}
        <Button variant="ghost" size="icon" onClick={toggleTheme} aria-label="Toggle theme" className="hidden sm:flex">
          <Icon name={theme === "light" ? "Moon" : "Sun"} className="w-4 h-4" />
        </Button>

        {/* Notifications */}
        <DropdownMenu open={notifOpen} onOpenChange={setNotifOpen}>
          <DropdownMenuTrigger asChild>
            <Button variant="ghost" size="icon" aria-label="Notifications" className="relative">
              <Icon name="Bell" className="w-4 h-4" />
              {unreadCount > 0 && (
                <span className="absolute top-1 right-1 min-w-[16px] h-4 px-1 rounded-full bg-red-500 text-white text-[10px] font-bold flex items-center justify-center">
                  {unreadCount}
                </span>
              )}
            </Button>
          </DropdownMenuTrigger>
          <DropdownMenuContent align="end" className="w-80 p-0">
            <div className="px-3 py-2 border-b border-border flex items-center justify-between">
              <span className="text-sm font-semibold">Notifications</span>
              <span className="text-xs text-muted-foreground">{notifications.length} total</span>
            </div>
            <div className="max-h-96 overflow-y-auto">
              {notifications.length === 0 ? (
                <div className="p-6 text-center text-sm text-muted-foreground">
                  <Icon name="CheckCircle2" className="w-8 h-8 mx-auto text-emerald-500 mb-2" />
                  You're all caught up!
                </div>
              ) : (
                notifications.map((n) => (
                  <DropdownMenuItem key={n.id} className="p-3 cursor-pointer flex items-start gap-2 border-b border-border last:border-0">
                    <div className="w-7 h-7 rounded-md flex items-center justify-center shrink-0 mt-0.5" style={{ background: `${n.color}15`, color: n.color }}>
                      <Icon name={n.icon} className="w-3.5 h-3.5" />
                    </div>
                    <div className="min-w-0 flex-1">
                      <div className="text-sm font-medium truncate">{n.title}</div>
                      <div className="text-xs text-muted-foreground truncate">{n.subtitle}</div>
                      <div className="text-[10px] text-muted-foreground mt-0.5">{n.time}</div>
                    </div>
                  </DropdownMenuItem>
                ))
              )}
            </div>
            <div className="p-2 border-t border-border">
              <Button
                variant="ghost"
                size="sm"
                className="w-full text-xs"
                onClick={() => { setView("logs"); setNotifOpen(false); }}
              >
                View all audit logs
              </Button>
            </div>
          </DropdownMenuContent>
        </DropdownMenu>

        {/* Desktop sidebar collapse toggle */}
        <Button
          variant="ghost"
          size="icon"
          onClick={toggleSidebar}
          aria-label={sidebarCollapsed ? "Expand sidebar" : "Collapse sidebar"}
          className="hidden lg:flex"
        >
          <Icon name={sidebarCollapsed ? "PanelLeftOpen" : "PanelLeftClose"} className="w-4 h-4" />
        </Button>

        {/* User menu */}
        <DropdownMenu>
          <DropdownMenuTrigger asChild>
            <button className="flex items-center gap-2 px-2 py-1.5 rounded-lg hover:bg-secondary transition" aria-label="Account menu">
              <Avatar className="w-7 h-7">
                <AvatarFallback className="bg-brand text-white text-xs font-semibold">{initials}</AvatarFallback>
              </Avatar>
              <div className="hidden sm:block text-left leading-none">
                <div className="text-xs font-semibold">{user?.name}</div>
                <div className="text-[10px] text-muted-foreground capitalize">{user?.role.replace("_", " ")}</div>
              </div>
              <Icon name="ChevronDown" className="w-3.5 h-3.5 text-muted-foreground hidden sm:block" />
            </button>
          </DropdownMenuTrigger>
          <DropdownMenuContent align="end" className="w-56">
            <DropdownMenuLabel>
              <div className="text-sm font-semibold">{user?.name}</div>
              <div className="text-xs text-muted-foreground font-normal">{user?.email}</div>
              <div className="text-[10px] text-muted-foreground mt-1 capitalize">{user?.provider} · {user?.role.replace("_", " ")}</div>
            </DropdownMenuLabel>
            <DropdownMenuSeparator />
            <DropdownMenuItem onClick={() => setView("settings")}>
              <Icon name="Settings" className="w-4 h-4 mr-2" /> Account settings
            </DropdownMenuItem>
            <DropdownMenuItem onClick={() => setView("downloads")}>
              <Icon name="Download" className="w-4 h-4 mr-2" /> My downloads
            </DropdownMenuItem>
            <DropdownMenuItem onClick={toggleTheme}>
              <Icon name={theme === "light" ? "Moon" : "Sun"} className="w-4 h-4 mr-2" /> {theme === "light" ? "Dark mode" : "Light mode"}
            </DropdownMenuItem>
            <DropdownMenuSeparator />
            <DropdownMenuItem onClick={() => setView("settings")} className="gap-2">
              <Icon name="KeyRound" className="w-4 h-4 mr-2" /> Change password
            </DropdownMenuItem>
            <DropdownMenuSeparator />
            <DropdownMenuItem onClick={signOut} className="text-destructive focus:text-destructive">
              <Icon name="LogOut" className="w-4 h-4 mr-2" /> Sign out
            </DropdownMenuItem>
          </DropdownMenuContent>
        </DropdownMenu>
      </header>

      {/* Mobile sidebar drawer */}
      <AnimatePresence>
        {mobileSidebarOpen && (
          <MobileSidebarDrawer onClose={() => setMobileSidebarOpen(false)} />
        )}
      </AnimatePresence>
    </>
  );
}

function MobileSidebarDrawer({ onClose }: { onClose: () => void }) {
  const setView = useApp((s) => s.setView);
  const user = useApp((s) => s.user);
  const toggleTheme = useApp((s) => s.toggleTheme);
  const theme = useApp((s) => s.theme);
  const signOut = useApp((s) => s.signOut);

  const role = user?.role ?? "user";
  const groups: { label: string; items: any[] }[] = [{ label: "Workspace", items: NAV_USER }];
  if (role === "admin" || role === "super_admin") groups.push({ label: "Admin", items: NAV_ADMIN });
  if (role === "super_admin") groups.push({ label: "Super Admin", items: NAV_SUPER });

  return (
    <motion.div
      initial={{ opacity: 0 }}
      animate={{ opacity: 1 }}
      exit={{ opacity: 0 }}
      className="fixed inset-0 z-50 bg-background/80 backdrop-blur-sm lg:hidden"
      onClick={onClose}
    >
      <motion.div
        initial={{ x: -260 }}
        animate={{ x: 0 }}
        exit={{ x: -260 }}
        transition={{ type: "spring", damping: 28, stiffness: 280 }}
        className="bg-sidebar text-sidebar-foreground w-[260px] h-full flex flex-col"
        onClick={(e) => e.stopPropagation()}
      >
        <div className="h-16 px-4 flex items-center justify-between border-b border-sidebar-border">
          <div className="font-display font-bold text-lg">ResumeAI <span className="text-gold">Pro</span></div>
          <Button variant="ghost" size="icon" onClick={onClose} className="text-sidebar-foreground hover:bg-sidebar-accent">
            <Icon name="X" className="w-5 h-5" />
          </Button>
        </div>
        <nav className="flex-1 overflow-y-auto p-3 space-y-5">
          {groups.map((g) => (
            <div key={g.label}>
              <div className="px-2 mb-2 text-[10px] uppercase tracking-wider text-sidebar-foreground/50 font-semibold">{g.label}</div>
              <div className="space-y-0.5">
                {g.items.map((item: any) => (
                  <button
                    key={item.key}
                    onClick={() => { setView(item.key); onClose(); }}
                    className="w-full flex items-center gap-3 px-2.5 py-2 rounded-lg text-sm font-medium text-sidebar-foreground/80 hover:bg-sidebar-accent hover:text-white transition"
                  >
                    <Icon name={item.icon} className="w-4 h-4 shrink-0" />
                    <span>{item.label}</span>
                  </button>
                ))}
              </div>
            </div>
          ))}
        </nav>
        <div className="p-3 border-t border-sidebar-border space-y-1">
          <button onClick={toggleTheme} className="w-full flex items-center gap-3 px-2.5 py-2 rounded-lg text-sm text-sidebar-foreground/80 hover:bg-sidebar-accent">
            <Icon name={theme === "light" ? "Moon" : "Sun"} className="w-4 h-4" /> {theme === "light" ? "Dark mode" : "Light mode"}
          </button>
          <button onClick={signOut} className="w-full flex items-center gap-3 px-2.5 py-2 rounded-lg text-sm text-red-300 hover:bg-sidebar-accent">
            <Icon name="LogOut" className="w-4 h-4" /> Sign out
          </button>
        </div>
      </motion.div>
    </motion.div>
  );
}

function timeAgo(d: Date): string {
  const seconds = Math.floor((Date.now() - d.getTime()) / 1000);
  if (seconds < 60) return "just now";
  if (seconds < 3600) return `${Math.floor(seconds / 60)}m ago`;
  if (seconds < 86400) return `${Math.floor(seconds / 3600)}h ago`;
  if (seconds < 604800) return `${Math.floor(seconds / 86400)}d ago`;
  return d.toLocaleDateString();
}

src/components/interview/InterviewPrepSu:
"use client";

import { useState, useCallback, useRef } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge, Icon, ScoreRing } from "@/components/shared";
import { callAI, extractJSON } from "@/lib/ai";
import { toast } from "sonner";
import type { ResumeData, JobDescription, InterviewPackage, InterviewQuestion } from "@/lib/types";
import { useApp, uid } from "@/lib/store";

// ============================================================================
// Types
// ============================================================================

interface WebSearchResult {
  query: string;
  title: string;
  url: string;
  snippet: string;
  source: string;
}

interface InterviewPrepResult {
  readinessScore: number;
  companyInsights: string[];
  likelyTopics: string[];
  skillsToReview: string[];
  questions: InterviewQuestion[];
}

interface InterviewPrepSuiteProps {
  optimizedResume: ResumeData;
  jd: JobDescription;
  onClose: () => void;
}

const CATEGORIES = [
  { id: "technical", label: "Technical", icon: "Code2", color: "#1154A3" },
  { id: "behavioral", label: "Behavioral", icon: "Users", color: "#F59E0B" },
  { id: "situational", label: "Situational", icon: "GitBranch", color: "#10B981" },
  { id: "hr", label: "HR", icon: "UserCheck", color: "#8B5CF6" },
  { id: "company", label: "Company-specific", icon: "Building2", color: "#EC4899" },
] as const;

const DIFFICULTY_COLORS: Record<string, string> = { easy: "#10B981", medium: "#F59E0B", hard: "#DC2626" };

// ============================================================================
// Main component
// ============================================================================

export function InterviewPrepSuite({ optimizedResume, jd, onClose }: InterviewPrepSuiteProps) {
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [prepResult, setPrepResult] = useState<InterviewPrepResult | null>(null);
  const [webResults, setWebResults] = useState<WebSearchResult[]>([]);
  const [expandedQuestion, setExpandedQuestion] = useState<string | null>(null);
  const [showMockInterview, setShowMockInterview] = useState(false);

  const addInterview = useApp((s) => s.addInterview);
  const incUsage = useApp((s) => s.incUsage);
  const log = useApp((s) => s.log);

  const company = jd.company || "";
  const jobTitle = jd.title || "";

  // === Generate interview prep package ===
  const generatePrep = useCallback(async () => {
    setLoading(true);
    setError(null);
    setPrepResult(null);
    setWebResults([]);

    try {
      // Step 1: Web research (parallel with AI generation)
      const webSearchPromise = fetch("/api/web-search", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ company, jobTitle, industry: "" }),
      }).then((r) => r.json()).catch(() => ({ results: [] }));

      // Step 2: AI generates the interview prep package
      const resumeContext = JSON.stringify({
        name: optimizedResume.name,
        headline: optimizedResume.headline,
        summary: optimizedResume.summary,
        experience: optimizedResume.experience.map((e) => ({
          title: e.title,
          company: e.company,
          bullets: e.bullets,
        })),
        skills: optimizedResume.skills.map((s) => s.name),
        education: optimizedResume.education.map((ed) => ({ degree: ed.degree, institution: ed.institution })),
        languages: optimizedResume.languages.map((l) => l.name),
      });

      const jdContext = jd.rawText ?? JSON.stringify({
        title: jd.title,
        company: jd.company,
        responsibilities: jd.responsibilities,
        requiredSkills: jd.requiredSkills,
        keywords: jd.keywords,
      });

      const result = await callAI({
        systemPrompt: `You are an expert interview coach. Generate a comprehensive interview preparation package for a ${jobTitle} role${company ? ` at ${company}` : ""}. Use the candidate's resume and the job description to generate TAILORED questions that align with their actual experience and skills. NEVER ask about technologies or experiences not present in the resume. Return ONLY valid JSON.`,
        userPrompt: `CANDIDATE'S OPTIMIZED RESUME:
${resumeContext}

JOB DESCRIPTION:
${jdContext}

Generate an interview preparation package with 9-15 questions. Distribution:
- 3-5 Technical questions (about technologies in the resume)
- 3-5 Behavioral questions (STAR method, past experiences from the resume)
- 2-3 Situational questions (hypothetical scenarios relevant to the role)
- 1-3 Company-specific questions (about the company's values, culture, products)

For each question, provide:
- category: "technical" | "behavioral" | "situational" | "hr" | "company"
- question: the interview question
- difficulty: "easy" | "medium" | "hard"
- recommendedAnswer: a recruiter-grade answer using the candidate's REAL experience
- talkingPoints: 3-5 bullet points for the answer
- starExample: { situation, task, action, result } (for behavioral questions)
- followUps: 2-3 follow-up questions the interviewer might ask

Also provide:
- readinessScore: 0-100 (how prepared the candidate is for this role)
- companyInsights: 3-5 insights about the company/role
- likelyTopics: 5-8 topics likely to come up in the interview
- skillsToReview: 3-5 skills the candidate should brush up on

Return JSON:
{
  "readinessScore": 78,
  "companyInsights": ["insight1", "insight2", ...],
  "likelyTopics": ["topic1", "topic2", ...],
  "skillsToReview": ["skill1", "skill2", ...],
  "questions": [
    {
      "category": "technical",
      "question": "...",
      "difficulty": "medium",
      "recommendedAnswer": "...",
      "talkingPoints": ["...", "..."],
      "starExample": { "situation": "...", "task": "...", "action": "...", "result": "..." },
      "followUps": ["...", "..."]
    }
  ]
}`,
        maxTokens: 6000,
        temperature: 0.5,
        taskCategory: "document",
      });

      // Parse the AI response
      let parsed: InterviewPrepResult;
      try {
        const data = extractJSON<any>(result.text);
        parsed = {
          readinessScore: typeof data.readinessScore === "number" ? data.readinessScore : 75,
          companyInsights: Array.isArray(data.companyInsights) ? data.companyInsights : [],
          likelyTopics: Array.isArray(data.likelyTopics) ? data.likelyTopics : [],
          skillsToReview: Array.isArray(data.skillsToReview) ? data.skillsToReview : [],
          questions: (Array.isArray(data.questions) ? data.questions : []).map((q: any) => ({
            id: uid("q"),
            category: q.category || "hr",
            question: q.question || "",
            difficulty: q.difficulty || "medium",
            recommendedAnswer: q.recommendedAnswer || "",
            talkingPoints: Array.isArray(q.talkingPoints) ? q.talkingPoints : [],
            starExample: q.starExample,
            followUps: Array.isArray(q.followUps) ? q.followUps : [],
          })),
        };
      } catch {
        throw new Error("Failed to parse interview prep response. Please try again.");
      }

      if (!parsed.questions.length) {
        throw new Error("No questions generated. Please try again.");
      }

      // Get web search results
      const webData = await webSearchPromise;
      setWebResults(webData.results || []);

      setPrepResult(parsed);

      // Save to store
      const pkg: InterviewPackage = {
        id: uid("iv"),
        resumeId: optimizedResume.id,
        jdId: jd.id,
        company,
        role: jobTitle,
        questions: parsed.questions,
        createdAt: new Date().toISOString(),
      };
      addInterview(pkg);
      incUsage("interviewPreps");
      log({
        actor: "you",
        action: "Interview prep generated",
        category: "ai",
        details: `${parsed.questions.length} questions for ${jobTitle}${company ? ` at ${company}` : ""} · readiness ${parsed.readinessScore}/100`,
        severity: "info",
      });

      toast.success(`${parsed.questions.length} tailored interview questions generated!`);
    } catch (e: any) {
      setError(e?.message || "Failed to generate interview prep. Please try again.");
      toast.error(e?.message || "Failed to generate interview prep.");
    } finally {
      setLoading(false);
    }
  }, [optimizedResume, jd, company, jobTitle, addInterview, incUsage, log]);

  // === Start mock interview with preloaded questions ===
  const startMockInterview = () => {
    if (!prepResult) return;
    setShowMockInterview(true);
  };

  // === Render ===
  if (showMockInterview && prepResult) {
    // Dynamically load the mock interview with preloaded questions
    return (
      <PreloadedMockInterview
        questions={prepResult.questions}
        company={company}
        jobTitle={jobTitle}
        onClose={() => setShowMockInterview(false)}
      />
    );
  }

  return (
    <div className="space-y-4">
      {/* Header */}
      <Card>
        <CardContent className="p-4 sm:p-5">
          <div className="flex items-center justify-between gap-3 flex-wrap">
            <div className="flex items-center gap-2 min-w-0">
              <Icon name="GraduationCap" className="w-5 h-5 text-brand shrink-0" />
              <div className="min-w-0">
                <h2 className="font-semibold text-sm sm:text-base truncate">Interview Preparation Suite</h2>
                <p className="text-xs text-muted-foreground">{jobTitle}{company ? ` at ${company}` : ""} · AI-tailored questions + live web research</p>
              </div>
            </div>
            <Button variant="ghost" size="sm" onClick={onClose} className="gap-1.5 shrink-0">
              <Icon name="X" className="w-4 h-4" /> Back
            </Button>
          </div>
        </CardContent>
      </Card>

      {/* Generate button (if not yet generated) */}
      {!prepResult && !loading && (
        <Card>
          <CardContent className="p-5 sm:p-6 text-center">
            <Icon name="Sparkles" className="w-10 h-10 text-brand mx-auto" />
            <h3 className="mt-3 font-semibold text-base">Generate Your Interview Prep Package</h3>
            <p className="text-sm text-muted-foreground mt-1 max-w-md mx-auto">
              Get 9-15 tailored interview questions with recruiter-grade answers, talking points, STAR examples, and follow-up questions — all aligned with your optimized resume and the job description.
            </p>
            <Button onClick={generatePrep} className="bg-brand hover:bg-brand-dark text-white gap-2 mt-4">
              <Icon name="Wand2" className="w-4 h-4" /> Generate Interview Prep
            </Button>
            <p className="text-[10px] text-muted-foreground mt-2">Includes live web research for company-specific insights</p>
          </CardContent>
        </Card>
      )}

      {/* Loading */}
      {loading && (
        <Card>
          <CardContent className="p-5 sm:p-6">
            <div className="flex items-center gap-3 mb-4">
              <Icon name="Loader2" className="w-5 h-5 text-brand animate-spin" />
              <div>
                <div className="text-sm font-semibold">Generating interview prep package…</div>
                <div className="text-xs text-muted-foreground">Researching company + generating tailored questions</div>
              </div>
            </div>
            <div className="space-y-2">
              {[1, 2, 3].map((i) => (
                <div key={i} className="rounded-lg bg-secondary/40 p-3 animate-pulse">
                  <div className="flex gap-2 mb-2">
                    <div className="h-5 w-20 bg-secondary rounded-full" />
                    <div className="h-5 w-16 bg-secondary rounded-full" />
                  </div>
                  <div className="h-4 w-full bg-secondary rounded mb-1.5" />
                  <div className="h-3 w-3/4 bg-secondary rounded" />
                </div>
              ))}
            </div>
          </CardContent>
        </Card>
      )}

      {/* Error */}
      {error && (
        <Card className="border-red-200 dark:border-red-900">
          <CardContent className="p-4 flex items-center justify-between gap-3">
            <div className="flex items-center gap-2 min-w-0">
              <Icon name="AlertCircle" className="w-5 h-5 text-red-600 shrink-0" />
              <span className="text-sm text-red-700 dark:text-red-400 truncate">{error}</span>
            </div>
            <Button size="sm" onClick={generatePrep} className="bg-red-600 hover:bg-red-700 text-white shrink-0">Retry</Button>
          </CardContent>
        </Card>
      )}

      {/* Results */}
      {prepResult && (
        <>
          {/* Readiness Score */}
          <Card>
            <CardContent className="p-5 sm:p-6 flex flex-col sm:flex-row items-center gap-4">
              <ScoreRing value={prepResult.readinessScore} size={100} label="Readiness" />
              <div className="flex-1 text-center sm:text-left">
                <h3 className="font-semibold text-sm">Interview Readiness Score</h3>
                <p className="text-xs text-muted-foreground mt-0.5">
                  {prepResult.readinessScore >= 80 ? "Excellent — you're well-prepared for this interview!" :
                   prepResult.readinessScore >= 60 ? "Good — review the topics below to improve further." :
                   "Needs work — focus on the skills to review and practice the questions."}
                </p>
                <Button size="sm" onClick={startMockInterview} className="bg-brand hover:bg-brand-dark text-white gap-1.5 mt-3">
                  <Icon name="Mic" className="w-3.5 h-3.5" /> Start Mock Interview
                </Button>
              </div>
            </CardContent>
          </Card>

          {/* Company Insights + Likely Topics + Skills */}
          <div className="grid md:grid-cols-3 gap-4">
            {prepResult.companyInsights.length > 0 && (
              <Card>
                <CardHeader className="pb-2"><CardTitle className="text-xs flex items-center gap-1.5"><Icon name="Building2" className="w-3.5 h-3.5 text-brand" /> Company Insights</CardTitle></CardHeader>
                <CardContent className="pt-0">
                  <ul className="space-y-1">
                    {prepResult.companyInsights.map((insight, i) => (
                      <li key={i} className="text-xs text-foreground/80 flex gap-1.5"><span className="text-brand shrink-0">›</span> {insight}</li>
                    ))}
                  </ul>
                </CardContent>
              </Card>
            )}
            {prepResult.likelyTopics.length > 0 && (
              <Card>
                <CardHeader className="pb-2"><CardTitle className="text-xs flex items-center gap-1.5"><Icon name="ListChecks" className="w-3.5 h-3.5 text-amber-500" /> Likely Topics</CardTitle></CardHeader>
                <CardContent className="pt-0">
                  <div className="flex flex-wrap gap-1">
                    {prepResult.likelyTopics.map((topic, i) => <Badge key={i} variant="outline" className="text-[10px]">{topic}</Badge>)}
                  </div>
                </CardContent>
              </Card>
            )}
            {prepResult.skillsToReview.length > 0 && (
              <Card>
                <CardHeader className="pb-2"><CardTitle className="text-xs flex items-center gap-1.5"><Icon name="BookOpen" className="w-3.5 h-3.5 text-emerald-600" /> Skills To Review</CardTitle></CardHeader>
                <CardContent className="pt-0">
                  <div className="flex flex-wrap gap-1">
                    {prepResult.skillsToReview.map((skill, i) => <Badge key={i} variant="warning" className="text-[10px]">{skill}</Badge>)}
                  </div>
                </CardContent>
              </Card>
            )}
          </div>

          {/* Web Research Results */}
          {webResults.length > 0 && (
            <Card>
              <CardHeader className="pb-2">
                <CardTitle className="text-xs flex items-center gap-1.5"><Icon name="Globe" className="w-3.5 h-3.5 text-brand" /> Live Web Research</CardTitle>
                <CardDescription className="text-[10px]">Real search results about {company || jobTitle} interviews</CardDescription>
              </CardHeader>
              <CardContent className="pt-0">
                <div className="space-y-1.5 max-h-40 overflow-y-auto">
                  {webResults.slice(0, 10).map((r, i) => (
                    <a key={i} href={r.url} target="_blank" rel="noreferrer noopener" className="block rounded-lg p-2 hover:bg-secondary/50 transition">
                      <div className="text-xs font-medium text-brand truncate">{r.title}</div>
                      <div className="text-[10px] text-muted-foreground truncate">{r.source} — {r.snippet.slice(0, 100)}{r.snippet.length > 100 ? "…" : ""}</div>
                    </a>
                  ))}
                </div>
              </CardContent>
            </Card>
          )}

          {/* Questions */}
          <Card>
            <CardHeader>
              <CardTitle className="text-sm flex items-center gap-2"><Icon name="MessagesSquare" className="w-4 h-4 text-brand" /> Interview Questions ({prepResult.questions.length})</CardTitle>
              <CardDescription className="text-xs">Tailored to your resume and the job description</CardDescription>
            </CardHeader>
            <CardContent>
              <div className="space-y-3">
                {prepResult.questions.map((q, i) => {
                  const cat = CATEGORIES.find((c) => c.id === q.category) ?? CATEGORIES[0];
                  const isOpen = expandedQuestion === q.id;
                  return (
                    <div key={q.id} className="rounded-xl border border-border overflow-hidden">
                      <button onClick={() => setExpandedQuestion(isOpen ? null : q.id)} className="w-full flex items-start gap-3 p-3 text-left hover:bg-secondary/50 transition">
                        <div className="w-7 h-7 rounded-lg flex items-center justify-center shrink-0" style={{ background: `${cat.color}15`, color: cat.color }}>
                          <Icon name={cat.icon} className="w-3.5 h-3.5" />
                        </div>
                        <div className="flex-1 min-w-0">
                          <div className="flex items-center gap-1.5 mb-0.5 flex-wrap">
                            <Badge variant="outline" className="text-[9px] uppercase tracking-wide">{cat.label}</Badge>
                            <span className="text-[9px] px-1.5 py-0.5 rounded-full font-semibold" style={{ background: `${DIFFICULTY_COLORS[q.difficulty]}20`, color: DIFFICULTY_COLORS[q.difficulty] }}>{q.difficulty}</span>
                          </div>
                          <div className="text-xs font-semibold text-pretty">{i + 1}. {q.question}</div>
                        </div>
                        <Icon name="ChevronDown" className={`w-3.5 h-3.5 text-muted-foreground shrink-0 transition-transform ${isOpen ? "rotate-180" : ""}`} />
                      </button>
                      {isOpen && (
                        <motion.div initial={{ height: 0, opacity: 0 }} animate={{ height: "auto", opacity: 1 }} className="overflow-hidden">
                          <div className="p-3 pt-0 space-y-2.5 text-xs">
                            {q.recommendedAnswer && (
                              <div>
                                <div className="text-[10px] font-semibold uppercase tracking-wide text-muted-foreground mb-0.5">Recommended Answer</div>
                                <p className="text-foreground/90 text-pretty">{q.recommendedAnswer}</p>
                              </div>
                            )}
                            {q.talkingPoints.length > 0 && (
                              <div>
                                <div className="text-[10px] font-semibold uppercase tracking-wide text-muted-foreground mb-0.5">Talking Points</div>
                                <ul className="space-y-0.5">{q.talkingPoints.map((t, j) => <li key={j} className="flex gap-1.5"><span className="text-brand">›</span> {t}</li>)}</ul>
                              </div>
                            )}
                            {q.starExample && (
                              <div>
                                <div className="text-[10px] font-semibold uppercase tracking-wide text-muted-foreground mb-0.5">STAR Example</div>
                                <div className="rounded-lg bg-secondary p-2 space-y-0.5 text-[11px]">
                                  <div><span className="font-semibold text-brand">Situation:</span> {q.starExample.situation}</div>
                                  <div><span className="font-semibold text-brand">Task:</span> {q.starExample.task}</div>
                                  <div><span className="font-semibold text-brand">Action:</span> {q.starExample.action}</div>
                                  <div><span className="font-semibold text-brand">Result:</span> {q.starExample.result}</div>
                                </div>
                              </div>
                            )}
                            {q.followUps.length > 0 && (
                              <div>
                                <div className="text-[10px] font-semibold uppercase tracking-wide text-muted-foreground mb-0.5">Follow-Up Questions</div>
                                <ul className="space-y-0.5">{q.followUps.map((f, j) => <li key={j} className="flex gap-1.5"><span className="text-gold">?</span> {f}</li>)}</ul>
                              </div>
                            )}
                          </div>
                        </motion.div>
                      )}
                    </div>
                  );
                })}
              </div>
            </CardContent>
          </Card>

          {/* Start Mock Interview */}
          <Card className="gradient-brand text-white">
            <CardContent className="p-5 text-center">
              <Icon name="Mic" className="w-8 h-8 mx-auto mb-2 text-gold" />
              <h3 className="font-semibold">Ready to practice?</h3>
              <p className="text-xs opacity-90 mt-0.5">Start a mock interview with these preloaded questions</p>
              <Button onClick={startMockInterview} className="bg-white text-brand hover:bg-white/90 gap-2 mt-3">
                <Icon name="Play" className="w-4 h-4" /> Start Mock Interview
              </Button>
            </CardContent>
          </Card>
        </>
      )}
    </div>
  );
}

// ============================================================================
// Preloaded Mock Interview — uses questions from the prep suite
// ============================================================================

function PreloadedMockInterview({ questions, company, jobTitle, onClose }: {
  questions: InterviewQuestion[];
  company: string;
  jobTitle: string;
  onClose: () => void;
}) {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [answers, setAnswers] = useState<Record<string, { answer: string; submitted: boolean; feedback?: any }>>({});
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [showResults, setShowResults] = useState(false);

  const total = questions.length;
  const current = questions[currentIndex];
  const isLast = currentIndex === total - 1;
  const percent = Math.round(((currentIndex + 1) / total) * 100);
  const answeredCount = Object.values(answers).filter((a) => a.submitted).length;

  const submitAnswer = useCallback(async () => {
    if (!current || !answers[current.id]?.answer?.trim()) {
      toast.error("Please write an answer before submitting.");
      return;
    }
    setSubmitting(true);
    setError(null);
    try {
      const result = await callAI({
        systemPrompt: "You are an expert interview coach. Evaluate the candidate's answer and provide feedback. Return ONLY valid JSON.",
        userPrompt: `Question: ${current.question}\nCandidate's answer: ${answers[current.id].answer}\nRecommended answer: ${current.recommendedAnswer}\n\nReturn JSON: { "strengths": ["..."], "improvements": ["..."], "score": 85 }`,
        maxTokens: 1000,
        temperature: 0.4,
        taskCategory: "document",
      });
      const feedback = extractJSON<any>(result.text);
      setAnswers((prev) => ({ ...prev, [current.id]: { ...prev[current.id], feedback, submitted: true } }));
      toast.success(`Scored ${feedback.score}/100`);
    } catch (e: any) {
      setError(e?.message || "Failed to get feedback.");
    } finally {
      setSubmitting(false);
    }
  }, [current, answers]);

  if (showResults) {
    const scores = Object.values(answers).filter((a) => a.feedback).map((a) => a.feedback.score);
    const avg = scores.length ? Math.round(scores.reduce((s, n) => s + n, 0) / scores.length) : 0;
    return (
      <div className="space-y-4">
        <Card className="gradient-brand text-white">
          <CardContent className="p-5 text-center">
            <Icon name="Trophy" className="w-10 h-10 mx-auto mb-2 text-gold" />
            <h2 className="font-display text-xl font-bold">Mock Interview Complete!</h2>
            <p className="text-sm opacity-90 mt-1">{jobTitle}{company ? ` at ${company}` : ""}</p>
            <p className="text-xs opacity-75 mt-1">{answeredCount} of {total} questions answered</p>
          </CardContent>
        </Card>
        <Card><CardContent className="p-5 flex flex-col items-center">
          <ScoreRing value={avg} size={120} label="Overall Score" />
        </CardContent></Card>
        <div className="flex gap-2 justify-center">
          <Button variant="outline" onClick={() => setShowResults(false)} className="gap-1.5"><Icon name="RotateCcw" className="w-4 h-4" /> Review Answers</Button>
          <Button onClick={onClose} className="bg-brand hover:bg-brand-dark text-white gap-1.5"><Icon name="Check" className="w-4 h-4" /> Done</Button>
        </div>
      </div>
    );
  }

  if (!current) return null;
  const cat = CATEGORIES.find((c) => c.id === current.category) ?? CATEGORIES[0];

  return (
    <div className="space-y-4">
      <Card>
        <CardContent className="p-4 flex items-center justify-between gap-3">
          <div className="flex items-center gap-2 min-w-0">
            <Icon name="Mic" className="w-5 h-5 text-brand shrink-0" />
            <div className="min-w-0">
              <h2 className="font-semibold text-sm truncate">Mock Interview — {jobTitle}{company ? ` at ${company}` : ""}</h2>
              <p className="text-xs text-muted-foreground">Preloaded from your interview prep package</p>
            </div>
          </div>
          <Button variant="ghost" size="sm" onClick={onClose} className="gap-1.5 shrink-0"><Icon name="X" className="w-4 h-4" /> Exit</Button>
        </CardContent>
      </Card>

      <Card>
        <CardContent className="p-4">
          <div className="flex items-center justify-between text-xs mb-2">
            <span className="font-medium text-muted-foreground">Question {currentIndex + 1} of {total}</span>
            <span className="font-bold text-brand">{percent}%</span>
          </div>
          <div className="h-2.5 bg-secondary rounded-full overflow-hidden">
            <motion.div className="h-full bg-gradient-to-r from-brand to-brand-dark rounded-full" animate={{ width: `${percent}%` }} />
          </div>
          <div className="flex items-center justify-between mt-2 text-[10px] text-muted-foreground">
            <span>{answeredCount} answered</span><span>{total - answeredCount} remaining</span>
          </div>
        </CardContent>
      </Card>

      <AnimatePresence mode="wait">
        <motion.div key={current.id} initial={{ opacity: 0, x: 20 }} animate={{ opacity: 1, x: 0 }} exit={{ opacity: 0, x: -20 }}>
          <Card>
            <CardContent className="p-4 sm:p-5 space-y-3">
              <div className="flex gap-1.5 flex-wrap">
                <Badge variant="outline" className="text-[9px]">{cat.label}</Badge>
                <span className="text-[9px] px-2 py-0.5 rounded-full font-semibold" style={{ background: `${DIFFICULTY_COLORS[current.difficulty]}20`, color: DIFFICULTY_COLORS[current.difficulty] }}>{current.difficulty}</span>
              </div>
              <p className="text-sm sm:text-base font-semibold text-pretty">{current.question}</p>
              {current.talkingPoints.length > 0 && (
                <div className="rounded-lg bg-secondary/40 p-2.5">
                  <div className="text-[10px] uppercase tracking-wide text-muted-foreground font-semibold mb-1">Talking Points</div>
                  <ul className="space-y-0.5">{current.talkingPoints.map((t, j) => <li key={j} className="text-xs flex gap-1.5"><span className="text-brand">›</span> {t}</li>)}</ul>
                </div>
              )}
              <div>
                <div className="flex items-center justify-between mb-1">
                  <label className="text-xs font-semibold uppercase tracking-wide text-muted-foreground">Your Answer</label>
                  <span className="text-[10px] text-muted-foreground">{answers[current.id]?.answer?.length ?? 0} chars</span>
                </div>
                <textarea
                  value={answers[current.id]?.answer ?? ""}
                  onChange={(e) => setAnswers((prev) => ({ ...prev, [current.id]: { answer: e.target.value, submitted: prev[current.id]?.submitted ?? false } }))}
                  rows={5}
                  placeholder="Write your answer using the STAR method…"
                  disabled={submitting}
                  className="w-full rounded-md border border-input bg-background px-3 py-2 text-sm outline-none focus:ring-2 focus:ring-brand"
                />
              </div>
              {answers[current.id]?.feedback && (
                <div className="rounded-lg bg-brand/5 dark:bg-brand/10 border border-brand/20 p-3">
                  <div className="flex items-center justify-between mb-2">
                    <span className="text-xs font-semibold flex items-center gap-1"><Icon name="Sparkles" className="w-3.5 h-3.5 text-brand" /> AI Feedback</span>
                    <Badge variant="success" className="text-[10px]">{answers[current.id].feedback.score}/100</Badge>
                  </div>
                  {answers[current.id].feedback.strengths?.length > 0 && (
                    <div className="mb-1.5"><div className="text-[10px] font-semibold text-emerald-600 mb-0.5">Strengths</div>
                    <ul className="space-y-0.5">{answers[current.id].feedback.strengths.map((s: string, j: number) => <li key={j} className="text-xs flex gap-1"><span className="text-emerald-600">✓</span> {s}</li>)}</ul></div>
                  )}
                  {answers[current.id].feedback.improvements?.length > 0 && (
                    <div><div className="text-[10px] font-semibold text-amber-600 mb-0.5">Areas to Improve</div>
                    <ul className="space-y-0.5">{answers[current.id].feedback.improvements.map((s: string, j: number) => <li key={j} className="text-xs flex gap-1"><span className="text-amber-600">→</span> {s}</li>)}</ul></div>
                  )}
                </div>
              )}
              <div className="flex items-center justify-between gap-2 pt-1">
                <Button variant="outline" size="sm" onClick={() => setCurrentIndex((i) => Math.max(i - 1, 0))} disabled={currentIndex === 0 || submitting} className="gap-1.5"><Icon name="ArrowLeft" className="w-4 h-4" /> Prev</Button>
                <div className="flex gap-2">
                  {!answers[current.id]?.submitted ? (
                    <Button size="sm" onClick={submitAnswer} disabled={submitting || !answers[current.id]?.answer?.trim()} className="bg-brand hover:bg-brand-dark text-white gap-1.5">
                      {submitting ? <Icon name="Loader2" className="w-4 h-4 animate-spin" /> : <Icon name="Send" className="w-4 h-4" />}
                      {submitting ? "Analyzing…" : "Submit"}
                    </Button>
                  ) : (
                    <Badge variant="success" className="text-xs gap-1"><Icon name="CheckCircle2" className="w-3 h-3" /> {answers[current.id].feedback.score}/100</Badge>
                  )}
                  <Button size="sm" onClick={() => isLast ? setShowResults(true) : setCurrentIndex((i) => i + 1)} className="bg-brand hover:bg-brand-dark text-white gap-1.5">
                    {isLast ? "Finish" : "Next"} <Icon name={isLast ? "Flag" : "ArrowRight"} className="w-4 h-4" />
                  </Button>
                </div>
              </div>
            </CardContent>
          </Card>
        </motion.div>
      </AnimatePresence>
    </div>
  );
}

src/components/interview/InterviewSessio:
"use client";

import { useState, useCallback, useRef, useEffect } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Textarea } from "@/components/ui/textarea";
import { Badge, Icon, ScoreRing } from "@/components/shared";
import { callAI, extractJSON } from "@/lib/ai";
import { toast } from "sonner";
import type { InterviewPackage, InterviewQuestion } from "@/lib/types";

// ============================================================================
// Types
// ============================================================================

interface AnswerFeedback {
  strengths: string[];
  improvements: string[];
  suggestedAnswer: string;
  starFeedback: { situation: string; task: string; action: string; result: string; note: string };
  score: number;
}

interface QuestionAnswer {
  questionId: string;
  answer: string;
  feedback?: AnswerFeedback;
  submitted: boolean;
}

interface InterviewSessionProps {
  pkg: InterviewPackage;
  onClose: () => void;
}

const CATEGORIES = [
  { id: "technical", label: "Technical", icon: "Code2", color: "#1154A3" },
  { id: "behavioral", label: "Behavioral", icon: "Users", color: "#F59E0B" },
  { id: "situational", label: "Situational", icon: "GitBranch", color: "#10B981" },
  { id: "hr", label: "HR", icon: "UserCheck", color: "#8B5CF6" },
  { id: "company", label: "Company-specific", icon: "Building2", color: "#EC4899" },
] as const;

const DIFFICULTY_COLORS: Record<string, string> = { easy: "#10B981", medium: "#F59E0B", hard: "#DC2626" };

// ============================================================================
// Main component
// ============================================================================

export function InterviewSession({ pkg, onClose }: InterviewSessionProps) {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [answers, setAnswers] = useState<Record<string, QuestionAnswer>>({});
  const [submitting, setSubmitting] = useState(false);
  const [showFinalReport, setShowFinalReport] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const questions = pkg.questions;
  const total = questions.length;
  const current = questions[currentIndex];
  const currentAnswer = answers[current?.id];

  const isLastQuestion = currentIndex === total - 1;
  const answeredCount = Object.values(answers).filter((a) => a.submitted).length;
  const percent = Math.round(((currentIndex + 1) / total) * 100);

  // === Answer management ===
  const setAnswerText = useCallback((questionId: string, text: string) => {
    setAnswers((prev) => ({
      ...prev,
      [questionId]: {
        ...prev[questionId],
        questionId,
        answer: text,
        submitted: prev[questionId]?.submitted ?? false,
      },
    }));
  }, []);

  // === Submit answer for AI feedback ===
  const submitAnswer = useCallback(async () => {
    if (!current || !currentAnswer?.answer?.trim()) {
      toast.error("Please write an answer before submitting.");
      return;
    }

    setSubmitting(true);
    setError(null);

    try {
      const result = await callAI({
        systemPrompt: "You are an expert interview coach. Evaluate the candidate's answer and provide constructive feedback. Return ONLY valid JSON.",
        userPrompt: `Question: ${current.question}
Category: ${current.category}
Difficulty: ${current.difficulty}

Candidate's answer:
${currentAnswer.answer}

Recommended answer (for reference):
${current.recommendedAnswer}

Talking points: ${current.talkingPoints?.join(", ") ?? ""}

Evaluate the candidate's answer. Return JSON:
{
  "strengths": ["strength 1", "strength 2"],
  "improvements": ["improvement 1", "improvement 2"],
  "suggestedAnswer": "A model answer incorporating the talking points",
  "starFeedback": {
    "situation": "feedback on situation framing",
    "task": "feedback on task clarity",
    "action": "feedback on action description",
    "result": "feedback on result quantification",
    "note": "overall STAR feedback"
  },
  "score": 85
}

Score 0-100 based on: relevance, clarity, specificity, quantification, and STAR structure.`,
        maxTokens: 1500,
        temperature: 0.4,
        taskCategory: "document",
      });

      let feedback: AnswerFeedback;
      try {
        feedback = extractJSON<AnswerFeedback>(result.text);
      } catch {
        throw new Error("Could not parse AI feedback. Please try again.");
      }

      setAnswers((prev) => ({
        ...prev,
        [current.id]: {
          ...prev[current.id],
          feedback,
          submitted: true,
        },
      }));

      toast.success(`Answer scored ${feedback.score}/100`);
    } catch (e: any) {
      const msg = e?.message || "Failed to get feedback. Please try again.";
      setError(msg);
      toast.error(msg);
    } finally {
      setSubmitting(false);
    }
  }, [current, currentAnswer]);

  // === Navigation ===
  const goNext = useCallback(() => {
    if (isLastQuestion) {
      setShowFinalReport(true);
    } else {
      setCurrentIndex((i) => Math.min(i + 1, total - 1));
      setError(null);
    }
  }, [isLastQuestion, total]);

  const goPrev = useCallback(() => {
    setCurrentIndex((i) => Math.max(i - 1, 0));
    setError(null);
  }, []);

  // === Final report computation ===
  const finalReport = computeFinalReport(questions, answers);

  // === Render ===
  if (showFinalReport) {
    return <FinalReport pkg={pkg} report={finalReport} onClose={onClose} onRetry={() => setShowFinalReport(false)} />;
  }

  if (!current) {
    return (
      <Card>
        <CardContent className="py-12 text-center">
          <Icon name="AlertCircle" className="w-10 h-10 text-amber-500 mx-auto" />
          <p className="mt-3 text-sm text-muted-foreground">No questions available.</p>
          <Button onClick={onClose} variant="outline" className="mt-4">Back</Button>
        </CardContent>
      </Card>
    );
  }

  const cat = CATEGORIES.find((c) => c.id === current.category) ?? CATEGORIES[0];

  return (
    <div className="space-y-4">
      {/* Header */}
      <Card>
        <CardContent className="p-4 sm:p-5">
          <div className="flex items-center justify-between gap-3 flex-wrap">
            <div className="flex items-center gap-2 min-w-0">
              <Icon name="MessagesSquare" className="w-5 h-5 text-brand shrink-0" />
              <div className="min-w-0">
                <h2 className="font-semibold text-sm sm:text-base truncate">{pkg.role ?? "Interview Prep"}{pkg.company ? ` at ${pkg.company}` : ""}</h2>
                <p className="text-xs text-muted-foreground">Practice mode — answer each question and get AI feedback</p>
              </div>
            </div>
            <Button variant="ghost" size="sm" onClick={onClose} className="gap-1.5 shrink-0">
              <Icon name="X" className="w-4 h-4" /> Exit
            </Button>
          </div>
        </CardContent>
      </Card>

      {/* Progress bar */}
      <Card>
        <CardContent className="p-4 sm:p-5">
          <div className="flex items-center justify-between text-xs mb-2">
            <span className="font-medium text-muted-foreground">Question {currentIndex + 1} of {total}</span>
            <span className="font-bold text-brand">{percent}%</span>
          </div>
          <div className="h-2.5 bg-secondary rounded-full overflow-hidden">
            <motion.div
              className="h-full bg-gradient-to-r from-brand to-brand-dark rounded-full"
              animate={{ width: `${percent}%` }}
              transition={{ duration: 0.3 }}
            />
          </div>
          <div className="flex items-center justify-between mt-2 text-[10px] text-muted-foreground">
            <span>{answeredCount} answered</span>
            <span>{total - answeredCount} remaining</span>
          </div>
        </CardContent>
      </Card>

      {/* Question card */}
      <AnimatePresence mode="wait">
        <motion.div
          key={current.id}
          initial={{ opacity: 0, x: 20 }}
          animate={{ opacity: 1, x: 0 }}
          exit={{ opacity: 0, x: -20 }}
          transition={{ duration: 0.2 }}
        >
          <Card>
            <CardContent className="p-4 sm:p-6 space-y-4">
              {/* Category + difficulty badges */}
              <div className="flex items-center gap-2 flex-wrap">
                <div className="flex items-center gap-1.5 px-2.5 py-1 rounded-full text-xs font-medium" style={{ background: `${cat.color}15`, color: cat.color }}>
                  <Icon name={cat.icon} className="w-3.5 h-3.5" /> {cat.label}
                </div>
                <span className="text-[10px] px-2 py-0.5 rounded-full font-semibold" style={{ background: `${DIFFICULTY_COLORS[current.difficulty]}20`, color: DIFFICULTY_COLORS[current.difficulty] }}>
                  {current.difficulty}
                </span>
              </div>

              {/* Question */}
              <div>
                <div className="text-[10px] uppercase tracking-wide text-muted-foreground font-semibold mb-1">Question {currentIndex + 1}</div>
                <p className="text-base sm:text-lg font-semibold text-pretty">{current.question}</p>
              </div>

              {/* Talking points */}
              {current.talkingPoints && current.talkingPoints.length > 0 && (
                <div className="rounded-lg bg-secondary/40 p-3">
                  <div className="text-xs font-semibold uppercase tracking-wide text-muted-foreground mb-1.5 flex items-center gap-1.5">
                    <Icon name="Lightbulb" className="w-3.5 h-3.5 text-gold" /> Talking Points
                  </div>
                  <ul className="space-y-1">
                    {current.talkingPoints.map((t, j) => (
                      <li key={j} className="text-xs text-foreground/80 flex gap-2">
                        <span className="text-brand shrink-0">›</span> <span>{t}</span>
                      </li>
                    ))}
                  </ul>
                </div>
              )}

              {/* Follow-up questions */}
              {current.followUps && current.followUps.length > 0 && (
                <div>
                  <div className="text-xs font-semibold uppercase tracking-wide text-muted-foreground mb-1.5 flex items-center gap-1.5">
                    <Icon name="HelpCircle" className="w-3.5 h-3.5 text-amber-500" /> Follow-Up Questions
                  </div>
                  <ul className="space-y-1">
                    {current.followUps.map((f, j) => (
                      <li key={j} className="text-xs text-foreground/80 flex gap-2">
                        <span className="text-gold shrink-0">?</span> <span>{f}</span>
                      </li>
                    ))}
                  </ul>
                </div>
              )}

              {/* Answer textarea */}
              <div>
                <div className="flex items-center justify-between mb-1.5">
                  <label className="text-xs font-semibold uppercase tracking-wide text-muted-foreground">Your Answer</label>
                  <span className="text-[10px] text-muted-foreground">{currentAnswer?.answer?.length ?? 0} chars</span>
                </div>
                <Textarea
                  value={currentAnswer?.answer ?? ""}
                  onChange={(e) => setAnswerText(current.id, e.target.value)}
                  rows={5}
                  placeholder="Write your answer here. Use the STAR method (Situation, Task, Action, Result) for behavioral questions…"
                  disabled={submitting}
                  className="text-sm"
                />
              </div>

              {/* Error */}
              {error && (
                <div className="rounded-lg bg-red-50 dark:bg-red-950/20 border border-red-200 dark:border-red-900 p-2.5 flex items-start gap-2">
                  <Icon name="AlertCircle" className="w-4 h-4 text-red-600 shrink-0 mt-0.5" />
                  <span className="text-xs text-red-700 dark:text-red-400">{error}</span>
                </div>
              )}

              {/* AI Feedback (after submission) */}
              {currentAnswer?.feedback && (
                <FeedbackCard feedback={currentAnswer.feedback} recommendedAnswer={current.recommendedAnswer} />
              )}

              {/* Action buttons */}
              <div className="flex items-center justify-between gap-2 pt-2 flex-wrap">
                <Button variant="outline" size="sm" onClick={goPrev} disabled={currentIndex === 0 || submitting} className="gap-1.5">
                  <Icon name="ArrowLeft" className="w-4 h-4" /> Previous
                </Button>
                <div className="flex gap-2">
                  {!currentAnswer?.submitted ? (
                    <Button size="sm" onClick={submitAnswer} disabled={submitting || !currentAnswer?.answer?.trim()} className="bg-brand hover:bg-brand-dark text-white gap-1.5">
                      {submitting ? <Icon name="Loader2" className="w-4 h-4 animate-spin" /> : <Icon name="Send" className="w-4 h-4" />}
                      {submitting ? "Analyzing…" : "Submit Answer"}
                    </Button>
                  ) : (
                    <Badge variant="success" className="text-xs gap-1">
                      <Icon name="CheckCircle2" className="w-3 h-3" /> Scored {currentAnswer.feedback?.score}/100
                    </Badge>
                  )}
                  <Button size="sm" onClick={goNext} className="bg-brand hover:bg-brand-dark text-white gap-1.5">
                    {isLastQuestion ? "Finish" : "Next"}
                    <Icon name={isLastQuestion ? "Flag" : "ArrowRight"} className="w-4 h-4" />
                  </Button>
                </div>
              </div>
            </CardContent>
          </Card>
        </motion.div>
      </AnimatePresence>
    </div>
  );
}

// ============================================================================
// Feedback Card
// ============================================================================

function FeedbackCard({ feedback, recommendedAnswer }: { feedback: AnswerFeedback; recommendedAnswer: string }) {
  return (
    <motion.div initial={{ opacity: 0, y: 8 }} animate={{ opacity: 1, y: 0 }} className="rounded-xl border border-brand/30 bg-brand/5 dark:bg-brand/10 p-4 space-y-3">
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-2">
          <Icon name="Sparkles" className="w-4 h-4 text-brand" />
          <span className="text-sm font-semibold">AI Feedback</span>
        </div>
        <ScoreRing value={feedback.score} size={48} label="Score" />
      </div>

      {feedback.strengths.length > 0 && (
        <div>
          <div className="text-xs font-semibold uppercase tracking-wide text-emerald-600 mb-1 flex items-center gap-1">
            <Icon name="CheckCircle2" className="w-3.5 h-3.5" /> Strengths
          </div>
          <ul className="space-y-0.5">
            {feedback.strengths.map((s, i) => (
              <li key={i} className="text-xs text-foreground/80 flex gap-1.5">
                <span className="text-emerald-600 shrink-0">✓</span> {s}
              </li>
            ))}
          </ul>
        </div>
      )}

      {feedback.improvements.length > 0 && (
        <div>
          <div className="text-xs font-semibold uppercase tracking-wide text-amber-600 mb-1 flex items-center gap-1">
            <Icon name="AlertTriangle" className="w-3.5 h-3.5" /> Areas for Improvement
          </div>
          <ul className="space-y-0.5">
            {feedback.improvements.map((imp, i) => (
              <li key={i} className="text-xs text-foreground/80 flex gap-1.5">
                <span className="text-amber-600 shrink-0">→</span> {imp}
              </li>
            ))}
          </ul>
        </div>
      )}

      {feedback.suggestedAnswer && (
        <div>
          <div className="text-xs font-semibold uppercase tracking-wide text-brand mb-1 flex items-center gap-1">
            <Icon name="Lightbulb" className="w-3.5 h-3.5" /> Suggested Answer
          </div>
          <p className="text-xs text-foreground/90 text-pretty rounded-lg bg-card p-2.5">{feedback.suggestedAnswer}</p>
        </div>
      )}

      {feedback.starFeedback && (
        <div>
          <div className="text-xs font-semibold uppercase tracking-wide text-muted-foreground mb-1">STAR Feedback</div>
          <div className="rounded-lg bg-card p-2.5 space-y-1 text-xs">
            <div><span className="font-semibold text-brand">Situation:</span> {feedback.starFeedback.situation}</div>
            <div><span className="font-semibold text-brand">Task:</span> {feedback.starFeedback.task}</div>
            <div><span className="font-semibold text-brand">Action:</span> {feedback.starFeedback.action}</div>
            <div><span className="font-semibold text-brand">Result:</span> {feedback.starFeedback.result}</div>
            <div className="pt-1 border-t border-border mt-1"><span className="font-semibold">Overall:</span> {feedback.starFeedback.note}</div>
          </div>
        </div>
      )}

      {recommendedAnswer && (
        <details className="text-xs">
          <summary className="cursor-pointer text-muted-foreground hover:text-foreground font-medium">Show original recommended answer</summary>
          <p className="mt-1.5 text-foreground/80 text-pretty">{recommendedAnswer}</p>
        </details>
      )}
    </motion.div>
  );
}

// ============================================================================
// Final Report
// ============================================================================

interface FinalReportData {
  overallScore: number;
  categoryScores: Record<string, { score: number; count: number }>;
  strengths: string[];
  weaknesses: string[];
  recommendations: string[];
  answeredCount: number;
  totalCount: number;
}

function computeFinalReport(questions: InterviewQuestion[], answers: Record<string, QuestionAnswer>): FinalReportData {
  const submittedAnswers = Object.values(answers).filter((a) => a.submitted && a.feedback);
  const totalScore = submittedAnswers.reduce((sum, a) => sum + (a.feedback?.score ?? 0), 0);
  const overallScore = submittedAnswers.length > 0 ? Math.round(totalScore / submittedAnswers.length) : 0;

  // Category breakdown
  const categoryScores: Record<string, { score: number; count: number }> = {};
  for (const q of questions) {
    const ans = answers[q.id];
    if (ans?.submitted && ans.feedback) {
      if (!categoryScores[q.category]) categoryScores[q.category] = { score: 0, count: 0 };
      categoryScores[q.category].score += ans.feedback.score;
      categoryScores[q.category].count += 1;
    }
  }
  for (const cat of Object.keys(categoryScores)) {
    categoryScores[cat].score = Math.round(categoryScores[cat].score / categoryScores[cat].count);
  }

  // Aggregate strengths + weaknesses
  const allStrengths = submittedAnswers.flatMap((a) => a.feedback?.strengths ?? []);
  const allImprovements = submittedAnswers.flatMap((a) => a.feedback?.improvements ?? []);
  const strengths = [...new Set(allStrengths)].slice(0, 5);
  const weaknesses = [...new Set(allImprovements)].slice(0, 5);

  // Recommendations
  const recommendations: string[] = [];
  if (overallScore >= 85) recommendations.push("Excellent performance — you're interview-ready for this role.");
  else if (overallScore >= 70) recommendations.push("Good performance — focus on the weak areas below to improve further.");
  else if (overallScore >= 50) recommendations.push("Moderate performance — practice more on your weak categories.");
  else recommendations.push("Needs significant improvement — review the suggested answers and practice again.");

  for (const [cat, data] of Object.entries(categoryScores)) {
    if (data.score < 60) {
      const catLabel = CATEGORIES.find((c) => c.id === cat)?.label ?? cat;
      recommendations.push(`Focus on ${catLabel} questions — your average was ${data.score}/100.`);
    }
  }

  return {
    overallScore,
    categoryScores,
    strengths,
    weaknesses,
    recommendations,
    answeredCount: submittedAnswers.length,
    totalCount: questions.length,
  };
}

function FinalReport({ pkg, report, onClose, onRetry }: {
  pkg: InterviewPackage;
  report: FinalReportData;
  onClose: () => void;
  onRetry: () => void;
}) {
  return (
    <div className="space-y-4">
      {/* Header */}
      <Card className="gradient-brand text-white">
        <CardContent className="p-5 sm:p-6 text-center">
          <Icon name="Trophy" className="w-10 h-10 mx-auto mb-2 text-gold" />
          <h2 className="font-display text-xl sm:text-2xl font-bold">Interview Complete!</h2>
          <p className="text-sm opacity-90 mt-1">{pkg.role ?? "Interview Prep"}{pkg.company ? ` at ${pkg.company}` : ""}</p>
          <p className="text-xs opacity-75 mt-1">{report.answeredCount} of {report.totalCount} questions answered</p>
        </CardContent>
      </Card>

      {/* Overall score */}
      <Card>
        <CardContent className="p-5 sm:p-6 flex flex-col items-center">
          <ScoreRing value={report.overallScore} size={120} label="Overall Score" />
          <div className="mt-3 text-center">
            {report.overallScore >= 85 && <Badge variant="success" className="gap-1"><Icon name="Star" className="w-3 h-3" /> Excellent</Badge>}
            {report.overallScore >= 70 && report.overallScore < 85 && <Badge variant="brand" className="gap-1"><Icon name="ThumbsUp" className="w-3 h-3" /> Good</Badge>}
            {report.overallScore >= 50 && report.overallScore < 70 && <Badge variant="warning" className="gap-1"><Icon name="AlertCircle" className="w-3 h-3" /> Moderate</Badge>}
            {report.overallScore < 50 && <Badge variant="danger" className="gap-1"><Icon name="AlertTriangle" className="w-3 h-3" /> Needs Work</Badge>}
          </div>
        </CardContent>
      </Card>

      {/* Category scores */}
      {Object.keys(report.categoryScores).length > 0 && (
        <Card>
          <CardHeader className="pb-3">
            <CardTitle className="text-sm flex items-center gap-2"><Icon name="BarChart3" className="w-4 h-4 text-brand" /> Category Scores</CardTitle>
          </CardHeader>
          <CardContent className="pt-0 space-y-2">
            {Object.entries(report.categoryScores).map(([catId, data]) => {
              const cat = CATEGORIES.find((c) => c.id === catId);
              return (
                <div key={catId} className="flex items-center gap-3">
                  <div className="w-8 h-8 rounded-lg flex items-center justify-center shrink-0" style={{ background: `${cat?.color}15`, color: cat?.color }}>
                    <Icon name={cat?.icon ?? "Circle"} className="w-4 h-4" />
                  </div>
                  <div className="flex-1 min-w-0">
                    <div className="flex items-center justify-between text-xs">
                      <span className="font-medium">{cat?.label ?? catId}</span>
                      <span className="font-bold">{data.score}/100</span>
                    </div>
                    <div className="h-1.5 bg-secondary rounded-full overflow-hidden mt-1">
                      <div className="h-full rounded-full" style={{ width: `${data.score}%`, background: data.score >= 70 ? "#10B981" : data.score >= 50 ? "#F59E0B" : "#DC2626" }} />
                    </div>
                  </div>
                </div>
              );
            })}
          </CardContent>
        </Card>
      )}

      {/* Strengths */}
      {report.strengths.length > 0 && (
        <Card>
          <CardHeader className="pb-3">
            <CardTitle className="text-sm flex items-center gap-2"><Icon name="CheckCircle2" className="w-4 h-4 text-emerald-600" /> Strengths</CardTitle>
          </CardHeader>
          <CardContent className="pt-0">
            <ul className="space-y-1">
              {report.strengths.map((s, i) => (
                <li key={i} className="text-xs text-foreground/80 flex gap-1.5">
                  <span className="text-emerald-600 shrink-0">✓</span> {s}
                </li>
              ))}
            </ul>
          </CardContent>
        </Card>
      )}

      {/* Weaknesses */}
      {report.weaknesses.length > 0 && (
        <Card>
          <CardHeader className="pb-3">
            <CardTitle className="text-sm flex items-center gap-2"><Icon name="AlertTriangle" className="w-4 h-4 text-amber-600" /> Weaknesses</CardTitle>
          </CardHeader>
          <CardContent className="pt-0">
            <ul className="space-y-1">
              {report.weaknesses.map((w, i) => (
                <li key={i} className="text-xs text-foreground/80 flex gap-1.5">
                  <span className="text-amber-600 shrink-0">→</span> {w}
                </li>
              ))}
            </ul>
          </CardContent>
        </Card>
      )}

      {/* Recommendations */}
      {report.recommendations.length > 0 && (
        <Card>
          <CardHeader className="pb-3">
            <CardTitle className="text-sm flex items-center gap-2"><Icon name="Lightbulb" className="w-4 h-4 text-brand" /> Recommendations</CardTitle>
          </CardHeader>
          <CardContent className="pt-0">
            <ul className="space-y-1">
              {report.recommendations.map((r, i) => (
                <li key={i} className="text-xs text-foreground/80 flex gap-1.5">
                  <Icon name="ArrowRight" className="w-3 h-3 text-brand shrink-0 mt-0.5" /> {r}
                </li>
              ))}
            </ul>
          </CardContent>
        </Card>
      )}

      {/* Actions */}
      <div className="flex gap-2 justify-center">
        <Button variant="outline" onClick={onRetry} className="gap-1.5">
          <Icon name="RotateCcw" className="w-4 h-4" /> Review Answers
        </Button>
        <Button onClick={onClose} className="bg-brand hover:bg-brand-dark text-white gap-1.5">
          <Icon name="Check" className="w-4 h-4" /> Done
        </Button>
      </div>
    </div>
  );
}

// ============================================================================
// Loading skeleton (shown while generating)
// ============================================================================

export function InterviewSkeleton() {
