                    {e.bullets.map((b, i) => (
                      <li key={i} style={{ marginBottom: "0.5mm", color: "#000", textAlign: "justify" }}>{b}</li>
                    ))}
                  </ul>
                </div>
              ))}
            </div>
          </InfohasSection>
        )}

        {/* EDUCATION */}
        {resume.education.length > 0 && (
          <InfohasSection title="EDUCATION">
            <div style={{ display: "flex", flexDirection: "column", gap: "1.5mm" }}>
