Return ONLY valid JSON:
{
  "files": [
    {
      "path": "src/components/app/modules/MyFeature.tsx",
      "content": "\"use client\"\\nimport ...\\n// full file content",
      "type": "component"
    }
  ]
}`;

  try {
    const result = await callAI({
