// ResumeAI Pro — global Zustand store (cloud-backed + sessionStorage session persistence)
"use client";

import { create } from "zustand";
import type {
  User, ResumeData, JobDescription, AIProvider, AIProviderLog, AIProviderSettings, PromptTemplate,
  BrandingConfig, FeatureFlags, AuditLog, ViewKey, CoverLetter, InterviewPackage, ATSReport,
  OptimizerDirectiveConfig,
  AIDevAgentSettings, AIDevAgentHistory, AIDevReport,
  AITask, AIWorkspacePatch, AIGitBranch, AIGitCommit, AIRollback,
  ResumeReviewReport, AIHealingIssue, AIHealingReport,
} from "./types";
import {
  SEED_RESUMES, SEED_JDS, SEED_PROVIDERS, SEED_PROVIDER_LOGS, SEED_PROVIDER_SETTINGS,
  SEED_PROMPTS, SEED_BRANDING, SEED_FLAGS, SEED_LOGS, SEED_COVER_LETTERS, SEED_INTERVIEW, SEED_ATS_REPORTS,
  SEED_OPTIMIZER_DIRECTIVE,
  SEED_AI_DEV_SETTINGS, SEED_AI_DEV_HISTORY, SEED_AI_DEV_REPORTS,
  SEED_AI_TASKS, SEED_AI_PATCHES, SEED_AI_BRANCHES, SEED_AI_COMMITS, SEED_AI_ROLLBACKS,
} from "./mock-data";
import { BRAND, getRoleForEmail } from "./brand";
import { hashPassword, verifyPassword, SUPER_ADMIN_SEED, canSignIn, canAccessApp } from "./auth-utils";
import type { UserStatus as US } from "./types";
import { setUserId, clearUserId, api as cloudApi, cloudApiSafe } from "./cloud-api";

// Destructure cloud API methods so the existing cloudApiSafe(createResume)(...) call sites
// in this file resolve to the real functions. Each of these is an async function that hits
// the Cloudflare Worker → D1. cloudApiSafe wraps them so they never throw or reject.
const {
  createResume,
  updateResume,
  deleteResume,
  createJobDescription,
  deleteJobDescription,
  createCoverLetter,
  updateCoverLetter,
  deleteCoverLetter,
  createInterview,
  deleteInterview,
  createATSReport,
  createUser,
  updateUser,
  createProvider,
  updateProvider,
  deleteProvider,
  createPrompt,
  updatePrompt,
  deletePrompt,
  updateBranding,
  updateFlag,
  createAuditLog,
} = cloudApi;

interface AppState {
  // session
  user: User | null;
  isAuthed: boolean;
  authOpen: boolean;

  // user registry — all registered users (for admin management)
  users: User[];

  // navigation
  view: ViewKey;
  activeResumeId: string | null;
  activeJdId: string | null;
  activeCoverLetterId: string | null;
  activeInterviewId: string | null;
  landingSection: string | null;

  // collections
  resumes: ResumeData[];
  jobDescriptions: JobDescription[];
  coverLetters: CoverLetter[];
  interviews: InterviewPackage[];
  atsReports: ATSReport[];
  // AI Resume Review Platform — comprehensive multi-module review reports.
  // Stored as rich JSON blobs in the store; persisted to localStorage as
  // `resumeai-review-reports-backup` and best-effort synced to the
  // existing ats_reports D1 table (review_data_json column added in a
  // follow-up migration; until then, sync is localStorage-only).
  reviewReports: ResumeReviewReport[];

  // admin
  providers: AIProvider[];
  providerLogs: AIProviderLog[];
  providerSettings: AIProviderSettings;
  prompts: PromptTemplate[];
  branding: BrandingConfig;
  flags: FeatureFlags;
  optimizerDirective: OptimizerDirectiveConfig;
  aiDevSettings: AIDevAgentSettings;
  aiDevHistory: AIDevAgentHistory[];
  aiDevReports: AIDevReport[];
  // AI Workspace (Builder Agent)
  aiTasks: AITask[];
  aiPatches: AIWorkspacePatch[];
  aiBranches: AIGitBranch[];
  aiCommits: AIGitCommit[];
  aiRollbacks: AIRollback[];
  aiHealingIssues: AIHealingIssue[];
  aiHealingReport: AIHealingReport | null;
  aiHealingProgress: {
    status: "idle" | "scanning" | "classifying" | "analyzing" | "fixing" | "validating" | "completed";
    currentStep: string;
    progressPercent: number;
  };
  logs: AuditLog[];

  // ui
  theme: "light" | "dark";
  sidebarCollapsed: boolean;
  synced: boolean; // whether cloud data has been loaded
  // True when localStorage had a session at module load and rehydrateSession()
  // needs to be called from a useEffect to apply it (avoids hydration mismatch).
  _needsRehydrate: boolean;

  // fallback offer (rate-limit UI)
  fallbackOfferOpen: boolean;
  fallbackOfferChoices: AIProvider[];
  fallbackOfferCurrentProviderId: string | null;

  // actions
  rehydrateSession: () => void;
  setView: (v: ViewKey) => void;
  openAuth: () => void;
  closeAuth: () => void;
  signIn: (user: User) => void;
  signOut: () => void;
  // email/password auth
  signInWithEmail: (email: string, password: string) => { ok: boolean; error?: string; user?: User };
  registerWithEmail: (email: string, password: string, name: string, username?: string) => { ok: boolean; error?: string; user?: User };
  signInWithPuter: () => Promise<{ ok: boolean; error?: string; user?: User }>;
  // account self-service
  updateUserName: (newName: string) => void;
  updateUserEmail: (newEmail: string) => void;
  changePassword: (currentPassword: string, newPassword: string) => { ok: boolean; error?: string };
  /** Re-check the signed-in user's role against the email allowlist. Call on app load. */
  reconcileRole: () => void;
  toggleSidebar: () => void;
  toggleTheme: () => void;
  setLandingSection: (s: string | null) => void;
  // admin user management
  approveUser: (userId: string) => void;
  suspendUser: (userId: string) => void;
  unsuspendUser: (userId: string) => void;
  deleteUser: (userId: string) => void;
  promoteToAdmin: (userId: string) => void;
  demoteToUser: (userId: string) => void;
  resetUserPassword: (userId: string, newPassword: string) => void;
  updateUserStatus: (userId: string, status: US) => void;

  // resumes
  addResume: (r: ResumeData) => void;
  updateResume: (id: string, patch: Partial<ResumeData>) => void;
  removeResume: (id: string) => void;
  setActiveResume: (id: string | null) => void;

  // jd
  addJD: (j: JobDescription) => void;
  removeJD: (id: string) => void;
  setActiveJD: (id: string | null) => void;

  // cover letters
  addCoverLetter: (c: CoverLetter) => void;
  updateCoverLetter: (id: string, patch: Partial<CoverLetter>) => void;
  removeCoverLetter: (id: string) => void;
  setActiveCoverLetter: (id: string | null) => void;

  // interviews
  addInterview: (i: InterviewPackage) => void;
  removeInterview: (id: string) => void;
  setActiveInterview: (id: string | null) => void;

  // ats
  addATSReport: (r: ATSReport) => void;

  // resume review reports (AI Resume Review Platform)
  addReviewReport: (r: ResumeReviewReport) => void;
  updateReviewReport: (id: string, patch: Partial<ResumeReviewReport>) => void;
  removeReviewReport: (id: string) => void;

  // providers
  addProvider: (p: AIProvider) => void;
  updateProvider: (id: string, patch: Partial<AIProvider>) => void;
  removeProvider: (id: string) => void;
  duplicateProvider: (id: string) => string | null;
  setDefaultProvider: (id: string) => void;
  toggleFallback: (id: string) => void;
  reorderFallback: (id: string, direction: "up" | "down") => void;
  // provider logs
  addProviderLog: (l: AIProviderLog) => void;
  clearProviderLogs: (providerId?: string) => void;
  // provider settings
  updateProviderSettings: (patch: Partial<AIProviderSettings>) => void;

  // prompts
  addPrompt: (p: PromptTemplate) => void;
  updatePrompt: (id: string, patch: Partial<PromptTemplate>) => void;
  removePrompt: (id: string) => void;

  // branding & flags
  updateBranding: (patch: Partial<BrandingConfig>) => void;
  updateFlag: (k: keyof FeatureFlags, v: boolean) => void;
  updateOptimizerDirective: (patch: Partial<OptimizerDirectiveConfig>) => void;
  resetOptimizerDirective: () => void;
  // AI Dev Agent
  updateAIDevSettings: (patch: Partial<AIDevAgentSettings>) => void;
  addAIDevHistory: (entry: Omit<AIDevAgentHistory, "id" | "createdAt">) => void;
  addAIDevReport: (report: Omit<AIDevReport, "id" | "createdAt">) => void;
  // AI Workspace (Builder Agent)
  addAITask: (task: Omit<AITask, "id" | "createdAt" | "updatedAt">) => void;
  updateAITask: (id: string, patch: Partial<AITask>) => void;
  removeAITask: (id: string) => void;
  addAIPatch: (patch: Omit<AIWorkspacePatch, "id" | "createdAt">) => void;
  updateAIPatch: (id: string, patch: Partial<AIWorkspacePatch>) => void;
  addAIRollback: (rollback: Omit<AIRollback, "id" | "rolledBackAt">) => void;
  setAIHealingIssues: (issues: AIHealingIssue[]) => void;
  updateAIHealingIssue: (id: string, patch: Partial<AIHealingIssue>) => void;
  setAIHealingReport: (report: AIHealingReport | null) => void;
  setAIHealingProgress: (progress: {
    status: "idle" | "scanning" | "classifying" | "analyzing" | "fixing" | "validating" | "completed";
    currentStep: string;
    progressPercent: number;
  }) => void;

  // logs
  log: (entry: Omit<AuditLog, "id" | "timestamp">) => void;
  clearLogs: () => void;

  // usage tracking
  incUsage: (k: "resumesGenerated" | "atsChecks" | "coverLetters" | "interviewPreps" | "downloads") => void;
  openFallbackOffer: (choices: AIProvider[], currentProviderId: string | null) => void;
  closeFallbackOffer: () => void;
}

const uid = (p = "id") => `${p}_${Math.random().toString(36).slice(2, 9)}${Date.now().toString(36).slice(-4)}`;

/**
 * Normalize a JobDescription so every expected array field is a real array
 * and every expected string is a string. Prevents React-render crashes
 * ("Cannot read properties of undefined (reading 'length')") when a JD
 * arrives from a stale localStorage backup, an older D1 row, or an older
 * client code path that didn't populate all fields.
 *
 * This is a defensive, idempotent transform — calling it on an already-well-
 * formed JD returns an equivalent JD.
 */
export function normalizeJD<T extends Record<string, any>>(jd: T): T {
  if (!jd || typeof jd !== "object") return jd;
  const toArray = (v: any): any[] => Array.isArray(v) ? v : [];
  const toStr = (v: any): string | undefined => (v === null || v === undefined) ? undefined : String(v);
  return {
    ...jd,
    id: jd.id || uid("jd"),
    title: typeof jd.title === "string" ? jd.title : (jd.title ? String(jd.title) : "Untitled role"),
    company: toStr(jd.company),
    location: toStr(jd.location),
    employmentType: toStr(jd.employmentType),
    salary: toStr(jd.salary),
    experienceYears: toStr(jd.experienceYears),
    education: toStr(jd.education),
    rawText: toStr(jd.rawText),
    url: toStr(jd.url),
    source: typeof jd.source === "string" ? jd.source : "text",
    createdAt: jd.createdAt || new Date().toISOString(),
    responsibilities: toArray(jd.responsibilities),
    requiredSkills: toArray(jd.requiredSkills),
    preferredSkills: toArray(jd.preferredSkills),
    technologies: toArray(jd.technologies),
    keywords: toArray(jd.keywords),
  } as T;
}

// === Session persistence — survives browser refresh ===
// The user object is saved to localStorage on sign-in and restored on page load.
// This prevents the "login again on refresh" bug.
// On explicit signOut, the session is cleared.
const SESSION_KEY = "resumeai-session";

function persistSession(user: User) {
  if (typeof window === "undefined") return;
  try {
    localStorage.setItem(SESSION_KEY, JSON.stringify({
      user,
      expiresAt: Date.now() + 7 * 24 * 60 * 60 * 1000, // 7-day session expiry
    }));
  } catch (syncErr) { console.warn("[store] Operation failed:", syncErr instanceof Error ? syncErr.message : syncErr); }
}

function restoreSession(): User | null {
  if (typeof window === "undefined") return null;
  try {
    const raw = localStorage.getItem(SESSION_KEY);
    if (!raw) return null;
    const session = JSON.parse(raw);
    // Check expiry
    if (session.expiresAt && Date.now() > session.expiresAt) {
      localStorage.removeItem(SESSION_KEY);
      return null;
    }
    if (session.user && session.user.id) {
      return session.user as User;
    }
    return null;
  } catch (sessionErr) {
    console.warn("[store] Session restore failed:", sessionErr instanceof Error ? sessionErr.message : sessionErr);
    return null;
  }
}

function clearSession() {
  if (typeof window === "undefined") return;
  try {
    localStorage.removeItem(SESSION_KEY);
  } catch (syncErr) { console.warn("[store] Operation failed:", syncErr instanceof Error ? syncErr.message : syncErr); }
}

// === Hydration-safe session restore ===
// On the server (typeof window === "undefined"), restoreSession() returns
// null. On the client, it reads localStorage. If we initialized the store
// with the restored user at module load, the server render would have
// user=null+view="landing" while the first client render would have
// user=<restored>+view="dashboard" → React 19 hydration mismatch.
//
// Fix: initialize the store with SSR-safe empty values (user=null,
// view="landing", theme="light", reviewReports=[]), then call
// rehydrateSession() from a useEffect on the client. The first client
// render matches SSR, then the effect rehydrates and triggers a re-render
// with the restored state. This is the same pattern Next.js recommends
// for any client-persisted state.
const _restoredUser = restoreSession();
// Set the user-id for API calls immediately (pure side-effect, no React state)
if (_restoredUser && typeof window !== "undefined") {
  try { setUserId(_restoredUser.id); } catch (syncErr) { console.warn("[store] Operation failed:", syncErr instanceof Error ? syncErr.message : syncErr); }
}
// Flag the store that we have a pending rehydration — page.tsx will call
// rehydrateSession() in a useEffect to apply the restored user/theme/reports
// AFTER the first client render matches SSR.
const _hasPendingRehydration = !!_restoredUser;

export const useApp = create<AppState>()(
    (set, get) => ({
      // === SSR-SAFE INITIAL STATE ===
      // On the server AND the first client render, user is null and view
      // is "landing". This matches the server-rendered HTML so React 19
      // hydration succeeds. rehydrateSession() (called from page.tsx's
      // useEffect) then applies the restored user/theme/reports from
      // localStorage and triggers a re-render with the real state.
      user: null,
      isAuthed: false,
      authOpen: false,

      // User registry — seeded with the super admin
      users: (() => {
        const sa: User = {
          id: "u_superadmin",
          name: SUPER_ADMIN_SEED.name,
          username: SUPER_ADMIN_SEED.username,
          email: SUPER_ADMIN_SEED.email,
          passwordHash: hashPassword(SUPER_ADMIN_SEED.password),
          role: "super_admin",
          status: "approved",
          provider: "email",
          createdAt: "2025-01-01T00:00:00Z",
          updatedAt: new Date().toISOString(),
          lastActiveAt: new Date().toISOString(),
          lastLoginAt: undefined,
          usage: { resumesGenerated: 0, atsChecks: 0, coverLetters: 0, interviewPreps: 0, downloads: 0 },
        };
        return [sa];
      })(),

      // SSR-safe: always start on "landing" — rehydrateSession() will switch
      // to "dashboard" after hydration if a session was restored.
      view: "landing" as ViewKey,
      activeResumeId: SEED_RESUMES[0]?.id ?? null,
      activeJdId: SEED_JDS[0]?.id ?? null,
      activeCoverLetterId: SEED_COVER_LETTERS[0]?.id ?? null,
      activeInterviewId: SEED_INTERVIEW[0]?.id ?? null,
      landingSection: null,

      resumes: SEED_RESUMES,
      jobDescriptions: SEED_JDS,
      coverLetters: SEED_COVER_LETTERS,
      interviews: SEED_INTERVIEW,
      atsReports: SEED_ATS_REPORTS,
      // SSR-safe: start empty — rehydrateSession() restores from localStorage.
      reviewReports: [],

      providers: SEED_PROVIDERS,
      providerLogs: SEED_PROVIDER_LOGS,
      // === Restore provider settings from localStorage on init ===
      // This ensures the user's chosen provider is used BEFORE syncAllFromCloud
      // runs (which may take a few seconds). If localStorage has saved settings,
      // they override the seed defaults immediately.
      providerSettings: (() => {
        if (typeof localStorage === "undefined") return SEED_PROVIDER_SETTINGS;
        try {
          const saved = localStorage.getItem("resumeai-provider-settings");
          if (saved) {
            const ls = JSON.parse(saved);
            if (ls.defaultProviderId || ls.defaultModel) {
              return { ...SEED_PROVIDER_SETTINGS, ...ls };
            }
          }
        } catch (syncErr) { console.warn("[store] Operation failed:", syncErr instanceof Error ? syncErr.message : syncErr); }
        return SEED_PROVIDER_SETTINGS;
      })(),
      prompts: SEED_PROMPTS,
      branding: SEED_BRANDING,
      flags: SEED_FLAGS,
      optimizerDirective: SEED_OPTIMIZER_DIRECTIVE,
      aiDevSettings: SEED_AI_DEV_SETTINGS,
      aiDevHistory: SEED_AI_DEV_HISTORY,
      aiDevReports: SEED_AI_DEV_REPORTS,
      aiTasks: SEED_AI_TASKS,
      aiPatches: SEED_AI_PATCHES,
      aiBranches: SEED_AI_BRANCHES,
      aiCommits: SEED_AI_COMMITS,
      aiRollbacks: SEED_AI_ROLLBACKS,
      aiHealingIssues: [],
      aiHealingReport: null,
      aiHealingProgress: {
        status: "idle",
        currentStep: "",
        progressPercent: 0,
      },
      logs: SEED_LOGS,

      // SSR-safe: always start "light" — rehydrateSession() restores the real theme.
      theme: "light" as "light" | "dark",
      sidebarCollapsed: false,
      synced: false,

      // Flag: true when a session was found in localStorage at module load
      // and needs to be applied via rehydrateSession() after hydration.
      _needsRehydrate: _hasPendingRehydration,
      fallbackOfferOpen: false,
      fallbackOfferChoices: [],
      fallbackOfferCurrentProviderId: null,

      setView: (v) => set({ view: v, landingSection: null }),

      // === SSR-SAFE REHYDRATION ===
      // Called from page.tsx's useEffect on the client. Applies the restored
      // user/theme/reports from localStorage AFTER the first client render
      // has matched the server HTML. This prevents React 19 hydration
      // mismatches while still preserving the "login survives refresh" UX.
      rehydrateSession: () => {
        const restored = restoreSession();
        if (restored) {
          // Apply the dark theme class BEFORE setting state so there's no flash
          if (typeof document !== "undefined") {
            const savedTheme = localStorage.getItem("resumeai-theme");
            if (savedTheme === "dark") document.documentElement.classList.add("dark");
          }
          // Restore review reports from localStorage backup
          let restoredReports: any[] = [];
          try {
            restoredReports = JSON.parse(localStorage.getItem("resumeai-review-reports-backup") || "[]");
          } catch (parseErr) { console.warn("[store] Review reports backup parse failed:", parseErr instanceof Error ? parseErr.message : parseErr); restoredReports = []; }
          const savedTheme = (typeof localStorage !== "undefined" && localStorage.getItem("resumeai-theme") === "dark") ? "dark" as const : "light" as const;
          set({
            user: restored,
            isAuthed: true,
            view: "dashboard",
            theme: savedTheme,
            reviewReports: restoredReports,
            _needsRehydrate: false,
          });
        } else {
          set({ _needsRehydrate: false });
        }
      },
      openAuth: () => set({ authOpen: true }),
      closeAuth: () => set({ authOpen: false }),

      signIn: (user) => {
        const check = canSignIn(user);
        if (!check.allowed) return;
        const now = new Date().toISOString();
        const updatedUser = { ...user, lastLoginAt: now, lastActiveAt: now };
        setUserId(updatedUser.id); // Set user ID for API calls
        // Persist session to localStorage so it survives browser refresh
        persistSession(updatedUser);
        set((s) => {
          const exists = s.users.find((u) => u.email === user.email);
          const users = exists
            ? s.users.map((u) => (u.email === user.email ? { ...u, ...updatedUser } : u))
            : [...s.users, updatedUser];
          return { users, user: updatedUser, isAuthed: true, authOpen: false, view: "dashboard", synced: false };
        });
        useApp.getState().log({ actor: user.email, action: "User signed in", category: "auth", details: `Provider: ${user.provider}`, severity: "info" });
      },

      signOut: () => {
        const s = get();
        if (s.user) {
          useApp.getState().log({ actor: s.user.email, action: "User signed out", category: "auth", details: "", severity: "info" });
        }
        clearUserId();
        clearSession(); // Clear persisted session on explicit sign-out
        // === V3: Reset the Supervisor + all agent states ===
        // (imported lazily to avoid a circular dependency at module load)
        try {
          import("./agents/supervisor").then(({ resetSupervisor }) => resetSupervisor());
        } catch (syncErr) { console.warn("[store] Operation failed:", syncErr instanceof Error ? syncErr.message : syncErr); }
        // Reset active*Id fields so a different user signing in next doesn't
        // inherit the previous user's resume/JD/cover-letter/interview selection
        // (which could cause the Optimizer to auto-load the wrong JD, etc.).
        set({
          user: null,
          isAuthed: false,
          view: "landing",
          synced: false,
          activeResumeId: null,
          activeJdId: null,
          activeCoverLetterId: null,
          activeInterviewId: null,
        });
      },

      // === Email/Password Sign In ===
      signInWithEmail: (email, password) => {
        const s = get();
        const normalizedEmail = email.trim().toLowerCase();
        const existing = s.users.find((u) => u.email.toLowerCase() === normalizedEmail);
        if (!existing) {
          return { ok: false, error: "No account found with this email. Please register first." };
        }
        if (existing.status === "suspended") {
          return { ok: false, error: "Your account has been suspended. Please contact the administrator." };
        }
        if (existing.status === "deleted") {
          return { ok: false, error: "This account has been deleted." };
        }
        if (!existing.passwordHash || !verifyPassword(password, existing.passwordHash)) {
          return { ok: false, error: "Incorrect password." };
        }
        const now = new Date().toISOString();
        const updatedUser = { ...existing, lastLoginAt: now, lastActiveAt: now };
        // RACE-FIX: call setUserId BEFORE set() so any cloud-API call
        // triggered by synchronous store subscribers carries the correct
        // X-User-Id header (otherwise logs/usage are mis-attributed).
        setUserId(updatedUser.id);
        persistSession(updatedUser);
        set((s) => ({
          users: s.users.map((u) => (u.id === existing.id ? updatedUser : u)),
          user: updatedUser,
          isAuthed: true,
          authOpen: false,
          view: "dashboard",
          synced: false,
        }));
        useApp.getState().log({ actor: normalizedEmail, action: "User signed in", category: "auth", details: "Provider: email", severity: "info" });
        return { ok: true, user: updatedUser };
      },

      // === Email/Password Registration ===
      registerWithEmail: (email, password, name, username) => {
        const s = get();
        const normalizedEmail = email.trim().toLowerCase();
        const existing = s.users.find((u) => u.email.toLowerCase() === normalizedEmail);
        if (existing) {
          return { ok: false, error: "An account with this email already exists. Please sign in." };
        }
        const now = new Date().toISOString();
        const newUser: User = {
          id: uid("u"),
          name: name.trim() || normalizedEmail.split("@")[0],
          username: username?.trim() || normalizedEmail.split("@")[0],
          email: normalizedEmail,
          passwordHash: hashPassword(password),
          role: "user",
          status: "pending", // New users start as pending — require admin approval
          provider: "email",
          createdAt: now,
          updatedAt: now,
          lastActiveAt: now,
          lastLoginAt: now,
          usage: { resumesGenerated: 0, atsChecks: 0, coverLetters: 0, interviewPreps: 0, downloads: 0 },
        };
        set((s) => ({ users: [...s.users, newUser] }));
        // === BUG 2 FIX: sync the new email/password user to D1 so they
        // appear in the admin User Approval page. ===
        cloudApiSafe(createUser)(newUser).catch((e) => { console.warn("[store] Cloud sync failed:", e instanceof Error ? e.message : e); });
        useApp.getState().log({ actor: normalizedEmail, action: "User registered (pending approval)", category: "auth", details: `Name: ${newUser.name}`, severity: "warning" });
        // Auto-sign-in the new user (they'll see the pending approval screen)
        // RACE-FIX: setUserId BEFORE set() so cloud-API calls carry the
        // correct X-User-Id header.
        setUserId(newUser.id);
        persistSession(newUser);
        set({ user: newUser, isAuthed: true, authOpen: false, view: "dashboard", synced: false });
        return { ok: true, user: newUser };
      },

      // === Puter.js Sign In ===
      // Per https://docs.puter.com/Auth/signIn/ — signIn() must be called from a
      // user click handler (it opens a popup). This method is called from the
      // auth modal's "Sign in with Puter" button onClick, so it's user-initiated.
      signInWithPuter: async () => {
        if (typeof window === "undefined" || !window.puter?.auth) {
          return { ok: false, error: "Puter.js is not loaded. Please refresh the page and try again." };
        }
        try {
          // signIn() opens a popup — allowed because this is called from onClick
          await window.puter.auth.signIn();
          const puterUser = await window.puter.auth.getUser();
          const puterEmail = puterUser?.email || puterUser?.username || "";
          const puterName = puterUser?.username || puterUser?.name || puterEmail.split("@")[0];

          if (!puterEmail) {
            return { ok: false, error: "Could not retrieve your email from Puter. Please try again." };
          }

          const s = get();
          const existing = s.users.find((u) => u.email.toLowerCase() === puterEmail.toLowerCase());
          const now = new Date().toISOString();

          if (existing) {
            // Existing user — check status
            if (existing.status === "suspended") {
              return { ok: false, error: "Your account has been suspended. Please contact the administrator." };
            }
            if (existing.status === "deleted") {
              return { ok: false, error: "This account has been deleted." };
            }
            // If this is a Puter-authenticated user who was previously stuck in
            // "pending" status (from the old approval flow), auto-approve them now.
            // Puter OAuth already verified their email, so admin approval is unnecessary.
            const shouldAutoApprove = existing.provider === "puter" && existing.status === "pending";
            // Reconcile role from the email allowlist — this ensures that if the
            // super admin / admin allowlists change, the user's role is updated
            // on their next Puter sign-in. (e.g. if relsabah@gmail.com was initially
            // created as a regular user but is now in the super admin allowlist,
            // this upgrades their role on sign-in.)
            const reconciledRole = getRoleForEmail(puterEmail);
            const roleChanged = reconciledRole !== existing.role;
            const updatedUser = {
              ...existing,
              status: shouldAutoApprove ? "approved" as const : existing.status,
              role: reconciledRole as any,
              lastLoginAt: now,
              lastActiveAt: now,
              avatarUrl: puterUser?.photo || existing.avatarUrl,
              updatedAt: (shouldAutoApprove || roleChanged) ? now : existing.updatedAt,
            };
            // RACE-FIX: setUserId BEFORE set()
            setUserId(updatedUser.id);
            persistSession(updatedUser);
            set((s) => ({
              users: s.users.map((u) => (u.id === existing.id ? updatedUser : u)),
              user: updatedUser,
              isAuthed: true,
              authOpen: false,
              view: "dashboard",
              synced: false,
            }));
            // === BUG 2 FIX: sync updated Puter user to D1 (last_login + status) ===
            cloudApiSafe(updateUser)(updatedUser.id, {
              lastLoginAt: updatedUser.lastLoginAt,
              status: updatedUser.status,
              role: updatedUser.role,
            }).catch((e) => { console.warn("[store] Cloud sync failed:", e instanceof Error ? e.message : e); });
            if (shouldAutoApprove) {
              useApp.getState().log({ actor: puterEmail, action: "Puter user auto-approved on sign-in", category: "auth", details: `Name: ${updatedUser.name}`, severity: "info" });
            } else {
              useApp.getState().log({ actor: puterEmail, action: "User signed in", category: "auth", details: "Provider: puter", severity: "info" });
            }
            return { ok: true, user: updatedUser };
          } else {
            // New Puter user — AUTO-APPROVED.
            // Puter users authenticate via Google/GitHub/etc through Puter's OAuth,
            // so their email is already verified by the upstream provider. There's
            // no need for an admin approval step — they can use the app immediately.
            // (Email/password registrations still go through the pending approval flow.)
            // Role is assigned from the email allowlist: if the email is in
            // SUPER_ADMIN_EMAILS, they get super_admin; if in ADMIN_EMAILS, admin;
            // otherwise user.
            const newUser: User = {
              id: uid("u"),
              name: puterName,
              username: puterName,
              email: puterEmail,
              avatarUrl: puterUser?.photo || "",
              role: getRoleForEmail(puterEmail) as any, // Check allowlist for super_admin/admin
              status: "approved", // Auto-approved — Puter OAuth already verified the email
              provider: "puter",
              createdAt: now,
              updatedAt: now,
              lastActiveAt: now,
              lastLoginAt: now,
              usage: { resumesGenerated: 0, atsChecks: 0, coverLetters: 0, interviewPreps: 0, downloads: 0 },
            };
            // RACE-FIX: setUserId BEFORE set() so cloud-API calls during the
            // synchronous store update carry the correct X-User-Id header.
            setUserId(newUser.id);
            persistSession(newUser);
            set((s) => ({ users: [...s.users, newUser], user: newUser, isAuthed: true, authOpen: false, view: "dashboard", synced: false }));
            // === BUG 2 FIX: sync the new Puter user to D1 so they appear in
            // the admin Users + User Approval pages. Previously, Puter users
            // were only stored in the Zustand `users` array (in-memory) —
            // never persisted to D1. So when the admin pages loaded and
            // queried D1 via api.getUsers(), the Puter user was missing. ===
            cloudApiSafe(createUser)(newUser).catch((e) => { console.warn("[store] Cloud sync failed:", e instanceof Error ? e.message : e); });
            useApp.getState().log({ actor: puterEmail, action: "User registered via Puter (auto-approved)", category: "auth", details: `Name: ${newUser.name}`, severity: "info" });
            return { ok: true, user: newUser };
          }
        } catch (puterErr) {
          console.warn("[store] Puter sign-in failed:", puterErr instanceof Error ? puterErr.message : puterErr);
          return { ok: false, error: "Puter sign-in was cancelled or failed." };
        }
      },

      reconcileRole: () => {
        // Keep for backward compat — no-op now since roles are managed by admin actions
      },

